INSERT INTO `learning_item` VALUES (1,834729,'鍑拻瀵嗙爜 (Caesar Cipher)','浠嬬粛鍑拻瀵嗙爜鐨勫師鐞嗐€佸巻鍙插強瀹炵幇鏂规硶銆?,'鍙ゅ吀瀵嗙爜瀛?,'涓瓑','60鍒嗛挓','鍩虹浠ｆ暟銆丳ython缂栫▼','\"鐞嗚В骞跺疄鐜板嚡鎾掑瘑鐮乗"','[{\"title\": \"鍘熺悊绠€鍗昞", \"description\": \"鍗曞瓧姣嶄綅绉诲姞瀵哱"}, {\"title\": \"鍘嗗彶鎮犱箙\", \"description\": \"鍙ょ綏椹啗浜嬮€氫俊\"}, {\"title\": \"鏄撲簬瀹炵幇\", \"description\": \"閫傚悎缂栫▼鏁欏\"}]','PUBLISHED',NULL,NULL,NULL,'2026-03-20 21:42:19','2026-03-20 21:42:19'),(2,873492,'浠垮皠瀵嗙爜 (Affine Cipher)','鍗曡〃鏇挎崲瀵嗙爜锛屽熀浜庣嚎鎬у彉鎹㈠姞瀵嗭紝鏄嚡鎾掑瘑鐮佺殑鎺ㄥ箍锛屼緷璧栨ā杩愮畻涓庝箻娉曢€嗗厓','鍙ゅ吀瀵嗙爜瀛?,'涓瓑','2灏忔椂','鍩虹鏁拌锛堟ā杩愮畻銆佹渶澶у叕绾︽暟锛夈€佺畝鍗曞瘑鐮佸姒傚康','\"鎺屾彙浠垮皠瀵嗙爜鍘熺悊涓庡簲鐢╘"','[{\"title\": \"绾挎€у彉鎹", \"description\": \"涔樻硶缂╂斁缁撳悎鍔犳硶骞崇Щ\"}, {\"title\": \"瀵嗛挜绾︽潫\", \"description\": \"涔樺瓙闇€涓庡瓧姣嶈〃浜掕川\"}, {\"title\": \"浠ｆ暟鍩虹\", \"description\": \"渚濊禆妯￠€嗗厓涓庡悓浣欒繍绠梊"}]','PUBLISHED',NULL,NULL,NULL,'2026-03-20 21:42:19','2026-03-20 21:42:19'),(3,739265,'缁村悏灏间簹瀵嗙爜 (Vigen猫re Cipher)','澶氳〃鏇挎崲瀵嗙爜锛屼互鍏抽敭璇嶆帶鍒剁Щ浣嶏紝鏇捐璁や负涓嶅彲鐮磋В锛屽彲閫氳繃Kasiski妫€楠岀牬瑙?,'鍙ゅ吀瀵嗙爜瀛?,'绠€鍗?,'1.5灏忔椂','鍑拻瀵嗙爜鍩虹銆佸瓧姣嶉鐜囧垎鏋愭蹇?,'\"鎺屾彙缁村悏灏间簹瀵嗙爜鍔犺В瀵嗕笌鐮磋В\"','[{\"title\": \"澶氳〃鏇挎崲\", \"description\": \"鍏抽敭璇嶆帶鍒跺缁勭Щ浣嶈鍒橽"}, {\"title\": \"瀵嗛挜寰幆\", \"description\": \"瀵嗛挜閲嶅浣跨敤涓庢槑鏂囩瓑闀縗"}, {\"title\": \"Kasiski鐮磋В\", \"description\": \"閫氳繃閲嶅瀛愪覆鎺ㄦ祴瀵嗛挜闀垮害\"}]','PUBLISHED',NULL,NULL,NULL,'2026-03-20 21:42:19','2026-03-20 21:42:19'),(4,847391,'鏅幈璐瑰皵瀵嗙爜 (Playfair Cipher)','鍙屽瓧姣嶆浛鎹㈠瘑鐮侊紝鍩轰簬5脳5瀵嗛挜鏂归樀锛屾寜鐗瑰畾瑙勫垯鍔犲瘑锛屼竴鎴樹腑鑻卞啗鏇句娇鐢?,'鍙ゅ吀瀵嗙爜瀛?,'涓瓑','2灏忔椂','鍩虹瀵嗙爜瀛︽蹇点€佺煩闃靛潗鏍囪鐭?,'\"鎺屾彙鏅幈璐瑰皵瀵嗙爜鍔犺В瀵哱"','[{\"title\": \"鍙屽瓧姣嶆浛鎹", \"description\": \"浠ュ瓧姣嶅涓哄姞瀵嗗崟鍏僜"}, {\"title\": \"5脳5鏂归樀\", \"description\": \"瀵嗛挜鏋勫缓鏍稿績鐭╅樀缁撴瀯\"}, {\"title\": \"瑙勫垯鍔犲瘑\", \"description\": \"鍚岃鍚屽垪鐭╁舰涓夌被瑙勫垯\"}]','PUBLISHED',NULL,NULL,NULL,'2026-03-20 21:42:19','2026-03-20 21:42:19'),(5,928574,'鏅幈璐瑰皵瀵嗙爜 (Playfair Cipher)','鍩轰簬5脳5瀵嗛挜鏂归樀鐨勫弻瀛楁瘝鏇挎崲瀵嗙爜锛屾寜涓夌被瑙勫垯鍔犲瘑锛屼竴鎴樿嫳鍐涙浘骞挎硾浣跨敤','鍙ゅ吀瀵嗙爜瀛?,'涓瓑','2灏忔椂','鍩虹瀛楁瘝鏄犲皠銆佺煩闃靛潗鏍囨蹇点€佹ā杩愮畻鍩虹','\"鎺屾彙鏅幈璐瑰皵瀵嗙爜瀹屾暣搴旂敤\"','[{\"title\": \"鍙屽瓧姣嶆浛鎹", \"description\": \"浠ヤ簩鍏冪粍涓烘牳蹇冨姞瀵嗗崟鍏僜"}, {\"title\": \"鏂归樀瀵嗛挜\", \"descripti