DROP TABLE IF EXISTS `learning_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `learning_record` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '涓婚敭',
  `user_id` bigint NOT NULL COMMENT '鐢ㄦ埛ID锛屽叧鑱?sys_user.user_id',
  `item_pk` bigint NOT NULL COMMENT '鐭ヨ瘑ID锛屽叧鑱?learning_item.item_pk',
  `first_learn_time` datetime DEFAULT NULL COMMENT '棣栨瀛︿範鏃堕棿',
  `complete_time` datetime DEFAULT NULL COMMENT '瀛︿範瀹屾垚鏃堕棿',
  `complete_remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '瀛︿範瀹屾垚鏃跺娉紙鐢ㄦ埛/绯荤粺濉啓锛?,
  `learn_duration_sec` bigint unsigned NOT NULL DEFAULT '0' COMMENT '瀛︿範鏃堕暱(绉?',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_user_item` (`user_id`,`item_pk`) USING BTREE,
  KEY `idx_user` (`user_id`) USING BTREE,
  KEY `idx_item` (`item_pk`) USING BTREE,
  KEY `idx_complete_time` (`complete_time`) USING BTREE,
  CONSTRAINT `fk_lr_item` FOREIGN KEY (`item_pk`) REFERENCES `learning_item` (`item_pk`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_lr_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_time_order` CHECK (((`complete_time` is null) or (`first_learn_time` is null) or (`complete_time` >= `first_learn_time`)))
) ENGINE=InnoDB AUTO_INCREMENT=272 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='瀛︿範璁板綍琛?;
