git():\n            # 鍙栦袱浣嶆暟瀛椾负涓€缁刓n            r = int(ciphertext[i]) - 1  # 杞崲涓?绱㈠紩琛屽彿\n            c = int(ciphertext[i+1]) - 1  # 杞崲涓?绱㈠紩鍒楀彿\n            # 楠岃瘉鍧愭爣鏈夋晥鎬n            if 0 <= r < 5 and 0 <= c < 5:\n                plaintext += square[r][c]\n                i += 2  # 璺宠繃褰撳墠涓や綅鏁板瓧\n            else:\n                # 鍧愭爣鏃犳晥锛屼繚鐣欏綋鍓嶅瓧绗n                plaintext += ciphertext[i]\n                i += 1\n        else:\n            # 闈炴暟瀛楀瓧绗︾洿鎺ヤ繚鐣橽n            plaintext += ciphertext[i]\n            i += 1\n    \n    return plaintext\n\n# 娴嬭瘯瑙ｅ瘑\nciphertext = \"2315313134\"\ndecrypted = polybios_decrypt(ciphertext, poly_square)\nprint(f\"瀵嗘枃锛歿ciphertext}\")\nprint(f\"瑙ｅ瘑缁撴灉锛歿decrypted}\")  # 棰勬湡杈撳嚭锛欻ELLO'),(43,6,5,'瀹炵幇瀹屾暣瀵嗙爜绫讳笌鍔熻兘娴嬭瘯','鏁村悎涓婅堪姝ラ锛屽疄鐜板寘鍚柟闃靛垱寤恒€佸姞瀵嗐€佽В瀵嗗姛鑳界殑瀹屾暣绫伙紝鏂逛究澶嶇敤鍜屾祴璇曪紝姝ラ濡備笅锛歕n1. 绫诲垵濮嬪寲锛氬畾涔夋爣鍑嗗瓧姣嶈〃锛屽垱寤?脳5鏂归樀鍜屽瓧姣?鍧愭爣鏄犲皠琛紱\n2. 鍔犲瘑鏂规硶锛氬皝瑁呴澶勭悊銆佸瓧姣嶆槧灏勩€佸瘑鏂囨嫾鎺ラ€昏緫锛沑n3. 瑙ｅ瘑鏂规硶锛氬皝瑁呭垎缁勮В鏋愩€佸潗鏍囨槧灏勩€佹槑鏂囨嫾鎺ラ€昏緫锛沑n4. 鍔熻兘娴嬭瘯锛氶獙璇佸姞瑙ｅ瘑涓€鑷存€э紝娴嬭瘯鍚潪瀛楁瘝瀛楃鐨勫満鏅紙濡俓"HELLO WORLD!\"锛夈€俓n棰勬湡杈撳嚭锛歕n- 鍔犲瘑\"HELLO WORLD!\"寰楀埌\"2315313134 2344431514!\"锛沑n- 瑙ｅ瘑璇ュ瘑鏂囧彲杩樺師涓篭"HELLO WORLD!\"銆?,NULL,'from typing import List, Tuple, Dict\n\nclass PolybiosSquareCipher:\n    def __init__(self, alphabet: str = \"ABCDEFGHIKLMNOPQRSTUVWXYZ\"):\n        \"\"\"鍒濆鍖栵紝榛樿鍚堝苟I/J\"\"\"\n        if len(alphabet) != 25:\n            raise ValueError(\"瀛楁瘝琛ㄥ繀椤诲寘鍚?5涓瓧姣峔")\n        self.alphabet = alphabet\n        self.square = self._create_square()\n        self.char_to_pos = self._create_char_position_map()\n    \n    def _create_square(self) -> List[List[str]]:\n        \"\"\"鍒涘缓5脳5鏂归樀\"\"\"\n        square = []\n        for i in range(5):\n            row = list(self.alphabet[i*5 : (i+1)*5])\n            square.append(row)\n        return square\n    \n    def _create_char_position_map(self) -> Dict[str, Tuple[int, int]]:\n        \"\"\"鍒涘缓瀛楁瘝鍒板潗鏍囷紙1-5锛夌殑鏄犲皠\"\"\"\n        pos_map = {}\n        for r_idx, row in enumerate(self.square, 1):\n            for c_idx, char in enumerate(row, 1):\n                pos_map[char] = (r_idx, c_idx)\n        return pos_map\n    \n    def encrypt(self, plaintext: str) -> str:\n        \"\"\"鍔犲瘑鏄庢枃\"\"\"\n        plaintext = plaintext.upper().replace(\'J\', \'I\')\n        ciphertext = \"\"\n        for char in plaintext:\n            if char in self.char_to_pos:\n                r, c = self.char_to_pos[char]\n                ciphertext += f\"{r}{c}\"\n            else:\n                ciphertext += char\n        return ciphertext\n    \n    def decrypt(self, ciphertext: str) -> str:\n        \"\"\"瑙ｅ瘑瀵嗘枃\"\"\"\n        plaintext = \"\"\n        i = 0\n        while i < len(ciphertext):\n            if ciphertext[i].isdigit() and i+1 < len(ciphertext) and ciphertext[i+1].isdigit():\n                r = int(ciphertext[i]) - 1\n                c = int(ciphertext[i+1]) - 1\n                if 0 <= r < 5 and 0 <= c < 5:\n                    plaintext += self.square[r][c]\n                    i += 2\n                else:\n                    plaintext += ciphertext[i]\n                    i += 1\n            else:\n                plaintext += ciphertext[i]\n                i += 1\n        return plaintext\n\n# 娴嬭瘯瀹屾暣鍔熻兘\ncipher = PolybiosSquareCipher()\n\n# 娴嬭瘯1锛氬熀纭€鍔犺В瀵哱nplain1 = \"HELLO\"\nenc1 = cipher.encrypt(plain1)\ndec1 = cipher.decrypt(enc1)\nprint(f\"娴嬭瘯1 - 鏄庢枃锛歿plain1}\")\nprint(f\"娴嬭瘯1 - 瀵嗘枃锛歿enc1}\")  # 棰勬湡锛?315313134\nprint(f\"娴嬭瘯1 - 瑙ｅ瘑锛歿dec1}\")  # 棰勬湡锛欻ELLO\n\n# 娴嬭瘯2锛氬惈闈炲瓧姣嶅瓧绗nplain2 = \"HELLO WORLD!\"\nenc2 = cipher.encrypt(plain2)\ndec2 = cipher.decrypt(enc2)\nprint(f\"\\n娴嬭瘯2 - 鏄庢枃锛歿plain2}\")\nprint(f\"娴嬭瘯2 - 瀵嗘枃锛歿enc2}\")  # 棰勬湡锛?315313134 2344431514!\nprint(f\"娴嬭瘯2 - 瑙ｅ瘑锛歿dec2}\")  # 棰勬湡锛欻ELLO WORLD!'),(44,6,6,'鍒嗘瀽鐗圭偣涓庡畨鍏ㄦ€?,'1. 鏍稿績鐗圭偣锛歕n   - 缂栫爜鏈川锛氬睘浜庡崟瀛楁瘝鏇挎崲鐨勬墿灞曪紝姣忎釜瀛楁瘝鏄犲皠涓哄敮涓€鏁板瓧瀵癸紝瀹炵幇瀛楁瘝鍒版暟瀛楃殑绯荤粺鍖栬浆鎹紱\n   - 缁撴瀯绠€鍗曪細5脳5鏂归樀瑙勫垯鍥哄畾锛屾墜宸ュ姞瑙ｅ瘑瀹规槗锛屾棤闇€澶嶆潅璁惧锛沑n   - 琛嶇敓浠峰€硷細鏄櫘鑾辫垂灏斿瘑鐮佺瓑鍙屽瓧姣嶆浛鎹㈠瘑鐮佺殑鐞嗚鍩虹锛屽惎鍙戜簡鍚庣画浜岀淮鍔犲瘑鎬濇兂銆俓n2. 瀹夊叏鎬у眬闄愶細\n   - 棰戠巼鍙拷婧細瀵嗘枃涓殑鏁板瓧瀵归鐜囦笌鏄庢枃瀛楁瘝棰戠巼涓€涓€瀵瑰簲锛