n    for i, rail_chars in enumerate(fence):\n        chars = [char for _, char in rail_chars]\n        indices = [str(idx) for idx, _ in rail_chars]\n        print(f\"  杞ㄩ亾{i}锛氬瓧绗?{chars}锛屽搴旀槑鏂囦笅鏍?{indices}\")\n    \n# 娴嬭瘯鍙鍖朶nvisualize_encrypt(\"HELLO WORLD\", 3)'),(47,7,3,'瀹炵幇鍔犲瘑鍔熻兘骞舵祴璇?,'鍩轰簬鍔犲瘑閫昏緫锛屽垎姝ュ疄鐜板姞瀵嗗姛鑳斤紝姝ラ濡備笅锛歕n1. 杈圭晫澶勭悊锛氳嫢鏍呮爮鏁扳墹1锛屽瘑鏂囦笌鏄庢枃涓€鑷达紙鏃犻渶鎺掑垪锛夛紱\n2. 鍒濆鍖栬建閬擄細鍒涘缓k涓┖鍒楄〃锛屼唬琛╧鏉℃爡鏍忚建閬擄紱\n3. 閬嶅巻鏄庢枃瀛楃锛氭寜Z瀛楀舰瑙勫垯鍒嗛厤瀛楃鍒板搴旇建閬擄紝閫氳繃direction鍙橀噺鎺у埗绉诲姩鏂瑰悜锛堝悜涓嬩负1锛屽悜涓婁负-1锛夛紝褰撳埌杈捐建閬撻《绔紙rail=0锛夋垨搴曠锛坮ail=k-1锛夋椂锛屽弽杞琩irection锛沑n4. 鎷兼帴瀵嗘枃锛氬皢姣忔潯杞ㄩ亾鐨勫瓧绗﹀垪琛ㄦ嫾鎺ヤ负瀛楃涓诧紝鏈€缁堝悎骞舵墍鏈夎建閬撳瓧绗︿覆寰楀埌瀵嗘枃銆俓n娴嬭瘯妗堜緥锛氭槑鏂団€淲EAREDISCOVEREDFLEEATONCE鈥濓紝k=3锛岄鏈熷姞瀵嗙粨鏋滀负鈥淲ECRLTEERDSOEEFEAOCAIVDEN鈥濄€俓n鎵ц浠ｇ爜鍚庯紝杈撳嚭鏄庢枃銆佹爡鏍忔暟銆佸瘑鏂囷紝楠岃瘉鏄惁涓庨鏈熶竴鑷淬€?,NULL,'class RailFenceCipher:\n    def __init__(self):\n        pass\n    \n    def encrypt(self, plaintext: str, rails: int) -> str:\n        if rails <= 1:\n            return plaintext\n        # 鍒濆鍖杒鏉℃爡鏍忚建閬揬n        fence = [[] for _ in range(rails)]\n        rail = 0\n        direction = 1\n        \n        for char in plaintext:\n            fence[rail].append(char)\n            rail += direction\n            # 鍒拌揪杈圭晫锛屽弽杞柟鍚慭n            if rail == rails - 1 or rail == 0:\n                direction = -direction\n        \n        # 閫愯鎷兼帴瀵嗘枃\n        ciphertext = \'\'.join([\'\'.join(rail_chars) for rail_chars in fence])\n        return ciphertext\n\n# 娴嬭瘯鍔犲瘑鍔熻兘\ncipher = RailFenceCipher()\nplaintext = \"WEAREDISCOVEREDFLEEATONCE\"\nrails = 3\nencrypted = cipher.encrypt(plaintext, rails)\nprint(f\"鏄庢枃锛歿plaintext}\")\nprint(f\"鏍呮爮鏁帮細{rails}\")\nprint(f\"鍔犲瘑缁撴灉锛歿encrypted}\")\nprint(f\"棰勬湡缁撴灉锛歐ECRLTEERDSOEEFEAOCAIVDEN\")\nprint(f\"鍔犲瘑缁撴灉鏄惁绗﹀悎棰勬湡锛歿encrypted == \'WECRLTEERDSOEEFEAOCAIVDEN\'}\")  # 棰勬湡杈撳嚭True'),(48,7,4,'鐞嗚В瑙ｅ瘑鏍稿績閫昏緫','瑙ｅ瘑鏄姞瀵嗙殑閫嗚繃绋嬶紝鏍稿績鏄繕鍘熷瓧绗︾殑鍘熷浣嶇疆锛屾楠ゅ涓嬶細\n1. 璁＄畻姣忔潯杞ㄩ亾鐨勫瓧绗︽暟锛氭牴鎹姞瀵嗘椂鐨刏瀛楀舰瑙勫垯锛堢浉鍚屽懆鏈熷嚱鏁帮級锛岄亶鍘嗗瘑鏂囬暱搴锛岀粺璁℃瘡鏉¤建閬撳簲鍒嗛厤鐨勫瓧绗︽暟閲忥紙鍗冲姞瀵嗘椂姣忔潯杞ㄩ亾鐨勫瓧绗︽暟锛夛紱\n2. 鎷嗗垎瀵嗘枃鍒拌建閬擄細鎸夎绠楀嚭鐨勮建閬撻暱搴︼紝灏嗗瘑鏂囨媶鍒嗕负k涓儴鍒嗭紝鍒嗗埆瀵瑰簲k鏉¤建閬擄紱\n3. Z