\n    cipher_parts = []\n    for col_idx in key_order:\n        col_chars = [matrix[i][col_idx] for i in range(r)]\n        cipher_parts.append(\'\'.join(col_chars))\n        print(f\"璇诲彇鍒梴col_idx}锛歿col_chars}鈫抺\' \'.join(col_chars)}\")\n    \n    ciphertext = \'\'.join(cipher_parts)\n    print(f\"鏈€缁堝瘑鏂囷細{ciphertext}\")\n    return ciphertext\n\n# 娴嬭瘯婕旂ず娴佺▼\nvisualize_encrypt_process(\"ATTACKATDAWN\", \"ZEBRAS\")'),(54,8,3,'瀹炵幇鍔犲瘑鏍稿績鍑芥暟锛堝瘑閽ユ帓搴忎笌鐭╅樀鎿嶄綔锛?,'鍔犲瘑鍔熻兘鐨勬牳蹇冩槸瀹炵幇鈥滃瘑閽ユ帓搴忊€濆拰鈥滅煩闃佃鍐欌€濓紝鍒嗘瀹炵幇濡備笅锛歕n1. 瀹炵幇瀵嗛挜鎺掑簭鍑芥暟锛氳緭鍏ュ瘑閽ュ瓧绗︿覆锛岃繑鍥炲垪绱㈠紩鐨勮鍙栭『搴徬冦€傞€昏緫鏄細\n   - 鐢╡numerate缁戝畾姣忎釜瀛楃涓庡叾鍘熷垪绱㈠紩锛沑n   - 鎸夊瓧绗﹀崌搴忔帓搴忥紝鎻愬彇鎺掑簭鍚庣殑鍘熷垪绱㈠紩锛屽緱鍒跋冿紱\n2. 瀹炵幇鏄庢枃濉厖涓庣煩闃垫瀯寤猴細\n   - 璁＄畻濉厖闀垮害锛岀敤X琛ラ綈鏄庢枃鑷砶鐨勫€嶆暟锛沑n   - 鎸夎鍒嗗壊鏄庢枃锛屾瀯寤簉脳k鐭╅樀锛沑n3. 瀹炵幇鎸夊垪璇诲彇瀵嗘枃锛氶亶鍘喯冧腑鐨勫垪绱㈠紩锛岄€愬垪璇诲彇瀛楃骞舵嫾鎺ャ€俓n棰勬湡杈撳嚭锛氳緭鍏ユ槑鏂団€淎TTACKATDAWN鈥濄€佸瘑閽モ€淶EBRAS鈥濓紝杈撳嚭瀵嗘枃鈥淐WTDTTAAKNAA鈥濄€?,NULL,'def get_key_order(key: str) -> list:\n    \"\"\"鑾峰彇瀵嗛挜瀵瑰簲鐨勫垪绱㈠紩璇诲彇椤哄簭蟽\"\"\"\n    # 缁戝畾绱㈠紩鍜屽瓧绗︼紝鎸夊瓧绗﹀崌搴忔帓搴廫n    sorted_pairs = sorted(enumerate(key), key=lambda x: x[1])\n    # 鎻愬彇鎺掑簭鍚庣殑鍘熷垪绱㈠紩\n    return [idx for idx, _ in sorted_pairs]\n\n# 娴嬭瘯瀵嗛挜鎺掑簭\nkey = \"ZEBRAS\"\nkey_order = get_key_order(key)\nprint(f\"瀵嗛挜锛歿key}\")\nprint(f\"鍒楃储寮曢『搴徬冿細{key_order}\")  # 棰勬湡杈撳嚭锛歔4, 2, 1, 3, 5, 0]\n\n# 瀹炵幇鍔犲瘑鍑芥暟\ndef encrypt(plaintext: str, key: str) -> str:\n    k = len(key)\n    if k == 0:\n        return plaintext\n    \n    # 姝ラ1锛氬～鍏呮槑鏂嘰n    pad_length = (k - len(plaintext) % k) % k\n    padded_plain = plaintext + \'X\' * pad_length\n    r = len(padded_plain) // k\n    \n    # 姝ラ2锛氭寜琛屾瀯寤虹煩闃礬n    matrix = []\n    for i in range(r):\n        row = list(padded_plain[i*k : (i+1)*k])\n        matrix.append(row)\n    \n    # 姝ラ3锛氳幏鍙栧垪璇诲彇椤哄簭\n    key_order = get_key_order(key)\n    \n    # 姝ラ4锛氭寜鍒楄鍙栧瘑鏂嘰n    ciphertext = \"\"\n    for col_idx in key_order:\n        for i in range(r):\n            ciphertext += matrix[i][col_idx]\n    \n    return ciphertext\n\n# 娴嬭瘯鍔犲瘑\nplaintext = \"ATTACKATDAWN\"\nciphertext = encrypt(plaintext, key)\nprint(f\"鏄庢枃锛歿plaintext}\")\nprint(f\"瀵嗘枃锛歿ciphertext}\")  # 棰勬湡杈撳嚭锛欳WTDTTAAKNAA'),(55,8,4,'鐞嗚В瑙ｅ瘑鏍稿績閫昏緫','瑙ｅ瘑鏄姞瀵嗙殑閫嗚繃绋嬶紝鏍稿績鏄€滄寜瀵嗛挜鍒楀簭濉煩闃点€佹寜琛岃鏄庢枃鈥濓紝姝ラ濡備笅锛歕n1. 纭畾鐭╅樀鍙傛暟锛歕n   - 瀵嗛挜闀垮害k锛堢煩闃靛垪鏁帮級锛沑n   - 瀵嗘枃闀垮害n锛岀煩闃佃鏁皉 = n/k锛堝洜鍔犲瘑鏃跺凡濉厖锛宯鏄痥鐨勫€嶆暟锛夛紱\n2. 鑾峰彇鍒楀～鍏呴『搴忥細鍗冲姞瀵嗘椂鐨勫垪绱㈠紩椤哄簭蟽锛堥€氳繃瀵嗛挜鎺掑簭寰楀埌锛夛紱\n3. 鎸夊垪濉厖鐭╅樀锛歕n   - 鍒涘缓绌虹殑r脳k鐭╅樀锛沑n   - 鎸壪冪殑椤哄簭锛屽皢瀵嗘枃鎸夊垪閫愬瓧绗﹀～鍏呭埌瀵瑰簲鍒椾腑锛堟瘡鍒楀～鍏卹涓瓧绗︼級锛沑n4. 鎸夎璇诲彇鏄庢枃锛氶亶鍘嗙煩闃电殑姣忎竴琛岋紝鎷兼帴瀛楃寰楀埌鏄庢枃锛堟湯灏惧～鍏呯殑X鍙牴鎹笂涓嬫枃鍘婚櫎锛夈€俓n绀轰緥锛氬瘑鏂団€淐WTDTTAAKNAA鈥濓紝瀵嗛挜鈥淶EBRAS鈥濓紙k=6锛宺=2锛夛細\n蟽=[4,2,1,3,5,0]锛屽瘑鏂囧垎鍓蹭负6鍒楋紝姣忓垪2涓瓧绗︼細\n鍒?锛欳,W锛涘垪2锛歍,D锛涘垪1锛歍,T锛涘垪3锛欰,A锛涘垪5锛欿,N锛涘垪0锛欰,A锛沑n濉厖鐭╅樀锛歕n鍒?锛欰,A锛涘垪1锛歍,T锛涘垪2锛歍,D锛涘垪3锛欰,A锛涘垪4锛欳,W锛涘垪5锛欿,N锛沑n鎸夎璇诲彇锛氱0琛孉 T T A C K锛岀1琛孉 T D A W N鈫掓槑鏂団€淎TTACKATDAWN鈥濄€?,'瑙ｅ瘑鐨勫叧閿槸鈥滄寜鍔犲瘑鏃剁殑鍒楅『搴忓弽鍚戝～鍏呯煩闃碘€濓紝鐭╅樀鐨勮鍒楁暟涓庡姞瀵嗘椂瀹屽叏涓€鑷?,NULL),(56,8,5,'瀹炵幇瑙ｅ瘑鍑芥暟骞堕獙璇?,'鍩轰簬瑙ｅ瘑閫昏緫锛屽垎姝ュ疄鐜拌В瀵嗗嚱鏁帮細\n1. 澶嶇敤瀵嗛挜鎺掑簭鍑芥暟get_key_order锛岃幏鍙栧垪濉厖椤哄簭蟽锛沑n2. 纭畾鐭╅樀琛屽垪鏁帮細r = 瀵嗘枃闀垮害 // k锛沑n3. 鍒涘缓绌虹煩闃碉細r琛宬鍒楋紱\n4. 鎸壪冮『搴忓～鍏呯煩闃碉細閬嶅巻蟽涓殑鍒楃储寮曪紝閫愬垪浠庡瘑鏂囦腑鎻愬彇r涓瓧绗﹀～鍏呭埌瀵瑰簲鍒楋紱\n5. 鎸夎璇诲彇鏄庢枃锛氭嫾鎺ユ瘡琛屽瓧绗﹀緱鍒版渶缁堟槑鏂囥€俓n棰勬湡杈撳嚭锛氳緭鍏ュ瘑鏂団€淐WTDTTAAKNAA鈥濄€佸瘑閽モ€淶EBRAS鈥濓紝杈撳嚭鏄庢枃鈥淎TTACKATDAWN鈥濓紙鑻ユ湁濉厖X锛岄渶鍚庣画澶勭悊锛夈€?,NULL,'def decrypt(ciphertext: str, key: str) -> str:\n    k = len(key)\n    if k == 0:\n        return ciphertext\n    \n    # 姝ラ1锛氱‘瀹氱煩闃靛弬鏁癨n    n = len(ciphertext)\n    r = n // k\n    if r * k != n:\n        raise ValueError(\"瀵嗘枃闀垮害涓嶆槸瀵嗛挜闀垮害鐨勫€嶆暟锛屾棤娉曡В瀵哱")\n    \n    # 姝ラ2锛氳幏鍙栧垪濉厖椤哄簭锛堜笌鍔犲瘑涓€鑷达級\n    key_order = get_key_order(key)\n    \n    # 姝ラ3锛氬垱寤虹┖鐭╅樀\n    matrix = [[\'\' for _ in range(k)] for _ in range(r)]\n    \n    # 姝ラ4锛氭寜鍒楀～鍏呯煩闃礬n    char_idx = 0\n    for col_idx in key_order:\n        for i in range(r):\n            matrix[i][col_idx] = ciphertext[char_idx]\n            char_idx += 1\n    \n    # 姝ラ5锛氭寜琛岃鍙栨槑鏂嘰n    plaintext = \"\"\n    for row in matrix:\n        plaintext += \'\'.join(row)\n    \n    return plaintext\n\n# 娴嬭瘯瑙ｅ瘑\nciphertext = \"CWTDTTAAKNAA\"\nkey = \"ZEBRAS\"\ndecrypted = decrypt(ciphertext, key)\nprint(f\"瀵嗘枃锛歿ciphertext}\")\nprint(f\"瀵嗛挜锛歿key}\")\nprint(f\"瑙ｅ瘑缁撴灉锛歿decrypted}\")  # 棰勬湡杈撳嚭锛欰TTACKATDAWN\nprint(f\"涓庡師鏄庢枃涓€鑷达細{decrypted == \'ATTACKATDAWN\'}\")  # 棰勬湡杈撳嚭锛歍rue'),(57,8,6,'鏁村悎瀹屾暣绫诲苟娴嬭瘯澶氬満鏅?,'鏁村悎鍔犲瘑銆佽В瀵嗗強瀵嗛挜鎺掑簭鍔熻兘锛屽疄鐜板畬鏁寸殑鍒楃疆鎹㈠瘑鐮佺被锛屽苟娴嬭瘯涓嶅悓鍦烘櫙锛歕n1. 鍦烘櫙1锛氭槑鏂囬暱搴︿负瀵嗛挜闀垮害鐨勫€嶆暟锛堟棤濉厖锛夛紝濡傛槑鏂団€淗ELLOWORLD鈥濓紙n=10锛夛紝瀵嗛挜鈥淪ECRET鈥濓紙k=6锛屽～鍏?涓猉锛夛紱\n2. 鍦烘櫙2锛氬惈鐗规畩瀛楃鐨勬槑鏂囷紝濡傗€淗ELLO, WORLD!鈥濓紙鐗规畩瀛楃瑙嗕负鏅€氬瓧绗﹀弬涓庣疆鎹級锛沑n3. 鍦烘櫙3锛氬弻閲嶅垪缃崲锛堜袱娆″垪缃崲鍔犲瘑锛屼袱娆¤В瀵嗚繕鍘燂級锛岄獙璇佺疆鎹㈢殑鍚堟垚鎬с€俓n棰勬湡杈撳嚭锛氭墍鏈夊満鏅笅锛岃В瀵嗙粨鏋滃潎涓庡師濮嬫槑鏂囦竴鑷达紙濉厖鐨刋闄ゅ锛夈€?,NULL,'from typing import List\n\nclass ColumnarTranspositionCipher:\n    \"\"\"瀹屾暣鐨勫垪缃崲瀵嗙爜绫籠"\"\"\n    def __init__(self):\n        pass\n    \n    def _get_key_order(self, key: str) -> List[int]:\n        \"\"\"鑾峰彇瀵嗛挜瀵瑰簲鐨勫垪绱㈠紩椤哄簭\"\"\"\n        sorted_pairs = sorted(enumerate(key), key=lambda x: x[1])\n        return [idx for idx, _ in sorted_pairs]\n    \n    def encrypt(self, plaintext: str, key: str) -> str:\n        \"\"\"鍔犲瘑鏄庢枃\"\"\"\n        k = len(key)\n        if k <= 1:\n            return plaintext\n        \n        # 濉厖鏄庢枃\n        pad_length = (k - len(plaintext) % k) % k\n        padded_plain = plaintext + \'X\' * pad_length\n        r = len(padded_plain) // k\n        \n        # 鏋勫缓鐭╅樀\n        matrix = []\n        for i in range(r):\n            row = list(padded_plain[i*k : (i+1)*k])\n            matrix.append(row)\n        \n        # 鎸夊垪璇诲彇瀵嗘枃\n        key_order = self._get_key_order(key)\n        ciphertext = \"\"\n        for col_idx in key_order:\n            for i in range(r):\n                ciphertext += matrix[i][col_idx]\n        \n        return ciphertext\n    \n    def decrypt(self, ciphertext: str, key: str) -> str:\n        \"\"\"瑙ｅ瘑瀵嗘枃\"\"\"\n        k = len(key)\n        if k <= 1:\n            return ciphertext\n        \n        # 楠岃瘉瀵嗘枃闀垮害\n        n = len(ciphertext)\n        if n % k != 0:\n            raise ValueError(\"瀵嗘枃闀垮害闇€涓哄瘑閽ラ暱搴︾殑鍊嶆暟\")\n        r = n // k\n        \n        # 鍒涘缓鐭╅樀骞跺～鍏匼n        matrix = [[\'\' for _ in range(k)] for _ in range(r)]\n        key_order = self._get_key_order(key)\n        char_idx = 0\n        for col_idx in key_order:\n            for i in range(r):\n                matrix[i][col_idx] = ciphertext[char_idx]\n                char_idx += 1\n        \n        # 鎸夎璇诲彇鏄庢枃\n        plaintext = \'\'.join([\'\'.join(row) for row in matrix])\n        return plaintext\n\n# 娴嬭瘯澶氬満鏅痋ncipher = ColumnarTranspositionCipher()\n\n# 鍦烘櫙1锛氬熀纭€鍔犺В瀵哱nprint(\"鍦烘櫙1锛氬熀纭€鍔犺В瀵哱")\nplain1 = \"ATTACKATDAWN\"\nkey1 = \"ZEBRAS\"\nenc1 = cipher.encrypt(plain1, key1)\ndec1 = cipher.decrypt(enc1, key1)\nprint(f\"鏄庢枃锛歿plain1}\")\nprint(f\"瀵嗛挜锛歿key1}\")\nprint(f\"瀵嗘枃锛歿enc1}\")\nprint(f\"瑙ｅ瘑锛歿dec1}\")\nprint(f\"涓€鑷达細{dec1 == plain1}\")\n\n# 鍦烘櫙2锛氬惈鐗规畩瀛楃\nprint(\"\\n鍦烘櫙2锛氬惈鐗规畩瀛楃\")\nplain2 = \"HELLO, WORLD!\"\nkey2 = \"SECRET\"\nenc2 = cipher.encrypt(plain2, key2)\ndec2 = cipher.decrypt(enc2, key2)\nprint(f\"鏄庢枃锛歿plain2}\")\nprint(f\"瀵嗛挜锛歿key2}\")\nprint(f\"瀵嗘枃锛歿enc2}\")\nprint(f\"瑙ｅ瘑锛歿dec2}\")\nprint(f\"涓€鑷达細{dec2.replace(\'X\',\'\') == plain2}\")  # 蹇界暐濉厖鐨刋\n\n# 鍦烘櫙3锛氬弻閲嶅垪缃崲\nprint(\"\\n鍦烘櫙3锛氬弻閲嶅垪缃崲\")\nplain3 = \"WEAREDISCOVEREDFLEEATONCE\"\nkey3_1 = \"ZEBRAS\"\nkey3_2 = \"CRYPTO\"\n# 涓ゆ鍔犲瘑\nenc3_1 = cipher.encrypt(plain3, key3_1)\nenc3_2 = cipher.encrypt(enc3_1, key3_2)\n# 涓ゆ瑙ｅ瘑\ndec3_1 = cipher.decrypt(enc3_2, key3_2)\ndec3_2 = cipher.decrypt(enc3_1, key3_1)\nprint(f\"鏄庢枃锛歿plain3}\")\nprint(f\"绗竴娆″姞瀵嗭紙瀵嗛挜{key3_1}锛夛細{enc3_1}\")\nprint(f\"绗簩娆″姞瀵嗭紙瀵嗛挜{key3_2}锛夛細{enc3_2}\")\nprint(f\"涓ゆ瑙ｅ瘑鍚庯細{dec3_2}\")\nprint(f\"涓€鑷达細{dec3_2 == plain3}\")'),(58,8,7,'鍒嗘瀽鏁板鏈川涓庡畨鍏ㄦ€?,'1. 鏁板鏈川锛歕n   - 鍒楃疆鎹㈠瘑鐮佺殑鏍稿績鏄泦鍚圫鈧欙紙n涓烘槑鏂囬暱搴︼級涓婄殑鍙屽皠缃崲蟺锛屽姞瀵嗚繃绋嬪嵆瀛楃浣嶇疆鎸壪€閲嶆帓锛屽瘑鏂嘋[蟺(i)] = 鏄庢枃P[i]锛沑n   - 瑙勫垯鐭╅樀锛堟湁濉厖锛夌殑缃崲鍏紡锛毾€(i脳k + j) = rank(j)脳r + i锛坕涓鸿鍙凤紝j涓哄垪鍙凤紝rank(j)涓哄垪j鐨勬帓搴忓悕娆★紝r涓鸿鏁帮級锛沑n   - 鍙岄噸鍒楃疆鎹㈢殑缃崲涓轰袱娆＄疆鎹㈢殑鍚堟垚蟺鈧傗垬蟺鈧侊紝瀹夊叏鎬ч珮浜庡崟娆＄疆鎹€俓n2. 瀹夊叏鎬х壒鐐癸細\n   - 浼樺娍锛氱浉姣斿崟瀛楁瘝浠ｆ崲瀵嗙爜锛屽瓧姣嶉鐜囧垎甯冧笉鍙橈紝鑳芥姷鎶楀熀纭€棰戠巼鍒嗘瀽锛涘瘑閽ラ暱搴瓒婂ぇ锛屽垪鎺掑垪缁勫悎鏁拌秺澶氾紙k!绉嶏級锛岀牬瑙ｉ毦搴﹁秺楂橈紱\n   - 灞€闄愶細鏄撹宸茬煡鏄庢枃鏀诲嚮鎴栭儴鍒嗘槑鏂囨敾鍑伙紱鍙€氳繃鍒嗘瀽瀵嗘枃闀垮害涓庡彲鑳界殑瀵嗛挜闀垮害锛坘涓哄瘑鏂囬暱搴︾殑绾︽暟锛