= gcd(det_mod26, 26)\nprint(f\"gcd({det_mod26},26)={gcd_val}\")\nprint(f\"鐭╅樀鏄惁鍙€嗭細{gcd_val == 1}\")  # 棰勬湡杈撳嚭锛歍rue\n\n# 姝ラ3锛氭墿灞曟鍑犻噷寰楃畻娉曟眰妯￠€哱ndef extended_gcd(a: int, b: int) -> tuple:\n    \"\"\"杩斿洖(gcd, x, y)锛屾弧瓒砤*x + b*y = gcd\"\"\"\n    if a == 0:\n        return b, 0, 1\n    gcd_val, x1, y1 = extended_gcd(b % a, a)\n    x = y1 - (b // a) * x1\n    y = x1\n    return gcd_val, x, y\n\ndef mod_inverse(a: int, m: int) -> int:\n    \"\"\"璁＄畻a鍦ㄦām涓嬬殑閫嗗厓锛屼笉瀛樺湪鍒欒繑鍥濶one\"\"\"\n    gcd_val, x, _ = extended_gcd(a % m, m)\n    if gcd_val != 1:\n        return None\n    return (x % m + m) % m\n\ndet_inv = mod_inverse(det_mod26, 26)\nprint(f\"琛屽垪寮弡det_mod26}鐨勬ā26閫嗗厓锛歿det_inv}\")  # 棰勬湡杈撳嚭锛?\n\n# 姝ラ4-5锛氳绠楅€嗙煩闃礬ndef matrix_inverse_2x2(matrix: list, mod: int) -> list:\n    \"\"\"璁＄畻2x2鐭╅樀鐨勬ā閫哱"\"\"\n    a, b = matrix[0][0], matrix[0][1]\n    c, d = matrix[1][0], matrix[1][1]\n    det = (a*d - b*c) % mod\n    det_inv = mod_inverse(det, mod)\n    if det_inv is None:\n        raise ValueError(\"鐭╅樀涓嶅彲閫哱")\n    # 浼撮殢鐭╅樀 脳 琛屽垪寮忛€嗗厓锛屽彇妯n    inv_matrix = [\n        [(d * det_inv) % mod, (-b * det_inv) % mod],\n        [(-c * det_inv) % mod, (a * det_inv) % mod]\n    ]\n    return inv_matrix\n\ninv_key_matrix = matrix_inverse_2x2(key_matrix, 26)\nprint(f\"瀵嗛挜鐭╅樀鐨勬ā26閫嗙煩闃碉細{inv_key_matrix}\")  # 棰勬湡杈撳嚭锛歔[15, 17], [20, 9]]'),(62,9,4,'瀹炵幇鍔犲瘑鍔熻兘锛?脳2鐭╅樀锛?,'鍔犲瘑鍔熻兘鐨勬牳蹇冩槸鈥滄槑鏂囧垎缁勨啋鍚戦噺鏄犲皠鈫掔煩闃典箻娉曗啋妯?6鈫掑瓧绗︽槧灏勨€濓紝姝ラ濡備笅锛歕n1. 鏄庢枃棰勫鐞嗭細\n   - 杩囨护闈炲瓧姣嶅瓧绗︼紝缁熶竴杞负澶у啓锛沑n   - 鎸夊垎缁勯暱搴︼紙2涓瓧姣嶄竴缁勶級鎷嗗垎锛岃嫢闀垮害涓哄鏁帮紝鏈熬濉厖X锛堟槧灏勪负23锛夛紱\n2. 鍚戦噺鏄犲皠锛氬皢姣忕粍鏄庢枃杞崲涓?脳1鐨勬暟瀛楀悜閲忥紱\n3. 鐭╅樀涔樻硶锛氱敤瀵嗛挜鐭╅樀涓庢槑鏂囧瓧鍚戦噺鍋氫箻娉曪紝缁撴灉鍙栨ā26锛沑n4. 瀛楃鏄犲皠锛氬皢瀵嗘枃鍚戦噺杞崲鍥炲瓧姣嶏紝鎷兼帴寰楀埌鏈€缁堝瘑鏂囷紱\n5. 鍚堟硶鎬ф鏌ワ細楠岃瘉瀵嗛挜鐭╅樀鏄惁涓?脳2锛屼笖琛屽垪寮忎笌26浜掔礌锛堢‘淇濆彲閫嗭級銆俓n棰勬湡杈撳嚭锛氳緭鍏ユ槑鏂団€淗ELLO鈥濓紙棰勫鐞嗗悗涓衡€淗ELLO鈥濓紝闀垮害5锛屽～鍏呬负鈥淗ELLOX鈥濓級銆佸瘑閽ョ煩闃礫[3,3],[2,5]]锛屽姞瀵嗗悗瀵嗘枃涓衡€淭CSWXC鈥濄€?,NULL,'class HillCipher:\n    def __init__(self):\n        self.alphabet_size = 26  # 浠呮敮鎸佸ぇ鍐欒嫳鏂囧瓧姣峔n    \n    def _preprocess_plaintext(self, plaintext: str) -> str:\n        \"\"\"棰勫鐞嗘槑鏂囷細杩囨护闈炲瓧姣嶃€佸ぇ鍐欍€佸～鍏匵\"\"\"\n        processed = \'\'.join([c.upper() for c in plaintext if c.isalpha()])\n        # 濉厖X浣块暱搴︿负2鐨勫€嶆暟\n        if len(processed) % 2 != 0:\n            processed += \'X\'\n        return processed\n    \n    def _letter_to_num(self, letter: str) -> int:\n        return ord(letter) - ord(\'A\')\n    \n    def _num_to_letter(self, num: int) -> str:\n        return chr(num + ord(\'A\'))\n    \n    def _determinant_2x2(self, matrix: list) -> int:\n        \"\"\"璁＄畻2x2鐭╅樀琛屽垪寮廫"\"\"\n        return matrix[0][0] * matrix[1][1] - matrix[0][1] * matrix[1][0]\n    \n    def _gcd(self, a: int, b: int) -> int:\n        while b:\n            a, b = b, a % b\n        return a\n    \n    def encrypt(self, plaintext: str, key_matrix: list) -> str:\n        \"\"\"2脳2鐭╅樀鍔犲瘑\"\"\"\n        # 妫€鏌ュ瘑閽ョ煩闃电淮搴n        if len(key_matrix) != 2 or len(key_matrix[0]) != 2:\n            raise ValueError(\"浠呮敮鎸?脳2瀵嗛挜鐭╅樀\")\n        \n        # 妫€鏌ュ瘑閽ョ煩闃靛彲閫嗘€n        det = self._determinant_2x2(key_matrix) % self.alphabet_size\n        if self._gcd(det, self.alphabet_size) != 1:\n            raise ValueError(\"瀵嗛挜鐭╅樀涓嶅彲閫嗭紝鏃犳硶鍔犲瘑\")\n        \n        # 棰勫鐞嗘槑鏂嘰n        processed_plain = self._preprocess_plaintext(plaintext)\n        print(f\"棰勫鐞嗗悗鏄庢枃锛歿processed_plain}\")\n        \n        ciphertext = \"\"\n        # 鎸?涓瓧姣嶄竴缁勫鐞哱n        for i in range(0, len(processed_plain), 2):\n            # 杞崲涓烘槑鏂囧瓧鍚戦噺\n            p0 = self._letter_to_num(processed_plain[i])\n            p1 = self._letter_to_num(processed_plain[i+1])\n            plain_vector = [p0, p1]\n            print(f\"绗瑊i//2+1}缁勬槑鏂囷細{processed_plain[i:i+2]}鈫掑悜閲弡plain_vector}\")\n            \n            # 鐭╅樀涔樻硶锛?x2 脳 2x1锛塡n            c0 = (key_matrix[0][0] * p0 + key_matrix[0][1] * p1) % self.alphabet_size\n            c1 = (key_matrix[1][0] * p0 + key_matrix[1][1] * p1) % self.alphabet_size\n            cipher_vector = [c0, c1]\n            print(f\"鍔犲瘑鍚庡悜閲忥細{cipher_vector}鈫掑瓧绗self._num_to_letter(c0)}{self._num_to_letter(c1)}\")\n            \n            # 鎷兼帴瀵嗘枃\n            ciphertext += self._num_to_letter(c0) + self._num_to_letter(c1)\n        \n        return ciphertext\n\n# 娴嬭瘯鍔犲瘑\ncipher = HillCipher()\nplaintext = \"HELLO\"\nkey_matrix = [[3, 3], [2, 5]]\nencrypted = cipher.encrypt(plaintext, key_matrix)\nprint(f\"鏈€缁堝瘑鏂囷細{encrypted}\")  # 棰勬湡杈撳嚭锛歍CSWXC'),(63,9,5,'瀹炵幇瑙ｅ瘑鍔熻兘骞堕獙璇?,'瑙ｅ瘑鏄姞瀵嗙殑閫嗚繃绋嬶紝鏍稿績鏄€滅敤閫嗙煩闃垫浛浠ｅ瘑閽ョ煩闃碉紝閲嶅鍔犲瘑娴佺▼鈥濓紝姝ラ濡備笅锛歕n1. 瀹炵幇鐭╅樀妯￠€嗗嚱鏁帮細澶嶇敤涔嬪墠鐨勮鍒楀紡璁＄畻銆佹墿灞曟鍑犻噷寰楃畻娉曘€佷即闅忕煩闃佃绠楅€昏緫锛屽皝瑁呬负鐭╅樀姹傞€嗘柟娉曪紱\n2. 瑙ｅ瘑閫昏緫锛歕n   - 杈撳叆瀵嗘枃鍜屽瘑閽ョ煩闃碉紝鍏堣绠楀瘑閽ョ煩闃电殑妯?6閫嗙煩闃碉紱\n   - 鑻ラ€嗙煩闃典笉瀛樺湪锛屾姏鍑哄紓甯革紱\n   - 灏嗛€嗙煩闃典綔涓衡€滄柊瀵嗛挜鐭╅樀鈥濓紝璋冪敤鍔犲瘑鍑芥暟锛堝洜鍔犲瘑涓庤В瀵嗙殑鐭╅樀涔樻硶閫昏緫涓€鑷达紝浠呯煩闃典笉鍚岋級锛沑n3. 缁撴灉澶勭悊锛氳В瀵嗗悗鐨勬槑鏂囧彲鑳藉寘鍚湯灏惧～鍏呯殑X锛岄渶鏍规嵁涓婁笅鏂囧幓闄わ紙鏈ず渚嬩繚鐣欏～鍏咃紝楠岃瘉瀹屾暣鎬э級銆俓n棰勬湡杈撳嚭锛氳緭鍏ュ瘑鏂団€淭CSWXC鈥濄€佸瘑閽ョ煩闃礫[3,3],[2,5]]锛岃В瀵嗗悗鏄庢枃涓衡€淗ELLOX鈥濓紙涓庡姞瀵嗗墠濉厖鍚庣殑鏄庢枃涓€鑷达級銆?,NULL,'class HillCipher:\n    def __init__(self):\n        self.alphabet_size = 26\n    \n    # 澶嶇敤涔嬪墠鐨刜preprocess_plaintext銆乢letter_to_num銆乢num_to_letter銆乢determinant_2x2銆乢gcd鏂规硶\n    def _preprocess_plaintext(self, plaintext: str) -> str:\n        processed = \'\'.join([c.upper() for c in plaintext if c.isalpha()])\n        if len(processed) % 2 != 0:\n            processed += \'X\'\n        return processed\n    \n    def _letter_to_num(self, letter: str) -> int:\n        return ord(letter) - ord(\'A\')\n    \n    def _num_to_letter(self, num: int) -> str:\n        return chr(num + ord(\'A\'))\n    \n    def _determinant_2x2(self, matrix: list) -> int:\n        return matrix[0][0] * matrix[1][1] - matrix[0][1] * matrix[1][0]\n    \n    def _gcd(self, a: int, b: int) -> int:\n        while b:\n            a, b = b, a % b\n        return a\n    \n    # 鏂板鎵╁睍娆у嚑閲屽緱涓庢ā閫嗘柟娉昞n    def _extended_gcd(self, a: int, b: int) -> tuple:\n        if a == 0:\n            return b, 0, 1\n        gcd_val, x1, y1 = self._extended_gcd(b % a, a)\n        x = y1 - (b // a) * x1\n        y = x1\n        return gcd_val, x, y\n    \n    def _mod_inverse(self, a: int, m: int) -> int:\n        gcd_val, x, _ = self._extended_gcd(a % m, m)\n        if gcd_val != 1:\n            return None\n        return (x % m + m) % m\n    \n    # 鏂板2x2鐭╅樀姹傞€嗘柟娉昞n    def _matrix_inverse_2x2(self, matrix: list) -> list:\n        det = self._determinant_2x2(matrix) % self.alphabet_size\n        det_inv = self._mod_inverse(det, self.alphabet_size)\n        if det_inv is None:\n            return None\n        a, b = matrix[0][0], matrix[0][1]\n        c, d = matrix[1][0], matrix[1][1]\n        # 浼撮殢鐭╅樀 脳 琛屽垪寮忛€嗗厓\n        inv_matrix = [\n            [(d * det_inv) % self.alphabet_size, (-b * det_inv) % self.alphabet_size],\n            [(-c * det_inv) % self.alphabet_size, (a * det_inv) % self.alphabet_size]\n        ]\n        return inv_matrix\n    \n    # 澶嶇敤鍔犲瘑鏂规硶\n    def encrypt(self, plaintext: str, key_matrix: list) -> str:\n        if len(key_matrix) != 2 or len(key_matrix[0]) != 2:\n            raise ValueError(\"浠呮敮鎸?脳2瀵嗛挜鐭╅樀\")\n        det = self._determinant_2x2(key_matrix) % self.alphabet_size\n        if self._gcd(det, self.alphabet_size) != 1:\n            raise ValueError(\"瀵嗛挜鐭╅樀涓嶅彲閫哱")\n        processed_plain = self._preprocess_plaintext(plaintext)\n        ciphertext = \"\"\n        for i in range(0, len(processed_plain), 2):\n            p0 = self._letter_to_num(processed_plain[i])\n            p1 = self._letter_to_num(processed_plain[i+1])\n            c0 = (key_matrix[0][0] * p0 + key_matrix[0][1] * p1) % self.alphabet_size\n            c1 = (key_matrix[1][0] * p0 + key_matrix[1][1] * p1) % self.alphabet_size\n            ciphertext += self._num_to_letter(c0) + self._num_to_letter(c1)\n        return ciphertext\n    \n    # 鏂板瑙ｅ瘑鏂规硶\n    def decrypt(self, ciphertext: str, key_matrix: list) -> str:\n        \"\"\"2脳2鐭╅樀瑙ｅ瘑\"\"\"\n        # 璁＄畻閫嗙煩闃礬n        inv_key_matrix = self._matrix_inverse_2x2(key_matrix)\n        if inv_key_matrix is None:\n            raise ValueError(\"瀵嗛挜鐭╅樀涓嶅彲閫嗭紝鏃犳硶瑙ｅ瘑\")\n        print(f\"瀵嗛挜鐭╅樀鐨勯€嗙煩闃碉細{inv_key_matrix}\")\n        \n        # 鐢ㄩ€嗙煩闃靛姞瀵嗗嵆瑙ｅ瘑\n        decrypted = self.encrypt(ciphertext, inv_key_matrix)\n        return decrypted\n\n# 娴嬭瘯鍔犺В瀵嗗畬鏁存祦绋媆ncipher = HillCipher()\nplaintext = \"HELLO\"\nkey_matrix = [[3, 3], [2, 5]]\n\n# 鍔犲瘑\nencrypted = cipher.encrypt(plaintext, key_matrix)\nprint(f\"鏄庢枃锛歿plaintext}\")\nprint(f\"瀵嗛挜鐭╅樀锛歿key_matrix}\")\nprint(f\"瀵嗘枃锛歿encrypted}\")\n\n# 瑙ｅ瘑\ndecrypted = cipher.decrypt(encrypted, key_matrix)\nprint(f\"瑙ｅ瘑缁撴灉锛歿decrypted}\")  # 棰勬湡杈撳嚭锛欻ELLOX\nprint(f\"瑙ｅ瘑鏄惁姝ｇ‘锛堝惈濉厖锛夛細{decrypted == \'HELLOX\'}\")  # 棰勬湡杈撳嚭锛歍rue\nprint(f\"鍘熷鏄庢枃杩樺師锛歿decrypted.rstrip(\'X\')}\")  # 棰勬湡杈撳嚭锛欻ELLO'),(64,9,6,'瀹炵幇闅忔満瀵嗛挜鐢熸垚涓庡鍦烘櫙娴嬭瘯','瀵嗛挜鐭╅樀闇€婊¤冻鈥?脳2鈥濆拰鈥滆鍒楀紡涓?6浜掔礌鈥濓紝闅忔満鐢熸垚姝ラ濡備笅锛歕n1. 寰幆鐢熸垚2脳2鐭╅樀锛屽厓绱犱负0-25鐨勯殢鏈烘暣鏁帮紱\n2. 璁＄畻鐭╅樀琛屽垪寮忥紝楠岃瘉$\\gcd(\\det(K),26)=1$锛沑n3. 婊¤冻鏉′欢鍒欒繑鍥炵煩闃碉紝鍚﹀垯缁х画鐢熸垚銆俓n澶氬満鏅祴璇曪細\n1. 鍦烘櫙1锛氬惈鐗规畩瀛楃鐨勬槑鏂囷紙濡傗€淗ELLO, WORLD!鈥濓級锛岄獙璇侀潪瀛楁瘝瀛楃琚繃婊わ紱\n2. 鍦烘櫙2锛氬鏁伴暱搴︽槑鏂囷紙濡傗€淎TTACK鈥濓紝闀垮害6锛屾棤闇€濉厖锛涒€淎TTAC鈥濓紝闀垮害5锛屽～鍏呬负鈥淎TTACX鈥濓級锛沑n3. 鍦烘櫙3锛氶殢鏈哄瘑閽ュ姞瀵嗭紝楠岃瘉鍔犺В瀵嗕竴鑷存€с€俓n棰勬湡杈撳嚭锛氭墍鏈夊満鏅笅锛岃В瀵嗗悗鏄庢枃锛堝幓闄ゅ～鍏匵鍚庯級涓庡師濮嬫槑鏂囦竴鑷淬€?,NULL,'import random\n\nclass HillCipher:\n    def __init__(self):\n        self.alphabet_size = 26\n    \n    # 澶嶇敤涔嬪墠鐨勬墍鏈夋柟娉昞n    def _preprocess_plaintext(self, plaintext: str) -> str:\n        processed = \'\'.join([c.upper() for c in plaintext if c.isalpha()])\n        if len(processed) % 2 != 0:\n            processed += \'X\'\n        return processed\n    \n    def _letter_to_num(self, letter: str) -> int:\n        return ord(letter) - ord(\'A\')\n    \n    def _num_to_letter(self, num: int) -> str:\n        return chr(num + ord(\'A\'))\n    \n    def _determinant_2x2(self, matrix: list) -> int:\n        return matrix[0][0] * matrix[1][1] - matrix[0][1] * matrix[1][0]\n    \n    def _gcd(self, a: int, b: int) -> int:\n        while b:\n            a, b = b, a % b\n        return a\n    \n    def _extended_gcd(self, a: int, b: int) -> tuple:\n        if a == 0:\n            return b, 0, 1\n        gcd_val, x1, y1 = self._extended_gcd(b % a, a)\n        x = y1 - (b // a) * x1\n        y = x1\n        return gcd_val, x, y\n    \n    def _mod_inverse(self, a: int, m: int) -> int:\n        gcd_val, x, _ = self._extended_gcd(a % m, m)\n        if gcd_val != 1:\n            return None\n        return (x % m + m) % m\n    \n    def _matrix_inverse_2x2(self, matrix: list) -> list:\n        det = self._determinant_2x2(matrix) % self.alphabet_size\n        det_inv = self._mod_inverse(det, self.alphabet_size)\n        if det_inv is None:\n            return None\n        a, b = matrix[0][0], matrix[0][1]\n        c, d = matrix[1][0], matrix[1][1]\n        inv_matrix = [\n            [(d * det_inv) % self.alphabet_size, (-b * det_inv) % self.alphabet_size],\n            [(-c * det_inv) % self.alphabet_size, (a * det_inv) % self.alphabet_size]\n        ]\n        return inv_matrix\n    \n    def encrypt(self, plaintext: str, key_matrix: list) -> str:\n        if len(key_matrix) != 2 or len(key_matrix[0]) != 2:\n            raise ValueError(\"浠呮敮鎸?脳2瀵嗛挜鐭╅樀\")\n        det = self._determinant_2x2(key_matrix) % self.alphabet_size\n        if self._gcd(det, self.alphabet_size) != 1:\n            raise ValueError(\"瀵嗛挜鐭╅樀涓嶅彲閫哱")\n        processed_plain = self._preprocess_plaintext(plaintext)\n        ciphertext = \"\"\n        for i in range(0, len(processed_plain), 2):\n            p0 = self._letter_to_num(processed_plain[i])\n            p1 = self._letter_to_num(processed_plain[i+1])\n            c0 = (key_matrix[0][0] * p0 + key_matrix[0][1] * p1) % self.alphabet_size\n            c1 = (key_matrix[1][0] * p0 + key_matrix[1][1] * p1) % self.alphabet_size\n            ciphertext += self._num_to_letter(c0) + self._num_to_letter(c1)\n        return ciphertext\n    \n    def decrypt(self, ciphertext: str, key_matrix: list) -> str:\n        inv_key_matrix = self._matrix_inverse_2x2(key_matrix)\n        if inv_key_matrix is None:\n            raise ValueError(\"瀵嗛挜鐭╅樀涓嶅彲閫哱")\n        return self.encrypt(ciphertext, inv_key_matrix)\n    \n    # 鏂板闅忔満瀵嗛挜鐢熸垚鏂规硶\n    def generate_random_key(self) -> list:\n        \"\"\"鐢熸垚闅忔満鍙€?脳2瀵嗛挜鐭╅樀\"\"\"\n        while True:\n            # 鐢熸垚0-25鐨勯殢鏈哄厓绱燶n            matrix = [\n                [random.randint(0, self.alphabet_size-1), random.randint(0, self.alphabet_size-1)],\n                [random.randint(0, self.alphabet_size-1), random.randint(0, self.alphabet_size-1)]\n            ]\n            # 妫€鏌ュ彲閫嗘€n            det = self._determinant_2x2(matrix) % self.alphabet_size\n            if self._gcd(det, self.alphabet_size) == 1:\n                return matrix\n\n# 澶氬満鏅祴璇昞ncipher = HillCipher()\n\n# 鍦烘櫙1锛氬惈鐗规畩瀛楃\nprint(\"鍦烘櫙1锛氬惈鐗规畩瀛楃鐨勬槑鏂嘰")\nplain1 = \"HELLO, WORLD!\"\nkey1 = [[3, 3], [2, 5]]\nenc1 = cipher.encrypt(plain1, key1)\ndec1 = cipher.decrypt(enc1, key1)\nprint(f\"鏄庢枃锛歿plain1}\")\nprint(f\"瀵嗘枃锛歿enc1}\")\nprint(f\"瑙ｅ瘑锛歿dec1}\")\nprint(f\"杩樺師鍘熷鏄庢枃锛歿dec1.rstrip(\'X\')}\")\nprint(f\"鏄惁姝ｇ‘锛歿dec1.rstrip(\'X\') == \'HELLOWORLD\'}\")\n\n# 鍦烘櫙2锛氬鏁伴暱搴︽槑鏂嘰nprint(\"\\n鍦烘櫙2锛氬鏁伴暱搴︽槑鏂嘰")\nplain2 = \"ATTAC\"  # 闀垮害5锛屽～鍏呬负ATTACX\nkey2 = [[5, 8], [1, 3]]\nenc2 = cipher.encrypt(plain2, key2)\ndec2 = cipher.decrypt(enc2, key2)\nprint(f\"鏄庢枃锛歿plain2}\")\nprint(f\"棰勫鐞嗗悗锛歿cipher._preprocess_plaintext(plain2)}\")\nprint(f\"瀵嗘枃锛歿enc2}\")\nprint(f\"瑙ｅ瘑锛歿dec2}\")\nprint(f\"杩樺師鍘熷鏄庢枃锛歿dec2.rstrip(\'X\')}\")\nprint(f\"鏄惁姝ｇ‘锛歿dec2.rstrip(\'X\') == plain2}\")\n\n# 鍦烘櫙3锛氶殢鏈哄瘑閽nprint(\"\\n鍦烘櫙3锛氶殢鏈哄瘑閽ュ姞瀵哱")\nplain3 = \"WEAREDISCOVERED\"\nkey3 = cipher.generate_random_key()\nenc3 = cipher.encrypt(plain3, key3)\ndec3 = cipher.decrypt(enc3, key3)\nprint(f\"鏄庢枃锛歿plain3}\")\nprint(f\"闅忔満瀵嗛挜鐭╅樀锛歿key3}\")\nprint(f\"瀵嗘枃锛歿enc3}\")\nprint(f\"瑙ｅ瘑锛歿dec3}\")\nprint(f\"鏄惁姝ｇ‘锛歿dec3.rstrip(\'X\') == plain3}\")'),(65,9,7,'鍒嗘瀽鐗圭偣銆佸眬闄愭€т笌鏁欏浠峰€?,'1. 鏍稿績鐗圭偣锛歕n   - 浠ｆ暟鍖栧姞瀵嗭細鍩轰簬绾挎€т唬鏁扮殑鐭╅樀杩愮畻锛屽姞瀵嗛€昏緫涓ヨ皑锛屾槸浠ｆ暟瀵嗙爜瀛︾殑寮€绔紱\n   - 澶氬瓧姣嶅垎缁勶細涓€娆℃€у鐞嗗涓瓧姣嶏紝鎵撶牬鍗曞瓧姣嶉鐜囩壒寰侊紝鎶楅鐜囧垎鏋愯兘鍔涘己浜庝紶缁熸浛鎹㈠瘑鐮侊紱\n   - 瀵嗛挜鐏垫椿鎬э細瀵嗛挜涓虹煩闃碉紝鍙€氳繃璋冩暣鐭╅樀鍏冪礌鐢熸垚澶