ㄤ腑棰戠郴鏁帮紙濡俒3,4]浣嶇疆锛屽吋椤鹃瞾妫掓€у拰涓嶅彲瑙佹€э級宓屽叆姘村嵃浣嶏紝鏈€鍚庣粡IDCT閫嗗彉鎹㈤噸鏋勫浘鍍忋€俓n棰勬湡杈撳嚭锛氱悊瑙CT姘村嵃鐨勨€滃垎鍧?棰戝煙鍙樻崲-绯绘暟淇敼-閫嗗彉鎹⑩€濇牳蹇冩祦绋嬶紝鏄庣‘涓绯绘暟宓屽叆鐨勪紭鍔裤€?,NULL,'import numpy as np\nfrom scipy import fftpack\n# 楠岃瘉DCT鍙樻崲鍔熻兘\ndct_wm = DCTWatermark(alpha=0.2, block_size=8)\n# 鍒涘缓8x8娴嬭瘯鍧梊ntest_block = np.random.randint(0, 256, (8,8), dtype=np.float64)\n# DCT鍙樻崲\ndct_block = dct_wm._dct2(test_block)\n# IDCT閫嗗彉鎹nrecovered_block = dct_wm._idct2(dct_block)\n# 楠岃瘉閫嗗彉鎹㈢簿搴nmse = np.mean((test_block - recovered_block)**2)\nprint(f\"8x8鍧桪CT-IDCT閫嗗彉鎹SE锛歿mse:.6f}\")\nprint(f\"鍘熷鍧楀墠4x4锛歕\n{test_block[:4,:4].round(2)}\")\nprint(f\"DCT鍙樻崲鍚庡墠4x4锛堥鍩熺郴鏁帮級锛歕\n{dct_block[:4,:4].round(2)}\")\nprint(f\"閫嗗彉鎹㈡仮澶嶅悗鍓?x4锛歕\n{recovered_block[:4,:4].round(2)}\")'),(82,12,3,'DCT姘村嵃宓屽叆涓庢彁鍙栧疄鐜?,'鍩轰簬DCTWatermark绫伙紝瀹屾暣瀹炵幇姘村嵃宓屽叆涓庢彁鍙栨祦绋嬶紝姝ラ濡備笅锛歕n1. 鏁版嵁鍑嗗锛歕n   - 鍘熷鍥惧儚锛氬垱寤?56x256鐏板害娴嬭瘯鍥撅紙鍍忕礌鍊?00-200锛夛紝鎴栬鍙栨湰鍦板浘鍍忥紱\n   - 姘村嵃鍥惧儚锛氬垱寤轰簩鍊兼按鍗帮紙濡?2x32澶у皬锛屼腑闂翠负1鐨勬柟鍧楋級锛岀‘淇濇按鍗颁负0-1浜屽€兼暟缁勶紱\n2. 姘村嵃宓屽叆姝ラ锛歕n   a. 鍒濆鍖朌CTWatermark瀹炰緥锛岃缃祵鍏ュ己搴lpha鍜屽潡澶у皬block_size锛沑n   b. 璋冪敤embed_watermark鏂规硶锛屼紶鍏ュ師濮嬪浘鍍忓拰姘村嵃锛屽唴閮ㄨ嚜鍔ㄥ畬鎴愬垎鍧椼€丏CT鍙樻崲銆佷腑棰戠郴鏁颁慨鏀癸紙1鍒欏姞alpha脳绯绘暟缁濆鍊硷紝0鍒欏噺锛夈€両DCT閫嗗彉鎹紱\n   c. 杈撳嚭鍚按鍗板浘鍍忥紝瑁佸壀鍍忕礌鍊煎埌[0,255]骞惰浆鎹负uint8绫诲瀷锛沑n3. 姘村嵃鎻愬彇姝ラ锛歕n   a. 璋冪敤extract_watermark鏂规硶锛屼紶鍏ュ惈姘村嵃鍥惧儚鍜屽師濮嬫按鍗板昂瀵革紱\n   b. 鍐呴儴瀵规瘡涓浘鍍忓潡鎵цDCT鍙樻崲锛岃鍙栦腑棰戠郴鏁癧3,4]鐨勭鍙凤紙姝ｄ负1锛岃礋涓?锛夛紝鏀堕泦鎵€鏈夋按鍗颁綅骞堕噸濉戜负鍘熷姘村嵃灏哄锛沑n4. 鎬ц兘璇勪及锛氳绠楀師濮嬪浘鍍忎笌鍚按鍗板浘鍍忕殑PSNR锛堝嘲鍊间俊鍣瘮锛夛紝浠ュ強鍘熷姘村嵃涓庢彁鍙栨按鍗扮殑鐩镐技搴︼紙鍖归厤鍍忕礌鍗犳瘮锛夈€俓n棰勬湡杈撳嚭锛氭垚鍔熺敓鎴愬惈姘村嵃鍥惧儚锛孭SNR绾?8dB锛堝祵鍏ュ己搴?.2鏃讹級锛屾按鍗扮浉浼煎害鏍规嵁鍙傛暟鍙兘瀛樺湪宸紓锛岄渶璋冩暣alpha浼樺寲鎻愬彇鏁堟灉銆?,NULL,'def test_dct_watermark_embed_extract():\n    # 1. 鍑嗗鏁版嵁\n    # 鍒涘缓鍘熷鍥惧儚锛?56x256鐏板害鍥撅級\n    test_image = np.random.randint(100, 200, (256, 256), dtype=np.uint8)\n    # 鍒涘缓姘村嵃锛?2x32浜屽€煎浘鍍忥紝涓棿16x16涓?锛塡n    watermark = np.zeros((32, 32), dtype=int)\n    watermark[8:24, 8:24] = 1\n    print(f\"鍘熷鍥惧儚澶у皬锛歿test_image.shape}\")\n    print(f\"姘村嵃澶у皬锛歿watermark.shape}\")\n    \n    # 2. 鍒濆鍖朌CT姘村嵃绯荤粺\n    dct_wm = DCTWatermark(alpha=0.3, block_size=8)  # 璋冩暣寮哄害涓?.3鎻愬崌椴佹鎬n    \n    # 3. 宓屽叆姘村嵃\n    print(\"\\n宓屽叆DCT姘村嵃...\")\n    watermarked_image = dct_wm.embed_watermark(test_image, watermark)\n    \n    # 4. 璁＄畻PSNR\n    mse = np.mean((test_image.astype(float) - watermarked_image.astype(float))**2)\n    psnr = 20 * np.log10(255.0 / np.sqrt(mse)) if mse > 0 else float(\'inf\')\n    print(f\"鍘熷鍥惧儚 vs 鍚按鍗板浘鍍?PSNR锛歿psnr:.2f} dB\")\n    \n    # 5. 鎻愬彇姘村嵃\n    print(\"\\n鎻愬彇DCT姘村嵃...\")\n    extracted_watermark = dct_wm.extract_watermark(watermarked_image, watermark.shape)\n    \n    # 6. 璁＄畻姘村嵃鐩镐技搴n    similarity = np.sum(watermark == extracted_watermark) / watermark.size\n    print(f\"鍘熷姘村嵃涓庢彁鍙栨按鍗扮浉浼煎害锛歿similarity * 100:.2f}%\")\n    \n    if similarity > 0.8:\n        print(\"[OK] DCT姘村嵃宓屽叆鎻愬彇鎴愬姛锛乗")\n    else:\n        print(\"[鎻愮ず] 鍙澶lpha鎻愬崌鐩镐技搴︼紝浣嗕細闄嶄綆PSNR\")\n    \n    return test_image, watermarked_image, watermark, extracted_watermark\n\n# 鎵ц娴嬭瘯\ntest_img, wm_img, orig_wm, ext_wm = test_dct_watermark_embed_extract()'),(83,12,4,'DWT姘村嵃绯荤粺鏍稿績鍘熺悊涓庣被瑙ｆ瀽','DWT姘村嵃鍩轰簬绂绘暎灏忔尝鍙樻崲锛屽埄鐢ㄥ鍒嗚鲸鐜囩壒鎬у湪浣庨瀛愬甫宓屽叆姘村嵃锛屾牳蹇冧紭鍔挎槸鍏奸【涓嶅彲瑙佹€у拰椴佹鎬э紝瑙ｆ瀽DWTWatermark绫荤殑鏍稿績璁捐锛歕n1. 鍒濆鍖栧弬鏁帮細\n   - alpha锛氬祵鍏ュ己搴︼紙榛樿0.1锛夛紝鎺у埗姘村嵃淇″彿鐨勫箙搴︼紱\n   - wavelet锛氬皬娉㈠熀绫诲瀷锛堥粯璁'haar\'锛?Haar灏忔尝璁＄畻绠€鍗曘€侀€熷害蹇級锛沑n   - level锛氬皬娉㈠垎瑙ｅ眰鏁帮紙榛樿2锛夛紝鍒嗚В灞傛暟瓒婂锛屼綆棰戝瓙甯﹀昂瀵歌秺灏忥紱\n2. 鏍稿績宸ュ叿鏂规硶锛歕n   - _resize_watermark锛氬皢姘村嵃鍥惧儚褰掍竴鍖栧埌0-255鍚庯紝璋冩暣涓虹洰鏍囧昂瀵革紙閫氬父涓轰綆棰戝瓙甯﹀昂瀵革級锛屽啀褰掍竴鍖栧埌0-1锛沑n3. 鏍稿績閫昏緫锛氬師濮嬪浘鍍忕粡wavelet灏忔尝鍒嗚В涓轰綆棰戝瓙甯︼紙cA锛岃繎浼煎垎閲忥級鍜岄珮棰戝瓙甯︼紙cH銆乧V銆乧D锛岀粏鑺傚垎閲忥級锛屽湪浣庨瀛愬甫cA涓祵鍏ユ按鍗帮紙鍙犲姞alpha脳姘村嵃脳cA缁濆鍊硷級锛屾渶鍚庣粡灏忔尝閲嶆瀯寰楀埌鍚按鍗板浘鍍忥紱鎻愬彇鏃堕€氳繃瀵规瘮鍘熷鍥惧儚鍜屽惈姘村嵃鍥惧儚鐨勪綆棰戝瓙甯﹀樊寮傛仮澶嶆按鍗般€俓n棰勬湡杈撳嚭锛氱悊瑙WT姘村嵃鐨勨€滃皬娉㈠垎瑙?浣庨宓屽叆-閲嶆瀯鈥濇祦绋嬶紝鏄庣‘浣庨瀛愬甫宓屽叆鐨勫師鍥狅紙浣庨鍒嗛噺鑳介噺闆嗕腑锛屾姉鏀诲嚮鑳藉姏寮猴級銆?,NULL,'import pywt\n# 楠岃瘉灏忔尝鍒嗚В鍔熻兘\ndwt_wm = DWTWatermark(alpha=0.15, wavelet=\'haar\', level=2)\n# 鍒涘缓256x256娴嬭瘯鍥惧儚\ntest_image = np.random.randint(100, 200, (256, 256), dtype=np.float64)\n# 灏忔尝鍒嗚В\ncoeffs = pywt.wavedec2(test_image, wavelet=\'haar\', level=2)\ncA, (cH2, cV2, cD2), (cH1, cV1, cD1) = coeffs\nprint(f\"灏忔尝鍒嗚В鍚庝綆棰戝瓙甯A灏哄锛歿cA.shape}\")\nprint(f\"楂橀瀛愬甫cH2灏哄锛歿cH2.shape}\")\nprint(f\"楂橀瀛愬甫cH1灏哄锛歿cH1.shape}\")\n# 灏忔尝閲嶆瀯\nrecovered_image = pywt.waverec2(coeffs, wavelet=\'haar\')\nrecovered_image = recovered_image[:test_image.shape[0], :test_image.shape[1]]\n# 楠岃瘉閲嶆瀯绮惧害\nmse = np.mean((test_image - recovered_image)**2)\nprint(f\"灏忔尝鍒嗚В-閲嶆瀯MSE锛歿mse:.6f}\")'),(84,12,5,'DWT姘村嵃宓屽叆涓庢彁鍙栧疄鐜?,'鍩轰簬DWTWatermark绫伙紝瀹屾垚姘村嵃宓屽叆銆佹彁鍙栧強鎬ц兘楠岃瘉锛屾楠ゅ涓嬶細\n1. 鏁版嵁鍑嗗锛歕n   - 鍘熷鍥惧儚锛氫笌DCT姘村嵃娴嬭瘯涓€鑷达紝浣跨敤256x256鐏板害鍥撅紱\n   - 姘村嵃鍥惧儚锛?2x32浜屽€煎浘鍍忥紙濡備腑闂?x8涓?鐨勬柟鍧楋級锛屾敮鎸佹诞鐐瑰瀷杈撳叆锛沑n2. 姘村嵃宓屽叆姝ラ锛歕n   a. 鍒濆鍖朌WTWatermark瀹炰緥锛岃缃祵鍏ュ己搴lpha銆佸皬娉㈠熀绫诲瀷鍜屽垎瑙ｅ眰鏁帮紱\n   b. 璋冪敤embed_watermark鏂规硶锛屽唴閮ㄦ墽琛岋細灏忔尝鍒嗚В鈫掕幏鍙栦綆棰戝瓙甯A鈫掕皟鏁存按鍗板昂瀵镐笌cA鍖归厤鈫掑湪cA涓祵鍏ユ按鍗帮紙cA_watermarked = cA + alpha脳姘村嵃脳|cA|锛夆啋閲嶆瀯灏忔尝绯绘暟鈫掗€嗗彉鎹㈠緱鍒板惈姘村嵃鍥惧儚锛沑n   c. 瑁佸壀閲嶆瀯鍥惧儚鍒板師濮嬪昂瀵革紝鍍忕礌鍊艰鍓埌[0,255]骞惰浆鎹负uint8锛沑n3. 姘村嵃鎻愬彇姝ラ锛堥潪鐩叉彁鍙栵紝闇€鍘熷鍥惧儚锛夛細\n   a. 鍒嗗埆瀵瑰師濮嬪浘鍍忓拰鍚按鍗板浘鍍忔墽琛屽皬娉㈠垎瑙ｏ紝鑾峰彇鍚勮嚜鐨勪綆棰戝瓙甯A_orig鍜宑A_wm锛沑n   b. 璁＄畻瀛愬甫宸紓锛歸atermark = (cA_wm - cA_orig) / (alpha脳|cA_orig| + 1e-10)锛岄伩鍏嶉櫎闆讹紱\n   c. 璋冩暣姘村嵃灏哄鍒板師濮嬫按鍗板ぇ灏忥紝浜屽€煎寲锛?0涓?锛屽惁鍒欎负0锛夊緱鍒版彁鍙栨按鍗帮紱\n4. 鎬ц兘璇勪及锛氳绠桺SNR锛堣　閲忓浘鍍忓け鐪燂級鍜屾按鍗扮浉浼煎害锛堣　閲忔彁鍙栨晥鏋滐級銆俓n棰勬湡杈撳嚭锛氭垚鍔熺敓鎴愬惈姘村嵃鍥惧儚锛孭SNR绾?3dB锛堝祵鍏ュ己搴?.15鏃讹級锛岄€氳繃璋冩暣alpha鍜屽垎瑙ｅ眰鏁帮紝鍙紭鍖栨按鍗扮浉浼煎害锛堢洰鏍?80%锛夈€?,NULL,'def test_dwt_watermark_embed_extract():\n    # 1. 鍑嗗鏁版嵁\n    test_image = np.random.randint(100, 200, (256, 256), dtype=np.uint8)\n    # 鍒涘缓姘村嵃锛?2x32锛屼腑闂?x8涓?.0锛塡n    watermark = np.zeros((32, 32), dtype=np.float64)\n    watermark[12:20, 12:20] = 1.0\n    print(f\"鍘熷鍥惧儚澶у皬锛歿test_image.shape}\")\n    print(f\"姘村嵃澶у皬锛歿watermark.shape}\")\n    \n    # 2. 鍒濆鍖朌WT姘村嵃绯荤粺\n    dwt_wm = DWTWatermark(alpha=0.25, wavelet=\'haar\', level=2)  # 澧炲ぇ寮哄害鑷?.25\n    \n    # 3. 宓屽叆姘村嵃\n    print(\"\\n宓屽叆DWT姘村嵃...\")\n    watermarked_image = dwt_wm.embed_watermark(test_image, watermark)\n    \n    # 4. 璁＄畻PSNR\n    mse = np.mean((test_image.astype(float) - watermarked_image.astype(float))**2)\n    psnr = 20 * np.log10(255.0 / np.sqrt(mse)) if mse > 0 else float(\'inf\')\n    print(f\"鍘熷鍥惧儚 vs 鍚按鍗板浘鍍?PSNR锛歿psnr:.2f} dB\")\n    \n    # 5. 鎻愬彇姘村嵃锛堥潪鐩叉彁鍙栵紝闇€鍘熷鍥惧儚锛塡n    print(\"\\n鎻愬彇DWT姘村嵃...\")\n    extracted_watermark = dwt_wm.extract_watermark(watermarked_image, test_image, watermark.shape)\n    \n    # 6. 浜屽€煎寲骞惰绠楃浉浼煎害\n    orig_wm_binary = (watermark > 0.5).astype(int)\n    ext_wm_binary = (extracted_watermark > 0.5).astype(int)\n    similarity = np.sum(orig_wm_binary == ext_wm_binary) / orig_wm_binary.size\n    print(f\"鍘熷姘村嵃涓庢彁鍙栨按鍗扮浉浼煎害锛歿similarity * 100:.2f}%\")\n    \n    if similarity > 0.8:\n        print(\"[OK] DWT姘村嵃宓屽叆鎻愬彇鎴愬姛锛乗")\n    else:\n        print(\"[鎻愮ず] 鍙皟鏁碼lpha鎴栧垎瑙ｅ眰鏁颁紭鍖栨晥鏋淺")\n    \n    return test_image, watermarked_image, orig_wm_binary, ext_wm_binary\n\n# 鎵ц娴嬭瘯\ndwt_test_img, dwt_wm_img, dwt_orig_wm, dwt_ext_wm = test_dwt_watermark_embed_extract()'),(85,12,6,'DCT涓嶥WT姘村嵃鐗规€у姣斿垎鏋?,'閫氳繃瀹為獙缁撴灉瀵规瘮DCT鍜孌WT涓ょ棰戝煙姘村嵃鐨勬牳蹇冪壒鎬э紝鏄庣‘閫傜敤鍦烘櫙锛歕n1. 宓屽叆浣嶇疆宸紓锛歕n   - DCT姘村嵃锛氬湪8x8鍧楃殑涓绯绘暟宓屽叆锛岄€傞厤JPEG鍘嬬缉鐨勫潡澶勭悊鏈哄埗锛屾姉JPEG鍘嬬缉鑳藉姏鏇村己锛沑n   - DWT姘村嵃锛氬湪灏忔尝鍒嗚В鐨勪綆棰戝瓙甯﹀祵鍏ワ紝浣庨鍒嗛噺瀵瑰嚑浣曞彉鎹㈠拰鍣０鏇存晱鎰燂紝浣嗕笉鍙鎬ч€氬父鏇村ソ锛沑n2. 鎬ц兘鎸囨爣瀵规瘮锛堝熀浜庡疄楠岀粨鏋滐級锛歕n   - PSNR锛氱浉鍚屽祵鍏ュ己搴︿笅锛孌CT姘村嵃PSNR鏇撮珮锛堝alpha=0.2鏃禗CT绾?8dB锛孌WT绾?3dB锛夛紝鍥惧儚澶辩湡鏇村皬锛沑n   - 鎻愬彇鐩镐技搴︼細鍙梐lpha褰卞搷鏄捐憲锛孌CT姘村嵃鍦ㄤ腑绛夊己搴︿笅锛?.3锛夋槗杈惧埌楂樼浉浼煎害锛孌WT姘村嵃闇€骞宠　寮哄害涓庡け鐪燂紱\n3. 椴佹鎬у樊寮傦細\n   - DCT姘村嵃锛氭姉鍘嬬缉銆佹姉鍣０鑳藉姏杈冨己锛岄€傚悎瀵瑰帇缂╂湁瑕佹眰鐨勫満鏅紙濡傜綉缁滀紶杈撳浘鍍忥級锛沑n   - DWT姘村嵃锛氭姉鍑犱綍鏀诲嚮锛堝瑁佸壀銆佹棆杞級鑳藉姏鐣ヤ紭锛屼絾瀵瑰櫔澹版晱鎰燂紝閫傚悎瀵硅瑙夎川閲忚姹傞珮鐨勫満鏅紱\n4. 瀹炵幇澶嶆潅搴︼細\n   - DCT姘村嵃锛氬垎鍧楀鐞嗛€昏緫绠€鍗曪紝鏃犻渶鍘熷鍥惧儚鍗冲彲鎻愬彇锛堢洸鎻愬彇锛夛紱\n   - DWT姘村嵃锛氫緷璧栧皬娉㈠垎瑙ｉ噸鏋勶紝鎻愬彇闇€鍘熷鍥惧儚锛堥潪鐩叉彁鍙栵級锛屽疄鐜扮◢澶嶆潅銆俓n棰勬湡杈撳嚭锛氭槑纭袱绉嶆按鍗扮殑浼樼己鐐瑰強閫傜敤鍦烘櫙锛岃兘澶熸牴鎹疄闄呴渶姹傞€夋嫨鍚堥€傜殑棰戝煙姘村嵃鏂规銆?,'瀹為檯搴旂敤涓紝鍙粨鍚堜袱绉嶆妧鏈殑浼樺娍锛堝DWT+DCT娣峰悎姘村嵃锛夛紝杩涗竴姝ユ彁鍗囬瞾妫掓€у拰涓嶅彲瑙佹€?,NULL),(86,13,1,'宸ュ叿鍖呯粨鏋勪笌鏍稿績缁勪欢瑙ｆ瀽','鏁板瓧姘村嵃宸ュ叿鍖呴噰鐢ㄦā鍧楀寲璁捐锛屽寘鍚?涓牳蹇冪粍浠讹紝闇€鍏堟槑纭悇缁勪欢鍔熻兘涓庡崗浣滃叧绯伙細\n1. WatermarkToolkit锛堟牳蹇冨伐鍏风被锛夛細鎻愪緵娴嬭瘯鍥惧儚鐢熸垚銆佹按鍗板浘妗堝垱寤恒€佹按鍗版祦绋嬪彲瑙嗗寲銆佸己搴﹀垎鏋愬浘琛ㄧ粯鍒躲€佹祴璇曟姤鍛婄敓鎴?澶ф牳蹇冨姛鑳斤紝鏄伐鍏峰寘鐨勫叆鍙ｏ紱\n2. SpreadSpectrumWatermark锛堟墿棰戞按鍗版牳蹇冪被锛夛細灏佽姘村嵃宓屽叆銆佹彁鍙栥€丳SNR璁＄畻銆佹纭巼璁＄畻銆佸己搴﹁皟鏁淬€佹按鍗版摝闄ょ瓑鏍稿績绠楁硶锛屾槸宸ュ叿鍖呯殑绠楁硶鏀拺锛沑n3. WatermarkAnalyzer锛堟€ц兘鍒嗘瀽绫伙級锛氫笓娉ㄤ簬姘村嵃鎬ц兘娴嬭瘯锛屽寘鎷笉鍚屽