  - 鍏挜搴忓垪鍖栵細浣跨敤PEM缂栫爜鏍煎紡锛屼究浜庝紶杈撳拰瀛樺偍锛沑n   - HKDF娲剧敓锛氭秷闄ゅ師濮嬪叡浜瘑閽ョ殑缁熻鐗规€э紝澧炲己瀵嗛挜瀹夊叏鎬э紱\n   - 鍙傛暟澶嶇敤锛欱ob闇€浣跨敤涓嶢lice鐩稿悓鐨勫叕鍏卞弬鏁帮紝鍚﹀垯鏃犳硶璁＄畻鍑虹浉鍚屽瘑閽ャ€俓n棰勬湡杈撳嚭锛氭垚鍔熻繍琛屼唬鐮侊紝Alice鍜孊ob璁＄畻鍑虹浉鍚岀殑鍏变韩瀵嗛挜锛屽瘑閽ュ尮閰嶇粨鏋滀负True锛岄獙璇丏H鍗忚瀹炵幇姝ｇ‘鎬с€?,NULL,'import os\nimport hashlib\nfrom cryptography.hazmat.primitives.asymmetric import dh\nfrom cryptography.hazmat.primitives import hashes, serialization\nfrom cryptography.hazmat.primitives.kdf.hkdf import HKDF\nfrom cryptography.hazmat.backends import default_backend\n\nclass DiffieHellman:\n    def __init__(self, key_size: int = 2048):\n        self.key_size = key_size\n        self.parameters = None\n        self.private_key = None\n        self.public_key = None\n    \n    def generate_parameters(self) -> dh.DHParameters:\n        print(f\"[DH] 鐢熸垚{self.key_size}浣嶅弬鏁?..\")\n        self.parameters = dh.generate_parameters(\n            generator=2, key_size=self.key_size, backend=default_backend()\n        )\n        return self.parameters\n    \n    def generate_key_pair(self, parameters=None):\n        if parameters: self.parameters = parameters\n        if not self.parameters: self.generate_parameters()\n        self.private_key = self.parameters.generate_private_key()\n        self.public_key = self.private_key.public_key()\n        print(\"[DH] 瀵嗛挜瀵圭敓鎴愬畬鎴怽")\n    \n    def get_public_key_bytes(self) -> bytes:\n        return self.public_key.public_bytes(\n            encoding=serialization.Encoding.PEM,\n            format=serialization.PublicFormat.SubjectPublicKeyInfo\n        )\n    \n    def compute_shared_key(self, peer_public_key_bytes: bytes) -> bytes:\n        peer_public_key = serialization.load_pem_public_key(\n            peer_public_key_bytes, backend=default_backend()\n        )\n        shared_key = self.private_key.exchange(peer_public_key)\n        # HKDF娲剧敓瀵嗛挜\n        derived_key = HKDF(\n            algorithm=hashes.SHA256(), length=32, salt=None,\n            info=b\'diffie-hellman-key-exchange\', backend=default_backend()\n        ).derive(shared_key)\n        return derived_key\n\n# 婕旂ず浠ｇ爜\ndef demo_diffie_hellman():\n    print(\"=\"*60)\n    print(\"Diffie-Hellman瀵嗛挜浜ゆ崲婕旂ず\")\n    print(\"=\"*60)\n    \n    # Alice鍒濆鍖朶n    alice = DiffieHellman(key_size=2048)\n    alice.generate_parameters()\n    alice.generate_key_pair()\n    \n    # Bob浣跨敤鐩稿悓鍙傛暟\n    bob = DiffieHellman(key_size=2048)\n    bob.generate_key_pair(alice.parameters)\n    \n    # 浜ゆ崲鍏挜\n    alice_public = alice.get_public_key_bytes()\n    bob_public = bob.get_public_key_bytes()\n    print(f\"Alice鍏挜闀垮害: {len(alice_public)}瀛楄妭\")\n    \n    # 璁＄畻鍏变韩瀵嗛挜\n    alice_shared = alice.compute_shared_key(bob_public)\n    bob_shared = bob.compute_shared_key(alice_public)\n    \n    # 楠岃瘉\n    print(f\"Alice瀵嗛挜: {alice_shared.hex()}\")\n    print(f\"Bob瀵嗛挜:   {bob_shared.hex()}\")\n    print(f\"瀵嗛挜鍖归厤: {alice_shared == bob_shared}\")\n    \n    return alice_shared == bob_shared\n\n# 鎵ц婕旂ず\ndemo_diffie_hellman()'),(98,14,7,'ECDH鍗忚Python瀹炵幇涓庝紭鍔块獙璇?,'鍩轰簬cryptography搴撶殑妞渾鏇茬嚎妯″潡瀹炵幇ECDH鍗忚锛屽姣斾紶缁烡H楠岃瘉鍏跺瘑閽ラ暱搴︿紭鍔匡細\n1. 鏍稿績宸紓锛欵CDH浣跨敤妞渾鏇茬嚎鐐逛箻杩愮畻鏇夸唬DH鐨勬ā骞傝繍绠楋紝瀹炵幇绫荤粨鏋勪笌DH绫讳技锛屼絾鍙傛暟鏀逛负妞渾鏇茬嚎绫诲瀷锛沑n2. 瀹炵幇姝ラ锛歕n   a. 鍒濆鍖朎CDH绫伙細鎸囧畾妞渾鏇茬嚎锛堥粯璁ECP256R1锛屽嵆NIST P-256锛屽畨鍏ㄦ€х浉褰撲簬3072浣岲H锛夛紱\n   b. 鐢熸垚瀵嗛挜瀵癸細璋冪敤ec.generate_private_key鐢熸垚妞渾鏇茬嚎绉侀挜鍜屽叕閽ワ紝鏃犻渶鍗曠嫭鐢熸垚鍏叡鍙傛暟锛堟洸绾垮弬鏁颁负鏍囧噯棰勫畾涔夛級锛沑n   c. 鍏挜浜ゆ崲锛氬悓鏍峰簭鍒楀寲涓哄叕閽EM鏍煎紡瀛楄妭娴侊紱\n   d. 鍏变韩瀵嗛挜璁＄畻锛氶€氳繃ec.ECDH()浜ゆ崲绠楁硶璁＄畻鍘熷鍏变韩瀵嗛挜锛屽啀缁廐KDF娲剧敓锛沑n   e. 浼樺娍楠岃瘉锛氬姣擡CDH涓嶥H鐨勫叕閽ラ暱搴︺€佺敓鎴愯€楁椂锛岄獙璇?56浣岴CDH鐨勯珮鏁堟€с€俓n3. 鍏抽敭娉ㄦ剰鐐癸細\n   - 鏇茬嚎閫夋嫨锛氶渶浣跨敤鏍囧噯妞渾鏇茬嚎锛堝SECP256R1銆丼ECP384R1锛夛紝閬垮厤鑷畾涔夋洸绾跨殑瀹夊叏椋庨櫓锛沑n   - 瀵嗛挜娲剧敓锛氫笌DH鐩稿悓锛岄渶閫氳繃HKDF澧炲己瀵嗛挜瀹夊叏鎬с€俓n棰勬湡杈撳嚭锛氭垚鍔熻繍琛屼唬鐮侊紝Alice鍜孊ob寰楀埌鐩稿悓鍏变韩瀵嗛挜锛岃瀵熷埌ECDH鍏挜闀垮害锛堢害178瀛楄妭锛夎繙灏忎簬2048浣岲H锛堢害800瀛楄妭锛夛紝楠岃瘉鍏堕珮鏁堟€с€?,NULL,'from cryptography.hazmat.primitives.asymmetric import ec\nfrom cryptography.hazmat.primitives import hashes, serialization\nfrom cryptography.hazmat.primitives.kdf.hkdf import HKDF\nfrom cryptography.hazmat.backends import default_backend\n\nclass ECDH:\n    def __init__(self, curve=ec.SECP256R1()):\n        self.curve = curve\n        self.private_key = None\n        self.public_key = None\n    \n    def generate_key_pair(self):\n        self.private_key = ec.generate_private_key(self.curve, default_backend())\n        self.public_key = self.private_key.public_key()\n        print(f\"[ECDH] 瀵嗛挜瀵圭敓鎴愶紙鏇茬嚎: {self.curve.name}\")\n    \n    def get_public_key_bytes(self) -> bytes:\n        return self.public_key.public_bytes(\n            encoding=serialization.Encoding.PEM,\n            format=serialization.PublicFormat.SubjectPublicKeyInfo\n        )\n    \n    def compute_shared_key(self, peer_public_key_bytes: bytes) -> bytes:\n        peer_public_key = serialization.load_pem_public_key(\n            peer_public_key_bytes, backend=default_backend()\n        )\n        shared_key = self.private_key.exchange(ec.ECDH(), peer_public_key)\n        # HKDF娲剧敓\n        derived_key = HKDF(\n            algorithm=hashes.SHA256(), length=32, salt=None,\n            info=b\'ecdh-key-exchange\', backend=default_backend()\n        ).derive(shared_key)\n        return derived_key\n\n# 婕旂ず浠ｇ爜\ndef demo_ecdh():\n    print(\"\\n\" + \"=\"*60)\n    print(\"ECDH瀵嗛挜浜ゆ崲婕旂ず\")\n    print(\"=\"*60)\n    \n    # Alice鐢熸垚瀵嗛挜瀵筡n    alice = ECDH(curve=ec.SECP256R1())\n    alice.generate_key_pair()\n    \n    # Bob鐢熸垚瀵嗛挜瀵筡n    bob = ECDH(curve=ec.SECP256R1())\n    bob.generate_key_pair()\n    \n    # 浜ゆ崲鍏挜\n    alice_public = alice.get_public_key_bytes()\n    bob_public = bob.get_public_key_bytes()\n    print(f\"Alice鍏挜闀垮害: {len(alice_public)}瀛楄妭\")\n    print(f\"Bob鍏挜闀垮害: {len(bob_public)}瀛楄妭\")\n    \n    # 璁＄畻鍏变韩瀵嗛挜\n    alice_shared = alice.compute_shared_key(bob_public)\n    bob_shared = bob.compute_shared_key(alice_public)\n    \n    # 楠岃瘉\n    print(f\"Alice瀵嗛挜: {alice_shared.hex()}\")\n    print(f\"Bob瀵嗛挜:   {bob_shared.hex()}\")\n    print(f\"瀵嗛挜鍖归厤: {alice_shared == bob_shared}\")\n    print(\"\\n256浣岴CDH瀹夊叏鎬р増3072浣岲H锛屽瘑閽ユ洿鐭晥鐜囨洿楂榎")\n    \n    return alice_shared == bob_shared\n\n# 鎵ц婕旂ず\ndemo_ecdh()'),(99,14,8,'KDC瀵嗛挜鍒嗗彂鍗忚Python瀹炵幇','瀹炵幇绠€鍖栫増KDC鍗忚锛屾ā鎷熺敤鎴锋敞鍐屻€佷細璇濆瘑閽ョ敓鎴愩€佸垎鍙戜笌瑙ｅ瘑娴佺▼锛歕n1. 鏍稿績璁捐锛歕n   - KDC绫伙細缁存姢鐢ㄦ埛闀挎湡瀵嗛挜瀛楀吀锛屾彁渚涚敤鎴锋敞鍐屻€佷細璇濆瘑閽ョ敓鎴愩€佸姞瀵嗚В瀵嗗姛鑳斤紱\n   - 鍔犲瘑鏂规锛氫娇鐢╔OR+MAC妯℃嫙瀵圭О鍔犲瘑锛堝疄闄呭簲鐢ㄩ渶浣跨敤AES绛夋爣鍑嗙畻娉曪級锛岀‘淇濇秷鎭畬鏁存€у拰鏈哄瘑鎬э紱\n2. 瀹炵幇姝ラ锛歕n   a. KDC鍒濆鍖栵細鍒涘缓鐢ㄦ埛瀵嗛挜瀛楀吀锛屽瓨鍌ㄧ敤鎴稩D涓庨暱鏈熷瘑閽ユ槧灏勶紱\n   b. 鐢ㄦ埛娉ㄥ唽锛氱敤鎴峰悜KDC娉ㄥ唽锛屽彲鑷畾涔夐暱鏈熷瘑閽ユ垨鑷姩鐢熸垚锛?2瀛楄妭闅忔満鏁帮級锛沑n   c. 浼氳瘽瀵嗛挜鐢熸垚锛欿DC鎺ユ敹Alice涓嶣ob鐨勯€氫俊璇锋眰锛岀敓鎴?2瀛楄妭浼氳瘽瀵嗛挜锛屾瀯閫犲寘鍚細璇濆瘑閽ャ€佸鏂规爣璇嗐€佹椂闂存埑鐨勬秷鎭紱\n   d. 娑堟伅鍔犲瘑锛氱敤Alice鐨勯暱鏈熷瘑閽ュ姞瀵嗙粰Alice鐨勬秷鎭紝鐢˙ob鐨勯暱鏈熷瘑閽ュ姞瀵嗙粰Bob鐨勬秷鎭紱\n   e. 娑堟伅瑙ｅ瘑涓庡瘑閽ヨ幏鍙栵細Alice瑙ｅ瘑KDC娑堟伅寰楀埌浼氳瘽瀵嗛挜锛岃浆鍙態ob鐨勫姞瀵嗘秷鎭紱Bob瑙ｅ瘑寰楀埌浼氳瘽瀵嗛挜锛沑n   f. 楠岃瘉锛氬姣擜lice鍜孊ob鑾峰彇鐨勪細璇濆瘑閽ワ紝纭涓€鑷存€с€俓n3. 鍏抽敭瀹炵幇缁嗚妭锛歕n   - MAC楠岃瘉锛氶€氳繃HMAC-SHA256楠岃瘉娑堟伅瀹屾暣鎬э紝闃叉娑堟伅琚鏀癸紱\n   - 鏃堕棿鎴筹細鐢ㄤ簬闃叉閲嶆斁鏀诲嚮锛堢畝鍖栫増鏈疄鐜版牎楠岄€昏緫锛屽疄闄呴渶楠岃瘉鏃堕棿鎴虫湁鏁堟€э級锛沑n   - 闀挎湡瀵嗛挜瀛樺偍锛氬疄闄呭簲鐢ㄤ腑闇€瀹夊叏瀛樺偍锛屽鍔犲瘑鏁版嵁搴撱€俓n棰勬湡杈撳嚭锛氭垚鍔熷畬鎴愮敤鎴锋敞鍐屻€佷細璇濆瘑閽ョ敓鎴愪笌鍒嗗彂锛孉lice鍜孊ob鑾峰彇鐩稿悓浼氳瘽瀵嗛挜锛岄獙璇並DC鍗忚鐨勪腑蹇冨寲鍒嗗彂鍔熻兘銆?,NULL,'import secrets\nimport time\nhashlib\nfrom cryptography.hazmat.primitives import hmac, hashes\nfrom cryptography.hazmat.backends import default_backend\n\nclass KeyDistributionCenter:\n    def __init__(self):\n        self.user_keys = {}  # 瀛樺偍鐢ㄦ埛ID涓庨暱鏈熷瘑閽ユ槧灏刓n    \n    def register_user(self, user_id: str, key: bytes = None) -> bytes:\n        if not key: key = secrets.token_bytes(32)\n        self.user_keys[user_id] = key\n        print(f\"[KDC] 鐢ㄦ埛{user_id}娉ㄥ唽鎴愬姛\")\n        return key\n    \n    def generate_session_key(self, alice_id: str, bob_id: str) -> tuple:\n        if alice_id not in self.user_keys or bob_id not in self.user_keys:\n            raise ValueError(\"鐢ㄦ埛鏈敞鍐孿")\n        # 鐢熸垚浼氳瘽瀵嗛挜\n        session_key = secrets.token_bytes(32)\n        timestamp = str(int(time.time())).encode()\n        \n        # 鏋勯€犳秷鎭痋n        alice_msg = session_key + b\'||\' + bob_id.encode() + b\'||\' + timestamp\n        bob_msg = session_key + b\'||\' + alice_id.encode() + b\'||\' + timestamp\n        \n        # 鍔犲瘑娑堟伅\n        alice_encrypted = self._encrypt(alice_msg, self.user_keys[alice_id])\n        bob_encrypted = self._encrypt(bob_msg, self.user_keys[bob_id])\n        print(f\"[KDC] 鐢熸垚{alice_id}涓巤bob_id}鐨勪細璇濆瘑閽")\n        return alice_encrypted, bob_encrypted\n    \n    def _encrypt(self, data: bytes, key: bytes) -> bytes:\n        # XOR鍔犲瘑+MAC楠岃瘉\n        cipher_key = hashlib.sha256(key).digest()\n        encrypted = bytes([data[i] ^ cipher_key[i%len(cipher_key)] for i in range(len(data))])\n        # 璁＄畻MAC\n        h = hmac.HMAC(key, hashes.SHA256(), backend=default_backend())\n        h.update(encrypted)\n        mac = h.finalize()\n        return encrypted + b\'||MAC||\' + mac\n    \n    def _decrypt(self, encrypted_data: bytes, key: bytes) -> bytes:\n        # 鍒嗙鏁版嵁涓嶮AC\n        parts = encrypted_data.split(b\'||MAC||\')\n        if len(parts)!=2: raise ValueError(\"鏃犳晥鏁版嵁\")\n        encrypted, mac = parts\n        # 楠岃瘉MAC\n        h = hmac.HMAC(key, hashes.SHA256(), backend=default_backend())\n        h.update(encrypted)\n        h.verify(mac)\n        # 瑙ｅ瘑\n        cipher_key = hashlib.sha256(key).digest()\n        decrypted = bytes([encrypted[i]^cipher_key[i%len(cipher_key)] for i in range(len(encrypted))])\n        return decrypted\n\n# 婕旂ず浠ｇ爜\ndef demo_kdc():\n    print(\"\\n\" + \"=\"*60)\n    print(\"KDC瀵嗛挜鍒嗗彂婕旂ず\")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖朘DC骞舵敞鍐岀敤鎴穃n    kdc = KeyDistributionCenter()\n    alice_key = kdc.register_user(\"Alice\")\n    bob_key = kdc.register_user(\"Bob\")\n    \n    # 鐢熸垚浼氳瘽瀵嗛挜\n    alice_msg, bob_msg = kdc.generate_session_key(\"Alice\", \"Bob\")\n    \n    # Alice瑙ｅ瘑\n    alice_decrypted = kdc._decrypt(alice_msg, alice_key)\n    session_key_alice = alice_decrypted.split(b\'||\')[0]\n    print(f\"Alice鑾峰緱浼氳瘽瀵嗛挜: {session_key_alice.hex()}\")\n    \n    # Bob瑙ｅ瘑\n    bob_decrypted = kdc._decrypt(bob_msg, bob_key)\n    session_key_bob = bob_decrypted.split(b\'||\')[0]\n    print(f\"Bob鑾峰緱浼氳瘽瀵嗛挜: {session_key_bob.hex()}\")\n    \n    # 楠岃瘉\n    print(f\"瀵嗛挜鍖归厤: {session_key_alice == session_key_bob}\")\n    \n    return session_key_alice == session_key_bob\n\n# 鎵ц婕旂ず\ndemo_kdc()'),(100,14,9,'STS鍗忚Python瀹炵幇涓庢姉MITM楠岃瘉','瀹炵幇鍩轰簬ECDH鐨凷TS鍗忚锛岄泦鎴愭暟瀛楃鍚嶅姛鑳斤紝楠岃瘉鍏舵姉涓棿浜烘敾鍑昏兘鍔涳細\n1. 鏍稿績璁捐锛歕n   - 铻嶅悎ECDH瀵嗛挜浜ゆ崲涓嶳SA鏁板瓧绛惧悕锛沑n   - 瀵嗛挜鍗忓晢杩囩▼鍖呭惈韬唤璁よ瘉锛岀‘淇濋€氫俊鍙屾柟韬唤鍚堟硶锛沑n2. 瀹炵幇姝ラ锛歕n   a. 鍒濆鍖朣TS绫伙細鍐呴儴鍖呭惈ECDH妯″潡锛堢敤浜庡瘑閽ヤ氦鎹級鍜孯SA绛惧悕妯″潡锛堢敤浜庤韩浠借璇侊級锛沑n   b. 鐢熸垚瀵嗛挜瀵癸細鍚屾椂鐢熸垚ECDH瀵嗛挜瀵癸紙鐢ㄤ簬瀵嗛挜浜ゆ崲锛夊拰RSA绛惧悕瀵嗛挜瀵癸紙鐢ㄤ簬韬唤璁よ瘉锛夛紱\n   c. 绛惧悕浜ゆ崲锛歕n      - Alice鍙戦€丒CDH鍏挜缁橞ob锛沑n      - Bob鎺ユ敹鍚庯紝瀵光€淎lice鍏挜+Bob鍏挜鈥濈鍚嶏紝鍙戦€丅ob鍏挜鍜岀鍚嶇粰Alice锛沑n      - Alice楠岃瘉Bob绛惧悕閫氳繃鍚庯紝瀵光€淏ob鍏挜+Alice鍏挜鈥濈鍚嶏紝鍙戦€佺鍚嶇粰Bob锛沑n   d. 绛惧悕楠岃瘉锛氬弻鏂瑰垎鍒獙璇佸鏂圭鍚嶏紝纭繚韬唤鍚堟硶锛沑n   e. 瀵嗛挜璁＄畻锛氶獙璇侀€氳繃鍚庯紝鍙屾柟璁＄畻鍏变韩瀵嗛挜锛沑n3. 鎶桵ITM楠岃瘉閫昏緫锛歕n   - 涓棿浜烘棤娉曚吉閫犲悎娉曠鍚嶏紙鏃犲弻鏂筊SA绉侀挜锛夛紝鍗充娇鎷︽埅骞剁鏀瑰叕閽ワ紝涔熶細鍥犵鍚嶉獙璇佸け璐ヨ€岃璇嗙牬锛沑n   - 绛惧悕鍐呭鍖呭惈鍙屾柟鍏挜锛岀‘淇濆叕閽ユ湭琚鏀广€俓n4. 鍏抽敭瀹炵幇缁嗚妭锛歕n   - 绛惧悕绠楁硶锛氫娇鐢≧SA-PSS绛惧悕鏂规锛屽畨鍏ㄦ€ф洿楂橈紱\n   - 娑堟伅鏋勯€狅細绛惧悕鍐呭涓哄弻鏂瑰叕閽ユ嫾鎺ワ紝纭繚涓婁笅鏂囧畬鏁存€э紱\n   - 楠岃瘉澶辫触澶勭悊锛氱鍚嶉獙璇佸け璐ョ洿鎺ユ姏鍑哄紓甯革紝缁堟瀵嗛挜鍗忓晢銆俓n棰勬湡杈撳嚭锛氭垚鍔熷畬鎴愮鍚嶄氦鎹笌楠岃瘉锛屽弻鏂硅绠楀嚭鐩稿悓鍏变韩瀵嗛挜锛岄獙璇丼TS鍗忚鐨勮韩浠借璇佷笌鎶桵ITM鑳藉姏銆?,NULL,'from cryptography.hazmat.primitives.asymmetric import ec, rsa, padding\nfrom cryptography.hazmat.primitives import hashes, serialization\nfrom cryptography.hazmat.backends import default_backend\n\nclass KeyAgreementProtocol:\n    def __init__(self):\n        self.dh = ECDH()  # 澶嶇敤涔嬪墠瀹炵幇鐨凟CDH绫籠n        self.signature_key = None  # RSA绉侀挜锛堢鍚嶇敤锛塡n        self.verify_key = None     # RSA鍏挜锛堥獙璇佺敤锛塡n    \n    def generate_keys(self):\n        # 鐢熸垚ECDH瀵嗛挜瀵筡n        self.dh.generate_key_pair()\n        # 鐢熸垚RSA绛惧悕瀵嗛挜瀵筡n        self.signature_key = rsa.generate_private_key(\n            public_exponent=65537, key_size=2048, backend=default_backend()\n        )\n        self.verify_key = self.signature_key.public_key()\n        print(\"[STS] 瀵嗛挜鐢熸垚瀹屾垚\")\n    \n    def create_signed_exchange(self, peer_public_key_bytes: bytes) -> tuple:\n        # 瀵光€滆嚜宸卞叕閽?瀵规柟鍏挜鈥濈鍚峔n        my_public = self.dh.get_public_key_bytes()\n        message = my_public + peer_public_key_bytes\n        signature = self.signature_key.sign(\n            message,\n            padding.PSS(\n                mgf=padding.MGF1(hashes.SHA256()),\n                salt_length=padding.PSS.MAX_LENGTH\n            ),\n            hashes.SHA256()\n        )\n        return my_public, signature\n    \n    def verify_and_compute_key(self, peer_dh_public: bytes, peer_verify_key, signature: bytes) -> bytes:\n        # 楠岃瘉绛惧悕\n        my_public = self.dh.get_public_key_bytes()\n        message = peer_dh_public + my_public\n        try:\n            peer_verify_key.verify(\n                signature,\n                message,\n                padding.PSS(\n                    mgf=padding.MGF1(hashes.SHA256()),\n                    salt_length=padding.PSS.MAX_LENGTH\n                ),\n                hashes.SHA256()\n            )\n            print(\"[STS] 绛惧悕楠岃瘉鎴愬姛\")\n        except Exception as e:\n            raise ValueError(f\"绛惧悕楠岃瘉澶辫触: {e}\")\n        # 璁＄畻鍏变韩瀵嗛挜\n        return self.dh.compute_shared_key(peer_dh_public)\n\n# 婕旂ず浠ｇ爜\ndef demo_sts_protocol():\n    print(\"\\n\" + \"=\"*60)\n    print(\"STS瀵嗛挜鍗忓晢鍗忚婕旂ず\")\n    print(\"=\"*60)\n    \n    # 鐢熸垚瀵嗛挜瀵筡n    alice = KeyAgreementProtocol()\n    alice.generate_keys()\n    bob = KeyAgreementProtocol()\n    bob.generate_keys()\n    \n    # 绗竴杞細Alice鍙戦€丒CDH鍏挜\n    alice_dh_public = alice.dh.get_public_key_bytes()\n    \n    # 绗簩杞細Bob鍙戦€佸叕閽ュ拰绛惧悕\n    bob_dh_public, bob_signature = bob.create_signed_exchange(alice_dh_public)\n    \n    # 绗笁杞細Alice楠岃瘉绛惧悕骞跺彂閫佺鍚峔n    alice_shared = alice.verify_and_compute_key(\n        bob_dh_public, bob.verify_key, bob_signature\n    )\n    _, alice_signature = alice.create_signed_exchange(bob_dh_public)\n    \n    # 绗洓杞細Bob楠岃瘉绛惧悕\n    bob_shared = bob.verify_and_compute_key(\n        alice_dh_public, alice.verify_key, alice_signature\n    )\n    \n    # 楠岃瘉\n    print(f\"Alice瀵嗛挜: {alice_shared.hex()}\")\n    print(f\"Bob瀵嗛挜:   {bob_shared.hex()}\")\n    print(f\"瀵嗛挜鍖归厤: {alice_shared == bob_shared}\")\n    print(\"\\nSTS鍗忚鎻愪緵鐩镐簰璁よ瘉锛屾姉涓棿浜烘敾鍑籠")\n    \n    return alice_shared == bob_shared\n\n# 鎵ц婕旂ず\ndemo_sts_protocol()'),(101,14,10,'鍥涚被鍗忚瀵规瘮涓庡疄闄呭簲鐢ㄩ€夊瀷','鍩轰簬鍘熺悊銆佸畨鍏ㄦ€с€佹€ц兘銆侀€傜敤鍦烘櫙瀵瑰洓绫诲崗璁繘琛屽叏闈㈠姣旓紝鏄庣‘閫夊瀷渚濇嵁锛歕n1. 鏍稿績鐗规€у姣旓細\n   - DH鍗忚锛氬幓涓績鍖栵紝鏃犺韩浠借璇侊紙鏄撳彈MITM鏀诲嚮锛夛紝瀵嗛挜闀垮害闀匡紙2048+浣嶏級锛岄€傜敤浜庣畝鍗曞瘑閽ヤ氦鎹㈠満鏅紱\n   - ECDH鍗忚锛氬幓涓績鍖栵紝鏃犺韩浠借璇侊紝瀵嗛挜闀垮害鐭紙256浣嶏級锛岃绠楅珮鏁堬紝閫傜敤浜庤祫婧愬彈闄愬満鏅紙绉诲姩璁惧銆佺墿鑱旂綉锛夛紱\n   - KDC鍗忚锛氫腑蹇冨寲锛屼緷璧栧彲淇＄涓夋柟锛岄€傜敤浜庡ぇ瑙勬ā绯荤粺锛堜紒涓氬唴缃戙€佸垎甯冨紡鏈嶅姟锛夛紝绠＄悊鎴愭湰浣庯紝浣咾DC鏄崟鐐规晠闅滐紱\n   - STS鍗忚锛氬幓涓績鍖栵紝鏀寔韬唤璁よ瘉锛堟姉MITM锛夛紝瀹夊叏鎬ф渶楂橈紝閫傜敤浜庨珮瀹夊叏闇€姹傚満鏅紙閲戣瀺銆佹斂鍔￠€氫俊锛夛紱\n2. 瀹夊叏鎬у姣旓細\n   瀹夊叏绛夌骇鎺掑簭锛歋TS > ECDH = DH > KDC锛堜緷璧朘DC鍙俊搴︼級锛沑n   鎶楁敾鍑昏兘鍔涳細STS鎶桵ITM锛屽叾浠栨棤锛圞DC闇€淇濋殰鑷韩瀹夊叏锛夛紱\n3. 鎬ц兘瀵规瘮锛歕n   璁＄畻鏁堢巼锛欵CDH > STS > DH > KDC锛沑n   甯﹀娑堣€楋細ECDH < DH < STS < KDC锛沑n4. 瀹為檯搴旂敤閫夊瀷寤鸿锛歕n   - 灏忓瀷鍘讳腑蹇冨寲鍦烘櫙锛欵CDH锛堥珮鏁堝畨鍏級锛沑n   - 澶ц妯＄郴缁燂細KDC锛堢畝鍖栧瘑閽ョ鐞嗭級锛沑n   - 楂樺畨鍏ㄩ渶姹傚満鏅細STS锛堟姉MITM+韬唤璁よ瘉锛夛紱\n   - 鍏煎鎬ч渶姹傚満鏅細DH锛堜紶缁熺郴缁熷吋瀹癸級銆俓n棰勬湡杈撳嚭锛氳兘澶熸牴鎹疄闄呭満鏅殑瀹夊叏鎬с€佹€ц兘銆佹嫇鎵戠粨鏋勯渶姹傦紝閫夋嫨鍚堥€傜殑瀵嗛挜绠＄悊鍗忚銆?,'瀹為檯搴旂敤涓紝ECDH甯镐笌鏁板瓧绛惧悕缁撳悎锛堢被浼糞TS鎬濊矾锛夛紝鏃繚鐣欓珮鏁堟€э紝鍙堟彁渚涜韩浠借璇?,NULL),(102,15,1,'璁よ瘉鍗忚鏍稿績姒傚康涓庡垎绫?,'璁よ瘉鍗忚鏄繚闅滅綉缁滈€氫俊瀹夊叏鐨勫熀纭€锛屾牳蹇冪洰鏍囨槸楠岃瘉鍙備笌閫氫俊瀹炰綋鐨勮韩浠藉悎娉曟€э紝闃叉韬唤浼€犮€佸啋鍏呯瓑鏀诲嚮銆傞鍏堟槑纭璇佸崗璁殑鏍稿績鍒嗙被鍙婂簲鐢ㄥ満鏅細\n1. 瀹炰綋璁よ瘉鍗忚锛氳仛鐒﹀崟涓€瀹炰綋鐨勮韩浠介獙璇侊紝鏍稿績鏄瘉鏄庘€滀綘鏄皝鈥濓紝鍏稿瀷浠ｈ〃涓烘寫鎴?鍝嶅簲锛圕hallenge-Response锛夊崗璁紝閫傜敤浜庣偣瀵圭偣鐨勮韩浠芥牎楠岋紱\n2. 韬唤璁よ瘉鍗忚锛氶潰鍚戝鏉傜郴缁熺殑韬唤绠＄悊锛屼笉浠呴獙璇佽韩浠斤紝杩樻秹鍙婃巿鏉冦€佸崟鐐圭櫥褰曠瓑鍔熻兘锛屽吀鍨嬩唬琛ㄤ负Kerberos锛堜腑蹇冨寲璁よ瘉锛夊拰OAuth锛堢涓夋柟鎺堟潈锛夛紱\n3. 鐩镐簰璁よ瘉鍗忚锛氶€氫俊鍙屾柟浜掔浉楠岃瘉瀵规柟韬唤锛岄槻姝腑闂翠汉鏀诲嚮锛屽父瑙佷簬楂樺畨鍏ㄩ渶姹傚満鏅紝濡係TS鍗忚銆並erberos鍗忚鐨勬墿灞曞簲鐢ㄣ€俓n涓夌被鍗忚鐨勬牳蹇冨樊寮傚湪浜庨獙璇佸璞★紙鍗曟柟/澶氭柟锛夈€佸簲鐢ㄥ満鏅紙绠€鍗曠偣瀵圭偣/澶嶆潅绯荤粺锛夈€侀檮鍔犲姛鑳斤紙浠呰璇?璁よ瘉+鎺堟潈锛夈€傜悊瑙ｅ垎绫绘槸鍚庣画瀛︿範鐨勫熀纭€锛岄渶鏄庣‘涓嶅悓鍗忚鐨勫畾浣嶄笌鏍稿績瑙ｅ喅鐨勯棶棰樸€俓n棰勬湡杈撳嚭锛氬缓绔嬭璇佸崗璁殑鍒嗙被妗嗘灦锛屾槑纭悇绫诲崗璁殑鏍稿績鐩爣涓庨€傜敤鍦烘櫙銆?,'閲嶇偣鍖哄垎鈥滆璇佲€濅笌鈥滄巿鏉冣€濓細璁よ瘉鏄獙璇佽韩浠斤紝鎺堟潈鏄厑璁告搷浣?,NULL),(103,15,2,'鎸戞垬-鍝嶅簲锛圕hallenge-Response锛夊崗璁師鐞?,'鎸戞垬-鍝嶅簲鍗忚鏄疄浣撹璇佺殑缁忓吀鏂规锛?970骞翠唬鎻愬嚭锛屾牳蹇冭В鍐充紶缁熷瘑鐮佷紶杈撶殑瀹夊叏闅愭偅锛岄€氳繃鈥滈殢鏈烘寫鎴樷€濇満鍒堕槻姝㈤噸鏀炬敾鍑诲拰瀵嗙爜娉勯湶銆俓n1. 鍘嗗彶鑳屾櫙锛氫