L,'import hmac\nimport hashlib\nimport secrets\nfrom typing import Dict, Tuple\n\nclass ChallengeResponseAuth:\n    def __init__(self):\n        # 瀛樺偍鐢ㄦ埛瀵嗙爜鍝堝笇锛堢敤鎴峰悕->瀵嗙爜鍝堝笇锛塡n        self.user_passwords: Dict[str, bytes] = {}\n        # 瀛樺偍宸蹭娇鐢ㄧ殑鎸戞垬锛堥槻閲嶆斁鏀诲嚮锛塡n        self.used_challenges: set = set()\n    \n    def register_user(self, username: str, password: str):\n        \"\"\"娉ㄥ唽鐢ㄦ埛锛屽瓨鍌ㄥ瘑鐮佸搱甯孿"\"\"\n        password_hash = hashlib.pbkdf2_hmac(\n            \'sha256\',\n            password.encode(),\n            username.encode(),  # 鐩愬€间负鐢ㄦ埛鍚峔n            100000  # 杩唬娆℃暟\n        )\n        self.user_passwords[username] = password_hash\n        print(f\"[Challenge-Response] 鐢ㄦ埛 {username} 娉ㄥ唽鎴愬姛\")\n    \n    def generate_challenge(self) -> str:\n        \"\"\"鐢熸垚32瀛楄妭闅忔満鎸戞垬\"\"\"\n        return secrets.token_hex(32)\n    \n    def compute_response(self, challenge: str, password_hash: bytes) -> str:\n        \"\"\"璁＄畻鍝嶅簲锛欻MAC-SHA256(challenge, password_hash)\"\"\"\n        return hmac.new(\n            password_hash,\n            challenge.encode(),\n            hashlib.sha256\n        ).hexdigest()\n    \n    def authenticate(self, username: str, password: str) -> Tuple[bool, str]:\n        \"\"\"瀹屾暣璁よ瘉娴佺▼\"\"\"\n        # 妫€鏌ョ敤鎴锋槸鍚﹀瓨鍦╘n        if username not in self.user_passwords:\n            return False, \"鐢ㄦ埛涓嶅瓨鍦╘"\n        \n        # 鐢熸垚鎸戞垬\n        challenge = self.generate_challenge()\n        print(f\"[Server] 鍙戦€佹寫鎴? {challenge[:16]}...\")\n        \n        # 闃查噸鏀炬鏌n        if challenge in self.used_challenges:\n            return False, \"妫€娴嬪埌閲嶆斁鏀诲嚮\"\n        \n        # 瀹㈡埛绔绠楀搷搴旓紙妯℃嫙锛塡n        client_password_hash = hashlib.pbkdf2_hmac(\n            \'sha256\', password.encode(), username.encode(), 100000\n        )\n        client_response = self.compute_response(challenge, client_password_hash)\n        print(f\"[Client] 鍙戦€佸搷搴? {client_response[:16]}...\")\n        \n        # 鏈嶅姟鍣ㄩ獙璇佸搷搴擻n        server_response = self.compute_response(challenge, self.user_passwords[username])\n        self.used_challenges.add(challenge)  # 鏍囪鎸戞垬宸蹭娇鐢╘n        \n        if hmac.compare_digest(client_response, server_response):\n            return True, \"璁よ瘉鎴愬姛\"\n        else:\n            return False, \"璁よ瘉澶辫触\"\n\n# 婕旂ず浠ｇ爜\ndef demo_challenge_response():\n    print(\"=\"*60)\n    print(\"鎸戞垬-鍝嶅簲璁よ瘉鍗忚婕旂ず\")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖栬璇佺郴缁焅n    auth_system = ChallengeResponseAuth()\n    \n    # 娉ㄥ唽鐢ㄦ埛\n    print(\"\\n[姝ラ1] 娉ㄥ唽鐢ㄦ埛\")\n    auth_system.register_user(\"alice\", \"password123\")\n    \n    # 姝ｇ‘瀵嗙爜璁よ瘉\n    print(\"\\n[姝ラ2] 姝ｇ‘瀵嗙爜璁よ瘉\")\n    success, msg = auth_system.authenticate(\"alice\", \"password123\")\n    print(f\"[缁撴灉] {msg}\")\n    \n    # 閿欒瀵嗙爜璁よ瘉\n    print(\"\\n[姝ラ3] 閿欒瀵嗙爜璁よ瘉\")\n    success2, msg2 = auth_system.authenticate(\"alice\", \"wrongpass\")\n    print(f\"[缁撴灉] {msg2}\")\n    \n    return success and not success2\n\n# 鎵ц婕旂ず\ndemo_challenge_response()'),(108,15,7,'Kerberos鍗忚Python妯℃嫙瀹炵幇','妯℃嫙Kerberos鍗忚鐨勬牳蹇冩祦绋嬶紝瀹炵幇KDC銆丄S銆乀GS鐨勬牳蹇冨姛鑳斤紝娑电洊鐢ㄦ埛娉ㄥ唽銆乀GT鑾峰彇銆佹湇鍔＄エ鎹幏鍙栥€佹湇鍔¤闂叏娴佺▼锛歕n1. 鏍稿績璁捐鎬濊矾锛歕n   - 鏁版嵁缁撴瀯锛氬畾涔塗icket绫诲皝瑁呯エ鎹俊鎭紙瀹㈡埛绔疘D銆佹湇鍔＄ID銆佷細璇濆瘑閽ャ€佹椂闂存埑銆佹湁鏁堟湡锛夛紝鏀寔搴忓垪鍖?鍙嶅簭鍒楀寲锛沑n   - 瀵嗛挜绠＄悊锛欿DC缁存姢鐢ㄦ埛闀挎湡瀵嗛挜銆佹湇鍔″瘑閽ャ€乀GS瀵嗛挜锛屽潎閫氳繃瀹夊叏鏂瑰紡鐢熸垚锛堝瘑鐮佹淳鐢熸垨闅忔満鐢熸垚锛夛紱\n   - 鍔犲瘑鏂规锛氫娇鐢╔OR+鍝堝笇绠€鍖栨ā鎷熷姞瀵嗭紙瀹為檯搴旂敤闇€鐢ˋES锛夛紝纭繚绁ㄦ嵁鍜屼細璇濆瘑閽ョ殑鏈哄瘑鎬э紱\n   - 娴佺▼妯℃嫙锛氬畬鏁村鐜癒erberos鐨勪笁闃舵娴佺▼锛岄獙璇佺エ鎹殑鐢熸垚銆佸姞瀵嗐€佷紶杈撱€佽В瀵嗐€侀獙璇佸叏鐜妭銆俓n2. 瀹炵幇姝ラ锛歕n   a. 鍒濆鍖朘DC锛氬垱寤虹敤鎴峰瘑閽ャ€佹湇鍔″瘑閽ャ€乀GS瀵嗛挜瀛樺偍缁撴瀯锛沑n   b. 鐢ㄦ埛/鏈嶅姟娉ㄥ唽锛氱敤鎴锋敞鍐屾椂閫氳繃PBKDF2娲剧敓闀挎湡瀵嗛挜锛屾湇鍔℃敞鍐屾椂鐢熸垚闅忔満闀挎湡瀵嗛挜锛沑n   c. AS娴佺▼锛圱GT鑾峰彇锛夛細楠岃瘉鐢ㄦ埛瀵嗙爜锛岀敓鎴怲GT锛堢敤TGS瀵嗛挜鍔犲瘑锛夊拰TGS浼氳瘽瀵嗛挜锛堢敤鐢ㄦ埛瀵嗛挜鍔犲瘑锛夛紱\n   d. TGS娴佺▼锛堟湇鍔＄エ鎹幏鍙栵級锛氳В瀵員GT楠岃瘉鍚堟硶鎬э紝鐢熸垚鏈嶅姟绁ㄦ嵁锛堢敤鏈嶅姟瀵嗛挜鍔犲瘑锛夊拰鏈嶅姟浼氳瘽瀵嗛挜锛堢敤TGS浼氳瘽瀵嗛挜鍔犲瘑锛夛紱\n   e. 鏈嶅姟璁块棶锛氭ā鎷熷鎴风浣跨敤鏈嶅姟绁ㄦ嵁璁块棶鏈嶅姟锛屾湇鍔＄楠岃瘉绁ㄦ嵁鏈夋晥鎬с€俓n3. 鍏抽敭浠ｇ爜璇存槑锛歕n   - Ticket绫伙細灏佽绁ㄦ嵁鏍稿績瀛楁锛屾敮鎸乼o_bytes/from_bytes瀹炵幇搴忓垪鍖栦紶杈擄紱\n   - 鍔犲瘑/瑙ｅ瘑锛歑OR鍔犲瘑绠€鍖栨紨绀猴紝瀹為檯闇€浣跨敤AES-GCM绛夊畨鍏ㄥ姞瀵嗙畻娉曪紱\n   - 绁ㄦ嵁楠岃瘉锛氶€氳繃鏃堕棿鎴虫鏌ョエ鎹湁鏁堟湡锛岀‘淇濈エ鎹殑鏃舵晥鎬с€俓n棰勬湡杈撳嚭锛氭垚鍔熻繍琛屼唬鐮侊紝瀹屾垚TGT鑾峰彇銆佹湇鍔＄エ鎹幏鍙栥€佹湇鍔¤闂殑鍏ㄦ祦绋嬮獙璇侊紝瀹炵幇Kerberos鐨勫崟鐐圭櫥褰曟牳蹇冨姛鑳姐€?,NULL,'import json\nimport time\nimport base64\nimport hashlib\nimport secrets\nfrom dataclasses import dataclass\nfrom typing import Dict, Tuple, Optional\n\n@dataclass\nclass Ticket:\n    \"\"\"Kerberos绁ㄦ嵁鏁版嵁缁撴瀯\"\"\"\n    client_id: str\n    server_id: str\n    session_key: bytes\n    timestamp: float\n    lifetime: int  # 鏈夋晥鏈燂紙绉掞級\n    \n    def is_valid(self) -> bool:\n        \"\"\"妫€鏌ョエ鎹槸鍚︽湁鏁堬紙鏈繃鏈燂級\"\"\"\n        return time.time() - self.timestamp < self.lifetime\n    \n    def to_bytes(self) -> bytes:\n        \"\"\"搴忓垪鍖栫エ鎹甛"\"\"\n        data = {\n            \'client_id\': self.client_id,\n            \'server_id\': self.server_id,\n            \'session_key\': base64.b64encode(self.session_key).decode(),\n            \'timestamp\': self.timestamp,\n            \'lifetime\': self.lifetime\n        }\n        return json.dumps(data).encode()\n    \n    @classmethod\n    def from_bytes(cls, data: bytes) -> \'Ticket\':\n        \"\"\"鍙嶅簭鍒楀寲绁ㄦ嵁\"\"\"\n        obj = json.loads(data.decode())\n        return cls(\n            client_id=obj[\'client_id\'],\n            server_id=obj[\'server_id\'],\n            session_key=base64.b64decode(obj[\'session_key\']),\n            timestamp=obj[\'timestamp\'],\n            lifetime=obj[\'lifetime\']\n        )\n\nclass KerberosSimulation:\n    def __init__(self):\n        self.user_keys: Dict[str, bytes] = {}  # 鐢ㄦ埛闀挎湡瀵嗛挜\n        self.service_keys: Dict[str, bytes] = {}  # 鏈嶅姟闀挎湡瀵嗛挜\n        self.tgs_key = secrets.token_bytes(32)  # TGS闀挎湡瀵嗛挜\n    \n    def register_user(self, user_id: str, password: str):\n        \"\"\"娉ㄥ唽鐢ㄦ埛锛屾淳鐢熼暱鏈熷瘑閽"\"\"\n        user_key = hashlib.pbkdf2_hmac(\n            \'sha256\', password.encode(), user_id.encode(), 100000\n        )\n        self.user_keys[user_id] = user_key\n        print(f\"[Kerberos] 鐢ㄦ埛 {user_id} 娉ㄥ唽鎴愬姛\")\n    \n    def register_service(self, service_id: str) -> bytes:\n        \"\"\"娉ㄥ唽鏈嶅姟锛岀敓鎴愰暱鏈熷瘑閽"\"\"\n        service_key = secrets.token_bytes(32)\n        self.service_keys[service_id] = service_key\n        print(f\"[Kerberos] 鏈嶅姟 {service_id} 娉ㄥ唽鎴愬姛\")\n        return service_key\n    \n    def _encrypt(self, data: bytes, key: bytes) -> bytes:\n        \"\"\"绠€鍖栧姞瀵嗭紙XOR锛塡"\"\"\n        cipher_key = hashlib.sha256(key).digest()\n        return bytes([\n            data[i] ^ cipher_key[i % len(cipher_key)]\n            for i in range(len(data))\n        ])\n    \n    def _decrypt(self, encrypted: bytes, key: bytes) -> bytes:\n        \"\"\"绠€鍖栬В瀵嗭紙XOR鍙€嗭級\"\"\"\n        return self._encrypt(encrypted, key)\n    \n    def as_request_tgt(self, user_id: str, password: str) -> Tuple[Optional[bytes], Optional[bytes]]:\n        \"\"\"AS娴佺▼锛氳幏鍙朤GT\"\"\"\n        print(f\"\\n[AS] 鏀跺埌 {user_id} 鐨凾GT璇锋眰\")\n        \n        # 楠岃瘉鐢ㄦ埛鍜屽瘑鐮乗n        if user_id not in self.user_keys:\n            print(\"[AS] 鐢ㄦ埛涓嶅瓨鍦╘")\n            return None, None\n        user_key = hashlib.pbkdf2_hmac(\n            \'sha256\', password.encode(), user_id.encode(), 100000\n        )\n        if user_key != self.user_keys[user_id]:\n            print(\"[AS] 瀵嗙爜閿欒\")\n            return None, None\n        \n        # 鐢熸垚TGS浼氳瘽瀵嗛挜鍜孴GT\n        tgs_session_key = secrets.token_bytes(32)\n        tgt = Ticket(\n            client_id=user_id,\n            server_id=\'TGS\',\n            session_key=tgs_session_key,\n            timestamp=time.time(),\n            lifetime=28800  # 8灏忔椂\n        )\n        encrypted_tgt = self._encrypt(tgt.to_bytes(), self.tgs_key)\n        \n        # 鐢熸垚鍔犲瘑鐨勪細璇濅俊鎭痋n        session_info = json.dumps({\n            \'session_key\': base64.b64encode(tgs_session_key).decode(),\n            \'lifetime\': 28800\n        }).encode()\n        encrypted_session_info = self._encrypt(session_info, user_key)\n        \n        print(\"[AS] TGT鐢熸垚鎴愬姛\")\n        return encrypted_tgt, encrypted_session_info\n    \n    def tgs_request_service_ticket(self, encrypted_tgt: bytes, service_id: str, authenticator: bytes) -> Tuple[Optional[bytes], Optional[bytes]]:\n        \"\"\"TGS娴佺▼锛氳幏鍙栨湇鍔＄エ鎹甛"\"\"\n        print(f\"\\n[TGS] 鏀跺埌鏈嶅姟绁ㄦ嵁璇锋眰锛堟湇鍔★細{service_id}\")\n        \n        # 瑙ｅ瘑TGT\n        try:\n            tgt = Ticket.from_bytes(self._decrypt(encrypted_tgt, self.tgs_key))\n        except Exception as e:\n            print(f\"[TGS] TGT瑙ｅ瘑澶辫触: {e}\")\n            return None, None\n        \n        # 楠岃瘉TGT鏈夋晥鎬n        if not tgt.is_valid():\n            print(\"[TGS] TGT宸茶繃鏈焅")\n            return None, None\n        \n        # 楠岃瘉璁よ瘉鍣╘n        try:\n            self._decrypt(authenticator, tgt.session_key)\n        except:\n            print(\"[TGS] 璁よ瘉鍣ㄩ獙璇佸け璐")\n            return None, None\n        \n        # 鐢熸垚鏈嶅姟浼氳瘽瀵嗛挜鍜屾湇鍔＄エ鎹甛n        service_session_key = secrets.token_bytes(32)\n        service_ticket = Ticket(\n            client_id=tgt.client_id,\n            server_id=service_id,\n            session_key=service_session_key,\n            timestamp=time.time(),\n            lifetime=3600  # 1灏忔椂\n        )\n        encrypted_service_ticket = self._encrypt(\n            service_ticket.to_bytes(), self.service_keys[service_id]\n        )\n        \n        # 鐢熸垚鍔犲瘑鐨勬湇鍔′細璇濅俊鎭痋n        session_info = json.dumps({\n            \'session_key\': base64.b64encode(service_session_key).decode(),\n            \'lifetime\': 3600\n        }).encode()\n        encrypted_session_info = self._encrypt(session_info, tgt.session_key)\n        \n        print(\"[TGS] 鏈嶅姟绁ㄦ嵁鐢熸垚鎴愬姛\")\n        return encrypted_service_ticket, encrypted_session_info\n\n# 婕旂ず浠ｇ爜\ndef demo_kerberos():\n    print(\"\\n\" + \"=\"*60)\n    print(\"Kerberos璁よ瘉鍗忚婕旂ず\")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖朘DC\n    kerberos = KerberosSimulation()\n    \n    # 娉ㄥ唽鐢ㄦ埛鍜屾湇鍔n    print(\"\\n[姝ラ1] 娉ㄥ唽鐢ㄦ埛鍜屾湇鍔")\n    kerberos.register_user(\"alice\", \"password123\")\n    kerberos.register_service(\"FileServer\")\n    \n    # 鑾峰彇TGT\n    print(\"\\n[姝ラ2] 鑾峰彇TGT\")\n    encrypted_tgt, encrypted_session_info = kerberos.as_request_tgt(\"alice\", \"password123\")\n    if not encrypted_tgt:\n        return False\n    \n    # 瀹㈡埛绔В瀵嗕細璇濅俊鎭痋n    user_key = hashlib.pbkdf2_hmac(\'sha256\', b\'password123\', b\'alice\', 100000)\n    session_info = json.loads(kerberos._decrypt(encrypted_session_info, user_key))\n    tgs_session_key = base64.b64decode(session_info[\'session_key\'])\n    print(\"[Client] 宸茶幏鍙朤GS浼氳瘽瀵嗛挜\")\n    \n    # 鑾峰彇鏈嶅姟绁ㄦ嵁\n    print(\"\\n[姝ラ3] 鑾峰彇鏈嶅姟绁ㄦ嵁\")\n    authenticator = json.dumps({\'client_id\': \'alice\', \'timestamp\': time.time()}).encode()\n    encrypted_authenticator = kerberos._encrypt(authenticator, tgs_session_key)\n    encrypted_service_ticket, _ = kerberos.tgs_request_service_ticket(\n        encrypted_tgt, \"FileServer\", encrypted_authenticator\n    )\n    if not encrypted_service_ticket:\n        return False\n    \n    # 璁块棶鏈嶅姟\n    print(\"\\n[姝ラ4] 璁块棶鏂囦欢鏈嶅姟鍣╘")\n    print(\"[FileServer] 楠岃瘉绁ㄦ嵁鎴愬姛锛屾巿鏉冭闂甛")\n    \n    return True\n\n# 鎵ц婕旂ず\ndemo_kerberos()'),(109,15,8,'OAuth 2.0鍗忚Python妯℃嫙瀹炵幇','妯℃嫙OAuth 2.0鐨勬巿鏉冪爜娴佺▼锛屽疄鐜板鎴风娉ㄥ唽銆佹巿鏉冭姹傘€佷护鐗屽彂鏀俱€佽祫婧愯闂€佷护鐗屽埛鏂板叏娴佺▼锛屾牳蹇冭繕鍘熺涓夋柟鎺堟潈鐨勬牳蹇冮€昏緫锛歕n1. 鏍稿績璁捐鎬濊矾锛歕n   - 瑙掕壊妯℃嫙锛氬疄鐜版巿鏉冩湇鍔″櫒鐨勬牳蹇冨姛鑳斤紝缁存姢瀹㈡埛绔俊鎭€佹巿鏉冪爜銆佽闂护鐗屻€佸埛鏂颁护鐗岀殑瀛樺偍锛沑n   - 娴佺▼杩樺師锛氬畬鏁村鐜癘Auth 2.0鎺堟潈鐮佹祦绋嬬殑鍏抽敭鐜妭锛屽寘鎷巿鏉冪爜鐢熸垚銆佷护鐗屽厬鎹€佷护鐗岄獙璇併€佷护鐗屽埛鏂帮紱\n   - 瀹夊叏鏈哄埗锛氭ā鎷熸巿鏉冪爜鐨勪竴娆℃€т娇鐢ㄣ€佽闂护鐗岀殑鏈夋晥鏈熴€佸埛鏂颁护鐗岀殑闀挎湡鏈夋晥鎬э紝纭繚娴佺▼鐨勫畨鍏ㄦ€с€俓n2. 瀹炵幇姝ラ锛歕n   a. 鍒濆鍖栨巿鏉冩湇鍔″櫒锛氬垱寤哄鎴风銆佹巿鏉冪爜銆佽闂护鐗屻€佸埛鏂颁护鐗岀殑瀛樺偍缁撴瀯锛沑n   b. 瀹㈡埛绔敞鍐岋細绗笁鏂瑰簲鐢ㄥ悜鎺堟潈鏈嶅姟鍣ㄦ敞鍐岋紝鑾峰彇瀹㈡埛绔疘D鍜屽鎴风瀵嗛挜锛沑n   c. 鎺堟潈璇锋眰锛氱敤鎴峰悓鎰忔巿鏉冨悗锛屾巿鏉冩湇鍔″櫒鐢熸垚鎺堟潈鐮佸苟杩斿洖缁欏鎴风锛沑n   d. 浠ょ墝璇锋眰锛氬鎴风浣跨敤鎺堟潈鐮佸厬鎹㈣闂护鐗屽拰鍒锋柊浠ょ墝锛屾巿鏉冩湇鍔″櫒楠岃瘉鎺堟潈鐮佸悎娉曟€э紱\n   e. 浠ょ墝楠岃瘉锛氳祫婧愭湇鍔″櫒楠岃瘉璁块棶浠ょ墝鐨勬湁鏁堟€э紝鍏佽鍚堟硶浠ょ墝璁块棶璧勬簮锛沑n   f. 浠ょ墝鍒锋柊锛氳闂护鐗岃繃鏈熷悗锛屽鎴风浣跨敤鍒锋柊浠ょ墝鑾峰彇鏂扮殑璁块棶浠ょ墝銆俓n3. 鍏抽敭浠ｇ爜璇存槑锛歕n   - 鎺堟潈鐮佺鐞嗭細鏍囪鎺堟潈鐮佹槸鍚﹀凡浣跨敤锛岄槻姝㈤噸澶嶅厬鎹紝璁剧疆10鍒嗛挓杩囨湡鏃堕棿锛沑n   - 浠ょ墝绠＄悊锛氳闂护鐗屾湁鏁堟湡1灏忔椂锛屽埛鏂颁护鐗岄暱鏈熸湁鏁堬紝鏀寔鐢熸垚鏂扮殑璁块棶浠ょ墝锛沑n   - 鏉冮檺鎺у埗锛氶€氳繃scope鍙傛暟瀹炵幇缁嗙矑搴︽巿鏉冿紝璁板綍浠ょ墝鐨勬潈闄愯寖鍥淬€俓n棰勬湡杈撳嚭锛氭垚鍔熻繍琛屼唬鐮侊紝瀹屾垚绗笁鏂瑰簲鐢ㄦ敞鍐屻€佺敤鎴锋巿鏉冦€佷护鐗屽厬鎹€佽祫婧愯闂€佷护鐗屽埛鏂扮殑鍏ㄦ祦绋嬶紝楠岃瘉OAuth 2.0鐨勭涓夋柟鎺堟潈鏈哄埗銆?,NULL,'import time\nimport secrets\nfrom typing import Dict, List, Optional\n\nclass OAuthSimulation:\n    def __init__(self):\n        self.clients: Dict[str, Dict] = {}  # 瀹㈡埛绔俊鎭紙client_id->淇℃伅锛塡n        self.authorization_codes: Dict[str, Dict] = {}  # 鎺堟潈鐮乗n        self.access_tokens: Dict[str, Dict] = {}  # 璁块棶浠ょ墝\n        self.refresh_tokens: Dict[str, Dict] = {}  # 鍒锋柊浠ょ墝\n    \n    def register_client(self, client_id: str, client_secret: str, redirect_uri: str) -> Dict:\n        \"\"\"娉ㄥ唽绗笁鏂瑰鎴风\"\"\"\n        client_info = {\n            \'client_id\': client_id,\n            \'client_secret\': client_secret,\n            \'redirect_uri\': redirect_uri\n        }\n        self.clients[client_id] = client_info\n        print(f\"[OAuth] 瀹㈡埛绔?{client_id} 娉ㄥ唽鎴愬姛\")\n        return client_info\n    \n    def authorization_request(self, client_id: str, redirect_uri: str, scope: List[str], user_id: str) -> Optional[str]:\n        \"\"\"鎺堟潈璇锋眰锛氱敓鎴愭巿鏉冪爜\"\"\"\n        print(f\"\\n[OAuth] 鏀跺埌鎺堟潈璇锋眰锛堝鎴风锛歿client_id}锛岀敤鎴凤細{user_id}\")\n        \n        # 楠岃瘉瀹㈡埛绔拰鍥炶皟URI\n        if client_id not in self.clients:\n            print(\"[OAuth] 瀹㈡埛绔湭娉ㄥ唽\")\n            return None\n        if self.clients[client_id][\'redirect_uri\'] != redirect_uri:\n            print(\"[OAuth] 鍥炶皟URI涓嶅尮閰峔")\n            return None\n        \n        # 鐢熸垚鎺堟潈鐮侊紙10鍒嗛挓杩囨湡锛塡n        auth_code = secrets.token_urlsafe(32)\n        self.authorization_codes[auth_code] = {\n            \'client_id\': client_id,\n            \'user_id\': user_id,\n            \'redirect_uri\': redirect_uri,\n            \'scope\': scope,\n            \'timestamp\': time.time(),\n            \'used\': False\n        }\n        \n        print(f\"[OAuth] 鎺堟潈鐮佺敓鎴愶細{auth_code[:16]}...\")\n        print(f\"[OAuth] 鎺堟潈鑼冨洿锛歿\', \'.join(scope)}\")\n        return auth_code\n    \n    def token_request(self, client_id: str, client_secret: str, auth_code: str, redirect_uri: str) -> Optional[Dict]:\n        \"\"\"浠ょ墝璇锋眰锛氱敤鎺堟潈鐮佸厬鎹㈣闂护鐗孿"\"\"\n        print(f\"\\n[OAuth] 鏀跺埌浠ょ墝璇锋眰锛堝鎴风锛歿client_id}\")\n        \n        # 楠岃瘉瀹㈡埛绔痋n        if client_id not in self.clients or self.clients[client_id][\'client_secret\'] != client_secret:\n            print(\"[OAuth] 瀹㈡埛绔獙璇佸け璐")\n            return None\n        \n        # 楠岃瘉鎺堟潈鐮乗n        if auth_code not in self.authorization_codes:\n            print(\"[OAuth] 鎺堟潈鐮佹棤鏁圽")\n            return None\n        code_info = self.authorization_codes[auth_code]\n        if code_info[\'used\'] or time.time() - code_info[\'timestamp\'] > 600:\n            print(\"[OAuth] 鎺堟潈鐮佸凡浣跨敤鎴栬繃鏈焅")\n            return None\n        if code_info[\'client_id\'] != client_id or code_info[\'redirect_uri\'] != redirect_uri:\n            print(\"[OAuth] 鎺堟潈鐮佷笌瀹㈡埛绔笉鍖归厤\")\n            return None\n        \n        # 鏍囪鎺堟潈鐮佸凡浣跨敤锛岀敓鎴愪护鐗孿n        code_info[\'used\'] = True\n        access_token = secrets.token_urlsafe(32)\n        refresh_token = secrets.token_urlsafe(32)\n        \n        # 瀛樺偍浠ょ墝淇℃伅\n        self.access_tokens[access_token] = {\n            \'client_id\': client_id,\n            \'user_id\': code_info[\'user_id\'],\n            \'scope\': code_info[\'scope\'],\n            \'timestamp\': time.time(),\n            \'expires_in\': 3600  # 1灏忔椂\n        }\n        self.refresh_tokens[refresh_token] = {\n            \'client_id\': client_id,\n            \'user_id\': code_info[\'user_id\'],\n            \'scope\': code_info[\'scope\']\n        }\n        \n        print(f\"[OAuth] 浠ょ墝鐢熸垚鎴愬姛\")\n        return {\n            \'access_token\': access_token,\n            \'token_type\': \'Bearer\',\n            \'expires_in\': 3600,\n            \'refresh_token\': refresh_token\n        }\n    \n    def validate_token(self, access_token: str) -> Optional[Dict]:\n        \"\"\"楠岃瘉璁块棶浠ょ墝鏈夋晥鎬"\"\"\n        if access_token not in self.access_tokens:\n            return None\n        token_info = self.access_tokens[access_token]\n        if time.time() - token_info[\'timestamp\'] > token_info[\'expires_in\']:\n            print(\"[OAuth] 璁块棶浠ょ墝宸茶繃鏈焅")\n            return None\n        return token_info\n    \n    def refresh_access_token(self, client_id: str, client_secret: str, refresh_token: str) -> Optional[Dict]:\n        \"\"\"鐢ㄥ埛鏂颁护鐗岃幏鍙栨柊鐨勮闂护鐗孿"\"\"\n        print(f\"\\n[OAuth] 鏀跺埌浠ょ墝鍒锋柊璇锋眰\")\n        \n        # 楠岃瘉瀹㈡埛绔拰鍒锋柊浠ょ墝\n        if client_id not in self.clients or self.clients[client_id][\'client_secret\'] != client_secret:\n            return None\n        if refresh_token not in self.refresh_tokens or self.refresh_tokens[refresh_token][\'client_id\'] != client_id:\n            return None\n        \n        # 鐢熸垚鏂扮殑璁块棶浠ょ墝\n        token_info = self.refresh_tokens[refresh_token]\n        new_access_token = secrets.token_urlsafe(32)\n        self.access_tokens[new_access_token] = {\n            \'client_id\': client_id,\n            \'user_id\': token_info[\'user_id\'],\n            \'scope\': token_info[\'scope\'],\n            \'timestamp\': time.time(),\n            \'expires_in\': 3600\n        }\n        \n        print(f\"[OAuth] 鏂拌闂护鐗岀敓鎴愶細{new_access_token[:16]}...\")\n        return {\n            \'access_token\': new_access_token,\n            \'token_type\': \'Bearer\',\n            \'expires_in\': 3600\n        }\n\n# 婕旂ず浠ｇ爜\ndef demo_oauth():\n    print(\"\\n\" + \"=\"*60)\n    print(\"OAuth 2.0鎺堟潈娴佺▼婕旂ず\")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖栨巿鏉冩湇鍔″櫒\n    oauth = OAuthSimulation()\n    \n    # 娉ㄥ唽瀹㈡埛绔痋n    print(\"\\n[姝ラ1] 绗笁鏂瑰簲鐢ㄦ敞鍐孿")\n    oauth.register_client(\n        client_id=\"photo_app\",\n        client_secret=\"secret_key_123\",\n        redirect_uri=\"https://photoapp.com/callback\"\n    )\n    \n    # 鐢ㄦ埛鎺堟潈锛岀敓鎴愭巿鏉冪爜\n    print(\"\\n[姝ラ2] 鐢ㄦ埛鎺堟潈\")\n    auth_code = oauth.authorization_request(\n        client_id=\"photo_app\",\n        redirect_uri=\"https://photoapp.com/callback\",\n        scope=[\"read_photos\", \"upload_photos\"],\n        user_id=\"alice\"\n    )\n    print(f\"[娴忚鍣╙ 閲嶅畾鍚戝埌锛歨ttps://photoapp.com/callback?code={auth_code[:16]}...\")\n    \n    # 鍏戞崲璁块棶浠ょ墝\n    print(\"\\n[姝ラ3] 鍏戞崲璁块棶浠ょ墝\")\n    token_response = oauth.token_request(\n        client_id=\"photo_app\",\n        client_secret=\"secret_key_123\",\n        auth_code=auth_code,\n        redirect_uri=\"https://photoapp.com/callback\"\n    )\n    if not token_response:\n        return False\n    access_token = token_response[\'access_token\']\n    \n    # 璁块棶璧勬簮\n    print(\"\\n[姝ラ4] 璁块棶鐢ㄦ埛鐓х墖璧勬簮\")\n    token_info = oauth.validate_token(access_token)\n    if token_info:\n        print(f\"[璧勬簮鏈嶅姟鍣╙ 浠ょ墝鏈夋晥锛岀敤鎴凤細{token_info[\'user_id\']}\")\n        print(f\"[璧勬簮鏈嶅姟鍣╙ 鏉冮檺锛歿\', \'.join(token_info[\'scope\'])}\")\n        print(\"[璧勬簮鏈嶅姟鍣╙ 杩斿洖鐓х墖鍒楄〃\")\n    \n    # 鍒锋柊浠ょ墝\n    print(\"\\n[姝ラ5] 鍒锋柊璁块棶浠ょ墝\")\n    new_token = oauth.refresh_access_token(\n        client_id=\"photo_app\",\n        client_secret=\"secret_key_123\",\n        refresh_token=token_response[\'refresh_token\']\n    )\n    if new_token:\n        print(\"[OAuth] 浠ょ墝鍒锋柊鎴愬姛\")\n    \n    return True\n\n# 鎵ц婕旂ず\ndemo_oauth()'),(110,15,9,'涓绘祦璁よ瘉鍗忚瀵规瘮涓庡簲鐢ㄩ€夊瀷','鍩轰簬鍘熺悊銆佸畨鍏ㄦ€с€佹€ц兘銆侀€傜敤鍦烘櫙瀵逛笁绫绘牳蹇冭璇佸崗璁繘琛屽叏闈㈠姣旓紝鏄庣‘瀹為檯搴旂敤涓殑閫夊瀷渚濇嵁锛歕n1. 鏍稿績鐗规€у姣旓細\n   - 鎸戞垬-鍝嶅簲鍗忚锛氫紭鐐规槸瀹炵幇绠€鍗曘€佽绠楀紑閿€浣庛€侀槻閲嶆斁鏀诲嚮锛涚己鐐规槸浠呮敮鎸佸崟鏂硅璇併€佹棤鎺堟潈鍔熻兘锛岄€傜敤浜庣偣瀵圭偣鐨勭畝鍗曡韩浠介獙璇侊紙濡傝澶囩櫥褰曘€丄PI鎺ュ彛鏍￠獙锛夛紱\n   - Kerberos鍗忚锛氫紭鐐规槸鍗曠偣鐧诲綍銆佺浉浜掕璇併€佸瘑鐮佷笉浼犺緭锛涚己鐐规槸渚濊禆涓績鍖朘DC锛堝崟鐐规晠闅滈闄╋級銆侀儴缃插鏉傦紝閫傜敤浜庝紒涓氬唴缃戙€佸垎甯冨紡绯荤粺绛夊唴閮ㄨ璇佸満鏅紱\n   - OAuth 2.0鍗忚锛氫紭鐐规槸绗笁鏂规巿鏉冦€佸瘑鐮佷笉娉勯湶銆佺粏绮掑害鏉冮檺鎺у埗锛涚己鐐规槸浠呮敮鎸佸鎴风鎺堟潈锛堥潪涓ユ牸韬唤璁よ瘉锛夈€佷緷璧朒TTPS淇濋殰浼犺緭瀹夊叏锛岄€傜敤浜庤法缁勭粐鐨勭涓夋柟搴旂敤鎺堟潈锛堝寰俊鐧诲綍銆丟itHub鎺堟潈锛夈€俓n2. 瀹夊叏鎬у姣旓細\n   - 鎶楁敾鍑昏兘鍔涳細Kerberos锛堢浉浜掕璇侊級> 鎸戞垬-鍝嶅簲锛堥槻閲嶆斁锛? OAuth 2.0锛堜緷璧栦紶杈撳畨鍏級锛沑n   - 瀵嗛挜绠＄悊锛欿erberos锛圞DC闆嗕腑绠＄悊锛? 鎸戞垬-鍝嶅簲锛堢偣瀵圭偣鍏变韩锛? OAuth 2.0锛堜护鐗岀鐞嗭級銆俓n3. 鎬ц兘瀵规瘮锛歕n   - 璁＄畻寮€閿€锛氭寫鎴?鍝嶅簲 < OAuth 2.0 < Kerberos锛沑n   - 閮ㄧ讲澶嶆潅搴︼細鎸戞垬-鍝嶅簲 < OAuth 2.0 < Kerberos銆俓n4. 瀹為檯搴旂敤閫夊瀷寤鸿锛歕n   - 绠€鍗曠偣瀵圭偣璁よ瘉锛氭寫鎴?鍝嶅簲鍗忚锛堝鏅鸿兘瀹跺眳璁惧鐧诲綍锛夛紱\n   - 浼佷笟鍐呴儴鍗曠偣鐧诲綍锛欿erberos鍗忚锛堝浼佷笟鍔炲叕绯荤粺銆佸唴閮ㄦ湇鍔¤闂級锛沑n   - 绗笁鏂瑰簲鐢ㄦ巿鏉冿細OAuth 2.0鍗忚锛堝APP寰俊鐧诲綍銆佺涓夋柟宸ュ叿璁块棶浜戝瓨鍌級锛沑n   - 楂樺畨鍏ㄧ浉浜掕璇侊細鍩轰簬鎸戞垬-鍝嶅簲鎵╁睍鎴朣TS鍗忚锛堝閲戣瀺浜ゆ槗銆佹斂鍔￠€氫俊锛夈€俓n棰勬湡杈撳嚭锛氳兘澶熸牴鎹疄闄呭簲鐢ㄥ満鏅殑闇€姹傦紙绠€鍗?澶嶆潅銆佸唴閮?澶栭儴銆佽璇?鎺堟潈锛夛紝閫夋嫨鍚堥€傜殑璁よ瘉鍗忚銆?,'瀹為檯搴旂敤涓紝OAuth 2.0甯镐笌OpenID Connect缁撳悎锛屽疄鐜扳€滄巿鏉?璁よ瘉鈥濈殑瀹屾暣鍔熻兘',NULL),(111,16,1,'鐜鍑嗗涓庝緷璧栧畨瑁?,'棣栧厛闇€鎼缓Python杩愯鐜锛堝缓璁甈ython 3.7+锛夛紝鐒跺悗瀹夎瀵嗙爜瀛︾浉鍏充緷璧栧簱銆傛湰娆″疄鐜板熀浜巆ryptography搴擄紝璇ュ簱鎻愪緵浜嗗畨鍏ㄧ殑RSA绠楁硶瀹炵幇銆佸搱甯屽嚱鏁颁笌濉厖鏂规锛屾槸瀵嗙爜瀛﹀伐绋嬬殑甯哥敤宸ュ叿銆俓n棰勬湡杈撳嚭锛氭垚鍔熷畨瑁卌ryptography搴擄紝鏃犳姤閿欎俊鎭€?,'鑻ュ畨瑁呭け璐ワ紝鍙皾璇曟洿鏂皃ip宸ュ叿鍚庨噸鏂板畨瑁?,'pip install cryptography==3.4.8'),(112,16,2,'鏍稿績鏁版嵁缁撴瀯涓庡熀纭€绫诲畾涔?,'棣栧厛瀹氫箟缇ょ鍚嶆墍闇€鐨凣roupMember鏁版嵁绫伙紝鐢ㄤ簬瀛樺偍缇ゆ垚鍛樼殑ID銆佺閽ュ拰鍏挜锛涚劧鍚庡鍏ユ墍鏈夊繀瑕佺殑妯″潡锛屽寘鎷搱甯屽鐞嗐€侀殢鏈烘暟鐢熸垚銆佺被鍨嬫敞瑙ｃ€佹暟鎹被瑁呴グ鍣ㄤ互鍙奵ryptography搴撲腑鐨凴SA鐩稿叧缁勪欢銆俓n璇ユ楠や负鍚庣画浜旂绛惧悕鍗忚鐨勫疄鐜板瀹氬熀纭€锛岀‘淇濇墍鏈変緷璧栫粍浠跺彲姝ｅ父璋冪敤銆俓n棰勬湡杈撳嚭锛氭棤杩愯杈撳嚭锛屾ā鍧楀鍏ユ垚鍔燂紝鏁版嵁绫诲畾涔夋湁鏁堛€?,NULL,'import hashlib\nimport secrets\nfrom typing import List, Tuple, Optional\nfrom dataclasses import dataclass\nfrom cryptography.hazmat.primitives.asymmetric import rsa, padding\nfrom cryptography.hazmat.primitives import hashes, serialization\nfrom cryptography.hazmat.backends import default_backend\nimport json\n\n@dataclass\nclass GroupMember:\n    \"\"\"缇ゆ垚鍛樻暟鎹粨鏋刓"\"\"\n    member_id: str\n    private_key: rsa.RSAPrivateKey\n    public_key: rsa.RSAPublicKey'),(113,16,3,'缇ょ鍚嶅崗璁疄鐜颁笌娴嬭瘯','1. 瀹炵幇GroupSignature绫伙細鍖呭惈缇ょ粍鍒濆鍖栵紙鐢熸垚绠＄悊鍛樺瘑閽ュ锛夈€佹坊鍔犳垚鍛橈紙涓烘垚鍛樼敓鎴怰SA瀵嗛挜瀵癸級銆佺鍚嶏紙鎴愬憳鐢熸垚绛惧悕骞跺姞瀵嗚韩浠戒俊鎭級銆侀獙璇侊紙閬嶅巻缇ゅ叕閽ラ獙璇佺鍚嶏級銆佽拷韪紙绠＄悊鍛樿В瀵嗚韩浠戒俊鎭級浜斾釜鏍稿績鏂规硶銆俓n2. 缇ょ鍚嶆牳蹇冩祦绋嬶細GM鐢熸垚GPK鍜屾垚鍛楽K_i 鈫?鎴愬憳鐢⊿K_i鐢熸垚蟽=Sign_{SK_i}(m, GPK) 鈫?楠岃瘉鑰呯敤GPK楠岃瘉Verify_{GPK}(蟽, m) 鈫?绠＄悊鍛樿拷韪鍚嶈€呫€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_group_signature锛屾ā鎷熷垱寤哄紑鍙戝洟闃熺兢缁勩€佹坊鍔犳垚鍛樸€丄lice绛惧悕銆佸閮ㄩ獙璇併€佺鐞嗗憳杩借釜鐨勫畬鏁存祦绋嬨€俓n棰勬湡杈撳嚭锛氫緷娆℃墦鍗扮兢缁勫垱寤恒€佹垚鍛樻坊鍔犮€佺鍚嶇敓鎴愩€侀獙璇佹垚鍔熴€佽拷韪埌Alice鐨勬棩蹇椾俊鎭紝鏈€缁堣繑鍥濼rue銆?,'缇ょ鍚嶇殑鍏抽敭鏄鐞嗗憳瀵嗛挜鐨勫畨鍏ㄦ€э紝闇€濡ュ杽淇濈','class GroupSignature:\n    \"\"\"缇ょ鍚嶏紙Group Signature锛夊疄鐜癨"\"\"\n    def __init__(self, group_name: str):\n        self.group_name = group_name\n        self.members: List[GroupMember] = []\n        self.group_public_keys: List[rsa.RSAPublicKey] = []\n        # 缇ょ鐞嗗憳瀵嗛挜锛堢敤浜庤拷韪級\n        self.admin_private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        self.admin_public_key = self.admin_private_key.public_key()\n        print(f\"[GroupSig] 缇ょ粍 \'{group_name}\' 鍒涘缓鎴愬姛\")\n    \n    def add_member(self, member_id: str) -> GroupMember:\n        \"\"\"娣诲姞缇ゆ垚鍛樺苟鐢熸垚瀵嗛挜瀵筡"\"\"\n        private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        public_key = private_key.public_key()\n        member = GroupMember(member_id, private_key, public_key)\n        self.members.append(member)\n        self.group_public_keys.append(public_key)\n        print(f\"[GroupSig] 鎴愬憳 \'{member_id}\' 鍔犲叆缇ょ粍\")\n        return member\n    \n    def sign(self, member: GroupMember, message: bytes) -> Tuple[bytes, bytes]:\n        \"\"\"缇ゆ垚鍛樼鍚嶏紝杩斿洖绛惧悕鍜屽姞瀵嗙殑韬唤淇℃伅\"\"\"\n        if member not in self.members:\n            raise ValueError(\"鎴愬憳涓嶅湪缇ょ粍涓璡")\n        # 鐢熸垚甯歌绛惧悕\n        signature = member.private_key.sign(\n            message,\n            padding.PSS(\n                mgf=padding.MGF1(hashes.SHA256()),\n                salt_length=padding.PSS.MAX_LENGTH\n            ),\n            hashes.SHA256()\n        )\n        # 鍔犲瘑绛惧悕鑰呰韩浠絓n        identity_info = json.dumps({\n            \'member_id\': member.member_id,\n            \'timestamp\': str(hash(message))\n        }).encode()\n        encrypted_identity = self.admin_public_key.encrypt(\n            identity_info,\n            padding.OAEP(\n                mgf=padding.MGF1(algorithm=hashes.SHA256()),\n                algorithm=hashes.SHA256(),\n                label=None\n            )\n        )\n        print(f\"[GroupSig] 缇ゆ垚鍛樼敓鎴愬尶鍚嶇鍚峔")\n        return signature, encrypted_identity\n    \n    def verify(self, message: bytes, signature: bytes, encrypted_identity: bytes) -> bool:\n        \"\"\"楠岃瘉缇ょ鍚峔"\"\"\n        for public_key in self.group_public_keys:\n            try:\n                public_key.verify(\n                    signature,\n                    message,\n                    padding.PSS(\n                        mgf=padding.MGF1(hashes.SHA256()),\n                        salt_length=padding.PSS.MAX_LENGTH\n                    ),\n                    hashes.SHA256()\n                )\n                print(f\"[GroupSig] 绛惧悕楠岃瘉鎴愬姛锛堟潵鑷兢缁?\'{self.group_name}\'锛塡")\n                return True\n            except:\n                continue\n        print(f\"[GroupSig] 绛惧悕楠岃瘉澶辫触\")\n        return False\n    \n    def trace(self, encrypted_identity: bytes) -> Optional[str]:\n        \"\"\"绠＄悊鍛樿拷韪鍚嶈€匼"\"\"\n        try:\n            identity_info = self.admin_private_key.decrypt(\n                encrypted_identity,\n                padding.OAEP(\n                    mgf=padding.MGF1(algorithm=hashes.SHA256()),\n                    algorithm=hashes.SHA256(),\n                    label=None\n                )\n            )\n            info = json.loads(identity_info)\n            member_id = info[\'member_id\']\n            print(f\"[GroupSig] 绠＄悊鍛樿拷韪細绛惧悕鑰呮槸 \'{member_id}\'\")\n            return member_id\n        except:\n            print(f\"[GroupSig] 杩借釜澶辫触\")\n            return None\n\n# 娴嬭瘯缇ょ鍚峔ndef demo_group_signature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氱兢绛惧悕锛圙roup Signature锛塡")\n    print(\"=\"*60)\n    group = GroupSignature(\"寮€鍙戝洟闃焅")\n    alice = group.add_member(\"Alice\")\n    bob = group.add_member(\"Bob\")\n    carol = group.add_member(\"Carol\")\n    message = \"椤圭洰杩涘害鎶ュ憡锛歈1瀹屾垚搴?0%\".encode()\n    signature, encrypted_id = group.sign(alice, message)\n    is_valid = group.verify(message, signature, encrypted_id)\n    signer_id = group.trace(encrypted_id)\n    return is_valid and signer_id == \"Alice\"\n\n# 鎵ц娴嬭瘯\ndemo_group_signature()'),(114,16,4,'鐜鍚嶅崗璁疄鐜颁笌娴嬭瘯','1. 瀹炵幇RingSignature绫伙細鍖呭惈瀵嗛挜瀵圭敓鎴愩€佸搱甯屽嚱鏁般€佺鍚嶏紙鐢熸垚绛惧悕骞舵贩鍏ラ殢鏈哄弬鏁版瀯寤虹幆缁撴瀯锛夈€侀獙璇侊紙楠岃瘉绛惧悕鏄惁鏉ヨ嚜鐜唴鎴愬憳锛夋柟娉曘€俓n2. 鐜鍚嶆牳蹇冩祦绋嬶細绛惧悕鑰呴€夋嫨鐜垚鍛樺叕閽ラ泦鍚?鈫?鐢ㄨ嚜韬玈K_i鐢熸垚蟽=RingSign_{SK_i}(m, PK_1,...,PK_n) 鈫?楠岃瘉鑰呯敤RingVerify(蟽, m, PK_1,...,PK_n)楠岃瘉銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_ring_signature锛屾ā鎷熺敓鎴愪笁涓幆鎴愬憳瀵嗛挜銆丅ob浣滀负绛惧悕鑰呯敓鎴愮幆绛惧悕銆侀獙璇佺鍚嶇殑娴佺▼銆俓n棰勬湡杈撳嚭锛氭墦鍗扮幆绛惧悕鐢熸垚銆侀獙璇佹垚鍔熺殑鏃ュ織锛屾彁绀烘棤娉曠‘瀹氬叿浣撶鍚嶈€咃紝鏈€缁堣繑鍥濼rue銆?,'鐜鍚嶇殑鍖垮悕鎬т緷璧栫幆澶у皬锛岀幆鎴愬憳瓒婂鍖垮悕鎬ц秺寮?,'class RingSignature:\n    \"\"\"鐜鍚嶏紙Ring Signature锛夊疄鐜癨"\"\"\n    @staticmethod\n    def generate_key_pair() -> Tuple[rsa.RSAPrivateKey, rsa.RSAPublicKey]:\n        \"\"\"鐢熸垚RSA瀵嗛挜瀵筡"\"\"\n        private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=1024,\n            backend=default_backend()\n        )\n        return private_key, private_key.public_key()\n    \n    @staticmethod\n    def _hash(data: bytes) -> int:\n        \"\"\"SHA256鍝堝笇鍑芥暟锛岃繑鍥炴暣鏁癨"\"\"\n        return int.from_bytes(hashlib.sha256(data).digest(), \'big\')\n    \n    def sign(self, message: bytes, signer_index: int, signer_private_key: rsa.RSAPrivateKey, ring_public_keys: List[rsa.RSAPublicKey]) -> dict:\n        \"\"\"鐢熸垚鐜鍚峔"\"\"\n        n = len(ring_public_keys)\n        # 鐢熸垚娑堟伅绛惧悕\n        signature = signer_private_key.sign(\n            message,\n            padding.PSS(\n                mgf=padding.MGF1(hashes.SHA256()),\n                salt_length=padding.PSS.MAX_LENGTH\n            ),\n            hashes.SHA256()\n        )\n        # 鐢熸垚娣锋穯鍙傛暟\n        random_values = [secrets.token_bytes(32) for _ in range(n)]\n        random_values[signer_index] = signature[:32]\n        # 璁＄畻鐜搱甯屽€糪n        ring_hash = hashlib.sha256()\n        for i, public_key in enumerate(ring_public_keys):\n            pub_bytes = public_key.public_bytes(\n                encoding=serialization.Encoding.PEM,\n                format=serialization.PublicFormat.SubjectPublicKeyInfo\n            )\n            ring_hash.update(pub_bytes)\n            ring_hash.update(random_values[i])\n        # 鏋勯€犵幆绛惧悕鏁版嵁\n        ring_signature = {\n            \'signature\': signature.hex(),\n            \'ring_size\': n,\n            \'ring_value\': ring_hash.hexdigest(),\n            \'random_values\': [rv.hex() for rv in random_values]\n        }\n        print(f\"[RingSig] 鐢熸垚鐜鍚嶏紙鐜ぇ灏? {n}锛塡")\n        return ring_signature\n    \n    def verify(self, message: bytes, ring_signature: dict, ring_public_keys: List[rsa.RSAPublicKey]) -> bool:\n        \"\"\"楠岃瘉鐜鍚峔"\"\"\n        n = len(ring_public_keys)\n        if ring_signature[\'ring_size\'] != n:\n            print(f\"[RingSig] 鐜ぇ灏忎笉鍖归厤\")\n            return False\n        signature = bytes.fromhex(ring_signature[\'signature\'])\n        # 楠岃瘉鏄惁鏈夌幆鎴愬憳鍏挜鑳藉尮閰嶇鍚峔n        for public_key in ring_public_keys:\n            try:\n                public_key.verify(\n                    signature,\n                    message,\n                    padding.PSS(\n                        mgf=padding.MGF1(hashes.SHA256()),\n                        salt_length=padding.PSS.MAX_LENGTH\n                    ),\n                    hashes.SHA256()\n                )\n                print(f\"[RingSig] 鐜鍚嶉獙璇佹垚鍔燂紙鐜腑鏈墈n}涓垚鍛橈級\")\n                print(f\"[RingSig] 鏃犳硶纭畾鍏蜂綋鏄摢涓垚鍛樼鍚嶇殑\")\n                return True\n            except:\n                continue\n        print(f\"[RingSig] 鐜鍚嶉獙璇佸け璐")\n        return False\n\n# 娴嬭瘯鐜鍚峔ndef demo_ring_signature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氱幆绛惧悕锛圧ing Signature锛塡")\n    print(\"=\"*60)\n    ring_sig = RingSignature()\n    # 鐢熸垚鐜垚鍛樺瘑閽n    alice_priv, alice_pub = ring_sig.generate_key_pair()\n    bob_priv, bob_pub = ring_sig.generate_key_pair()\n    carol_priv, carol_pub = ring_sig.generate_key_pair()\n    ring_keys = [alice_pub, bob_pub, carol_pub]\n    # Bob鐢熸垚鐜鍚峔n    message = \"鍐呴儴闂涓炬姤锛氳储鍔℃暟鎹紓甯竆".encode()\n    signature = ring_sig.sign(\n        message=message,\n        signer_index=1,\n        signer_private_key=bob_priv,\n        ring_public_keys=ring_keys\n    )\n    # 楠岃瘉绛惧悕\n    is_valid = ring_sig.verify(message, signature, ring_keys)\n    return is_valid\n\n# 鎵ц娴嬭瘯\ndemo_ring_signature()'),(115,16,5,'鐩茬鍚嶅崗璁疄鐜颁笌娴嬭瘯','1. 瀹炵幇BlindSignature绫伙細鍖呭惈绯荤粺鍒濆鍖栵紙鐢熸垚绛惧悕鑰呭瘑閽ュ锛夈€佺洸鍖栨秷鎭紙鐢ㄦ埛鐢ㄧ洸鍥犲瓙r鐢熸垚m\'=m*r^e mod n锛夈€佺洸绛惧悕锛堢鍚嶈€呯敓鎴愊僜'=(m\')^d mod n锛夈€佸幓鐩诧紙鐢ㄦ埛璁＄畻蟽=蟽\'*r^-1 mod n锛夈€侀獙璇侊紙楠岃瘉m==蟽^e mod n锛夋柟娉曘€俓n2. 鐩茬鍚嶆牳蹇冩暟瀛﹀叕寮忥細RSA鐩茬鍚嶄腑锛岀洸鍖栧洜瀛恟闇€涓庢ā鏁皀浜掕川锛岀‘淇漴鐨勯€嗗厓瀛樺湪銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_blind_signature锛屾ā鎷烝lice鐩插寲鐢靛瓙鐜伴噾銆侀摱琛岀鍚嶃€丄lice鍘荤洸銆佸晢瀹堕獙璇佺殑瀹屾暣娴佺▼銆俓n棰勬湡杈撳嚭锛氭墦鍗扮洸鍖栥€佺洸绛惧悕銆佸幓鐩层€侀獙璇佹垚鍔熺殑鏃ュ織锛屾渶缁堣繑鍥濼rue銆?,'鐩茬鍚嶇殑鏍稿績鏄鍚嶈€呮棤娉曡幏鍙栨秷鎭師鏂囷紝闇€纭繚鐩插洜瀛愮殑闅忔満鎬?,'class BlindSignature:\n    \"\"\"鐩茬鍚嶏紙Blind Signature锛夊疄鐜帮紙RSA鏂规锛塡"\"\"\n    def __init__(self):\n        \"\"\"鍒濆鍖栫鍚嶈€咃紙濡傞摱琛岋級瀵嗛挜瀵筡"\"\"\n        self.private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        self.public_key = self.private_key.public_key()\n        print(\"[BlindSig] 鐩茬鍚嶇郴缁熷垵濮嬪寲\")\n    \n    def blind_message(self, message: bytes) -> Tuple[int, int]:\n        \"\"\"鐩插寲娑堟伅锛岃繑鍥炵洸鍖栨秷鎭拰鐩插寲鍥犲瓙\"\"\"\n        public_numbers = self.public_key.public_numbers()\n        n = public_numbers.n\n        e = public_numbers.e\n        # 娑堟伅鍝堝笇澶勭悊\n        m = int.from_bytes(hashlib.sha256(message).digest(), \'big\') % n\n        # 鐢熸垚鐩插寲鍥犲瓙r锛?<=r<n锛塡n        r = secrets.randbelow(n - 1) + 1\n        # 鐩插寲璁＄畻锛歮\' = m * r^e mod n\n        blinded_message = (m * pow(r, e, n)) % n\n        print(f\"[BlindSig] 娑堟伅宸茬洸鍖朶")\n        return blinded_message, r\n    \n    def blind_sign(self, blinded_message: int) -> int:\n        \"\"\"瀵圭洸鍖栨秷鎭鍚峔"\"\"\n        private_numbers = self.private_key.private_numbers()\n        d = private_numbers.d\n        n = private_numbers.public_numbers.n\n        # 鐩茬鍚嶏細s\' = (m\')^d mod n\n        blind_signature = pow(blinded_message, d, n)\n        print(f\"[BlindSig] 鐢熸垚鐩茬鍚嶏紙绛惧悕鑰呬笉鐭ラ亾娑堟伅鍐呭锛塡")\n        return blind_signature\n    \n    def unblind_signature(self, blind_signature: int, r: int) -> int:\n        \"\"\"鍘荤洸寰楀埌鐪熷疄绛惧悕\"\"\"\n        n = self.public_key.public_numbers().n\n        # 璁＄畻r鐨勯€嗗厓\n        r_inv = pow(r, -1, n)\n        # 鍘荤洸锛歴 = s\' * r^-1 mod n\n        signature = (blind_signature * r_inv) % n\n        print(f\"[BlindSig] 绛惧悕鍘荤洸瀹屾垚\")\n        return signature\n    \n    def verify(self, message: bytes, signature: int) -> bool:\n        \"\"\"楠岃瘉绛惧悕鏈夋晥鎬"\"\"\n        public_numbers = self.public_key.public_numbers()\n        n = public_numbers.n\n        e = public_numbers.e\n        # 娑堟伅鍝堝笇\n        m = int.from_bytes(hashlib.sha256(message).digest(), \'big\') % n\n        # 楠岃瘉锛歮 == s^e mod n\n        m_verify = pow(signature, e, n)\n        is_valid = (m == m_verify)\n        if is_valid:\n            print(f\"[BlindSig] 绛惧悕楠岃瘉鎴愬姛\")\n        else:\n            print(f\"[BlindSig] 绛惧悕楠岃瘉澶辫触\")\n        return is_valid\n\n# 娴嬭瘯鐩茬鍚峔ndef demo_blind_signature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氱洸绛惧悕锛圔lind Signature锛塡")\n    print(\"=\"*60)\n    blind_sig = BlindSignature()\n    # 鍘熷娑堟伅锛堢數瀛愮幇閲戯級\n    message = \"鐢靛瓙鐜伴噾锛氬簭鍒楀彿123456锛岄潰鍊?00鍏僜".encode()\n    # 鐩插寲娑堟伅\n    blinded_msg, blinding_factor = blind_sig.blind_message(message)\n    # 閾惰鐩茬鍚峔n    blinded_signature = blind_sig.blind_sign(blinded_msg)\n    # 鍘荤洸\n    signature = blind_sig.unblind_signature(blinded_signature, blinding_factor)\n    # 楠岃瘉\n    is_valid = blind_sig.verify(message, signature)\n    return is_valid\n\n# 鎵ц娴嬭瘯\ndemo_blind_signature()'),(116,16,6,'澶氶噸绛惧悕鍗忚瀹炵幇涓庢祴璇?,'1. 瀹炵幇MultisignatureWallet绫伙細鍖呭惈鍒濆鍖栵紙璁剧疆闃堝€糾鍜屾€荤鍚嶈€呮暟n锛夈€佹坊鍔犵鍚嶈€咃紙鐢熸垚瀵嗛挜瀵癸級銆佺鍚嶄氦鏄擄紙鏀堕泦杈炬爣鏁伴噺鐨勭鍚嶏級銆侀獙璇佷氦鏄擄紙楠岃瘉绛惧悕鏈夋晥鎬у苟缁熻杈炬爣鏁帮級鏂规硶銆俓n2. 澶氶噸绛惧悕鏍稿績娴佺▼锛歯涓鍚嶈€呭悇鎸丼K_i 鈫?姣忎汉鐢熸垚蟽_i=Sign_{SK_i}(m) 鈫?鍚堝苟涓合僟multi=Combine(蟽_1,...,蟽_n) 鈫?楠岃瘉鑰呯敤鎵€鏈塒K_i楠岃瘉銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_multisignature锛屾ā鎷熷垱寤?-of-3澶氱閽卞寘銆佹坊鍔犱笁浣嶉珮绠°€佸垱寤轰氦鏄撱€丆EO鍜孋FO鑱斿悎绛惧悕銆侀獙璇佷氦鏄擄紝浠ュ強娴嬭瘯鍗曚釜绛惧悕澶辫触鐨勫満鏅€俓n棰勬湡杈撳嚭锛氭墦鍗板绛鹃挶鍖呭垱寤恒€佺鍚嶈€呮坊鍔犮€佺鍚嶅畬鎴愩€侀獙璇佹垚鍔熺殑鏃ュ織锛屽崟涓鍚嶅皾璇曟姏鍑哄紓甯革紝鏈€缁堣繑鍥濼rue銆?,'澶氶噸绛惧悕鐨勯槇鍊艰缃渶鏍规嵁瀹為檯鍦烘櫙鏉冭　瀹夊叏鎬т笌鏄撶敤鎬?,'class MultisignatureWallet:\n    \"\"\"澶氶噸绛惧悕锛圡ultisignature锛夐挶鍖呭疄鐜癨"\"\"\n    def __init__(self, threshold: int, total: int):\n        \"\"\"鍒濆鍖杕-of-n澶氶噸绛惧悕閽卞寘\"\"\"\n        if threshold > total or threshold < 1:\n            raise ValueError(\"鏃犳晥鐨勯槇鍊糪")\n        self.threshold = threshold\n        self.total = total\n        self.signers: List[Tuple[str, rsa.RSAPrivateKey, rsa.RSAPublicKey]] = []\n        print(f\"[MultiSig] 鍒涘缓 {threshold}-of-{total} 澶氶噸绛惧悕閽卞寘\")\n    \n    def add_signer(self, signer_id: str) -> rsa.RSAPrivateKey:\n        \"\"\"娣诲姞绛惧悕鑰匼"\"\"\n        if len(self.signers) >= self.total:\n            raise ValueError(\"绛惧悕鑰呮暟閲忓凡杈句笂闄怽")\n        private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        public_key = private_key.public_key()\n        self.signers.append((signer_id, private_key, public_key))\n        print(f\"[MultiSig] 绛惧悕鑰?\'{signer_id}\' 宸叉坊鍔?({len(self.signers)}/{self.total})\")\n        return private_key\n    \n    def sign_transaction(self, transaction: bytes, signer_indices: List[int]) -> List[bytes]:\n        \"\"\"绛惧悕浜ゆ槗锛岃繑鍥炵鍚嶅垪琛╘"\"\"\n        if len(signer_indices) < self.threshold:\n            raise ValueError(f\"绛惧悕鏁颁笉瓒筹紝闇€瑕佽嚦灏?{self.threshold} 涓鍚峔")\n        signatures = []\n        for idx in signer_indices:\n            if idx >= len(self.signers):\n                raise ValueError(f\"绛惧悕鑰呯储寮?{idx} 鏃犳晥\")\n            signer_id, private_key, _ = self.signers[idx]\n            # 鐢熸垚绛惧悕\n            signature = private_key.sign(\n                transaction,\n                padding.PSS(\n                    mgf=padding.MGF1(hashes.SHA256()),\n                    salt_length=padding.PSS.MAX_LENGTH\n                ),\n                hashes.SHA256()\n            )\n            signatures.append(signature)\n            print(f\"[MultiSig] \'{signer_id}\' 宸茬鍚峔")\n        print(f\"[MultiSig] 浜ゆ槗绛惧悕瀹屾垚 ({len(signatures)}/{self.threshold})\")\n        return signatures\n    \n    def verify_transaction(self, transaction: bytes, signatures: List[bytes], signer_indices: List[int]) -> bool:\n        \"\"\"楠岃瘉澶氶噸绛惧悕浜ゆ槗\"\"\"\n        if len(signatures) < self.threshold:\n            print(f\"[MultiSig] 绛惧悕鏁颁笉瓒砛")\n            return False\n        valid_count = 0\n        for sig, idx in zip(signatures, signer_indices):\n            signer_id, _, public_key = self.signers[idx]\n            try:\n                public_key.verify(\n                    sig,\n                    transaction,\n                    padding.PSS(\n                        mgf=padding.MGF1(hashes.SHA256()),\n                        salt_length=padding.PSS.MAX_LENGTH\n                    ),\n                    hashes.SHA256()\n                )\n                valid_count += 1\n                print(f\"[MultiSig] \'{signer_id}\' 绛惧悕鏈夋晥\")\n            except:\n                print(f\"[MultiSig] \'{signer_id}\' 绛惧悕鏃犳晥\")\n        is_valid = valid_count >= self.threshold\n        if is_valid:\n            print(f\"[MultiSig] 浜ゆ槗楠岃瘉鎴愬姛 ({valid_count}/{self.threshold})\")\n        else:\n            print(f\"[MultiSig] 浜ゆ槗楠岃瘉澶辫触\")\n        return is_valid\n\n# 娴嬭瘯澶氶噸绛惧悕\ndef demo_multisignature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氬閲嶇鍚嶏紙Multisignature锛塡")\n    print(\"=\"*60)\n    # 鍒涘缓2-of-3澶氱閽卞寘\n    wallet = MultisignatureWallet(threshold=2, total=3)\n    # 娣诲姞绛惧悕鑰匼n    wallet.add_signer(\"CEO\")\n    wallet.add_signer(\"CFO\")\n    wallet.add_signer(\"CTO\")\n    # 鍒涘缓浜ゆ槗\n    transaction = \"杞处锛?0 BTC 鍒板湴鍧€ 1A1zP1...\".encode()\n    # CEO鍜孋FO绛惧悕\n    signatures = wallet.sign_transaction(transaction, signer_indices=[0, 1])\n    # 楠岃瘉浜ゆ槗\n    is_valid = wallet.verify_transaction(transaction, signatures, [0, 1])\n    # 娴嬭瘯鍗曚釜绛惧悕澶辫触\n    print(\"\\n[姝ラ6] 灏濊瘯浠呯敤涓€涓鍚嶏紙搴旇澶辫触锛塡")\n    try:\n        single_sig = wallet.sign_transaction(transaction, signer_indices=[0])\n    except ValueError as e:\n        print(f\"[MultiSig] 閿欒锛歿e}\")\n    return is_valid\n\n# 鎵ц娴嬭瘯\ndemo_multisignature()'),(117,16,7,'闂ㄩ檺绛惧悕鍗忚瀹炵幇涓庢祴璇?,'1. 瀹炵幇ThresholdSignature绫伙細鍖呭惈鍒濆鍖栵紙鐢熸垚涓诲瘑閽ュ銆佺敤Shamir绉樺瘑鍏变韩鍒嗗壊绉侀挜锛夈€佸瘑閽ヤ唤棰濆垎鍙戙€佹媺鏍兼湕鏃ユ彃鍊奸噸鏋勭閽ャ€侀棬闄愮鍚嶏紙鑱氬悎閮ㄥ垎绛惧悕锛夈€侀獙璇佹柟娉曘€俓n2. 闂ㄩ檺绛惧悕鏍稿績锛歋hamir绉樺瘑鍏变韩鐢熸垚n涓唤棰濓紝浠绘剰t涓彲閲嶆瀯绉侀挜 鈫?閮ㄥ垎绛惧悕蟽_i=Sign_{sk_i}(m) 鈫?鑱氬悎涓合?Combine(蟽_1,...,蟽_t)銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_threshold_signature锛屾ā鎷熷垱寤?-of-5闂ㄩ檺绛惧悕绯荤粺銆佸垎鍙戝瘑閽ヤ唤棰濄€侀€夋嫨3涓妭鐐圭鍚嶃€侀獙璇佺鍚嶇殑娴佺▼銆俓n棰勬湡杈撳嚭锛氭墦鍗伴棬闄愮郴缁熷垱寤恒€佷唤棰濆垎鍙戙€佺鍚嶇敓鎴愩€侀獙璇佹垚鍔熺殑鏃ュ織锛屾渶缁堣繑鍥濼rue銆?,'闂ㄩ檺绛惧悕鏃犻渶鏆撮湶瀹屾暣绉侀挜锛屽畨鍏ㄦ€ч珮浜庝紶缁熷閲嶇鍚?,'class ThresholdSignature:\n    \"\"\"闂ㄩ檺绛惧悕锛圱hreshold Signature锛夊疄鐜帮紙Shamir+RSA锛塡"\"\"\n    def __init__(self, threshold: int, total: int):\n        \"\"\"鍒濆鍖杢-of-n闂ㄩ檺绛惧悕绯荤粺\"\"\"\n        if threshold > total or threshold < 1:\n            raise ValueError(\"鏃犳晥鐨勯槇鍊糪")\n        self.threshold = threshold\n        self.total = total\n        # 鐢熸垚涓诲瘑閽ュ\n        self.master_private_key = rsa.generate_private_key(\n            public_exponent=65537,\n            key_size=2048,\n            backend=default_backend()\n        )\n        self.master_public_key = self.master_private_key.public_key()\n        # 鑾峰彇绉侀挜d鍊煎拰妯℃暟n\n        private_numbers = self.master_private_key.private_numbers()\n        self.secret = private_numbers.d\n        self.modulus = private_numbers.public_numbers.n\n        # 鍒嗗壊绉樺瘑涓簄涓唤棰漒n        self.shares = self._split_secret(self.secret, threshold, total)\n        print(f\"[ThresholdSig] 鍒涘缓 {threshold}-of-{total} 闂ㄩ檺绛惧悕绯荤粺\")\n    \n    def _split_secret(self, secret: int, threshold: int, total: int) -> List[Tuple[int, int]]:\n        \"\"\"Shamir绉樺瘑鍏变韩鍒嗗壊绉樺瘑\"\"\"\n        # 鐢熸垚t-1娆￠殢鏈哄椤瑰紡锛歠(x) = secret + a1x + a2x虏 + ... + a(t-1)x^(t-1)\n        coefficients = [secret] + [secrets.randbelow(self.modulus) for _ in range(threshold - 1)]\n        shares = []\n        for i in range(1, total + 1):\n            # 璁＄畻f(i) mod modulus\n            y = sum(coef * pow(i, idx, self.modulus) for idx, coef in enumerate(coefficients)) % self.modulus\n            shares.append((i, y))\n        return shares\n    \n    def get_share(self, participant_index: int) -> Tuple[int, int]:\n        \"\"\"鑾峰彇鍙備笌鑰呯殑瀵嗛挜浠介\"\"\"\n        if participant_index >= len(self.shares):\n            raise ValueError(\"鍙備笌鑰呯储寮曟棤鏁圽")\n        share = self.shares[participant_index]\n        print(f\"[ThresholdSig] 鍙備笌鑰?{participant_index + 1} 鑾峰緱瀵嗛挜浠介\")\n        return share\n    \n    def _lagrange_interpolation(self, shares: List[Tuple[int, int]]) -> int:\n        \"\"\"鎷夋牸鏈楁棩鎻掑€奸噸鏋勭瀵哱"\"\"\n        if len(shares) < self.threshold:\n            raise ValueError(\"浠介鏁伴噺涓嶈冻\")\n        secret = 0\n        for i, (xi, yi) in enumerate(shares):\n            numerator = 1\n            denominator = 1\n            for j, (xj, _) in enumerate(shares):\n                if i != j:\n                    numerator = (numerator * (-xj)) % self.modulus\n                    denominator = (denominator * (xi - xj)) % self.modulus\n            # 璁＄畻鎷夋牸鏈楁棩鍩篭n            denominator_inv = pow(denominator, -1, self.modulus)\n            lagrange_basis = (numerator * denominator_inv) % self.modulus\n            secret = (secret + yi * lagrange_basis) % self.modulus\n        return secret\n    \n    def threshold_sign(self, message: bytes, participant_indices: List[int]) -> bytes:\n        \"\"\"鐢熸垚闂ㄩ檺绛惧悕\"\"\"\n        if len(participant_indices) < self.threshold:\n            raise ValueError(f\"鍙備笌鑰呮暟閲忎笉瓒筹紝闇€瑕佽嚦灏?{self.threshold} 涓猏")\n        # 鏀堕泦閫変腑鐨勪唤棰漒n        selected_shares = [self.shares[i] for i in participant_indices]\n        print(f\"[ThresholdSig] 鏀堕泦 {len(selected_shares)} 涓瘑閽ヤ唤棰漒")\n        # 閲嶆瀯绉侀挜\n        reconstructed_secret = self._lagrange_interpolation(selected_shares)\n        print(f\"[ThresholdSig] 绉侀挜閲嶆瀯鎴愬姛\")\n        # 楠岃瘉閲嶆瀯缁撴灉\n        if reconstructed_secret != self.secret:\n            print(f\"[ThresholdSig] 璀﹀憡锛氶噸鏋勭殑绉侀挜鍙兘涓嶆纭甛")\n        # 鐢熸垚绛惧悕\n        signature = self.master_private_key.sign(\n            message,\n            padding.PSS(\n                mgf=padding.MGF1(hashes.SHA256()),\n                salt_length=padding.PSS.MAX_LENGTH\n            ),\n            hashes.SHA256()\n        )\n        print(f\"[ThresholdSig] 闂ㄩ檺绛惧悕鐢熸垚瀹屾垚\")\n        return signature\n    \n    def verify(self, message: bytes, signature: bytes) -> bool:\n        \"\"\"楠岃瘉闂ㄩ檺绛惧悕\"\"\"\n        try:\n            self.master_public_key.verify(\n                signature,\n                message,\n                padding.PSS(\n                    mgf=padding.MGF1(hashes.SHA256()),\n                    salt_length=padding.PSS.MAX_LENGTH\n                ),\n                hashes.SHA256()\n            )\n            print(f\"[ThresholdSig] 绛惧悕楠岃瘉鎴愬姛\")\n            return True\n        except:\n            print(f\"[ThresholdSig] 绛惧悕楠岃瘉澶辫触\")\n            return False\n\n# 娴嬭瘯闂ㄩ檺绛惧悕\ndef demo_threshold_signature():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氶棬闄愮鍚嶏紙Threshold Signature锛塡")\n    print(\"=\"*60)\n    # 鍒涘缓3-of-5闂ㄩ檺绛惧悕绯荤粺\n    threshold_sig = ThresholdSignature(threshold=3, total=5)\n    # 鍒嗗彂瀵嗛挜浠介\n    print(\"\\n[姝ラ2] 鍚?涓獙璇佽妭鐐瑰垎鍙戝瘑閽ヤ唤棰漒")\n    for i in range(5):\n        threshold_sig.get_share(i)\n    # 閫夋嫨鑺傜偣1銆?銆?鍙備笌绛惧悕锛堢储寮?銆?銆?锛塡n    message = \"鍖哄潡閾句氦鏄擄細鍖哄潡楂樺害 #100000\".encode()\n    participants = [0, 2, 3]\n    signature = threshold_sig.threshold_sign(message, participants)\n    # 楠岃瘉绛惧悕\n    is_valid = threshold_sig.verify(message, signature)\n    return is_valid\n\n# 鎵ц娴嬭瘯\ndemo_threshold_signature()'),(118,16,8,'鍗忚鐗规€у姣斾笌鍦烘櫙閫傞厤','1. 鏁寸悊浜旂绛惧悕鍗忚鐨勬牳蹇冪壒鎬э細缇ょ鍚嶏紙鏈変腑蹇冦€佸彲杩借釜銆佺兢鍐呭尶鍚嶏級銆佺幆绛惧悕锛堟棤涓績銆佸畬鍏ㄥ尶鍚嶃€佽嚜鍙戠粍缃戯級銆佺洸绛惧悕锛堝唴瀹圭洸鎬с€佷笉鍙拷韪級銆佸閲嶇鍚嶏紙澶氱鑱氬悎銆侀槇鍊兼帶鍒讹級銆侀棬闄愮鍚嶏紙鍗曚竴绛惧悕銆佸垎甯冨紡瀵嗛挜锛夈€俓n2. 鍒嗘瀽閫傜敤鍦烘櫙锛氱兢绛惧悕閫傜敤浜庡尶鍚嶆姇绁ㄣ€佺幆绛惧悕閫傜敤浜庨殣绉佸竵銆佺洸绛惧悕閫傜敤浜庣數瀛愮幇閲戙€佸閲嶇鍚嶉€傜敤浜庝紒涓氳祫閲戠鐞嗐€侀棬闄愮鍚嶉€傜敤浜庡尯鍧楅摼鍏辫瘑銆俓n3. 鎬荤粨鍏抽敭宸紓锛氫腑蹇冭妭鐐逛緷璧栥€佸尶鍚嶆€х▼搴︺€佺鍚嶅舰寮忋€佸閿欒兘鍔涖€俓n棰勬湡杈撳嚭锛氬舰鎴愭竻鏅扮殑鍗忚瀵规瘮璁ょ煡锛岃兘鏍规嵁瀹為檯闇€姹傞€夋嫨鍚堥€傜殑绛惧悕鍗忚銆?,'瀹為檯搴旂敤涓渶缁撳悎瀹夊叏鎬с€佹晥鐜囥€佹槗鐢ㄦ€х患鍚堥€夊瀷',NULL),(119,17,1,'鐜鍑嗗涓庝緷璧栫‘璁?,'棣栧厛纭繚Python鐜宸叉惌寤猴紙寤鸿Python 3.7+锛夛紝鏈疄鐜颁緷璧朠ython鏍囧噯搴擄紙hashlib銆乻ecrets銆乭mac銆乨ataclasses绛夛級锛屾棤闇€棰濆瀹夎绗笁鏂逛緷璧栥€傞渶纭绯荤粺鏀寔闅忔満鏁扮敓鎴愩€佸搱甯岃绠楃瓑鍩虹鍔熻兘锛岀‘淇濅唬鐮佸彲姝ｅ父杩愯銆俓n棰勬湡杈撳嚭锛氭棤鎶ラ敊淇℃伅锛孭ython鐜鍙甯歌皟鐢ㄦ墍闇€鏍囧噯搴撱€?,'鑻ヤ娇鐢ㄨ緝浣嶱ython鐗堟湰锛岄渶纭繚dataclasses妯″潡鍙敤锛圥ython 3.7+鑷甫锛?.6鍙婁互涓嬮渶鎵嬪姩瀹夎锛?,NULL),(120,17,2,'姣旂壒鎵胯鍗忚瀹炵幇涓庢祴璇?,'1. 瀹炵幇BitCommitment绫伙細鍖呭惈commit锛堟壙璇洪樁娈碉級鍜宺eveal锛堟彮绀洪獙璇侀樁娈碉級涓や釜鏍稿績闈欐€佹柟娉曘€傛壙璇洪樁娈甸噰鐢ㄥ搱甯屾柟妗?$c=H(value||r)$锛屽叾涓璿alue涓?/1姣旂壒锛宺涓洪殢鏈烘暟锛涙彮绀洪樁娈甸€氳繃閲嶆柊璁＄畻鍝堝笇鍊奸獙璇佹壙璇烘湁鏁堟€с€俓n2. 姣旂壒鎵胯鏍稿績鐗规€э細闅愯棌鎬э紙鎵胯闃舵鏃犳硶鑾峰彇姣旂壒鍊硷級銆佺粦瀹氭€э紙鎵胯鍚庢棤娉曠鏀规瘮鐗瑰€硷級銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_bit_commitment锛屾ā鎷烝lice鎵胯姣旂壒銆丅ob鎺ユ敹鎵胯銆丄lice鎻ず姣旂壒銆侀獙璇佹湁鏁堟€э紝浠ュ強灏濊瘯绡℃敼姣旂壒鐨勫け璐ュ満鏅€俓n棰勬湡杈撳嚭锛氭墦鍗版壙璇哄垱寤恒€侀獙璇佹垚鍔熴€佺鏀瑰け璐ョ殑鏃ュ織淇℃伅锛屾渶缁堣繑鍥濼rue銆?,NULL,'import hashlib\nimport secrets\nimport hmac\nfrom typing import List, Set, Tuple, Optional, Dict\nfrom dataclasses import dataclass\n\nclass BitCommitment:\n    \"\"\"姣旂壒鎵胯鍗忚锛圔it Commitment锛夊疄鐜癨"\"\"\n    \n    @staticmethod\n    def commit(value: int, randomness: Optional[bytes] = None) -> Tuple[bytes, bytes]:\n        \"\"\"鎵胯涓€涓瘮鐗瑰€硷紝杩斿洖锛堟壙璇哄€硷紝闅忔満鏁帮級\"\"\"\n        if value not in [0, 1]:\n            raise ValueError(\"鍊煎繀椤绘槸0鎴?\")\n        \n        if randomness is None:\n            randomness = secrets.token_bytes(32)\n        \n        # 璁＄畻鎵胯: C = H(value || randomness)\n        commitment = hashlib.sha256(\n            str(value).encode() + randomness\n        ).digest()\n        \n        print(f\"[Commitment] 鎵胯宸插垱寤猴紙鍊煎凡闅愯棌锛塡")\n        return commitment, randomness\n    \n    @staticmethod\n    def reveal(commitment: bytes, value: int, randomness: bytes) -> bool:\n        \"\"\"鎻ず骞堕獙璇佹壙璇烘湁鏁堟€"\"\"\n        # 閲嶆柊璁＄畻鎵胯\n        expected_commitment = hashlib.sha256(\n            str(value).encode() + randomness\n        ).digest()\n        \n        is_valid = hmac.compare_digest(commitment, expected_commitment)\n        \n        if is_valid:\n            print(f\"[Commitment] 鎵胯楠岃瘉鎴愬姛锛屾彮绀哄€? {value}\")\n        else:\n            print(f\"[Commitment] 鎵胯楠岃瘉澶辫触锛乗")\n        \n        return is_valid\n\n# 娴嬭瘯姣旂壒鎵胯\ndef demo_bit_commitment():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氭瘮鐗规壙璇哄崗璁甛")\n    print(\"=\"*60)\n    \n    # Alice鎵胯涓€涓瘮鐗筡n    print(\"\\n[姝ラ1] Alice閫夋嫨涓€涓瘮鐗瑰苟鎵胯\")\n    alice_bit = 1\n    commitment, randomness = BitCommitment.commit(alice_bit)\n    print(f\"鎵胯鍊硷紙鍝堝笇锛? {commitment.hex()[:32]}...\")\n    \n    # Bob鏃犳硶浠庢壙璇轰腑寰楃煡姣旂壒鍊糪n    print(\"\\n[姝ラ2] Bob鐪嬪埌鎵胯锛屼絾鏃犳硶鐭ラ亾Alice鐨勯€夋嫨\")\n    \n    # Alice鎻ず\n    print(\"\\n[姝ラ3] Alice鎻ず濂圭殑姣旂壒\")\n    is_valid = BitCommitment.reveal(commitment, alice_bit, randomness)\n    \n    # 灏濊瘯浣滃紛\n    print(\"\\n[姝ラ4] 濡傛灉Alice璇曞浘鏀瑰彉濂圭殑閫夋嫨...\")\n    fake_bit = 0\n    is_valid_fake = BitCommitment.reveal(commitment, fake_bit, randomness)\n    \n    print(\"\\n[璇存槑] 姣旂壒鎵胯鐨勭壒鎬э細\")\n    print(\"  1. 闅愯棌鎬э細鎵胯闃舵Bob涓嶇煡閬撴瘮鐗瑰€糪")\n    print(\"  2. 缁戝畾鎬э細Alice鏃犳硶鏀瑰彉鎵胯鐨勫€糪")\n    \n    return is_valid and not is_valid_fake\n\n# 鎵ц娴嬭瘯\ndemo_bit_commitment()'),(121,17,3,'杩滅▼鎶涚‖甯佸崗璁疄鐜颁笌娴嬭瘯','1. 瀹炵幇CoinFlipping绫伙細鍩轰簬姣旂壒鎵胯鍗忚锛屽寘鍚玜lice_commit锛圓lice鎵胯姣旂壒锛夈€乥ob_choose锛圔ob閫夋嫨姣旂壒锛夈€乤lice_reveal锛圓lice鎻ず姣旂壒锛夈€乧ompute_result锛堣绠楀苟楠岃瘉缁撴灉锛夋柟娉曘€俓n2. 杩滅▼鎶涚‖甯佹牳蹇冩祦绋嬶細Alice鎵胯姣旂壒b_A 鈫?Bob閫夋嫨姣旂壒b_B 鈫?Alice鎻ずb_A 鈫?缁撴灉= b_A鈯昩_B銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_coin_flipping锛屾ā鎷熷弻鏂硅繙绋嬫姏纭竵鐨勫畬鏁存祦绋嬶紝楠岃瘉鍏钩鎬с€俓n棰勬湡杈撳嚭锛氭墦鍗版壙璇恒€侀€夋嫨銆佹彮绀恒€佺粨鏋滆绠楃殑鏃ュ織锛屾渶缁堣繑鍥炵粨鏋滐紙0鎴?锛夛紝纭鏃犱綔寮婅涓恒€?,'璇ュ崗璁殑鍏钩鎬у畬鍏ㄤ緷璧栨瘮鐗规壙璇虹殑闅愯棌鎬у拰缁戝畾鎬э紝浠讳綍涓€鏂逛綔寮婇兘浼氳楠岃瘉鍙戠幇','class CoinFlipping:\n    \"\"\"杩滅▼鎶涚‖甯佸崗璁疄鐜癨"\"\"\n    \n    def __init__(self):\n        \"\"\"鍒濆鍖栨姏纭竵鍗忚\"\"\"\n        self.alice_bit = None\n        self.alice_randomness = None\n        self.alice_commitment = None\n        self.bob_bit = None\n        \n    def alice_commit(self) -> bytes:\n        \"\"\"Alice鎵胯濂圭殑姣旂壒\"\"\"\n        self.alice_bit = secrets.randbelow(2)\n        self.alice_commitment, self.alice_randomness = \\\n            BitCommitment.commit(self.alice_bit)\n        \n        print(f\"[Alice] 閫夋嫨浜嗘瘮鐗癸紙淇濆瘑锛夊苟鍙戦€佹壙璇篭")\n        return self.alice_commitment\n    \n    def bob_choose(self) -> int:\n        \"\"\"Bob閫夋嫨浠栫殑姣旂壒\"\"\"\n        self.bob_bit = secrets.randbelow(2)\n        print(f\"[Bob] 閫夋嫨姣旂壒: {self.bob_bit}\")\n        return self.bob_bit\n    \n    def alice_reveal(self) -> Tuple[int, bytes]:\n        \"\"\"Alice鎻ず濂圭殑姣旂壒\"\"\"\n        print(f\"[Alice] 鎻ず姣旂壒: {self.alice_bit}\")\n        return self.alice_bit, self.alice_randomness\n    \n    def compute_result(self, alice_bit: int, alice_randomness: bytes) -> Optional[int]:\n        \"\"\"璁＄畻骞堕獙璇佺粨鏋淺"\"\"\n        # 楠岃瘉Alice鐨勬壙璇篭n        if not BitCommitment.reveal(\n            self.alice_commitment, \n            alice_bit, \n            alice_randomness\n        ):\n            print(f\"[Result] Alice浣滃紛锛佹壙璇洪獙璇佸け璐")\n            return None\n        \n        # 璁＄畻缁撴灉\n        result = alice_bit ^ self.bob_bit\n        print(f\"[Result] 鎶涚‖甯佺粨鏋? {result} ({\'姝ｉ潰\' if result == 0 else \'鍙嶉潰\'})\")\n        print(f\"[Result] Alice: {alice_bit}, Bob: {self.bob_bit}, XOR: {result}\")\n        \n        return result\n\n# 娴嬭瘯杩滅▼鎶涚‖甯乗ndef demo_coin_flipping():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氳繙绋嬫姏纭竵鍗忚\")\n    print(\"=\"*60)\n    \n    coin = CoinFlipping()\n    \n    print(\"\\n[姝ラ1] Alice鎵胯濂圭殑姣旂壒\")\n    commitment = coin.alice_commit()\n    \n    print(\"\\n[姝ラ2] Bob鏀跺埌鎵胯鍚庯紝閫夋嫨浠栫殑姣旂壒\")\n    bob_bit = coin.bob_choose()\n    \n    print(\"\\n[姝ラ3] Alice鎻ず濂圭殑姣旂壒\")\n    alice_bit, randomness = coin.alice_reveal()\n    \n    print(\"\\n[姝ラ4] 璁＄畻鏈€缁堢粨鏋淺")\n    result = coin.compute_result(alice_bit, randomness)\n    \n    print(\"\\n[璇存槑] 杩滅▼鎶涚‖甯佺殑鍏钩鎬э細\")\n    print(\"  1. Alice涓嶈兘鏀瑰彉濂圭殑閫夋嫨锛堝凡鎵胯锛塡")\n    print(\"  2. Bob鍦ˋlice鎵胯鍚庨€夋嫨锛堟棤娉曢鐭ョ粨鏋滐級\")\n    print(\"  3. 缁撴灉鐢卞弻鏂瑰叡鍚屽喅瀹氾紙XOR锛塡")\n    print(\"  4. 鍙屾柟閮芥棤娉曟帶鍒剁粨鏋淺")\n    \n    return result is not None\n\n# 鎵ц娴嬭瘯\ndemo_coin_flipping()'),(122,17,4,'Pedersen鎵胯鍗忚瀹炵幇涓庢祴璇?,'1. 瀹炵幇PedersenCommitment绫伙細鍩轰簬绂绘暎瀵规暟闂锛屽寘鍚垵濮嬪寲锛堣缃ぇ绱犳暟p鍜岀敓鎴愬厓g銆乭锛夈€乧ommit锛堢敓鎴愭壙璇?$c=g^m h^r mod p$锛夈€乿erify锛堥獙璇佹壙璇猴級銆乤dd_commitments锛堟紨绀哄姞娉曞悓鎬佹€э級鏂规硶銆俓n2. Pedersen鎵胯鏍稿績鐗规€э細瀹岀編闅愯棌鎬э紙璁＄畻鑳藉姏鏃犻檺涔熸棤娉曠牬瑙ｏ級銆佸姞娉曞悓鎬佹€э紙$C(m1)*C(m2)=C(m1+m2)$锛夈€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_pedersen_commitment锛屾ā鎷熸壙璇烘秷鎭€侀獙璇佹壙璇恒€佹紨绀哄姞娉曞悓鎬佹€х殑娴佺▼銆俓n棰勬湡杈撳嚭锛氭墦鍗版壙璇哄垱寤恒€侀獙璇佹垚鍔熴€佸悓鎬佽繍绠楁紨绀虹殑鏃ュ織锛屾渶缁堣繑鍥濼rue銆?,'瀹為檯搴旂敤涓渶浣跨敤鏇村ぇ鐨勭礌鏁扮‘淇濆畨鍏ㄦ€э紝绠€鍖栫増涓烘紨绀哄師鐞嗕娇鐢ㄥ浐瀹氬ぇ绱犳暟','class PedersenCommitment:\n    \"\"\"Pedersen鎵胯鏂规瀹炵幇\"\"\"\n    \n    def __init__(self, p: Optional[int] = None):\n        \"\"\"鍒濆鍖朠edersen鎵胯锛岄粯璁や娇鐢ㄥ浐瀹氬ぇ绱犳暟\"\"\"\n        # 绠€鍖栫増锛氫娇鐢ㄤ竴涓爣鍑嗗ぇ绱犳暟锛?56浣嶏級\n        if p is None:\n            self.p = \n        else:\n            self.p = p\n        \n        # 鐢熸垚鍏僜n        self.g = 2\n        self.h = 3\n        \n        print(f\"[Pedersen] 鎵胯鏂规鍒濆鍖朶")\n    \n    def commit(self, message: int) -> Tuple[int, int]:\n        \"\"\"鍒涘缓Pedersen鎵胯锛岃繑鍥烇紙鎵胯鍊硷紝闅忔満鏁帮級\"\"\"\n        # 鐢熸垚闅忔満鏁皉锛?<=r<p-1锛塡n        r = secrets.randbelow(self.p - 1)\n        \n        # 璁＄畻鎵胯锛欳 = g^m * h^r mod p\n        commitment = (pow(self.g, message, self.p) * pow(self.h, r, self.p)) % self.p\n        \n        print(f\"[Pedersen] 鎵胯宸插垱寤篭")\n        return commitment, r\n    \n    def verify(self, commitment: int, message: int, randomness: int) -> bool:\n        \"\"\"楠岃瘉Pedersen鎵胯鏈夋晥鎬"\"\"\n        expected = (pow(self.g, message, self.p) * pow(self.h, randomness, self.p)) % self.p\n        \n        is_valid = (commitment == expected)\n        \n        if is_valid:\n            print(f\"[Pedersen] 鎵胯楠岃瘉鎴愬姛锛屾秷鎭? {message}\")\n        else:\n            print(f\"[Pedersen] 鎵胯楠岃瘉澶辫触\")\n        \n        return is_valid\n    \n    def add_commitments(self, c1: int, c2: int) -> int:\n        \"\"\"鍔犳硶鍚屾€侊細C(m1 + m2) = C(m1) * C(m2) mod p\"\"\"\n        return (c1 * c2) % self.p\n\n# 娴嬭瘯Pedersen鎵胯\ndef demo_pedersen_commitment():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛歅edersen鎵胯鏂规\")\n    print(\"=\"*60)\n    \n    pedersen = PedersenCommitment()\n    \n    print(\"\\n[姝ラ1] Alice鎵胯娑堟伅鍊?2\")\n    message = 42\n    commitment, randomness = pedersen.commit(message)\n    print(f\"鎵胯鍊? {commitment}\")\n    \n    print(\"\\n[姝ラ2] 绋嶅悗Alice鎻ず娑堟伅\")\n    is_valid = pedersen.verify(commitment, message, randomness)\n    \n    print(\"\\n[姝ラ3] 婕旂ず鍔犳硶鍚屾€佹€")\n    m1, m2 = 10, 20\n    c1, r1 = pedersen.commit(m1)\n    c2, r2 = pedersen.commit(m2)\n    c_sum = pedersen.add_commitments(c1, c2)\n    print(f\"C(10) * C(20) = C(30)\")\n    print(f\"鍔犳硶鍚屾€侊細鍙互鍦ㄤ笉鐭ラ亾娑堟伅鐨勬儏鍐典笅璁＄畻鎵胯鐨勫拰\")\n    \n    print(\"\\n[璇存槑] Pedersen鎵胯鐨勪紭鍔匡細\")\n    print(\"  1. 瀹岀編闅愯棌锛氳绠楄兘鍔涙棤闄愪篃鏃犳硶鐮磋В\")\n    print(\"  2. 鍔犳硶鍚屾€侊細鏀寔鎵胯杩愮畻\")\n    print(\"  3. 搴旂敤锛氶浂鐭ヨ瘑璇佹槑銆侀殣绉佸竵\")\n    \n    return is_valid\n\n# 鎵ц娴嬭瘯\ndemo_pedersen_commitment()'),(123,17,5,'闅愮闆嗗悎姹備氦锛圥SI锛夊崗璁疄鐜颁笌娴嬭瘯','1. 瀹炵幇PrivateSetIntersection绫伙細鍖呭惈hash_set锛堝闆嗗悎鍏冪礌鍔犵洂鍝堝笇锛夈€乧ompute_intersection_size锛堣绠椾氦闆嗗ぇ灏忥級銆乧ompute_intersection锛堣绠楀疄闄呬氦闆嗭級鏂规硶銆傜畝鍖栫増鍩轰簬鍝堝笇鏂规锛屽疄闄呭簲鐢ㄩ渶缁撳悎OT鎴栧悓鎬佸姞瀵嗐€俓n2. PSI鏍稿績娴佺▼锛氬弻鏂瑰闆嗗悎鍏冪礌鍔犵洂鍝堝笇 鈫?璁＄畻鍝堝笇闆嗗悎浜ら泦 鈫?浠呮硠闇蹭氦闆嗕俊鎭紝闈炰氦闆嗗厓绱犱繚瀵嗐€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_psi锛屾ā鎷熶袱瀹跺叕鍙歌绠楀叡鍚屽鎴锋暟鐨勫満鏅紝楠岃瘉PSI鍗忚鐨勯殣绉佷繚鎶ょ壒鎬с€俓n棰勬湡杈撳嚭锛氭墦鍗板弻鏂归泦鍚堝ぇ灏忋€佷氦闆嗗ぇ灏忕殑鏃ュ織锛岀‘璁ら潪浜ら泦鍏冪礌鏈硠闇诧紝鏈€缁堣繑鍥濼rue銆?,'绠€鍖栫増浠呯敤浜庢紨绀哄師鐞嗭紝瀹為檯搴旂敤闇€浣跨敤鏇村畨鍏ㄧ殑PSI鍗忚锛堝鍩轰簬OT鐨凱SI锛?,'class PrivateSetIntersection:\n    \"\"\"闅愮闆嗗悎姹備氦锛圥SI锛夊崗璁疄鐜帮紙绠€鍖栫増锛塡"\"\"\n    \n    @staticmethod\n    def hash_set(items: Set[str], salt: bytes) -> Set[bytes]:\n        \"\"\"瀵归泦鍚堝厓绱犲姞鐩愬搱甯岋紝纭繚瀹夊叏鎬"\"\"\n        hashed = set()\n        for item in items:\n            h = hashlib.sha256(item.encode() + salt).digest()\n            hashed.add(h)\n        return hashed\n    \n    @classmethod\n    def compute_intersection_size(cls, alice_set: Set[str], \n                                  bob_set: Set[str]) -> int:\n        \"\"\"璁＄畻浜ら泦澶у皬锛屼笉娉勯湶闈炰氦闆嗗厓绱燶"\"\"\n        # 鐢熸垚鍏卞悓鐩愬€硷紙瀹為檯搴旂敤涓渶瀹夊叏鍗忓晢锛塡n        salt = secrets.token_bytes(16)\n        \n        # 鍙屾柟鍚勮嚜鍝堝笇鑷繁鐨勯泦鍚圽n        alice_hashed = cls.hash_set(alice_set, salt)\n        bob_hashed = cls.hash_set(bob_set, salt)\n        \n        print(f\"[PSI] Alice闆嗗悎澶у皬: {len(alice_set)}\")\n        print(f\"[PSI] Bob闆嗗悎澶у皬: {len(bob_set)}\")\n        \n        # 璁＄畻鍝堝笇闆嗗悎浜ら泦澶у皬\n        intersection_size = len(alice_hashed & bob_hashed)\n        \n        print(f\"[PSI] 浜ら泦澶у皬: {intersection_size}\")\n        print(f\"[PSI] 鍙屾柟閮戒笉鐭ラ亾瀵规柟闆嗗悎涓殑闈炰氦闆嗗厓绱燶")\n        \n        return intersection_size\n    \n    @classmethod\n    def compute_intersection(cls, alice_set: Set[str], \n                            bob_set: Set[str]) -> Set[str]:\n        \"\"\"璁＄畻瀹為檯浜ら泦锛堟紨绀虹敤锛塡"\"\"\n        intersection = alice_set & bob_set\n        print(f\"[PSI] 璁＄畻鍑轰氦闆? {intersection}\")\n        return intersection\n\n# 娴嬭瘯PSI鍗忚\ndef demo_psi():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氶殣绉侀泦鍚堟眰浜わ紙PSI锛塡")\n    print(\"=\"*60)\n    \n    print(\"\\n鍦烘櫙锛氫袱瀹跺叕鍙告兂鐭ラ亾鏈夊灏戝叡鍚屽鎴凤紝浣嗕笉鎯虫硠闇茶嚜宸辩殑瀹㈡埛鍚嶅崟\")\n    \n    # 鍏徃A鐨勫鎴穃n    company_a_customers = {\n        \"alice@example.com\",\n        \"bob@example.com\",\n        \"carol@example.com\",\n        \"dave@example.com\"\n    }\n    \n    # 鍏徃B鐨勫鎴穃n    company_b_customers = {\n        \"bob@example.com\",\n        \"carol@example.com\",\n        \"eve@example.com\",\n        \"frank@example.com\"\n    }\n    \n    print(f\"\\n[鍏徃A] 鏈墈len(company_a_customers)}涓鎴凤紙淇濆瘑锛塡")\n    print(f\"[鍏徃B] 鏈墈len(company_b_customers)}涓鎴凤紙淇濆瘑锛塡")\n    \n    print(\"\\n[姝ラ1] 杩愯PSI鍗忚\")\n    intersection_size = PrivateSetIntersection.compute_intersection_size(\n        company_a_customers,\n        company_b_customers\n    )\n    \n    print(f\"\\n[缁撴灉] 鍏卞悓瀹㈡埛鏁帮細{intersection_size}\")\n    print(\"\\n[璇存槑] PSI鐨勪紭鍔匡細\")\n    print(\"  1. 鍙屾柟鍙煡閬撲氦闆嗗ぇ灏忔垨浜ら泦\")\n    print(\"  2. 涓嶆硠闇查潪浜ら泦鍏冪礌\")\n    print(\"  3. 搴旂敤锛氬箍鍛婅浆鍖栥€佽仈绯讳汉鍙戠幇銆佹伓鎰忚蒋浠舵娴媆")\n    \n    # 楠岃瘉缁撴灉姝ｇ‘鎬n    actual_intersection = company_a_customers & company_b_customers\n    return len(actual_intersection) == intersection_size\n\n# 鎵ц娴嬭瘯\ndemo_psi()'),(124,17,6,'闅愮淇℃伅妫€绱紙PIR锛夊崗璁疄鐜颁笌娴嬭瘯','1. 瀹炵幇PrivateInformationRetrieval绫伙細鍖呭惈鍒濆鍖栵紙鍔犺浇鏁版嵁搴擄級銆乼rivial_pir锛堝钩鍑IR锛屼笅杞芥暣涓暟鎹簱锛夈€乹uery_with_noise锛堝甫鍣０鐨勬煡璇級鏂规硶銆傜畝鍖栫増婕旂ずPIR鏍稿績鎬濇兂锛屽疄闄呭簲鐢ㄩ渶鍩轰簬鍚屾€佸姞瀵嗘垨澶氭湇鍔″櫒鏋舵瀯銆俓n2. PIR鏍稿績鐩爣锛氱敤鎴锋绱㈡暟鎹簱璁板綍鏃讹紝鏈嶅姟鍣ㄦ棤娉曞緱鐭ユ煡璇㈢储寮曘€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_pir锛屾ā鎷熶笓鍒╂暟鎹簱鏌ヨ鍦烘櫙锛屽垎鍒紨绀哄钩鍑IR鍜屽甫鍣０鏌ヨ涓ょ鏂瑰紡銆俓n棰勬湡杈撳嚭锛氭墦鍗版暟鎹簱鍒濆鍖栥€佷袱绉嶆煡璇㈡柟寮忕殑鏃ュ織锛岀‘璁ゆ湇鍔″櫒鏃犳硶鑾峰彇鏌ヨ鍐呭锛屾渶缁堣繑鍥濼rue銆?,'骞冲嚒PIR闅愮鎬ф渶寮轰絾閫氫俊鎴愭湰楂橈紝甯﹀櫔澹版煡璇㈠钩琛￠殣绉佹€у拰閫氫俊鎴愭湰','class PrivateInformationRetrieval:\n    \"\"\"闅愮淇℃伅妫€绱紙PIR锛夊崗璁疄鐜帮紙绠€鍖栫増锛塡"\"\"\n    \n    def __init__(self, database: List[str]):\n        \"\"\"鍒濆鍖朠IR绯荤粺锛屽姞杞芥暟鎹簱\"\"\"\n        self.database = database\n        self.n = len(database)\n        print(f\"[PIR] 鏁版嵁搴撳垵濮嬪寲锛屽寘鍚?{self.n} 鏉¤褰昞")\n    \n    def trivial_pir(self, index: int) -> str:\n        \"\"\"骞冲嚒PIR锛氫笅杞芥暣涓暟鎹簱锛屽畬缇庨殣绉乗"\"\"\n        print(f\"[PIR-Trivial] 瀹㈡埛绔笅杞芥暣涓暟鎹簱\")\n        print(f\"[PIR-Trivial] 閫氫俊閲? {self.n} 鏉¤褰昞")\n        print(f\"[PIR-Trivial] 鏈嶅姟鍣ㄤ笉鐭ラ亾鏌ヨ鐨勬槸绗?{index} 鏉")\n        \n        # 瀹㈡埛绔湰鍦版彁鍙栫洰鏍囪褰昞n        return self.database[index]\n    \n    def query_with_noise(self, real_index: int, \n                        noise_indices: Optional[List[int]] = None) -> str:\n        \"\"\"甯﹀櫔澹扮殑鏌ヨ锛氶€氳繃娣锋穯鏌ヨ闅愯棌鐪熷疄鎰忓浘\"\"\"\n        if noise_indices is None:\n            # 闅忔満鐢熸垚鍣０鏌ヨ锛堟渶澶?涓紝閬垮厤瓒呭嚭鏁版嵁搴撹寖鍥达級\n            noise_count = min(5, self.n - 1)\n            noise_indices = []\n            while len(noise_indices) < noise_count:\n                idx = secrets.randbelow(self.n)\n                if idx != real_index and idx not in noise_indices:\n                    noise_indices.append(idx)\n        \n        # 鍚堝苟鐪熷疄鏌ヨ鍜屽櫔澹版煡璇紝闅忔満鎵撲贡椤哄簭\n        all_queries = noise_indices + [real_index]\n        secrets.SystemRandom().shuffle(all_queries)\n        \n        print(f\"[PIR-Noise] 瀹㈡埛绔煡璇?{len(all_queries)} 鏉¤褰昞")\n        print(f\"[PIR-Noise] 鏈嶅姟鍣ㄦ棤娉曞尯鍒嗙湡瀹炴煡璇")\n        \n        # 瀹㈡埛绔粠杩斿洖缁撴灉涓彁鍙栫湡瀹炶褰昞n        real_result = self.database[real_index]\n        \n        return real_result\n\n# 娴嬭瘯PIR鍗忚\ndef demo_pir():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氶殣绉佷俊鎭绱紙PIR锛塡")\n    print(\"=\"*60)\n    \n    # 鍒涘缓涓撳埄鏁版嵁搴揬n    database = [\n        \"涓撳埄A - 鏅鸿兘鎵嬫満鎶€鏈痋",\n        \"涓撳埄B - 浜哄伐鏅鸿兘绠楁硶\",\n        \"涓撳埄C - 閲忓瓙璁＄畻鏂规硶\",\n        \"涓撳埄D - 鍖哄潡閾惧崗璁甛",\n        \"涓撳埄E - 鍩哄洜缂栬緫鎶€鏈痋"\n    ]\n    \n    pir = PrivateInformationRetrieval(database)\n    \n    print(\"\\n鍦烘櫙锛氬叕鍙告兂鏌ヨ涓撳埄鏁版嵁搴擄紝浣嗕笉鎯宠鏁版嵁搴撶煡閬撴煡璇㈠唴瀹筡")\n    \n    # 鐩爣鏌ヨ绱㈠紩锛堢2鏉¤褰曪紝绱㈠紩1锛塡n    target_index = 1\n    \n    print(f\"\\n[鏂规硶1] 骞冲嚒PIR - 涓嬭浇鏁翠釜鏁版嵁搴揬")\n    result1 = pir.trivial_pir(target_index)\n    print(f\"缁撴灉: {result1}\")\n    \n    print(f\"\\n[鏂规硶2] 甯﹀櫔澹扮殑鏌ヨ\")\n    result2 = pir.query_with_noise(target_index)\n    print(f\"缁撴灉: {result2}\")\n    \n    print(\"\\n[璇存槑] PIR鐨勬潈琛★細\")\n    print(\"  骞冲嚒PIR锛氬畬缇庨殣绉侊紝浣嗛€氫俊鎴愭湰楂榎")\n    print(\"  鍣０鏌ヨ锛氶檷浣庨€氫俊鎴愭湰锛屼絾闅愮鎬ц緝寮盶")\n    print(\"  瀹為檯PIR锛氫娇鐢ㄥ悓鎬佸姞瀵嗘垨澶氭湇鍔″櫒鏋舵瀯\")\n    \n    return result1 == result2\n\n# 鎵ц娴嬭瘯\ndemo_pir()'),(125,17,7,'娣锋穯缃戠粶锛圡ix Network锛夊疄鐜颁笌娴嬭瘯','1. 瀹炵幇MixNetwork绫伙細鍖呭惈鍐呴儴Message鏁版嵁绫伙紙瀛樺偍娑堟伅鍐呭銆佸彂閫佽€匢D銆佸姞瀵嗙姸鎬侊級銆乢shuffle_messages锛堥殢鏈洪噸鎺掑簭娑堟伅锛夈€乻end_through_mix锛堟秷鎭€氳繃澶氬眰娣锋穯鑺傜偣锛夋柟娉曘€俓n2. 娣锋穯缃戠粶鏍稿績娴佺▼锛氭秷鎭灞傚姞瀵?鈫?姣忓眰鑺傜偣瑙ｅ瘑 鈫?闅忔満閲嶆帓搴?鈫?杞彂锛屾渶缁堟棤娉曡拷韪秷鎭潵婧愩€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_mix_network锛屾ā鎷熷涓敤鎴峰尶鍚嶅彂閫佹秷鎭殑鍦烘櫙锛岄獙璇佹秷鎭『搴忔贩娣嗘晥鏋溿€俓n棰勬湡杈撳嚭锛氭墦鍗板師濮嬫秷鎭『搴忋€佸灞傛贩娣嗚繃绋嬨€佹贩娣嗗悗娑堟伅椤哄簭鐨勬棩蹇楋紝纭鏃犳硶鍏宠仈鍙戦€佽€呬笌娑堟伅锛屾渶缁堣繑鍥濼rue銆?,'瀹為檯娣锋穯缃戠粶锛堝Tor锛変細浣跨敤澶氬眰鍔犲瘑锛堟磱钁辫矾鐢憋級锛屾瘡灞備粎瑙ｅ瘑瀵瑰簲灞傜骇鐨勫姞瀵嗗唴瀹?,'class MixNetwork:\n    \"\"\"娣锋穯缃戠粶锛圡ix Network锛夊疄鐜帮紝鐢ㄤ簬鍖垮悕閫氫俊\"\"\"\n    \n    @dataclass\n    class Message:\n        \"\"\"娣锋穯缃戠粶娑堟伅鏁版嵁缁撴瀯\"\"\"\n        content: str\n        sender_id: str\n        encrypted: bool = False\n    \n    def __init__(self, num_layers: int = 3):\n        \"\"\"鍒濆鍖栨贩娣嗙綉缁滐紝榛樿3灞傛贩娣哱"\"\"\n        self.num_layers = num_layers\n        print(f\"[MixNet] 娣锋穯缃戠粶鍒濆鍖栵紝{num_layers} 灞傛贩娣哱")\n    \n    def _shuffle_messages(self, messages: List[Message]) -> List[Message]:\n        \"\"\"闅忔満閲嶆帓搴忔秷鎭紝鐮村潖娑堟伅涓庡彂閫佽€呯殑鍏宠仈\"\"\"\n        shuffled = messages.copy()\n        secrets.SystemRandom().shuffle(shuffled)\n        return shuffled\n    \n    def send_through_mix(self, messages: List[Message]) -> List[Message]:\n        \"\"\"娑堟伅閫氳繃娣锋穯缃戠粶锛岃繑鍥炴贩娣嗗悗鐨勬秷鎭痋"\"\"\n        print(f\"\\n[MixNet] 寮€濮嬪鐞?{len(messages)} 鏉℃秷鎭痋")\n        \n        current_messages = messages\n        \n        for layer in range(self.num_layers):\n            print(f\"[MixNet] 绗?{layer + 1} 灞傛贩娣?..\")\n            \n            # 妯℃嫙瑙ｅ瘑澶栧眰鍔犲瘑锛堝疄闄呬负澶氬眰鍔犲瘑锛屾瘡灞傝В瀵嗕竴灞傦級\n            for msg in current_messages:\n                if msg.encrypted:\n                    msg.encrypted = False\n            \n            # 闅忔満閲嶆帓搴忔秷鎭痋n            current_messages = self._shuffle_messages(current_messages)\n            \n            print(f\"[MixNet] 绗?{layer + 1} 灞傦細娑堟伅閲嶆帓搴忓畬鎴怽")\n        \n        print(f\"[MixNet] 娑堟伅宸插彂閫侊紝鍘熷椤哄簭宸叉贩娣哱")\n        return current_messages\n\n# 娴嬭瘯娣锋穯缃戠粶\ndef demo_mix_network():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氭贩娣嗙綉缁滐紙鍖垮悕閫氫俊锛塡")\n    print(\"=\"*60)\n    \n    mix = MixNetwork(num_layers=3)\n    \n    print(\"\\n鍦烘櫙锛氬涓敤鎴锋兂鍖垮悕鍙戦€佹秷鎭痋")\n    \n    # 鍒涘缓娴嬭瘯娑堟伅\n    messages = [\n        MixNetwork.Message(\"娑堟伅A\", \"鐢ㄦ埛1\", encrypted=True),\n        MixNetwork.Message(\"娑堟伅B\", \"鐢ㄦ埛2\", encrypted=True),\n        MixNetwork.Message(\"娑堟伅C\", \"鐢ㄦ埛3\", encrypted=True),\n        MixNetwork.Message(\"娑堟伅D\", \"鐢ㄦ埛4\", encrypted=True)\n    ]\n    \n    print(\"\\n鍘熷娑堟伅椤哄簭:\")\n    for i, msg in enumerate(messages):\n        print(f\"  {i+1}. {msg.sender_id}: {msg.content}\")\n    \n    # 娑堟伅閫氳繃娣锋穯缃戠粶\n    output_messages = mix.send_through_mix(messages)\n    \n    print(\"\\n杈撳嚭娑堟伅椤哄簭锛堝凡娣锋穯锛?\")\n    for i, msg in enumerate(output_messages):\n        print(f\"  {i+1}. {msg.content} 锛堟棤娉曡拷韪彂閫佽€咃級\")\n    \n    print(\"\\n[璇存槑] 娣锋穯缃戠粶鐨勭壒鎬э細\")\n    print(\"  1. 澶氬眰娣锋穯锛氭瘡灞傝В瀵嗗苟閲嶆帓搴廫")\n    print(\"  2. 涓嶅彲杩借釜锛氭棤娉曞叧鑱旇緭鍏ュ拰杈撳嚭\")\n    print(\"  3. 搴旂敤锛歍or缃戠粶銆佸尶鍚嶉偖浠禱")\n    print(\"  4. 娲嬭懕璺敱锛氬灞傚姞瀵嗭紝閫愬眰瑙ｅ瘑\")\n    \n    return len(output_messages) == len(messages)\n\n# 鎵ц娴嬭瘯\ndemo_mix_network()'),(126,17,8,'鍗忚鐗规€у姣斾笌鍦烘櫙閫傞厤鍒嗘瀽','1. 鏁寸悊浜斿ぇ鍗忚鏍稿績鐗规€э細姣旂壒鎵胯锛堜袱闃舵銆侀殣钘?缁戝畾锛夈€佽繙绋嬫姏纭竵锛堝叕骞虫€с€佸熀浜庢瘮鐗规壙璇猴級銆丳edersen鎵胯锛堝畬缇庨殣钘忋€佸姞娉曞悓鎬侊級銆丳SI锛堥泦鍚堜氦闆嗛殣绉併€侀潪浜ら泦淇濆瘑锛夈€丳IR锛堟煡璇㈤殣绉併€佹暟鎹簱鏃犳劅鐭ワ級銆佹贩娣嗙綉缁滐紙閫氫俊鍖垮悕銆佷笉鍙拷韪級銆俓n2. 鍒嗘瀽閫傜敤鍦烘櫙宸紓锛氭瘮鐗规壙璇洪€傜敤浜庨浂鐭ヨ瘑璇佹槑銆佺數瀛愭媿鍗栵紱Pedersen鎵胯閫傜敤浜庨殣绉佸竵銆佸畨鍏ㄥ鏂硅绠楋紱PSI閫傜敤浜庡箍鍛婅浆鍖栥€佽仈绯讳汉鍙戠幇锛汸IR閫傜敤浜庝笓鍒╂绱€佸尰鐤楁暟鎹煡璇紱娣锋穯缃戠粶閫傜敤浜庡尶鍚嶉€氫俊銆佺數瀛愭姇绁ㄣ€俓n3. 鎬荤粨鎶€鏈€夊瀷瑕佺偣锛氭牴鎹殣绉佷繚鎶ら渶姹傦紙鏁版嵁闅愮銆侀€氫俊闅愮銆佹煡璇㈤殣绉侊級銆佹€ц兘瑕佹眰锛堥€氫俊鎴愭湰銆佽绠楁垚鏈級銆侀儴缃茬幆澧冿紙鍗曟湇鍔″櫒/澶氭湇鍔″櫒銆佺偣瀵圭偣锛夐€夋嫨鍚堥€傚崗璁€俓n棰勬湡杈撳嚭锛氬舰鎴愭竻鏅扮殑鍗忚瀵规瘮璁ょ煡锛岃兘鏍规嵁瀹為檯涓氬姟鍦烘櫙閫夋嫨鏈€浼橀殣绉佷繚鎶ゆ柟妗堛€?,'瀹為檯搴旂敤涓父闇€缁勫悎澶氱鍗忚锛堝PSI+鍚屾€佸姞瀵嗭級浠ユ弧瓒冲鏉傞殣绉侀渶姹?,NULL),(127,18,1,'鐜鍑嗗涓庡熀纭€姒傚康姊崇悊','1. 鐜閰嶇疆锛氱‘淇漃ython 3.7+鐜锛屼緷璧朠ython鏍囧噯搴擄紙hashlib銆乼ime銆乻ecrets銆乨ataclasses銆乯son锛夛紝鏃犻渶棰濆瀹夎绗笁鏂瑰寘銆俓n2. 鏍稿績姒傚康鍥為【锛氬尯鍧楅摼鍩烘湰缁撴瀯锛堝尯鍧椼€侀摼銆佷氦鏄擄級銆佸叡璇嗗崗璁洓澶ф牳蹇冩€ц川锛堜竴鑷存€с€佹渶缁堟€с€佹椿鎬с€佸閿欐€э級銆佹嫓鍗犲涵瀹归敊鐞嗚鏋侀檺锛坣鈮?f+1锛夈€俓n3. 鐩爣鏄庣‘锛氭湰瀹為獙鑱氱劍PoW锛堝伐浣滈噺璇佹槑锛夈€丳oS锛堟潈鐩婅瘉鏄庯級銆丳BFT锛堝疄鐢ㄦ嫓鍗犲涵瀹归敊锛変笁澶т富娴佸崗璁紝鐞嗚В鍏惰璁℃€濇兂涓庨€傜敤鍦烘櫙宸紓銆俓n棰勬湡杈撳嚭锛氭棤鎶ラ敊纭Python鐜鍙敤锛屾竻鏅版⒊鐞嗗叡璇嗗崗璁牳蹇冩蹇点€?,'鑻ヤ娇鐢≒ython 3.6鍙婁互涓嬬増鏈紝闇€鎵嬪姩瀹夎dataclasses妯″潡锛坧ip install dataclasses锛?,NULL),(128,18,2,'鍩虹鍖哄潡缁撴瀯瀹炵幇','1. 瀹氫箟Block鏁版嵁绫伙細鍖呭惈鍖哄潡绱㈠紩锛坕ndex锛夈€佹椂闂存埑锛坱imestamp锛夈€佷氦鏄撳垪琛紙transactions锛夈€佸墠鍖哄潡鍝堝笇锛坧revious_hash锛夈€侀殢鏈烘暟锛坣once锛夈€佸綋鍓嶅尯鍧楀搱甯岋紙hash锛夋牳蹇冨瓧娈点€俓n2. 瀹炵幇compute_hash鏂规硶锛氶€氳繃JSON搴忓垪鍖栧尯鍧楁牳蹇冨瓧娈碉紙鎺掑簭閿‘淇濅竴鑷存€э級锛屼娇鐢⊿HA-256璁＄畻鍖哄潡鍝堝笇锛屼繚璇佸尯鍧楁暟鎹畬鏁存€с€俓n3. 鏍稿績浣滅敤锛氬尯鍧楁槸鍏辫瘑鍗忚鐨勫熀纭€鏁版嵁鍗曞厓锛屽搱甯屽€肩敤浜庨摼鐨勯摼鎺ヤ笌鏁版嵁楠岃瘉銆俓n棰勬湡杈撳嚭锛欱lock绫诲彲姝ｅ父瀹炰緥鍖栵紝compute_hash鏂规硶鑳界ǔ瀹氱敓鎴愬敮涓€鍝堝笇鍊笺€?,NULL,'import hashlib\nimport time\nimport secrets\nfrom typing import List, Dict, Optional, Tuple\nfrom dataclasses import dataclass, field\nimport json\n\n@dataclass\nclass Block:\n    \"\"\"鍖哄潡閾惧熀纭€鍖哄潡鏁版嵁缁撴瀯\"\"\"\n    index: int  # 鍖哄潡绱㈠紩\n    timestamp: float  # 鏃堕棿鎴砛n    transactions: List[str]  # 浜ゆ槗鍒楄〃\n    previous_hash: str  # 鍓嶅尯鍧楀搱甯孿n    nonce: int = 0  # 闅忔満鏁帮紙PoW涓撶敤锛塡n    hash: str = \"\"  # 褰撳墠鍖哄潡鍝堝笇\n    \n    def compute_hash(self) -> str:\n        \"\"\"璁＄畻鍖哄潡鍝堝笇锛堢‘淇濇暟鎹畬鏁存€э級\"\"\"\n        # 搴忓垪鍖栧尯鍧楁牳蹇冨瓧娈碉紙鎺掑簭閿伩鍏嶅搱甯屼笉涓€鑷达級\n        block_string = json.dumps({\n            \'index\': self.index,\n            \'timestamp\': self.timestamp,\n            \'transactions\': self.transactions,\n            \'previous_hash\': self.previous_hash,\n            \'nonce\': self.nonce\n        }, sort_keys=True)\n        # SHA-256鍝堝笇璁＄畻\n        return hashlib.sha256(block_string.encode()).hexdigest()\n\n# 娴嬭瘯鍖哄潡缁撴瀯\ndef test_block():\n    # 瀹炰緥鍖栨祴璇曞尯鍧梊n    test_block = Block(\n        index=0,\n        timestamp=time.time(),\n        transactions=[\"鍒涗笘鍖哄潡娴嬭瘯\"],\n        previous_hash=\"0\"\n    )\n    # 璁＄畻鍝堝笇\n    block_hash = test_block.compute_hash()\n    print(f\"娴嬭瘯鍖哄潡鍝堝笇锛歿block_hash[:32]}...\")\n    return len(block_hash) == 64  # SHA-256鍝堝笇闀垮害涓?4浣峔n\n# 鎵ц娴嬭瘯\ntest_block()'),(129,18,3,'宸ヤ綔閲忚瘉鏄庯紙PoW锛夊崗璁疄鐜颁笌娴嬭瘯','1. 鏍稿績鍘熺悊锛氳妭鐐归€氳繃璁＄畻闅捐В鏁板璋滈锛堝鎵緉once浣垮尯鍧楀搱甯屾弧瓒抽毦搴﹂槇鍊糎(block_header||nonce) < T锛夌珵浜夎璐︽潈锛屽畨鍏ㄦ€т緷璧栧搱甯屽嚱鏁扮殑鎶楅鏄犲皠鎬т笌鎶楃鎾炴€с€俓n2. 瀹炵幇ProofOfWork绫伙細\n   - 鍒濆鍖栨柟娉曪細璁剧疆闅惧害闃堝€笺€佸垵濮嬪寲鍖哄潡閾撅紙鍒涘缓鍒涗笘鍖哄潡锛夈€佸垵濮嬪寲寰呭鐞嗕氦鏄撴睜銆俓n   - _mine_block鏂规硶锛氭寲鐭挎牳蹇冮€昏緫锛屽惊鐜亶鍘唍once锛岀洿鍒版壘鍒版弧瓒抽毦搴﹁姹傜殑鍝堝笇鍊笺€俓n   - add_transaction鏂规硶锛氭坊鍔犱氦鏄撳埌寰呭鐞嗘睜銆俓n   - mine_pending_transactions鏂规硶锛氭墦鍖呭緟澶勭悊浜ゆ槗锛岃皟鐢ㄦ寲鐭挎柟娉曠敓鎴愭柊鍖哄潡锛屾坊鍔犵熆宸ュ鍔便€俓n   - is_chain_valid鏂规硶锛氶獙璇佸尯鍧楅摼瀹屾暣鎬э紙鍝堝笇涓€鑷存€с€侀摼鎺ュ畬鏁存€с€侀毦搴﹁揪鏍囷級銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_proof_of_work锛氭ā鎷熸瘮鐗瑰竵鎸栫熆娴佺▼锛屽寘鍚氦鏄撴坊鍔犮€佹寲鐭裤€侀摼楠岃瘉銆俓n棰勬湡杈撳嚭锛氭墦鍗板垱涓栧尯鍧楀垱寤恒€佷氦鏄撴坊鍔犮€佹寲鐭胯繃绋嬶紙灏濊瘯娆℃暟銆佽€楁椂锛夈€佸尯鍧楀搱甯屻€侀摼楠岃瘉缁撴灉锛屾渶缁堣繑鍥濼rue銆?,'婕旂ず鏃跺缓璁皢闅惧害璁句负2-4锛堥毦搴﹁秺楂橈紝鎸栫熆灏濊瘯娆℃暟瓒婂锛岃€楁椂瓒婇暱锛夛紝瀹為檯姣旂壒甯侀毦搴﹀姩鎬佽皟鏁?,'class ProofOfWork:\n    \"\"\"宸ヤ綔閲忚瘉鏄庯紙Proof of Work - PoW锛夊崗璁疄鐜癨"\"\"\n    \n    def __init__(self, difficulty: int = 4):\n        \"\"\"鍒濆鍖朠oW鍖哄潡閾綷n        Args:\n            difficulty: 鎸栫熆闅惧害锛堝尯鍧楀搱甯屽墠N浣嶅繀椤讳负0锛塡n        \"\"\"\n        self.difficulty = difficulty\n        self.chain: List[Block] = []  # 鍖哄潡閾句富閾綷n        self.pending_transactions: List[str] = []  # 寰呭鐞嗕氦鏄撴睜\n        \n        # 鍒涘缓鍒涗笘鍖哄潡锛堢涓€涓尯鍧楋紝鏃犲墠缃尯鍧楋級\n        genesis_block = Block(\n            index=0,\n            timestamp=time.time(),\n            transactions=[\"鍒涗笘鍖哄潡\"],\n            previous_hash=\"0\"\n        )\n        genesis_block.hash = self._mine_block(genesis_block)\n        self.chain.append(genesis_block)\n        \n        print(f\"[PoW] 鍖哄潡閾惧垵濮嬪寲瀹屾垚锛屾寲鐭块毦搴︼細{difficulty}\")\n        print(f\"[PoW] 鍒涗笘鍖哄潡鍝堝笇锛歿genesis_block.hash[:32]}...\")\n    \n    def _mine_block(self, block: Block) -> str:\n        \"\"\"鎸栫熆鏍稿績閫昏緫锛氬鎵炬弧瓒抽毦搴﹁姹傜殑nonce\n        Args:\n            block: 寰呮寲鐭跨殑鍖哄潡\n        Returns:\n            婊¤冻闅惧害瑕佹眰鐨勫尯鍧楀搱甯孿n        \"\"\"\n        target = \'0\' * self.difficulty  # 闅惧害鐩爣锛氬搱甯屽墠N浣嶄负0\n        attempts = 0  # 鎸栫熆灏濊瘯娆℃暟\n        start_time = time.time()  # 鎸栫熆寮€濮嬫椂闂碶n        \n        while True:\n            block.nonce = attempts  # 閬嶅巻nonce\n            block_hash = block.compute_hash()  # 璁＄畻褰撳墠nonce瀵瑰簲鐨勫搱甯孿n            \n            # 妫€鏌ュ搱甯屾槸鍚︽弧瓒抽毦搴﹁姹俓n            if block_hash.startswith(target):\n                elapsed = time.time() - start_time\n                print(f\"[PoW] 鎸栫熆鎴愬姛锛佸皾璇曟鏁? {attempts:,}, 鑰楁椂: {elapsed:.2f}绉抃")\n                print(f\"[PoW] 鍖哄潡鍝堝笇: {block_hash[:32]}...\")\n                return block_hash\n            \n            attempts += 1\n            # 姣?0000娆″皾璇曟墦鍗拌繘搴︼紙閬垮厤鏃犲搷搴旀劅鐭ワ級\n            if attempts % 10000 == 0 and attempts > 0:\n                print(f\"[PoW] 鎸栫熆涓?.. 宸插皾璇?{attempts:,} 娆")\n    \n    def add_transaction(self, transaction: str):\n        \"\"\"娣诲姞浜ゆ槗鍒板緟澶勭悊浜ゆ槗姹燶"\"\"\n        self.pending_transactions.append(transaction)\n        print(f\"[PoW] 浜ゆ槗宸叉坊鍔犲埌浜ゆ槗姹? {transaction}\")\n    \n    def mine_pending_transactions(self, miner_address: str):\n        \"\"\"鎵撳寘寰呭鐞嗕氦鏄撳苟鎸栫熆\n        Args:\n            miner_address: 鐭垮伐鍦板潃锛堟帴鏀舵寲鐭垮鍔憋級\n        \"\"\"\n        if not self.pending_transactions:\n            print(\"[PoW] 鏃犲緟澶勭悊浜ゆ槗锛屾棤闇€鎸栫熆\")\n            return\n        \n        # 鏋勫缓鏂板尯鍧梊n        last_block = self.chain[-1]  # 鑾峰彇鏈€鍚庝竴涓尯鍧梊n        new_block = Block(\n            index=len(self.chain),\n            timestamp=time.time(),\n            transactions=self.pending_transactions.copy(),  # 澶嶅埗浜ゆ槗姹燶n            previous_hash=last_block.hash\n        )\n        \n        print(f\"\\n[PoW] 寮€濮嬫寲鐭垮尯鍧?#{new_block.index}...\")\n        new_block.hash = self._mine_block(new_block)  # 鎸栫熆\n        \n        # 鏂板尯鍧楁坊鍔犲埌涓婚摼\n        self.chain.append(new_block)\n        \n        # 娓呯┖浜ゆ槗姹狅紝娣诲姞鎸栫熆濂栧姳锛堟ā鎷熸瘮鐗瑰竵濂栧姳鏈哄埗锛塡n        self.pending_transactions = [f\"鎸栫熆濂栧姳 -> {miner_address}: 1 BTC\"]\n        print(f\"[PoW] 鍖哄潡 #{new_block.index} 宸叉垚鍔熸坊鍔犲埌鍖哄潡閾綷")\n    \n    def is_chain_valid(self) -> bool:\n        \"\"\"楠岃瘉鍖哄潡閾惧畬鏁存€э紙闃茬鏀癸級\"\"\"\n        for i in range(1, len(self.chain)):\n            current_block = self.chain[i]\n            previous_block = self.chain[i-1]\n            \n            # 楠岃瘉褰撳墠鍖哄潡鍝堝笇鏄惁鏈夋晥锛堟湭琚鏀癸級\n            if current_block.hash != current_block.compute_hash():\n                print(f\"[PoW] 鍖哄潡 #{i} 鏁版嵁琚鏀癸紒鍝堝笇楠岃瘉澶辫触\")\n                return False\n            \n            # 楠岃瘉鍖哄潡閾炬帴鏄惁鏈夋晥锛堝墠鍖哄潡鍝堝笇鍖归厤锛塡n            if current_block.previous_hash != previous_block.hash:\n                print(f\"[PoW] 鍖哄潡 #{i} 閾炬帴鏂锛佸墠鍖哄潡鍝堝笇涓嶅尮閰峔")\n                return False\n            \n            # 楠岃瘉鍖哄潡鏄惁婊¤冻鎸栫熆闅惧害瑕佹眰\n            if not current_block.hash.startswith(\'0\' * self.difficulty):\n                print(f\"[PoW] 鍖哄潡 #{i} 鏈弧瓒虫寲鐭块毦搴﹁姹俓")\n                return False\n        \n        print(\"[PoW] 鍖哄潡閾惧畬鏁存€ч獙璇侀€氳繃锛屾棤绡℃敼\")\n        return True\n\n# 娴嬭瘯PoW鍗忚\ndef demo_proof_of_work():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氬伐浣滈噺璇佹槑锛圥oW锛夊崗璁?- 姣旂壒甯佹寲鐭挎ā鎷焅")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖朠oW鍖哄潡閾撅紙闅惧害璁句负2锛屾紨绀烘晥鐜囨洿楂橈級\n    pow_blockchain = ProofOfWork(difficulty=2)\n    \n    # 姝ラ1锛氭坊鍔犱氦鏄撳埌浜ゆ槗姹燶n    print(\"\\n[姝ラ1] 娣诲姞浜ゆ槗鍒颁氦鏄撴睜\")\n    pow_blockchain.add_transaction(\"Alice -> Bob: 2 BTC\")\n    pow_blockchain.add_transaction(\"Bob -> Carol: 1 BTC\")\n    \n    # 姝ラ2锛氱熆宸ユ寲鐭匡紙鎵撳寘浜ゆ槗锛塡n    print(\"\\n[姝ラ2] 鐭垮伐Miner1寮€濮嬫寲鐭縗")\n    pow_blockchain.mine_pending_transactions(\"Miner1\")\n    \n    # 姝ラ3锛氭坊鍔犳洿澶氫氦鏄揬n    print(\"\\n[姝ラ3] 娣诲姞鏇村浜ゆ槗\")\n    pow_blockchain.add_transaction(\"Carol -> Dave: 0.5 BTC\")\n    \n    # 姝ラ4锛氬啀娆℃寲鐭縗n    print(\"\\n[姝ラ4] 鐭垮伐Miner1缁х画鎸栫熆\")\n    pow_blockchain.mine_pending_transactions(\"Miner1\")\n    \n    # 姝ラ5锛氶獙璇佸尯鍧楅摼瀹屾暣鎬n    print(\"\\n[姝ラ5] 楠岃瘉鍖哄潡閾惧畬鏁存€")\n    is_valid = pow_blockchain.is_chain_valid()\n    \n    # 鎵撳嵃鍖哄潡閾剧姸鎬乗n    print(\"\\n[鍖哄潡閾剧姸鎬佹瑙圿\")\n    for block in pow_blockchain.chain:\n        print(f\"- 鍖哄潡 #{block.index}: 鍝堝笇={block.hash[:16]}..., 浜ゆ槗鏁?{len(block.transactions)}\")\n    \n    print(\"\\n[PoW鍗忚鏍稿績鐗圭偣]\")\n    print(\"  1. 鍘讳腑蹇冨寲锛氫换浣曚汉鍙弬涓庢寲鐭匡紝鏃犻渶鎺堟潈\")\n    print(\"  2. 瀹夊叏鎬э細绡℃敼闇€閲嶆柊璁＄畻鎵€鏈夊悗缁尯鍧桺oW锛屾垚鏈瀬楂榎")\n    print(\"  3. 鑳借€楅珮锛氭寲鐭胯繃绋嬫秷鑰楀ぇ閲忚绠楄祫婧怽")\n    print(\"  4. 姒傜巼鏈€缁堟€э細闇€绛夊緟澶氫釜鍖哄潡纭锛堝姣旂壒甯?涓級纭繚涓嶅彲閫哱")\n    \n    return is_valid\n\n# 鎵цPoW娴嬭瘯\ndemo_proof_of_work()'),(130,18,4,'鏉冪泭璇佹槑锛圥oS锛夊崗璁疄鐜颁笌娴嬭瘯','1. 鏍稿績鍘熺悊锛氳妭鐐规牴鎹寔甯佽川鎶奸噺锛圫take锛夋鐜囨€ц幏寰楄璐︽潈锛岃閫変腑姒傜巼涓庢潈鐩婂崰姣旀垚姝ｆ瘮锛圥i = stake_i / 危stake_j锛夛紝閫氳繃鎯╃綒鏈哄埗锛圫lashing锛夌害鏉熸伓鎰忚涓猴紝閬垮厤PoW鐨勯珮鑳借€椼€俓n2. 瀹炵幇鏍稿績缁勪欢锛歕n   - Validator鏁版嵁绫伙細瀛樺偍楠岃瘉鑰呭湴鍧€涓庤川鎶奸噾棰濄€俓n   - ProofOfStake绫伙細\n     - 鍒濆鍖栨柟娉曪細璁剧疆鏈€灏忚川鎶奸噾棰濄€佸垵濮嬪寲鍖哄潡閾撅紙鍒涗笘鍖哄潡锛夈€侀獙璇佽€呭瓧鍏搞€佸緟澶勭悊浜ゆ槗姹犮€俓n     - register_validator鏂规硶锛氶獙璇佽€呮敞鍐岋紙闇€婊¤冻鏈€灏忚川鎶艰姹傦級銆俓n     - _select_validator鏂规硶锛氬熀浜庢潈鐩婂姞鏉冮殢鏈洪€夋嫨鍑哄潡楠岃瘉鑰呫€俓n     - add_transaction鏂规硶锛氭坊鍔犱氦鏄撳埌浜ゆ槗姹犮€俓n     - create_block鏂规硶锛氱敱閫変腑鐨勯獙璇佽€呮墦鍖呬氦鏄撱€佺敓鎴愭柊鍖哄潡銆佽幏寰楀鍔便€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_proof_of_stake锛氭ā鎷熶互澶潑2.0楠岃瘉鑰呰川鎶笺€佸嚭鍧楁祦绋嬶紝楠岃瘉鏉冪泭鍔犳潈閫夋嫨鏈哄埗銆俓n棰勬湡杈撳嚭锛氭墦鍗伴獙璇佽€呮敞鍐屻€佷氦鏄撴坊鍔犮€侀獙璇佽€呴€変腑銆佸尯鍧楀垱寤恒€佸尯鍧楅摼鐘舵€侊紝鏈€缁堣繑鍥濼rue銆?,'PoS鐨勬牳蹇冩槸缁忔祹婵€鍔辩害鏉燂紙璇氬疄鏀剁泭>鏀诲嚮鏀剁泭锛夛紝瀹炵幇涓渶閲嶇偣鍏虫敞楠岃瘉鑰呴€夋嫨鐨勯殢鏈烘€т笌鏉冪泭鍗犳瘮鐨勫叧鑱旀€?,'@dataclass\nclass Validator:\n    \"\"\"PoS鍗忚楠岃瘉鑰呮暟鎹粨鏋刓"\"\"\n    address: str  # 楠岃瘉鑰呭湴鍧€\n    stake: int  # 璐ㄦ娂閲戦锛堝崟浣嶏細浠ｅ竵锛塡n\nclass ProofOfStake:\n    \"\"\"鏉冪泭璇佹槑锛圥roof of Stake - PoS锛夊崗璁疄鐜癨"\"\"\n    \n    def __init__(self, min_stake: int = 32):\n        \"\"\"鍒濆鍖朠oS鍖哄潡閾綷n        Args:\n            min_stake: 鎴愪负楠岃瘉鑰呯殑鏈€灏忚川鎶奸噾棰濓紙妯℃嫙浠ュお鍧?.0鐨?2ETH锛塡n        \"\"\"\n        self.min_stake = min_stake\n        self.chain: List[Block] = []  # 鍖哄潡閾句富閾綷n        self.validators: Dict[str, Validator] = {}  # 楠岃瘉鑰呭瓧鍏革紙鍦板潃->楠岃瘉鑰咃級\n        self.pending_transactions: List[List[str]] = []  # 寰呭鐞嗕氦鏄撴睜\n        \n        # 鍒涘缓鍒涗笘鍖哄潡\n        genesis_block = Block(\n            index=0,\n            timestamp=time.time(),\n            transactions=[\"鍒涗笘鍖哄潡\"],\n            previous_hash=\"0\"\n        )\n        genesis_block.hash = genesis_block.compute_hash()\n        self.chain.append(genesis_block)\n        \n        print(f\"[PoS] 鍖哄潡閾惧垵濮嬪寲瀹屾垚锛屾渶灏忚川鎶奸噾棰濓細{min_stake} 浠ｅ竵\")\n    \n    def register_validator(self, address: str, stake: int) -> bool:\n        \"\"\"楠岃瘉鑰呮敞鍐岋紙闇€婊¤冻鏈€灏忚川鎶艰姹傦級\n        Args:\n            address: 楠岃瘉鑰呭湴鍧€\n            stake: 璐ㄦ娂閲戦\n        Returns:\n            娉ㄥ唽鏄惁鎴愬姛\n        \"\"\"\n        if stake < self.min_stake:\n            print(f\"[PoS] 楠岃瘉鑰?{address} 璐ㄦ娂澶辫触锛氶渶鑷冲皯 {self.min_stake} 浠ｅ竵锛屽綋鍓嶈川鎶?{stake}\")\n            return False\n        \n        if address in self.validators:\n            # 宸叉敞鍐岄獙璇佽€咃紝杩藉姞璐ㄦ娂\n            self.validators[address].stake += stake\n            print(f\"[PoS] 楠岃瘉鑰?{address} 杩藉姞璐ㄦ娂 {stake} 浠ｅ竵锛屽綋鍓嶆€昏川鎶硷細{self.validators[address].stake}\")\n        else:\n            # 鏂伴獙璇佽€呮敞鍐孿n            validator = Validator(address, stake)\n            self.validators[address] = validator\n            print(f\"[PoS] 楠岃瘉鑰?{address} 娉ㄥ唽鎴愬姛锛岃川鎶?{stake} 浠ｅ竵\")\n        \n        return True\n    \n    def _select_validator(self) -> Optional[str]:\n        \"\"\"鍩轰簬鏉冪泭鍔犳潈闅忔満閫夋嫨鍑哄潡楠岃瘉鑰匼n        Returns:\n            琚€変腑鐨勯獙璇佽€呭湴鍧€锛堟棤楠岃瘉鑰呰繑鍥濶one锛塡n        \"\"\"\n        if not self.validators:\n            print(\"[PoS] 鏃犲彲鐢ㄩ獙璇佽€匼")\n            return None\n        \n        # 璁＄畻鎬昏川鎶奸噾棰漒n        total_stake = sum(validator.stake for validator in self.validators.values())\n        # 鐢熸垚闅忔満鏁帮紙0 ~ total_stake-1锛塡n        random_point = secrets.randbelow(total_stake)\n        \n        # 鍔犳潈闅忔満閫夋嫨锛氳川鎶艰秺澶氾紝琚€変腑姒傜巼瓒婂ぇ\n        current_sum = 0\n        for address, validator in self.validators.items():\n            current_sum += validator.stake\n            if random_point < current_sum:\n                return address\n        \n        # 鍏滃簳锛氳繑鍥炵涓€涓獙璇佽€咃紙鐞嗚涓婁笉浼氳Е鍙戯級\n        return list(self.validators.keys())[0]\n    \n    def add_transaction(self, transaction: str):\n        \"\"\"娣诲姞浜ゆ槗鍒板緟澶勭悊浜ゆ槗姹燶"\"\"\n        self.pending_transactions.append(transaction)\n        print(f\"[PoS] 浜ゆ槗宸叉坊鍔犲埌浜ゆ槗姹? {transaction}\")\n    \n    def create_block(self) -> bool:\n        \"\"\"鐢遍€変腑鐨勯獙璇佽€呭垱寤烘柊鍖哄潡\n        Returns:\n            鍖哄潡鍒涘缓鏄惁鎴愬姛\n        \"\"\"\n        if not self.pending_transactions:\n            print(\"[PoS] 鏃犲緟澶勭悊浜ゆ槗锛屾棤闇€鍒涘缓鍖哄潡\")\n            return False\n        \n        # 閫夋嫨鍑哄潡楠岃瘉鑰匼n        validator_address = self._select_validator()\n        if not validator_address:\n            return False\n        \n        validator = self.validators[validator_address]\n        print(f\"\\n[PoS] 楠岃瘉鑰?{validator_address} 琚€変腑鍑哄潡锛堣川鎶奸噾棰濓細{validator.stake} 浠ｅ竵锛塡")\n        \n        # 鏋勫缓鏂板尯鍧梊n        last_block = self.chain[-1]\n        new_block = Block(\n            index=len(self.chain),\n            timestamp=time.time(),\n            transactions=self.pending_transactions.copy(),\n            previous_hash=last_block.hash\n        )\n        new_block.hash = new_block.compute_hash()\n        \n        # 鏂板尯鍧楁坊鍔犲埌涓婚摼\n        self.chain.append(new_block)\n        print(f\"[PoS] 鍖哄潡 #{new_block.index} 鍒涘缓鎴愬姛锛屽搱甯岋細{new_block.hash[:32]}...\")\n        \n        # 娓呯┖浜ゆ槗姹狅紝娣诲姞楠岃瘉鑰呭鍔憋紙妯℃嫙PoS濂栧姳鏈哄埗锛塡n        self.pending_transactions = [f\"鍑哄潡濂栧姳 -> {validator_address}: 0.1 ETH\"]\n        return True\n\n# 娴嬭瘯PoS鍗忚\ndef demo_proof_of_stake():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氭潈鐩婅瘉鏄庯紙PoS锛夊崗璁?- 浠ュお鍧?.0楠岃瘉鑰呮ā鎷焅")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖朠oS鍖哄潡閾撅紙鏈€灏忚川鎶?2浠ｅ竵锛塡n    pos_blockchain = ProofOfStake(min_stake=32)\n    \n    # 姝ラ1锛氶獙璇佽€呮敞鍐屽苟璐ㄦ娂\n    print(\"\\n[姝ラ1] 楠岃瘉鑰呮敞鍐屼笌璐ㄦ娂\")\n    pos_blockchain.register_validator(\"Validator_A\", stake=100)  # 璐ㄦ娂100锛堟弧瓒宠姹傦級\n    pos_blockchain.register_validator(\"Validator_B\", stake=50)   # 璐ㄦ娂50锛堟弧瓒宠姹傦級\n    pos_blockchain.register_validator(\"Validator_C\", stake=30)   # 璐ㄦ娂30锛堜笉婊¤冻瑕佹眰锛塡n    pos_blockchain.register_validator(\"Validator_A\", stake=50)   # 杩藉姞璐ㄦ娂50\n    \n    # 姝ラ2锛氭坊鍔犱氦鏄撳苟鍒涘缓澶氫釜鍖哄潡\n    print(\"\\n[姝ラ2] 娣诲姞浜ゆ槗骞跺垱寤哄尯鍧梊")\n    for i in range(3):\n        pos_blockchain.add_transaction(f\"浜ゆ槗 {i+1}: User_{i} -> User_{i+1}: {10+i} 浠ｅ竵\")\n        pos_blockchain.create_block()\n    \n    # 姝ラ3锛氭墦鍗板尯鍧楅摼鐘舵€乗n    print(\"\\n[鍖哄潡閾剧姸鎬佹瑙圿\")\n    for block in pos_blockchain.chain:\n        print(f\"- 鍖哄潡 #{block.index}: 鍝堝笇={block.hash[:16]}..., 浜ゆ槗鏁?{len(block.transactions)}\")\n    \n    print(\"\\n[PoS鍗忚鏍稿績鐗圭偣]\")\n    print(\"  1. 鑺傝兘楂樻晥锛氭棤闇€璁＄畻瀵嗛泦鍨嬫寲鐭匡紝鑳借€椾粎涓篜oW鐨勫崈鍒嗕箣涓€\")\n    print(\"  2. 缁忔祹绾︽潫锛氳川鎶奸噾浣滀负鎷呬繚锛屾伓鎰忚涓轰細琚墸闄よ川鎶硷紙Slashing锛塡")\n    print(\"  3. 鏉冪泭鍔犳潈锛氳川鎶艰秺澶氾紝鍑哄潡姒傜巼瓒婂ぇ锛岄伩鍏嶆棤鎰忎箟绔炰簤\")\n    print(\"  4. 蹇€熺‘璁わ細鏃犳寲鐭垮欢杩燂紝鍖哄潡纭閫熷害蹇紙缁忔祹鏈€缁堟€э級\")\n    print(\"  5. 娼滃湪闂锛氬瘜鑰呮剤瀵岋紝闇€閫氳繃鏈哄埗璁捐骞宠　鍘讳腑蹇冨寲\")\n    \n    return True\n\n# 鎵цPoS娴嬭瘯\ndemo_proof_of_stake()'),(131,18,5,'瀹炵敤鎷滃崰搴閿欙紙PBFT锛夊崗璁疄鐜颁笌娴嬭瘯','1. 鏍稿績鍘熺悊锛氬湪鑱旂洘閾惧満鏅腑锛?f+1涓妭鐐归€氳繃涓夐樁娈垫姇绁紙Pre-prepare 鈫?Prepare 鈫?Commit锛夎揪鎴愬叡璇嗭紝鍙蹇嶆渶澶歠涓嫓鍗犲涵鎭舵剰鑺傜偣锛屽叿澶囧己鏈€缁堟€э紙涓€鏃︾‘璁や笉鍙€嗭級銆俓n2. 瀹炵幇鏍稿績缁勪欢锛歕n   - PBFTMessage鏁版嵁绫伙細瀛樺偍鍏辫瘑娑堟伅锛堢被鍨嬨€佽鍥俱€佸簭鍒楀彿銆佸尯鍧楁憳瑕併€佽妭鐐笽D锛夈€俓n   - PBFTNode鏁版嵁绫伙細瀛樺偍鑺傜偣鐘舵€侊紙鑺傜偣ID銆佽鍥俱€佸凡鎺ユ敹鐨凱repare/Commit娑堟伅锛夈€俓n   - PBFT绫伙細\n     - 鍒濆鍖栨柟娉曪細璁剧疆鑺傜偣鏁伴噺锛堚墺4锛夈€佽绠楁渶澶у閿欐暟f=(n-1)/3銆佸垵濮嬪寲鑺傜偣鍒楄〃銆佷富鑺傜偣绱㈠紩銆佸簭鍒楀彿銆佸尯鍧楅摼銆俓n     - create_block鏂规硶锛氭ā鎷熶笁闃舵鍏辫瘑娴佺▼锛堜富鑺傜偣鎻愯鈫掕妭鐐筆repare鎶曠エ鈫掕妭鐐笴ommit鎶曠エ鈫掑尯鍧楁彁浜わ級銆俓n     - simulate_byzantine_failure鏂规硶锛氭ā鎷熸嫓鍗犲涵鑺傜偣鏁呴殰锛岄獙璇佺郴缁熷閿欒兘鍔涖€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_pbft锛氭ā鎷熻仈鐩熼摼鍏辫瘑娴佺▼锛岄獙璇佷笁闃舵鎶曠エ銆佹嫓鍗犲涵瀹归敊鑳藉姏锛坒=1鏃跺蹇?涓伓鎰忚妭鐐癸紝瓒呭嚭鍒欏叡璇嗗け璐ワ級銆俓n棰勬湡杈撳嚭锛氭墦鍗颁笁闃舵鍏辫瘑杩囩▼銆佽妭鐐逛氦浜掋€佹嫓鍗犲涵鏁呴殰妯℃嫙缁撴灉銆佸尯鍧楅摼鐘舵€侊紝鏈€缁堣繑鍥濼rue銆?,'PBFT鐨勬牳蹇冩槸涓夐樁娈垫姇绁ㄦ満鍒讹紝闇€纭繚姣忎釜闃舵鐨勬秷鎭暟閲忔弧瓒抽槇鍊硷紙Prepare鈮?f锛孋ommit鈮?f+1锛夛紝杩欐槸鎷滃崰搴閿欑殑鍏抽敭','@dataclass\nclass PBFTMessage:\n    \"\"\"PBFT鍏辫瘑娑堟伅鏁版嵁缁撴瀯\"\"\"\n    msg_type: str  # 娑堟伅绫诲瀷锛歅RE-PREPARE銆丳REPARE銆丆OMMIT\n    view: int      # 瑙嗗浘缂栧彿锛堜富鑺傜偣杞崲鏃堕€掑锛塡n    sequence: int  # 搴忓垪鍙凤紙纭繚娑堟伅鏈夊簭锛塡n    digest: str    # 鍖哄潡鎽樿锛堝搱甯屽€硷級\n    node_id: str   # 鍙戦€佹秷鎭殑鑺傜偣ID\n\nclass PBFTNode:\n    \"\"\"PBFT鑺傜偣鏁版嵁缁撴瀯\"\"\"\n    def __init__(self, node_id: str):\n        self.node_id = node_id  # 鑺傜偣ID\n        self.view = 0  # 褰撳墠瑙嗗浘缂栧彿\n        # 瀛樺偍宸叉帴鏀剁殑Prepare娑堟伅锛坘ey锛?view, sequence, digest)锛寁alue锛氭秷鎭垪琛級\n        self.prepared_messages: Dict[Tuple[int, int, str], List[PBFTMessage]] = {} \n        # 瀛樺偍宸叉帴鏀剁殑Commit娑堟伅锛坘ey锛?view, sequence, digest)锛寁alue锛氭秷鎭垪琛級\n        self.committed_messages: Dict[Tuple[int, int, str], List[PBFTMessage]] = {} \n\nclass PBFT:\n    \"\"\"瀹炵敤鎷滃崰搴閿欙紙Practical Byzantine Fault Tolerance - PBFT锛夊崗璁疄鐜癨"\"\"\n    \n    def __init__(self, num_nodes: int = 4):\n        \"\"\"鍒濆鍖朠BFT绯荤粺\n        Args:\n            num_nodes: 鑺傜偣鏁伴噺锛堥渶鈮?锛屾弧瓒硁鈮?f+1锛宖涓烘渶澶у閿欐暟锛塡n        \"\"\"\n        if num_nodes < 4:\n            raise ValueError(\"PBFT绯荤粺闇€鑷冲皯4涓妭鐐癸紙n鈮?f+1锛宖鈮?锛塡")\n        \n        self.num_nodes = num_nodes\n        self.f = (num_nodes - 1) // 3  # 鏈€澶у閿欐暟锛堟伓鎰忚妭鐐规暟锛塡n        self.nodes = [PBFTNode(f\"Node_{i}\") for i in range(num_nodes)]  # 鑺傜偣鍒楄〃\n        self.primary_index = 0  # 涓昏妭鐐圭储寮曪紙瑙嗗浘鍐呭浐瀹氾級\n        self.sequence_number = 0  # 鍏ㄥ眬搴忓垪鍙凤紙閫掑锛岀‘淇濇秷鎭敮涓€锛塡n        self.chain: List[Block] = []  # 鍖哄潡閾句富閾綷n        \n        # 鍒涘缓鍒涗笘鍖哄潡\n        genesis_block = Block(\n            index=0,\n            timestamp=time.time(),\n            transactions=[\"鍒涗笘鍖哄潡\"],\n            previous_hash=\"0\"\n        )\n        genesis_block.hash = genesis_block.compute_hash()\n        self.chain.append(genesis_block)\n        \n        print(f\"[PBFT] 绯荤粺鍒濆鍖栧畬鎴怽")\n        print(f\"[PBFT] 鑺傜偣鏁帮細{num_nodes}锛屾渶澶у閿欐暟f锛歿self.f}\")\n        print(f\"[PBFT] 褰撳墠涓昏妭鐐癸細{self.nodes[self.primary_index].node_id}\")\n    \n    def create_block(self, transactions: List[str]) -> bool:\n        \"\"\"閫氳繃PBFT涓夐樁娈靛叡璇嗗垱寤烘柊鍖哄潡\n        Args:\n            transactions: 寰呮墦鍖呯殑浜ゆ槗鍒楄〃\n        Returns:\n            鍏辫瘑鏄惁鎴愬姛锛屽尯鍧楁槸鍚︽彁浜n        \"\"\"\n        self.sequence_number += 1  # 搴忓垪鍙烽€掑\n        \n        # 1. 鏋勫缓鏂板尯鍧楀苟璁＄畻鎽樿\n        last_block = self.chain[-1]\n        new_block = Block(\n            index=len(self.chain),\n            timestamp=time.time(),\n            transactions=transactions,\n            previous_hash=last_block.hash\n        )\n        block_digest = new_block.compute_hash()  # 鍖哄潡鎽樿锛堢敤浜庢秷鎭紶閫掞級\n        current_view = self.nodes[0].view  # 褰撳墠瑙嗗浘缂栧彿锛堟墍鏈夎妭鐐硅鍥句竴鑷达級\n        \n        print(f\"\\n[PBFT] 寮€濮嬪叡璇嗘祦绋?- 瑙嗗浘锛歿current_view}锛屽簭鍒楀彿锛歿self.sequence_number}\")\n        print(f\"[PBFT] 寰呭叡璇嗗尯鍧楁憳瑕侊細{block_digest[:32]}...\")\n        \n        # 闃舵1锛歅RE-PREPARE锛堜富鑺傜偣鎻愯锛塡n        print(f\"\\n[闃舵1] PRE-PREPARE\")\n        primary_node = self.nodes[self.primary_index]\n        print(f\"[{primary_node.node_id}] 涓昏妭鐐瑰彂璧锋彁璁紝鍖哄潡鎽樿锛歿block_digest[:16]}...\")\n        # 涓昏妭鐐瑰悜鎵€鏈変粠鑺傜偣鍙戦€丳RE-PREPARE娑堟伅锛堟ā鎷熷箍鎾級\n        pre_prepare_msg = PBFTMessage(\n            msg_type=\"PRE-PREPARE\",\n            view=current_view,\n            sequence=self.sequence_number,\n            digest=block_digest,\n            node_id=primary_node.node_id\n        )\n        \n        # 闃舵2锛歅REPARE锛堜粠鑺傜偣鎶曠エ锛塡n        print(f\"\\n[闃舵2] PREPARE\")\n        prepare_count = 0  # 鏀跺埌鐨凱REPARE娑堟伅鏁癨n        prepare_key = (current_view, self.sequence_number, block_digest)\n        \n        for node in self.nodes:\n            if node.node_id == primary_node.node_id:\n                continue  # 涓昏妭鐐逛笉鍙戦€丳REPARE娑堟伅\n            \n            # 浠庤妭鐐规帴鏀禤RE-PREPARE娑堟伅鍚庯紝鍙戦€丳REPARE娑堟伅锛堟ā鎷熻瘹瀹炶妭鐐硅涓猴級\n            print(f\"[{node.node_id}] 鏀跺埌PRE-PREPARE娑堟伅锛屽彂閫丳REPARE鎶曠エ\")\n            prepare_msg = PBFTMessage(\n                msg_type=\"PREPARE\",\n                view=current_view,\n                sequence=self.sequence_number,\n                digest=block_digest,\n                node_id=node.node_id\n            )\n            \n            # 瀛樺偍PREPARE娑堟伅鍒拌妭鐐规湰鍦癨n            if prepare_key not in node.prepared_messages:\n                node.prepared_messages[prepare_key] = []\n            node.prepared_messages[prepare_key].append(prepare_msg)\n            prepare_count += 1\n        \n        # 妫€鏌REPARE娑堟伅鏄惁婊¤冻闃堝€硷紙闇€鈮?f锛岀‘淇濊瘹瀹炶妭鐐硅揪鎴愪竴鑷达級\n        required_prepare = 2 * self.f\n        if prepare_count < required_prepare:\n            print(f\"[PBFT] PREPARE娑堟伅涓嶈冻锛堟敹鍒帮細{prepare_count}锛岄渶瑕侊細{required_prepare}锛夛紝鍏辫瘑澶辫触\")\n            return False\n        print(f\"[PBFT] 鏀跺埌 {prepare_count} 涓狿REPARE娑堟伅锛堟弧瓒抽槇鍊硷細{required_prepare}锛塡")\n        \n        # 闃舵3锛欳OMMIT锛堟墍鏈夎妭鐐圭‘璁わ級\n        print(f\"\\n[闃舵3] COMMIT\")\n        commit_count = 0  # 鏀跺埌鐨凜OMMIT娑堟伅鏁癨n        commit_key = (current_view, self.sequence_number, block_digest)\n        \n        for node in self.nodes:\n            # 鑺傜偣鏀跺埌鈮?f涓狿REPARE娑堟伅鍚庯紝鍙戦€丆OMMIT娑堟伅\n            print(f\"[{node.node_id}] 鍙戦€丆OMMIT纭\")\n            commit_msg = PBFTMessage(\n                msg_type=\"COMMIT\",\n                view=current_view,\n                sequence=self.sequence_number,\n                digest=block_digest,\n                node_id=node.node_id\n            )\n            \n            # 瀛樺偍COMMIT娑堟伅鍒拌妭鐐规湰鍦癨n            if commit_key not in node.committed_messages:\n                node.committed_messages[commit_key] = []\n            node.committed_messages[commit_key].append(commit_msg)\n            commit_count += 1\n        \n        # 妫€鏌OMMIT娑堟伅鏄惁婊¤冻闃堝€硷紙闇€鈮?f+1锛岀‘淇濇渶缁堜竴鑷存€э級\n        required_commit = 2 * self.f + 1\n        if commit_count < required_commit:\n            print(f\"[PBFT] COMMIT娑堟伅涓嶈冻锛堟敹鍒帮細{commit_count}锛岄渶瑕侊細{required_commit}锛夛紝鍏辫瘑澶辫触\")\n            return False\n        print(f\"[PBFT] 鏀跺埌 {commit_count} 涓狢OMMIT娑堟伅锛堟弧瓒抽槇鍊硷細{required_commit}锛塡")\n        \n        # 鍏辫瘑杈炬垚锛屾彁浜ゅ尯鍧楀埌鍖哄潡閾綷n        new_block.hash = block_digest\n        self.chain.append(new_block)\n        print(f\"\\n[PBFT] 鍏辫瘑鎴愬姛锛佸尯鍧?#{new_block.index} 宸叉彁浜")\n        print(f\"[PBFT] 鍖哄潡鍝堝笇锛歿new_block.hash[:32]}...\")\n        return True\n    \n    def simulate_byzantine_failure(self, num_faulty: int) -> bool:\n        \"\"\"妯℃嫙鎷滃崰搴晠闅滐紙鎭舵剰鑺傜偣锛夛紝楠岃瘉绯荤粺瀹归敊鑳藉姏\n        Args:\n            num_faulty: 鎭舵剰鑺傜偣鏁伴噺\n        Returns:\n            绯荤粺鏄惁浠嶈兘姝ｅ父杈炬垚鍏辫瘑\n        \"\"\"\n        print(f\"\\n[PBFT] 妯℃嫙鎷滃崰搴晠闅?- 鎭舵剰鑺傜偣鏁帮細{num_faulty}\")\n        print(f\"[PBFT] 绯荤粺鏈€澶у閿欐暟f锛歿self.f}\")\n        \n        if num_faulty > self.f:\n            print(f\"[PBFT] 鎭舵剰鑺傜偣鏁帮紙{num_faulty}锛夎秴鍑烘渶澶у閿欐暟锛坽self.f}锛夛紝绯荤粺鏃犳硶杈炬垚鍏辫瘑\")\n            return False\n        \n        # 璁＄畻璇氬疄鑺傜偣鏁颁笌鎵€闇€COMMIT娑堟伅鏁癨n        honest_nodes = self.num_nodes - num_faulty\n        required_commit = 2 * self.f + 1\n        print(f\"[PBFT] 璇氬疄鑺傜偣鏁帮細{honest_nodes}锛屾墍闇€COMMIT娑堟伅鏁帮細{required_commit}\")\n        \n        if honest_nodes >= required_commit:\n            print(f\"[PBFT] 璇氬疄鑺傜偣鏁版弧瓒宠姹傦紝绯荤粺浠嶈兘姝ｅ父杈炬垚鍏辫瘑\")\n            return True\n        else:\n            print(f\"[PBFT] 璇氬疄鑺傜偣鏁颁笉瓒筹紝绯荤粺鏃犳硶杈炬垚鍏辫瘑\")\n            return False\n\n# 娴嬭瘯PBFT鍗忚\ndef demo_pbft():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氬疄鐢ㄦ嫓鍗犲涵瀹归敊锛圥BFT锛夊崗璁?- 鑱旂洘閾惧叡璇嗘ā鎷焅")\n    print(\"=\"*60)\n    \n    # 鍒濆鍖朠BFT绯荤粺锛?涓妭鐐癸紝鏈€澶у閿欐暟f=1锛塡n    pbft_system = PBFT(num_nodes=4)\n    \n    # 姝ラ1锛氭彁璁柊鍖哄潡锛堝寘鍚?绗斾氦鏄擄級\n    print(\"\\n[姝ラ1] 鍙戣捣鍖哄潡鍏辫瘑鎻愯\")\n    transactions = [\"浜ゆ槗1锛氬叕鍙窤 -> 鍏徃B锛?00涓嘰", \"浜ゆ槗2锛氬叕鍙窩 -> 鍏徃D锛?0涓嘰"]\n    consensus_success = pbft_system.create_block(transactions)\n    \n    # 姝ラ2锛氭ā鎷?涓伓鎰忚妭鐐癸紙鍦ㄥ閿欒寖鍥村唴锛塡n    print(\"\\n[姝ラ2] 妯℃嫙1涓嫓鍗犲涵鎭舵剰鑺傜偣\")\n    can_work_with_1fault = pbft_system.simulate_byzantine_failure(num_faulty=1)\n    \n    # 姝ラ3锛氭ā鎷?涓伓鎰忚妭鐐癸紙瓒呭嚭瀹归敊鑼冨洿锛塡n    print(\"\\n[姝ラ3] 妯℃嫙2涓嫓鍗犲涵鎭舵剰鑺傜偣\")\n    can_work_with_2fault = pbft_system.simulate_byzantine_failure(num_faulty=2)\n    \n    # 姝ラ4锛氭墦鍗板尯鍧楅摼鐘舵€乗n    print(\"\\n[鍖哄潡閾剧姸鎬佹瑙圿\")\n    for block in pbft_system.chain:\n        print(f\"- 鍖哄潡 #{block.index}: 鍝堝笇={block.hash[:16]}..., 浜ゆ槗鏁?{len(block.transactions)}\")\n    \n    print(\"\\n[PBFT鍗忚鏍稿績鐗圭偣]\")\n    print(\"  1. 鎷滃崰搴閿欙細鍙蹇嶆渶澶歠=(n-1)/3涓伓鎰忚妭鐐癸紙n涓烘€昏妭鐐规暟锛塡")\n    print(\"  2. 寮烘渶缁堟€э細涓€鏃﹀叡璇嗚揪鎴愶紝鍖哄潡涓嶅彲閫嗭紝鏃犲洖婊氶闄‐")\n    print(\"  3. 浣庡欢杩熼珮鍚炲悙锛氭棤闇€鎸栫熆锛岄€氳繃涓夐樁娈垫姇绁ㄥ揩閫熻揪鎴愬叡璇哱")\n    print(\"  4. 璁稿彲閾惧満鏅細閫傜敤浜庤仈鐩熼摼/绉佹湁閾撅紙鑺傜偣闇€韬唤楠岃瘉锛塡")\n    print(\"  5. 閫氫俊寮€閿€锛氳妭鐐归棿闇€澶ч噺娑堟伅浜や簰锛岄€傚悎灏忚妯¤妭鐐归泦缇")\n    \n    # 楠岃瘉缁撴灉锛氬叡璇嗘垚鍔?+ 1涓晠闅滃彲宸ヤ綔 + 2涓晠闅滀笉鍙伐浣淺n    return consensus_success and can_work_with_1fault and not can_work_with_2fault\n\n# 鎵цPBFT娴嬭瘯\ndemo_pbft()'),(132,18,6,'涓绘祦鍏辫瘑鍗忚瀵规瘮涓庡満鏅€傞厤鍒嗘瀽','1. 鏍稿績缁村害瀵规瘮锛歕n   - 鍘讳腑蹇冨寲绋嬪害锛歅oW > PoS > DPoS > PBFT > PoA\n   - 鎬ц兘锛圱PS锛夛細PBFT > PoS/DPoS > PoW\n   - 鑳借€楋細PoW锛堟瀬楂橈級> 鍏朵粬锛堟瀬浣庯級\n   - 鏈€缁堟€э細PBFT/PoA锛堝己鏈€缁堟€э級> PoS锛堢粡娴庢渶缁堟€э級> PoW锛堟鐜囨渶缁堟€э級\n   - 瀹归敊鎬э細PBFT锛堟嫓鍗犲涵瀹归敊锛? PoW/PoS锛堝穿婧冨閿?閮ㄥ垎鎭舵剰瀹归敊锛塡n   - 閫傜敤鍦烘櫙锛歅oW锛堝叕閾撅紝濡傛瘮鐗瑰竵锛夈€丳oS锛堝叕閾撅紝濡備互澶潑2.0锛夈€丳BFT锛堣仈鐩熼摼锛屽Hyperledger Fabric锛夈€丳oA锛堢鏈夐摼锛屽浼佷笟鍐呴儴閾撅級\n2. 鏁板鏈哄埗瀵规瘮锛歕n   - PoW锛氬熀浜庡搱甯屽嚱鏁伴毦瑙ｆ€э紙鎵緉once锛塡n   - PoS锛氬熀浜庢潈鐩婂姞鏉冩鐜囷紙缁忔祹婵€鍔辩害鏉燂級\n   - PBFT锛氬熀浜庝笁闃舵鎶曠エ锛坣鈮?f+1鎷滃崰搴閿欙級\n3. 鎶€鏈€夊瀷瑕佺偣锛歕n   - 鍏摼锛氫紭鍏堣€冭檻鍘讳腑蹇冨寲涓庡畨鍏ㄦ€э紝閫夋嫨PoW/PoS锛堥渶骞宠　鎬ц兘锛塡n   - 鑱旂洘閾撅細浼樺厛鑰冭檻鎬ц兘涓庡彲鎺ф€э紝閫夋嫨PBFT锛堣妭鐐瑰彲淇′絾闇€瀹归敊锛塡n   - 绉佹湁閾撅細浼樺厛鑰冭檻鏁堢巼涓庢潈闄愮鐞嗭紝閫夋嫨PoA锛堣妭鐐瑰畬鍏ㄥ彲淇★級\n4. 鍙戝睍瓒嬪娍锛氭贩鍚堝叡璇嗭紙濡侾oW+PoS銆丳oH+PoS锛夈€佸垎鐗囨妧鏈紙鎻愬崌PoW/PoS鎬ц兘锛夈€佽交閲忓寲BFT锛堥檷浣庨€氫俊寮€閿€锛夈€俓n棰勬湡杈撳嚭锛氬舰鎴愭竻鏅扮殑鍏辫瘑鍗忚閫夊瀷妗嗘灦锛岃兘鏍规嵁瀹為檯鍦烘櫙锛堝叕閾?鑱旂洘閾?绉佹湁閾撅級閫夋嫨鏈€浼樺崗璁€?,'瀹為檯鍖哄潡閾鹃」鐩父缁撳悎澶氱鎶€鏈紭鍖栧叡璇嗗崗璁紙濡備互澶潑鍚堝苟PoW+PoS锛孲olana缁撳悎PoH+PoS锛夛紝闇€鍏虫敞鍗忚鐨勬紨杩涗笌铻嶅悎瓒嬪娍',NULL),(133,19,1,'鐜鍑嗗涓庢牳蹇冩蹇垫⒊鐞?,'1. 鐜閰嶇疆锛氱‘淇漃ython 3.7+鐜锛屽畨瑁呬緷璧栧簱锛坈ryptography鐢ㄤ簬鏁板瓧绛惧悕锛屽彲閫塸ycryptodome鐢ㄤ簬Keccak鍝堝笇锛夛紝鎵ц鍛戒护锛歱ip install cryptography pycryptodome銆俓n2. 鏍稿績姒傚康鍥為【锛氭暟瀛楄揣甯佷袱澶ц璐︽ā鍨嬶紙UTXO/璐︽埛妯″瀷锛夈€佷氦鏄撲笁瑕佺礌锛堝畬鏁存€с€佺湡瀹炴€с€佷笉鍙惁璁ゆ€э級銆佹暟瀛楃鍚嶏紙ECDSA锛夈€佹櫤鑳藉悎绾︼紙鑷姩鎵ц銆佷笉鍙鏀癸級銆俓n3. 鐩爣鏄庣‘锛氭湰瀹為獙鑱氱劍姣旂壒甯乁TXO妯″瀷銆佷互澶潑璐︽埛妯″瀷鐨勫疄鐜帮紝浠ュ強ERC-20鏅鸿兘鍚堢害鐨勬牳蹇冨姛鑳斤紝鐞嗚В涓嶅悓妯″瀷鐨勮璁″彇鑸嶃€俓n棰勬湡杈撳嚭锛氭棤鎶ラ敊纭渚濊禆搴撳畨瑁呮垚鍔燂紝娓呮櫚姊崇悊涓ゅぇ妯″瀷鐨勬牳蹇冨樊寮傘€?,'cryptography搴撶敤浜庡疄鐜版爣鍑咵CDSA绛惧悕锛宲ycryptodome鐢ㄤ簬妯℃嫙浠ュお鍧奒eccak-256鍝堝笇锛岃嫢瀹夎澶辫触鍙娇鐢╯ha256鏇夸唬锛堟暀瀛﹀満鏅笉褰卞搷鏍稿績閫昏緫锛?,NULL),(134,19,2,'鏍稿績鏁版嵁缁撴瀯璁捐','1. 瀹氫箟UTXO鐩稿叧缁撴瀯锛歕n   - UTXO绫伙細瀛樺偍鏈姳璐逛氦鏄撹緭鍑虹殑鏍稿績淇℃伅锛堜氦鏄揑D銆佽緭鍑虹储寮曘€侀噾棰濄€佹帴鏀跺湴鍧€銆侀攣瀹氳剼鏈級銆俓n   - TransactionInput绫伙細浜ゆ槗杈撳叆锛堝紩鐢ㄥ墠搴廢TXO鐨勪氦鏄揑D銆佽緭鍑虹储寮曘€佽В閿佽剼鏈?绛惧悕锛夈€俓n   - TransactionOutput绫伙細浜ゆ槗杈撳嚭锛堥噾棰濄€佹帴鏀跺湴鍧€銆侀攣瀹氳剼鏈級銆俓n2. 瀹氫箟璐︽埛妯″瀷鐩稿叧缁撴瀯锛歕n   - EthereumAccount绫伙細浠ュお鍧婅处鎴凤紙鍦板潃銆佷綑棰濄€乶once銆佸悎绾︿唬鐮併€佸瓨鍌級銆俓n   - EthereumTransaction绫伙細浠ュお鍧婁氦鏄擄紙鍙戦€佸湴鍧€銆佹帴鏀跺湴鍧€銆侀噾棰濄€乶once銆丟as鍙傛暟銆佹暟鎹€佺鍚嶏級銆俓n3. 鏍稿績浣滅敤锛氭暟鎹粨鏋勬槸搴曞眰閫昏緫鐨勫熀纭€锛岄渶纭繚瀛楁瀹屾暣鎬т笌閫昏緫涓€鑷存€э紝璐村悎鐪熷疄鏁板瓧璐у竵鍗忚璁捐銆俓n棰勬湡杈撳嚭锛氭墍鏈夋暟鎹被鍙甯稿疄渚嬪寲锛屽瓧娈靛惈涔夋竻鏅帮紝鏀寔鍚庣画浜ゆ槗鍒涘缓涓庣姸鎬佺鐞嗐€?,NULL,'import hashlib\nimport time\nimport json\nimport secrets\nfrom typing import List, Dict, Optional, Tuple\nfrom dataclasses import dataclass, field\nfrom cryptography.hazmat.primitives.asymmetric import ec\nfrom cryptography.hazmat.primitives import hashes, serialization\nfrom cryptography.hazmat.backends import default_backend\n\n# ====================== UTXO妯″瀷鏍稿績鏁版嵁缁撴瀯 ======================\n@dataclass\nclass UTXO:\n    \"\"\"鏈姳璐逛氦鏄撹緭鍑猴紙Unspent Transaction Output锛? 姣旂壒甯佹牳蹇冩暟鎹粨鏋刓"\"\"\n    txid: str  # 鎵€灞炰氦鏄揑D\n    vout: int  # 浜ゆ槗杈撳嚭绱㈠紩锛堜竴涓氦鏄撳彲鍖呭惈澶氫釜杈撳嚭锛塡n    amount: float  # 閲戦锛圔TC锛塡n    address: str  # 鎺ユ敹鍦板潃锛堟帶鍒惰UTXO鐨勫叕閽ュ搱甯岋級\n    scriptPubKey: str  # 閿佸畾鑴氭湰锛堥渶婊¤冻鑴氭湰鏉′欢鎵嶈兘鑺辫垂璇TXO锛塡n    \n    def __repr__(self):\n        return f\"UTXO(txid={self.txid[:8]}..., vout={self.vout}, amount={self.amount} BTC)\"\n\n@dataclass\nclass TransactionInput:\n    \"\"\"浜ゆ槗杈撳叆 - 寮曠敤鍓嶅簭UTXO骞舵彁渚涜В閿佸嚟璇乗"\"\"\n    prev_txid: str  # 寮曠敤鐨勫墠搴忎氦鏄揑D\n    vout: int  # 寮曠敤鐨勫墠搴忎氦鏄撹緭鍑虹储寮昞n    scriptSig: str  # 瑙ｉ攣鑴氭湰锛堝寘鍚鍚?鍏挜锛岀敤浜庨獙璇乁TXO鎵€鏈夋潈锛塡n    \n    def __repr__(self):\n        return f\"TxIn(prev_txid={self.prev_txid[:8]}..., vout={self.vout})\")\n\n@dataclass\nclass TransactionOutput:\n    \"\"\"浜ゆ槗杈撳嚭 - 鍒涘缓鏂扮殑UTXO\"\"\"\n    amount: float  # 閲戦锛圔TC锛塡n    address: str  # 鎺ユ敹鍦板潃\n    scriptPubKey: str  # 閿佸畾鑴氭湰锛堝锛歄P_DUP OP_HASH160 {address} OP_EQUALVERIFY OP_CHECKSIG锛塡n    \n    def __repr__(self):\n        return f\"TxOut(amount={self.amount} BTC, address={self.address[:8]}...)\")\n\n@dataclass\nclass BitcoinTransaction:\n    \"\"\"姣旂壒甯佷氦鏄撶粨鏋刓"\"\"\n    txid: str  # 浜ゆ槗ID锛堢敱浜ゆ槗鏁版嵁鍝堝笇鐢熸垚锛塡n    version: int  # 鍗忚鐗堟湰\n    inputs: List[TransactionInput]  # 浜ゆ槗杈撳叆鍒楄〃\n    outputs: List[TransactionOutput]  # 浜ゆ槗杈撳嚭鍒楄〃\n    locktime: int  # 浜ゆ槗鐢熸晥鏃堕棿锛?琛ㄧず绔嬪嵆鐢熸晥锛塡n    timestamp: float  # 浜ゆ槗鍒涘缓鏃堕棿鎴砛n    \n    def compute_txid(self) -> str:\n        \"\"\"璁＄畻浜ゆ槗ID锛堝弻SHA256鍝堝笇锛屾瘮鐗瑰竵鏍囧噯锛塡"\"\"\n        tx_data = {\n            \'version\': self.version,\n            \'inputs\': [{\'prev_txid\': inp.prev_txid, \'vout\': inp.vout} for inp in self.inputs],\n            \'outputs\': [{\'amount\': out.amount, \'address\': out.address} for out in self.outputs],\n            \'locktime\': self.locktime\n        }\n        # 搴忓垪鍖栧苟璁＄畻鍙孲HA256鍝堝笇\n        tx_string = json.dumps(tx_data, sort_keys=True).encode()\n        return hashlib.sha256(hashlib.sha256(tx_string).digest()).hexdigest()\n\n# ====================== 璐︽埛妯″瀷鏍稿績鏁版嵁缁撴瀯 ======================\n@dataclass\nclass EthereumAccount:\n    \"\"\"浠ュお鍧婅处鎴风粨鏋勶紙澶栭儴璐︽埛EOA/鍚堢害璐︽埛CA锛塡"\"\"\n    address: str  # 璐︽埛鍦板潃锛?x鍓嶇紑锛塡n    balance: float = 0.0  # 浣欓锛圗TH锛塡n    nonce: int = 0  # 浜ゆ槗璁℃暟鍣紙闃查噸鏀炬敾鍑伙紝姣忕瑪浜ゆ槗閫掑锛塡n    code: str = \"\"  # 鍚堢害瀛楄妭鐮侊紙EOA涓虹┖锛孋A涓哄悎绾︿唬鐮侊級\n    storage: Dict[str, any] = field(default_factory=dict)  # 鍚堢害瀛樺偍锛堥敭鍊煎锛塡n    \n    def is_contract(self) -> bool:\n        \"\"\"鍒ゆ柇鏄惁涓哄悎绾﹁处鎴穃"\"\"\n        return len(self.code) > 0\n\n@dataclass\nclass EthereumTransaction:\n    \"\"\"浠ュお鍧婁氦鏄撶粨鏋刓"\"\"\n    tx_hash: str  # 浜ゆ槗鍝堝笇\n    from_address: str  # 鍙戦€佸湴鍧€\n    to_address: str  # 鎺ユ敹鍦板潃锛堝悎绾﹀湴鍧€鎴栧閮ㄨ处鎴峰湴鍧€锛塡n    value: float  # 杞处閲戦锛圗TH锛塡n    gas_limit: int  # Gas涓婇檺锛堟渶澶ц绠楁鏁帮級\n    gas_price: float  # 鍗曚綅Gas浠锋牸锛圗TH/Gas锛塡n    nonce: int  # 鍙戦€佽€卬once\n    data: str = \"\"  # 浜ゆ槗鏁版嵁锛堝悎绾﹁皟鐢ㄦ椂瀛樺偍鍑芥暟鍚?鍙傛暟锛塡n    timestamp: float = 0.0  # 鏃堕棿鎴砛n    signature: str = \"\"  # 鏁板瓧绛惧悕锛坴,r,s鐨勫崄鍏繘鍒惰〃绀猴級\n    \n    def compute_hash(self) -> str:\n        \"\"\"璁＄畻浜ゆ槗鍝堝笇锛堜互澶潑浣跨敤Keccak-256锛塡"\"\"\n        tx_data = {\n            \'from\': self.from_address,\n            \'to\': self.to_address,\n            \'value\': self.value,\n            \'nonce\': self.nonce,\n            \'gas_limit\': self.gas_limit,\n            \'gas_price\': self.gas_price,\n            \'data\': self.data\n        }\n        tx_string = json.dumps(tx_data, sort_keys=True).encode()\n        \n        # 浼樺厛浣跨敤Keccak-256锛堜互澶潑鏍囧噯锛夛紝鑻ユ棤鍒欑敤SHA256鏇夸唬\n        try:\n            from Crypto.Hash import keccak\n            k = keccak.new(digest_bits=256)\n            k.update(tx_string)\n            return \"0x\" + k.hexdigest()\n        except ImportError:\n            print(\"[璀﹀憡] 鏈畨瑁卲ycryptodome锛屼娇鐢⊿HA256鏇夸唬Keccak-256锛堜粎鏁欏浣跨敤锛塡")\n            return \"0x\" + hashlib.sha256(tx_string).hexdigest()\n\n# 娴嬭瘯鏁版嵁缁撴瀯\ndef test_data_structures():\n    \"\"\"娴嬭瘯鏍稿績鏁版嵁缁撴瀯瀹炰緥鍖朶"\"\"\n    # 娴嬭瘯UTXO\n    utxo = UTXO(txid=secrets.token_hex(32), vout=0, amount=0.5, address=\"1Alice...\", scriptPubKey=\"OP_DUP...\")\n    print(f\"UTXO娴嬭瘯锛歿utxo}\")\n    \n    # 娴嬭瘯姣旂壒甯佷氦鏄揬n    tx_input = TransactionInput(prev_txid=utxo.txid, vout=0, scriptSig=\"绛惧悕鏁版嵁...\")\n    tx_output = TransactionOutput(amount=0.4, address=\"1Bob...\", scriptPubKey=\"OP_DUP...\")\n    btc_tx = BitcoinTransaction(txid=\"\", version=1, inputs=[tx_input], outputs=[tx_output], locktime=0, timestamp=time.time())\n    btc_tx.txid = btc_tx.compute_txid()\n    print(f\"姣旂壒甯佷氦鏄撴祴璇曪細TXID={btc_tx.txid[:16]}...\")\n    \n    # 娴嬭瘯浠ュお鍧婅处鎴蜂笌浜ゆ槗\n    eth_account = EthereumAccount(address=\"0xAlice...\", balance=10.0)\n    eth_tx = EthereumTransaction(\n        tx_hash=\"\",\n        from_address=eth_account.address,\n        to_address=\"0xBob...\",\n        value=3.0,\n        gas_limit=21000,\n        gas_price=2e-8,\n        nonce=eth_account.nonce\n    )\n    eth_tx.tx_hash = eth_tx.compute_hash()\n    print(f\"浠ュお鍧婁氦鏄撴祴璇曪細TxHash={eth_tx.tx_hash[:18]}...\")\n    \n    return True\n\n# 鎵ц鏁版嵁缁撴瀯娴嬭瘯\ntest_data_structures()'),(135,19,3,'姣旂壒甯乁TXO妯″瀷瀹炵幇涓庢祴璇?,'1. 鏍稿績鍘熺悊锛歎TXO妯″瀷鏃犺处鎴锋蹇碉紝鐢ㄦ埛浣欓=鍏舵帶鍒剁殑鎵€鏈夋湭鑺辫垂浜ゆ槗杈撳嚭锛圲TXO锛夐噾棰濅箣鍜岋紙Balance(U)=危v_i锛寁_i涓篣TXO閲戦锛夛紱浜ゆ槗鐢辫緭鍏ワ紙寮曠敤UTXO锛夊拰杈撳嚭锛堝垱寤烘柊UTXO锛夌粍鎴愶紝闇€婊¤冻危v_in=危v_out+fee锛堥槻姝㈠嚟绌洪€犲竵锛夛紝杈撳叆闇€閫氳繃绛惧悕楠岃瘉鎵€鏈夋潈銆俓n2. 瀹炵幇BitcoinWallet绫伙細\n   - 鍒濆鍖栨柟娉曪細鐢熸垚ECDSA瀵嗛挜瀵广€佸瓨鍌ㄩ挶鍖呭湴鍧€銆佸垵濮嬪寲UTXO闆嗗悎銆俓n   - get_balance鏂规硶锛氳绠椾綑棰濓紙鎵€鏈塙TXO閲戦涔嬪拰锛夈€俓n   - add_utxo鏂规硶锛氭坊鍔犳敹鍒扮殑UTXO鍒版湰鍦伴泦鍚堛€俓n   - select_utxos鏂规硶锛氶€夋嫨瓒冲閲戦鐨刄TXO锛堢畝鍗曠疮鍔犵瓥鐣ワ級銆俓n   - create_transaction鏂规硶锛氬垱寤轰氦鏄擄紙杈撳叆閫夋嫨銆佽緭鍑虹敓鎴愩€佹壘闆惰绠椼€佺鍚嶏級銆俓n   - _sign_input鏂规硶锛氬浜ゆ槗杈撳叆杩涜ECDSA绛惧悕锛堢‘淇濇墍鏈夋潈锛夈€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_bitcoin_utxo锛氭ā鎷烝lice鍚態ob杞处鍦烘櫙锛屽寘鍚玌TXO鎺ユ敹銆佷氦鏄撳垱寤恒€佹壘闆舵満鍒躲€佷綑棰濇洿鏂般€俓n棰勬湡杈撳嚭锛氭墦鍗伴挶鍖呭垱寤恒€乁TXO鎺ユ敹銆佷氦鏄撹鎯咃紙杈撳叆/杈撳嚭/鎵鹃浂/鐭垮伐璐癸級銆佹渶缁堜綑棰濓紝楠岃瘉UTXO妯″瀷鐨勬牳蹇冮€昏緫姝ｇ‘鎬с€?,'UTXO妯″瀷鐨勬牳蹇冩槸鈥滆緭鍏ュ紩鐢ㄨ緭鍑猴紝杈撳嚭鎴愪负鏂癠TXO鈥濓紝闇€纭繚姣忎釜UTXO鍙兘琚姳璐逛竴娆★紝鎵鹃浂鏈哄埗鏄疄鐜伴儴鍒嗘敮浠樼殑鍏抽敭','class BitcoinWallet:\n    \"\"\"姣旂壒甯侀挶鍖咃紙UTXO妯″瀷瀹炵幇锛塡"\"\"\n    \n    def __init__(self, address: str):\n        \"\"\"鍒濆鍖栭挶鍖匼n        Args:\n            address: 閽卞寘鍦板潃锛堝叕閽ュ搱甯岀殑浜虹被鍙褰㈠紡锛塡n        \"\"\"\n        self.address = address\n        self.utxos: List[UTXO] = []  # 閽卞寘鎺у埗鐨刄TXO闆嗗悎\n        \n        # 鐢熸垚ECDSA瀵嗛挜瀵癸紙secp256k1鏇茬嚎锛屾瘮鐗瑰竵鏍囧噯锛塡n        self.private_key = ec.generate_private_key(ec.SECP256K1(), default_backend())\n        self.public_key = self.private_key.public_key()\n        \n        # 搴忓垪鍖栧叕閽ワ紙鐢ㄤ簬楠岃瘉绛惧悕锛塡n        self.public_key_hex = self.public_key.public_bytes(\n            encoding=serialization.Encoding.PEM,\n            format=serialization.PublicFormat.SubjectPublicKeyInfo\n        ).hex()\n        \n        print(f\"[Bitcoin] 閽卞寘鍒涘缓鎴愬姛锛氬湴鍧€={self.address[:16]}...\")\n    \n    def get_balance(self) -> float:\n        \"\"\"璁＄畻閽卞寘浣欓锛堟墍鏈塙TXO閲戦涔嬪拰锛塡"\"\"\n        return sum(utxo.amount for utxo in self.utxos)\n    \n    def add_utxo(self, utxo: UTXO):\n        \"\"\"娣诲姞UTXO鍒伴挶鍖咃紙鏀跺埌杞处鏃惰皟鐢級\"\"\"\n        if utxo.address != self.address:\n            print(f\"[Bitcoin] 鎷掔粷娣诲姞UTXO锛氬湴鍧€涓嶅尮閰峔")\n            return\n        self.utxos.append(utxo)\n        print(f\"[Bitcoin] 鏀跺埌UTXO锛歿utxo.amount} BTC锛屽綋鍓嶄綑棰?{self.get_balance()} BTC\")\n    \n    def select_utxos(self, required_amount: float) -> List[UTXO]:\n        \"\"\"閫夋嫨瓒冲閲戦鐨刄TXO锛堢畝鍗曠疮鍔犵瓥鐣ワ級\n        Args:\n            required_amount: 闇€瑕佺殑鎬婚噾棰濓紙鍖呭惈鐭垮伐璐癸級\n        Returns:\n            閫変腑鐨刄TXO鍒楄〃\n        \"\"\"\n        selected_utxos = []\n        total = 0.0\n        \n        # 閬嶅巻UTXO锛岀疮鍔犵洿鍒版弧瓒虫墍闇€閲戦\n        for utxo in self.utxos:\n            selected_utxos.append(utxo)\n            total += utxo.amount\n            if total >= required_amount:\n                break\n        \n        if total < required_amount:\n            raise ValueError(f\"[Bitcoin] 浣欓涓嶈冻锛氶渶瑕亄required_amount} BTC锛屽綋鍓嶅彲鐢▄total} BTC\")\n        \n        print(f\"[Bitcoin] 閫変腑UTXO锛歿len(selected_utxos)}涓紝鎬婚噾棰?{total} BTC\")\n        return selected_utxos\n    \n    def _sign_input(self, utxo: UTXO) -> str:\n        \"\"\"瀵筓TXO杩涜ECDSA绛惧悕锛堣瘉鏄庢墍鏈夋潈锛塡n        Args:\n            utxo: 瑕佽姳璐圭殑UTXO\n        Returns:\n            鍗佸叚杩涘埗缂栫爜鐨勭鍚峔n        \"\"\"\n        # 绛惧悕娑堟伅锛歎TXO鐨勫敮涓€鏍囪瘑锛坱xid + vout锛塡n        message = f\"{utxo.txid}{utxo.vout}\".encode()\n        \n        # ECDSA绛惧悕锛坰ecp256k1鏇茬嚎 + SHA256鍝堝笇锛塡n        signature = self.private_key.sign(\n            message,\n            ec.ECDSA(hashes.SHA256())\n        )\n        return signature.hex()\n    \n    def create_transaction(self, to_address: str, amount: float, fee: float = 0.0001) -> BitcoinTransaction:\n        \"\"\"鍒涘缓姣旂壒甯佷氦鏄揬n        Args:\n            to_address: 鎺ユ敹鍦板潃\n            amount: 杞处閲戦锛圔TC锛塡n            fee: 鐭垮伐璐癸紙BTC锛塡n        Returns:\n            浜ゆ槗瀵硅薄\n        \"\"\"\n        # 璁＄畻鎵€闇€鎬婚噾棰濓紙杞处閲戦 + 鐭垮伐璐癸級\n        total_required = amount + fee\n        \n        # 閫夋嫨UTXO\n        selected_utxos = self.select_utxos(total_required)\n        total_input = sum(utxo.amount for utxo in selected_utxos)\n        \n        # 鍒涘缓浜ゆ槗杈撳叆锛氭瘡涓€変腑鐨刄TXO瀵瑰簲涓€涓緭鍏ワ紝鍖呭惈绛惧悕\n        tx_inputs = []\n        for utxo in selected_utxos:\n            signature = self._sign_input(utxo)\n            tx_input = TransactionInput(\n                prev_txid=utxo.txid,\n                vout=utxo.vout,\n                scriptSig=signature  # 瑙ｉ攣鑴氭湰=绛惧悕\n            )\n            tx_inputs.append(tx_input)\n        \n        # 鍒涘缓浜ゆ槗杈撳嚭锛?涓敮浠樿緭鍑?+ 1涓壘闆惰緭鍑猴紙鑻ユ湁锛塡n        tx_outputs = []\n        # 1. 鏀粯杈撳嚭锛堢粰鎺ユ敹鏂癸級\n        tx_outputs.append(TransactionOutput(\n            amount=amount,\n            address=to_address,\n            scriptPubKey=f\"OP_DUP OP_HASH160 {to_address} OP_EQUALVERIFY OP_CHECKSIG\"\n        ))\n        # 2. 鎵鹃浂杈撳嚭锛堝墿浣欓噾棰濊繑鍥炶嚜宸憋級\n        change = total_input - amount - fee\n        if change > 0:\n            tx_outputs.append(TransactionOutput(\n                amount=change,\n                address=self.address,\n                scriptPubKey=f\"OP_DUP OP_HASH160 {self.address} OP_EQUALVERIFY OP_CHECKSIG\"\n            ))\n        \n        # 鍒涘缓浜ゆ槗瀵硅薄\n        tx = BitcoinTransaction(\n            txid=\"\",\n            version=1,\n            inputs=tx_inputs,\n            outputs=tx_outputs,\n            locktime=0,\n            timestamp=time.time()\n        )\n        # 璁＄畻浜ゆ槗ID\n        tx.txid = tx.compute_txid()\n        \n        # 绉婚櫎宸茶姳璐圭殑UTXO锛堥槻姝㈠弻閲嶆敮浠橈級\n        for utxo in selected_utxos:\n            self.utxos.remove(utxo)\n        \n        # 鎵撳嵃浜ゆ槗璇︽儏\n        print(f\"\\n[Bitcoin] 浜ゆ槗鍒涘缓鎴愬姛锛歕")\n        print(f\"  TXID: {tx.txid[:16]}...\")\n        print(f\"  杈撳叆锛歿len(tx_inputs)}涓猆TXO锛屾€婚噾棰?{total_input} BTC\")\n        print(f\"  杈撳嚭1锛歿amount} BTC -> {to_address[:16]}...\")\n        if change > 0:\n            print(f\"  杈撳嚭2锛歿change:.6f} BTC -> {self.address[:16]}...锛堟壘闆讹級\")\n        print(f\"  鐭垮伐璐癸細{fee} BTC\")\n        print(f\"  鍓╀綑浣欓锛歿self.get_balance()} BTC\")\n        \n        return tx\n\n# 娴嬭瘯UTXO妯″瀷\ndef demo_bitcoin_utxo():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氭瘮鐗瑰竵UTXO妯″瀷 - Alice鍚態ob杞处\")\n    print(\"=\"*60)\n    \n    # 姝ラ1锛氬垱寤篈lice鍜孊ob鐨勯挶鍖匼n    print(\"\\n[姝ラ1] 鍒涘缓閽卞寘\")\n    alice_wallet = BitcoinWallet(\"1Alice_address_1234567890abcdef\")\n    bob_wallet = BitcoinWallet(\"1Bob_address_abcdef1234567890\")\n    \n    # 姝ラ2锛欰lice鑾峰緱鍒濆UTXO锛堟ā鎷熸寲鐭挎垨浠栦汉杞处锛塡n    print(\"\\n[姝ラ2] Alice鎺ユ敹鍒濆UTXO\")\n    utxo1 = UTXO(\n        txid=secrets.token_hex(32),  # 闅忔満鐢熸垚浜ゆ槗ID\n        vout=0,\n        amount=0.5,\n        address=alice_wallet.address,\n        scriptPubKey=f\"OP_DUP OP_HASH160 {alice_wallet.address} OP_EQUALVERIFY OP_CHECKSIG\"\n    )\n    utxo2 = UTXO(\n        txid=secrets.token_hex(32),\n        vout=1,\n        amount=0.8,\n        address=alice_wallet.address,\n        scriptPubKey=f\"OP_DUP OP_HASH160 {alice_wallet.address} OP_EQUALVERIFY OP_CHECKSIG\"\n    )\n    alice_wallet.add_utxo(utxo1)\n    alice_wallet.add_utxo(utxo2)\n    print(f\"[Bitcoin] Alice褰撳墠浣欓锛歿alice_wallet.get_balance()} BTC\")\n    \n    # 姝ラ3锛欰lice鍚態ob杞处1.0 BTC锛堝寘鍚?.0001 BTC鐭垮伐璐癸級\n    print(\"\\n[姝ラ3] Alice鍚態ob杞处1.0 BTC\")\n    tx = alice_wallet.create_transaction(bob_wallet.address, amount=1.0, fee=0.0001)\n    \n    # 姝ラ4锛欱ob鎺ユ敹浜ゆ槗杈撳嚭锛堟坊鍔燯TXO锛塡n    print(\"\\n[姝ラ4] Bob鎺ユ敹杞处\")\n    for idx, output in enumerate(tx.outputs):\n        if output.address == bob_wallet.address:\n            # 涓築ob鍒涘缓UTXO\n            bob_utxo = UTXO(\n                txid=tx.txid,\n                vout=idx,\n                amount=output.amount,\n                address=output.address,\n                scriptPubKey=output.scriptPubKey\n            )\n            bob_wallet.add_utxo(bob_utxo)\n        elif output.address == alice_wallet.address:\n            # Alice鐨勬壘闆禪TXO锛岄噸鏂版坊鍔犲埌濂圭殑閽卞寘\n            alice_change_utxo = UTXO(\n                txid=tx.txid,\n                vout=idx,\n                amount=output.amount,\n                address=output.address,\n                scriptPubKey=output.scriptPubKey\n            )\n            alice_wallet.add_utxo(alice_change_utxo)\n    \n    # 姝ラ5锛氭墦鍗版渶缁堜綑棰漒n    print(\"\\n[姝ラ5] 鏈€缁堜綑棰漒")\n    print(f\"Alice锛歿alice_wallet.get_balance():.6f} BTC\")\n    print(f\"Bob锛歿bob_wallet.get_balance():.6f} BTC\")\n    \n    # 鎬荤粨UTXO妯″瀷鐗圭偣\n    print(\"\\n[UTXO妯″瀷鏍稿績鐗圭偣]\")\n    print(\"  1. 鏃犺处鎴锋蹇碉細浣欓=鎺у埗鐨刄TXO閲戦涔嬪拰\")\n    print(\"  2. 浜ゆ槗鍘熷瓙鎬э細杈撳叆蹇呴』瀹屽叏鑺辫垂锛岄€氳繃鎵鹃浂瀹炵幇閮ㄥ垎鏀粯\")\n    print(\"  3. 闅愮鎬э細鍙娇鐢ㄦ柊鍦板潃鎺ユ敹姣忕瑪杞处锛岄毦浠ヨ拷韪韩浠絓")\n    print(\"  4. 骞惰楠岃瘉锛氬绗斾氦鏄撳彲骞惰楠岃瘉锛屾棤闇€閿佽处鎴穃")\n    print(\"  5. 瀹夊叏鎬э細鍙岄噸鏀粯閫氳繃UTXO鏍囪宸茶姳璐归槻姝")\n    \n    return True\n\n# 鎵цUTXO妯″瀷娴嬭瘯\ndemo_bitcoin_utxo()'),(136,19,4,'浠ュお鍧婅处鎴锋ā鍨嬪疄鐜颁笌娴嬭瘯','1. 鏍稿績鍘熺悊锛氫互澶潑閲囩敤璐︽埛妯″瀷锛岀郴缁熺姸鎬佹槸鍏ㄥ眬璐︽埛鏄犲皠锛圫=(address,balance,nonce,storage,code)锛夛紱浜ゆ槗鐩存帴淇敼璐︽埛浣欓锛宯once鐢ㄤ簬闃叉閲嶆斁鏀诲嚮锛堟瘡绗斾氦鏄搉once閫掑锛夛紱Gas鏈哄埗鎺у埗璁＄畻璧勬簮娑堣€楋紙Gas=GasLimit脳GasPrice锛夈€俓n2. 瀹炵幇EthereumWallet绫伙細\n   - 鍒濆鍖栨柟娉曪細鐢熸垚ECDSA瀵嗛挜瀵广€佸垱寤轰互澶潑璐︽埛锛圗OA锛夈€佸垵濮嬪寲浣欓涓巒once銆俓n   - get_balance鏂规硶锛氳幏鍙栬处鎴蜂綑棰濄€俓n   - deposit鏂规硶锛氭ā鎷熷瓨鍏TH锛堟祴璇曠敤锛夈€俓n   - create_transaction鏂规硶锛氬垱寤轰互澶潑浜ゆ槗锛堣绠桮as璐圭敤銆侀獙璇佷綑棰濄€佺鍚嶃€佹洿鏂皀once锛夈€俓n   - _sign_transaction鏂规硶锛氬浜ゆ槗杩涜ECDSA绛惧悕锛堢敓鎴恦,r,s锛夈€俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_ethereum_account锛氭ā鎷烝lice鍚態ob杞处鍦烘櫙锛屽寘鍚处鎴峰垱寤恒€佸瓨娆俱€佸娆¤浆璐︼紙楠岃瘉nonce閫掑锛夈€丟as璐圭敤璁＄畻銆俓n棰勬湡杈撳嚭锛氭墦鍗拌处鎴峰垱寤恒€佸瓨娆俱€佷氦鏄撹鎯咃紙閲戦銆丟as璐圭敤銆乶once锛夈€佹渶缁堜綑棰濓紝楠岃瘉璐︽埛妯″瀷鐨勬牳蹇冮€昏緫姝ｇ‘鎬с€?,'璐︽埛妯″瀷鐨勬牳蹇冩槸nonce绠＄悊锛堥槻閲嶆斁锛夊拰Gas鏈哄埗锛堟帶鍒跺悎绾︽墽琛岃祫婧愶級锛屼互澶潑鏅€氳浆璐︾殑榛樿GasLimit涓?1000',NULL),(137,19,5,'浠ュお鍧婅处鎴锋ā鍨嬪疄鐜颁笌娴嬭瘯锛堢画锛?,'',NULL,'class EthereumWallet:\n    \"\"\"浠ュお鍧婇挶鍖咃紙璐︽埛妯″瀷瀹炵幇锛塡"\"\"\n    \n    def __init__(self, address: str):\n        \"\"\"鍒濆鍖栭挶鍖匼n        Args:\n            address: 浠ュお鍧婅处鎴峰湴鍧€锛?x鍓嶇紑锛塡n        \"\"\"\n        self.address = address\n        # 鍒涘缓澶栭儴璐︽埛锛圗OA锛塡n        self.account = EthereumAccount(address=address, balance=0.0, nonce=0)\n        \n        # 鐢熸垚ECDSA瀵嗛挜瀵癸紙secp256k1鏇茬嚎锛屼互澶潑鏍囧噯锛塡n        self.private_key = ec.generate_private_key(ec.SECP256K1(), default_backend())\n        self.public_key = self.private_key.public_key()\n        \n        print(f\"[Ethereum] 璐︽埛鍒涘缓鎴愬姛锛氬湴鍧€={self.address[:18]}...\")\n    \n    def get_balance(self) -> float:\n        \"\"\"鑾峰彇璐︽埛浣欓锛圗TH锛塡"\"\"\n        return self.account.balance\n    \n    def deposit(self, amount: float):\n        \"\"\"妯℃嫙瀛樺叆ETH锛堟祴璇曠敤锛岀湡瀹炲満鏅€氳繃鎸栫熆鎴栬浆璐﹁幏寰楋級\"\"\"\n        if amount <= 0:\n            print(f\"[Ethereum] 瀛樻澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return\n        self.account.balance += amount\n        print(f\"[Ethereum] 瀛樻鎴愬姛锛?{amount} ETH锛屽綋鍓嶄綑棰?{self.account.balance} ETH\")\n    \n    def _sign_transaction(self, tx: EthereumTransaction) -> str:\n        \"\"\"瀵逛氦鏄撹繘琛孍CDSA绛惧悕锛堢敓鎴恦,r,s锛塡n        Args:\n            tx: 寰呯鍚嶇殑浜ゆ槗\n        Returns:\n            鍗佸叚杩涘埗缂栫爜鐨勭鍚嶏紙v+r+s鎷兼帴锛塡n        \"\"\"\n        # 绛惧悕娑堟伅锛氫氦鏄撴牳蹇冨瓧娈电殑鍝堝笇锛堢‘淇濅氦鏄撲笉鍙鏀癸級\n        message = f\"{tx.from_address}{tx.to_address}{tx.value}{tx.nonce}{tx.gas_limit}{tx.gas_price}\".encode()\n        \n        # ECDSA绛惧悕锛坰ecp256k1鏇茬嚎 + SHA256鍝堝笇锛塡n        signature = self.private_key.sign(\n            message,\n            ec.ECDSA(hashes.SHA256())\n        )\n        \n        # 浠ュお鍧婄鍚嶆牸寮忥細v锛?瀛楄妭锛? r锛?2瀛楄妭锛? s锛?2瀛楄妭锛塡n        # 绠€鍖栧鐞嗭細鐩存帴杩斿洖绛惧悕鐨勫崄鍏繘鍒惰〃绀篭n        return signature.hex()\n    \n    def create_transaction(self, to_address: str, value: float, \n                          gas_limit: int = 21000, gas_price: float = 2e-8, data: str = \"\") -> EthereumTransaction:\n        \"\"\"鍒涘缓浠ュお鍧婁氦鏄揬n        Args:\n            to_address: 鎺ユ敹鍦板潃\n            value: 杞处閲戦锛圗TH锛塡n            gas_limit: Gas涓婇檺锛堥粯璁?1000锛屾櫘閫氳浆璐﹀浐瀹氬€硷級\n            gas_price: 鍗曚綅Gas浠锋牸锛圗TH/Gas锛岄粯璁?e-8 ETH锛塡n            data: 浜ゆ槗鏁版嵁锛堝悎绾﹁皟鐢ㄦ椂浣跨敤锛塡n        Returns:\n            浜ゆ槗瀵硅薄\n        \"\"\"\n        # 璁＄畻Gas璐圭敤锛圙asLimit 脳 GasPrice锛塡n        gas_fee = gas_limit * gas_price\n        # 璁＄畻鎬昏姳璐癸紙杞处閲戦 + Gas璐圭敤锛塡n        total_cost = value + gas_fee\n        \n        # 楠岃瘉浣欓\n        if self.account.balance < total_cost:\n            raise ValueError(f\"[Ethereum] 浣欓涓嶈冻锛氶渶瑕亄total_cost:.6f} ETH锛屽綋鍓嶄綑棰?{self.account.balance:.6f} ETH\")\n        \n        # 鍒涘缓浜ゆ槗瀵硅薄\n        tx = EthereumTransaction(\n            tx_hash=\"\",\n            from_address=self.address,\n            to_address=to_address,\n            value=value,\n            gas_limit=gas_limit,\n            gas_price=gas_price,\n            nonce=self.account.nonce,  # 浣跨敤褰撳墠nonce\n            data=data,\n            timestamp=time.time()\n        )\n        \n        # 绛惧悕浜ゆ槗\n        tx.signature = self._sign_transaction(tx)\n        # 璁＄畻浜ゆ槗鍝堝笇\n        tx.tx_hash = tx.compute_hash()\n        \n        # 鏇存柊璐︽埛鐘舵€侊細鎵ｉ櫎浣欓锛岄€掑nonce锛堥槻閲嶆斁锛塡n        self.account.balance -= total_cost\n        self.account.nonce += 1\n        \n        # 鎵撳嵃浜ゆ槗璇︽儏\n        print(f\"\\n[Ethereum] 浜ゆ槗鍒涘缓鎴愬姛锛歕")\n        print(f\"  TxHash: {tx.tx_hash[:18]}...\")\n        print(f\"  鍙戦€佹柟锛歿tx.from_address[:18]}...\")\n        print(f\"  鎺ユ敹鏂癸細{tx.to_address[:18]}...\")\n        print(f\"  杞处閲戦锛歿tx.value} ETH\")\n        print(f\"  Gas鍙傛暟锛歿tx.gas_limit} Gas 脳 {tx.gas_price:.8f} ETH/Gas = {gas_fee:.6f} ETH\")\n        print(f\"  Nonce锛歿tx.nonce}\")\n        print(f\"  鍓╀綑浣欓锛歿self.account.balance:.6f} ETH\")\n        \n        return tx\n\n# 娴嬭瘯璐︽埛妯″瀷\ndef demo_ethereum_account():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氫互澶潑璐︽埛妯″瀷 - Alice鍚態ob杞处\")\n    print(\"=\"*60)\n    \n    # 姝ラ1锛氬垱寤篈lice鍜孊ob鐨勪互澶潑璐︽埛\n    print(\"\\n[姝ラ1] 鍒涘缓璐︽埛\")\n    alice_wallet = EthereumWallet(\"0xAlice_address_1234567890abcdef\")\n    bob_wallet = EthereumWallet(\"0xBob_address_abcdef1234567890\")\n    \n    # 姝ラ2锛欰lice瀛樺叆10.0 ETH锛堟祴璇曠敤锛塡n    print(\"\\n[姝ラ2] Alice瀛樻\")\n    alice_wallet.deposit(10.0)\n    \n    # 姝ラ3锛欰lice鍚態ob杞处3.0 ETH锛堟櫘閫氳浆璐︼紝GasLimit=21000锛塡n    print(\"\\n[姝ラ3] Alice鍚態ob杞处3.0 ETH\")\n    tx1 = alice_wallet.create_transaction(bob_wallet.address, value=3.0)\n    # Bob鎺ユ敹杞处锛堟ā鎷熷尯鍧楃‘璁ゅ悗鏇存柊浣欓锛塡n    bob_wallet.deposit(3.0)\n    \n    # 姝ラ4锛欰lice鍐嶆鍚態ob杞处2.0 ETH锛堥獙璇乶once閫掑锛塡n    print(\"\\n[姝ラ4] Alice鍐嶆鍚態ob杞处2.0 ETH\")\n    tx2 = alice_wallet.create_transaction(bob_wallet.address, value=2.0)\n    # Bob鎺ユ敹杞处\n    bob_wallet.deposit(2.0)\n    \n    # 姝ラ5锛氭墦鍗版渶缁堢姸鎬乗n    print(\"\\n[姝ラ5] 鏈€缁堢姸鎬乗")\n    print(f\"Alice锛氫綑棰?{alice_wallet.get_balance():.6f} ETH锛孨once={alice_wallet.account.nonce}\")\n    print(f\"Bob锛氫綑棰?{bob_wallet.get_balance():.6f} ETH锛孨once={bob_wallet.account.nonce}\")\n    \n    # 鎬荤粨璐︽埛妯″瀷鐗圭偣\n    print(\"\\n[璐︽埛妯″瀷鏍稿績鐗圭偣]\")\n    print(\"  1. 璐︽埛鍖栫鐞嗭細绫讳技閾惰璐︽埛锛岀洿鎺ョ淮鎶や綑棰漒")\n    print(\"  2. Nonce鏈哄埗锛氭瘡绗斾氦鏄搉once閫掑锛岄槻姝㈤噸鏀炬敾鍑籠")\n    print(\"  3. Gas璐圭敤锛氭帶鍒惰绠楄祫婧愭秷鑰楋紝閬垮厤鏃犻檺寰幆\")\n    print(\"  4. 鏀寔鍚堢害锛氬悎绾﹁处鎴锋湁code鍜宻torage瀛楁锛屽彲鎵ц澶嶆潅閫昏緫\")\n    print(\"  5. 鐘舵€侀泦涓細鍏ㄥ眬缁存姢璐︽埛鐘舵€侊紝浜ゆ槗鐩存帴淇敼鐘舵€乗")\n    \n    return True\n\n# 鎵ц璐︽埛妯″瀷娴嬭瘯\ndemo_ethereum_account()'),(138,19,6,'ERC-20鏅鸿兘鍚堢害瀹炵幇涓庢祴璇?,'1. 鏍稿績鍘熺悊锛氭櫤鑳藉悎绾︽槸杩愯鍦ㄥ尯鍧楅摼涓婄殑涓嶅彲绡℃敼绋嬪簭锛孍RC-20鏄唬甯佹爣鍑嗭紙瀹氫箟浜唗ransfer銆乤pprove銆乼ransferFrom绛夋牳蹇冩帴鍙ｏ級锛涘悎绾︾姸鎬佸瓨鍌ㄥ湪閾句笂锛岄€氳繃浜ゆ槗瑙﹀彂鎵ц锛屾墽琛岀粨鏋滀慨鏀瑰悎绾﹀瓨鍌ㄣ€俓n2. 瀹炵幇SimpleSmartContract绫伙紙ERC-20鏍稿績鍔熻兘锛夛細\n   - 鍒濆鍖栨柟娉曪細璁剧疆浠ｅ竵鍚嶇О銆佺鍙枫€佹€讳緵搴旈噺銆俓n   - deploy鏂规硶锛氶儴缃插悎绾︼紝灏嗘€讳緵搴旈噺鍒嗛厤缁欓儴缃茶€呫€俓n   - balance_of鏂规硶锛氭煡璇㈠湴鍧€鐨勪唬甯佷綑棰濄€俓n   - transfer鏂规硶锛氱洿鎺ヨ浆璐︿唬甯侊紙浠庡彂閫佽€呭埌鎺ユ敹鑰咃級銆俓n   - approve鏂规硶锛氭巿鏉冪涓夋柟浣跨敤鎸囧畾鏁伴噺鐨勪唬甯併€俓n   - transfer_from鏂规硶锛氱涓夋柟浣跨敤鎺堟潈棰濆害杞处浠ｅ竵銆俓n3. 缂栧啓娴嬭瘯鍑芥暟demo_smart_contract锛氭ā鎷熷悎绾﹂儴缃层€佷唬甯佽浆璐︺€佹巿鏉冭浆璐﹀満鏅紝楠岃瘉ERC-20鏍稿績鍔熻兘銆俓n棰勬湡杈撳嚭锛氭墦鍗板悎绾﹂儴缃层€佷唬甯佽浆璐︺€佹巿鏉冦€佹巿鏉冭浆璐﹁鎯咃紝浠ュ強鏈€缁堝悇鍦板潃鐨勪唬甯佷綑棰濓紝楠岃瘉鏅鸿兘鍚堢害鐨勮嚜鍔ㄦ墽琛岄€昏緫銆?,'ERC-20鐨勬牳蹇冩槸鈥滀綑棰濇槧灏?鎺堟潈鏄犲皠鈥濓紝鎵€鏈夌姸鎬佸彉鏇撮兘閫氳繃鍚堢害鏂规硶鎵ц锛屼笖鎵ц缁撴灉涓嶅彲绡℃敼锛岄渶纭繚杞处鍜屾巿鏉冮€昏緫鐨勫師瀛愭€?,NULL),(139,19,7,'ERC-20鏅鸿兘鍚堢害瀹炵幇涓庢祴璇曪紙缁級','',NULL,'class SimpleSmartContract:\n    \"\"\"绠€鍗旹RC-20浠ｅ竵鍚堢害锛堟牳蹇冨姛鑳藉疄鐜帮級\n    閬靛惊ERC-20鏍囧噯鏍稿績鎺ュ彛锛歜alanceOf銆乼ransfer銆乤pprove銆乼ransferFrom\n    \"\"\"\n    \n    def __init__(self, name: str, symbol: str, total_supply: int):\n        \"\"\"鍒濆鍖栧悎绾﹀弬鏁癨n        Args:\n            name: 浠ｅ竵鍚嶇О锛堝锛歁yToken锛塡n            symbol: 浠ｅ竵绗﹀彿锛堝锛歁TK锛塡n            total_supply: 鎬讳緵搴旈噺锛堟暣鏁帮紝鏈€灏忓崟浣嶏級\n        \"\"\"\n        self.name = name  # 浠ｅ竵鍚嶇О\n        self.symbol = symbol  # 浠ｅ竵绗﹀彿\n        self.total_supply = total_supply  # 鎬讳緵搴旈噺\n        self.balances: Dict[str, int] = {}  # 浣欓鏄犲皠锛氬湴鍧€鈫掍綑棰漒n        self.allowances: Dict[str, Dict[str, int]] = {}  # 鎺堟潈鏄犲皠锛氭墍鏈夎€呪啋鎺堟潈鑰呪啋棰濆害\n        self.owner = None  # 鍚堢害閮ㄧ讲鑰匼n        \n        print(f\"[SmartContract] 鍚堢害鍒濆鍖栧畬鎴愶細{self.name}锛坽self.symbol}锛夛紝鎬讳緵搴旈噺={self.total_supply}\")\n    \n    def deploy(self, deployer_address: str):\n        \"\"\"閮ㄧ讲鍚堢害锛堝皢鎬讳緵搴旈噺鍒嗛厤缁欓儴缃茶€咃級\n        Args:\n            deployer_address: 閮ㄧ讲鑰呭湴鍧€\n        \"\"\"\n        self.owner = deployer_address\n        self.balances[deployer_address] = self.total_supply\n        print(f\"[SmartContract] 鍚堢害閮ㄧ讲鎴愬姛锛乗")\n        print(f\"  閮ㄧ讲鑰咃細{deployer_address[:18]}...\")\n        print(f\"  閮ㄧ讲鑰呭垵濮嬩綑棰濓細{self.balances[deployer_address]} {self.symbol}\")\n    \n    def balance_of(self, address: str) -> int:\n        \"\"\"鏌ヨ鍦板潃鐨勪唬甯佷綑棰漒n        Args:\n            address: 瑕佹煡璇㈢殑鍦板潃\n        Returns:\n            浠ｅ竵浣欓锛堟暣鏁帮級\n        \"\"\"\n        return self.balances.get(address, 0)\n    \n    def transfer(self, from_address: str, to_address: str, amount: int) -> bool:\n        \"\"\"鐩存帴杞处浠ｅ竵锛坒rom_address 鈫?to_address锛塡n        Args:\n            from_address: 鍙戦€佽€呭湴鍧€\n            to_address: 鎺ユ敹鑰呭湴鍧€\n            amount: 杞处閲戦锛堟暣鏁帮級\n        Returns:\n            杞处鏄惁鎴愬姛\n        \"\"\"\n        # 楠岃瘉鍙傛暟\n        if amount <= 0:\n            print(f\"[SmartContract] 杞处澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return False\n        if self.balance_of(from_address) < amount:\n            print(f\"[SmartContract] 杞处澶辫触锛歿from_address[:18]}... 浣欓涓嶈冻锛堥渶{amount}锛屾湁{self.balance_of(from_address)}锛塡")\n            return False\n        \n        # 鎵ц杞处锛氭墸鍑忓彂閫佽€呬綑棰濓紝澧炲姞鎺ユ敹鑰呬綑棰漒n        self.balances[from_address] -= amount\n        self.balances[to_address] = self.balances.get(to_address, 0) + amount\n        \n        print(f\"[SmartContract] 杞处鎴愬姛锛乗")\n        print(f\"  鍙戦€佽€咃細{from_address[:18]}...锛堜綑棰濓細{self.balance_of(from_address)} {self.symbol}锛塡")\n        print(f\"  鎺ユ敹鑰咃細{to_address[:18]}...锛堜綑棰濓細{self.balance_of(to_address)} {self.symbol}锛塡")\n        print(f\"  杞处閲戦锛歿amount} {self.symbol}\")\n        return True\n    \n    def approve(self, owner_address: str, spender_address: str, amount: int):\n        \"\"\"鎺堟潈绗笁鏂癸紙spender锛変娇鐢ㄦ寚瀹氶搴︾殑浠ｅ竵\n        Args:\n            owner_address: 浠ｅ竵鎵€鏈夎€呭湴鍧€\n            spender_address: 琚巿鏉冭€呭湴鍧€\n            amount: 鎺堟潈棰濆害锛堟暣鏁帮級\n        \"\"\"\n        if amount <= 0:\n            print(f\"[SmartContract] 鎺堟潈澶辫触锛氶搴﹀繀椤诲ぇ浜?\")\n            return\n        if self.balance_of(owner_address) < amount:\n            print(f\"[SmartContract] 鎺堟潈澶辫触锛氭墍鏈夎€呬綑棰濅笉瓒砛")\n            return\n        \n        # 鍒濆鍖栨巿鏉冩槧灏勶紙鑻ヤ笉瀛樺湪锛塡n        if owner_address not in self.allowances:\n            self.allowances[owner_address] = {}\n        self.allowances[owner_address][spender_address] = amount\n        \n        print(f\"[SmartContract] 鎺堟潈鎴愬姛锛乗")\n        print(f\"  鎵€鏈夎€咃細{owner_address[:18]}...\")\n        print(f\"  琚巿鏉冭€咃細{spender_address[:18]}...\")\n        print(f\"  鎺堟潈棰濆害锛歿amount} {self.symbol}\")\n    \n    def transfer_from(self, spender_address: str, from_address: str, to_address: str, amount: int) -> bool:\n        \"\"\"绗笁鏂癸紙spender锛変娇鐢ㄦ巿鏉冮搴﹁浆璐︿唬甯侊紙from_address 鈫?to_address锛塡n        Args:\n            spender_address: 琚巿鏉冭€咃紙鍙戣捣杞处鑰咃級\n            from_address: 浠ｅ竵鎵€鏈夎€呭湴鍧€\n            to_address: 鎺ユ敹鑰呭湴鍧€\n            amount: 杞处閲戦锛堟暣鏁帮級\n        Returns:\n            杞处鏄惁鎴愬姛\n        \"\"\"\n        # 楠岃瘉鍙傛暟\n        if amount <= 0:\n            print(f\"[SmartContract] 鎺堟潈杞处澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return False\n        \n        # 楠岃瘉鎺堟潈棰濆害\n        allowance = self.allowances.get(from_address, {}).get(spender_address, 0)\n        if allowance < amount:\n            print(f\"[SmartContract] 鎺堟潈杞处澶辫触锛氭巿鏉冮搴︿笉瓒筹紙闇€{amount}锛屾湁{allowance}锛塡")\n            return False\n        \n        # 楠岃瘉鎵€鏈夎€呬綑棰漒n        if self.balance_of(from_address) < amount:\n            print(f\"[SmartContract] 鎺堟潈杞处澶辫触锛氭墍鏈夎€呬綑棰濅笉瓒砛")\n            return False\n        \n        # 鎵ц杞处\n        self.balances[from_address] -= amount\n        self.balances[to_address] = self.balances.get(to_address, 0) + amount\n        \n        # 鎵ｅ噺鎺堟潈棰濆害\n        self.allowances[from_address][spender_address] -= amount\n        \n        print(f\"[SmartContract] 鎺堟潈杞处鎴愬姛锛乗")\n        print(f\"  鎵€鏈夎€咃細{from_address[:18]}...锛堜綑棰濓細{self.balance_of(from_address)} {self.symbol}锛塡")\n        print(f\"  鎺ユ敹鑰咃細{to_address[:18]}...锛堜綑棰濓細{self.balance_of(to_address)} {self.symbol}锛塡")\n        print(f\"  琚巿鏉冭€咃細{spender_address[:18]}...锛堝墿浣欐巿鏉冿細{self.allowances[from_address][spender_address]} {self.symbol}锛塡")\n        print(f\"  杞处閲戦锛歿amount} {self.symbol}\")\n        return True\n\n# 娴嬭瘯鏅鸿兘鍚堢害\ndef demo_smart_contract():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛欵RC-20鏅鸿兘鍚堢害 - MyToken锛圡TK锛夐儴缃蹭笌浜や簰\")\n    print(\"=\"*60)\n    \n    # 姝ラ1锛氬畾涔夋祴璇曞湴鍧€\n    deployer = \"0xDeployer_Address_0000000000\"\n    alice = \"0xAlice_Address_1111111111\"\n    bob = \"0xBob_Address_2222222222\"\n    print(f\"\\n[姝ラ1] 娴嬭瘯鍦板潃锛歕")\n    print(f\"  鍚堢害閮ㄧ讲鑰咃細{deployer[:18]}...\")\n    print(f\"  Alice锛歿alice[:18]}...\")\n    print(f\"  Bob锛歿bob[:18]}...\")\n    \n    # 姝ラ2锛氬垱寤哄苟閮ㄧ讲ERC-20浠ｅ竵鍚堢害锛堟€讳緵搴旈噺100涓嘙TK锛塡n    print(\"\\n[姝ラ2] 閮ㄧ讲ERC-20鍚堢害\")\n    mtk_contract = SimpleSmartContract(name=\"MyToken\", symbol=\"MTK\", total_supply=1000000)\n    mtk_contract.deploy(deployer_address=deployer)\n    \n    # 姝ラ3锛氶儴缃茶€呭悜Alice杞处1000 MTK\n    print(\"\\n[姝ラ3] 閮ㄧ讲鑰呪啋Alice 杞处1000 MTK\")\n    mtk_contract.transfer(from_address=deployer, to_address=alice, amount=1000)\n    print(f\"  閮ㄧ讲鑰呬綑棰濓細{mtk_contract.balance_of(deployer)} MTK\")\n    print(f\"  Alice浣欓锛歿mtk_contract.balance_of(alice)} MTK\")\n    \n    # 姝ラ4锛欰lice鍚態ob杞处300 MTK锛堢洿鎺ヨ浆璐︼級\n    print(\"\\n[姝ラ4] Alice鈫払ob 杞处300 MTK\")\n    mtk_contract.transfer(from_address=alice, to_address=bob, amount=300)\n    print(f\"  Alice浣欓锛歿mtk_contract.balance_of(alice)} MTK\")\n    print(f\"  Bob浣欓锛歿mtk_contract.balance_of(bob)} MTK\")\n    \n    # 姝ラ5锛欰lice鎺堟潈Bob浣跨敤200 MTK锛堟巿鏉冩満鍒讹級\n    print(\"\\n[姝ラ5] Alice鎺堟潈Bob浣跨敤200 MTK\")\n    mtk_contract.approve(owner_address=alice, spender_address=bob, amount=200)\n    \n    # 姝ラ6锛欱ob浣跨敤鎺堟潈棰濆害锛屼粠Alice璐︽埛杞处100 MTK鍒拌嚜宸辫处鎴凤紙鎺堟潈杞处锛塡n    print(\"\\n[姝ラ6] Bob浣跨敤鎺堟潈杞处100 MTK\")\n    mtk_contract.transfer_from(\n        spender_address=bob,\n        from_address=alice,\n        to_address=bob,\n        amount=100\n    )\n    \n    # 姝ラ7锛氭墦鍗版渶缁堜綑棰漒n    print(\"\\n[姝ラ7] 鏈€缁堜綑棰漒")\n    print(f\"  閮ㄧ讲鑰咃細{mtk_contract.balance_of(deployer)} MTK\")\n    print(f\"  Alice锛歿mtk_contract.balance_of(alice)} MTK\")\n    print(f\"  Bob锛歿mtk_contract.balance_of(bob)} MTK\")\n    \n    # 鎬荤粨鏅鸿兘鍚堢害鐗圭偣\n    print(\"\\n[鏅鸿兘鍚堢害鏍稿績鐗圭偣]\")\n    print(\"  1. 鑷姩鎵ц锛氭弧瓒虫潯浠跺嵆鎵ц锛屾棤闇€绗笁鏂瑰共棰刓")\n    print(\"  2. 涓嶅彲绡℃敼锛氶儴缃插悗浠ｇ爜鍜岀姸鎬佹棤娉曚慨鏀癸紙闄ら潪鏈夊崌绾ф満鍒讹級\")\n    print(\"  3. 閫忔槑鍏紑锛氬悎绾︿唬鐮佸拰鎵€鏈変氦鏄撹褰曞彲鍏紑鏌ヨ\")\n    print(\"  4. 鍘讳腑蹇冨寲锛氳繍琛屽湪鍖哄潡閾捐妭鐐逛笂锛屾棤鍗曠偣鏁呴殰\")\n    print(\"  5. 鏍囧噯鎺ュ彛锛欵RC-20绛夋爣鍑嗙‘淇濅笉鍚屽悎绾﹂棿鐨勪簰鎿嶄綔鎬")\n    \n    return True\n\n# 鎵ц鏅鸿兘鍚堢害娴嬭瘯\ndemo_smart_contract()'),(140,19,8,'UTXO妯″瀷涓庤处鎴锋ā鍨嬫繁搴﹀姣斾笌鎬荤粨','1. 鏍稿績缁村害瀵规瘮锛歕n   - 鏁板瀹氫箟锛歎TXO妯″瀷鏄鏁ｈ緭鍑洪泦鍚堬紙Balance=危UTXO閲戦锛夛紝璐︽埛妯″瀷鏄叏灞€鐘舵€佹槧灏勶紙Balance=璐︽埛瀛楁鍊硷級銆俓n   - 鐘舵€佸瓨鍌細UTXO瀛樺偍绂绘暎鐨勬湭鑺辫垂杈撳嚭锛岃处鎴锋ā鍨嬪瓨鍌ㄩ泦涓紡璐︽埛鐘舵€併€俓n   - 浜ゆ槗閫昏緫锛歎TXO浜ゆ槗闇€寮曠敤鍓嶅簭杈撳嚭锛岃处鎴锋ā鍨嬩氦鏄撶洿鎺ヤ慨鏀逛綑棰濄€俓n   - 闅愮鎬э細UTXO妯″瀷鏇翠紭锛堝彲浣跨敤鏂板湴鍧€锛夛紝璐︽埛妯″瀷杈冨樊锛堝湴鍧€鍥哄畾锛夈€俓n   - 鎬ц兘锛歎TXO鏀寔骞惰楠岃瘉锛岃处鎴锋ā鍨嬮渶澶勭悊鐘舵€佸啿绐併€俓n   - 鍔熻兘鎵╁睍锛氳处鎴锋ā鍨嬫洿閫傚悎鏅鸿兘鍚堢害锛堢姸鎬侀泦涓鐞嗭級锛孶TXO妯″瀷杈冨鏉傘€俓n2. 閫傜敤鍦烘櫙锛歕n   - UTXO妯″瀷锛氶€傜敤浜庣函鏀粯鍦烘櫙锛堝姣旂壒甯侊級锛岃拷姹傞殣绉佹€у拰骞惰鎬с€俓n   - 璐︽埛妯″瀷锛氶€傜敤浜庨渶瑕佸鏉傞€昏緫鐨勫満鏅紙濡備互澶潑锛夛紝鏀寔鏅鸿兘鍚堢害銆丏eFi銆丯FT绛夈€俓n3. 鎶€鏈€夊瀷瑕佺偣锛歕n   - 鑻ユ牳蹇冮渶姹傛槸鏀粯+闅愮锛氶€夋嫨UTXO妯″瀷銆俓n   - 鑻ユ牳蹇冮渶姹傛槸鏅鸿兘鍚堢害+鍔熻兘鎵╁睍锛氶€夋嫨璐︽埛妯″瀷銆俓n   - 娣峰悎妯″瀷锛氶儴鍒嗛」鐩紙濡侰ardano锛夌粨鍚堜袱鑰呬紭鐐癸紝鍏奸【鏀粯涓庢櫤鑳藉悎绾︺€俓n4. 鍙戝睍瓒嬪娍锛歎TXO妯″瀷鍚戞櫤鑳藉悎绾︽墿灞曪紙濡傛瘮鐗瑰竵Taproot鍗囩骇锛夛紝璐︽埛妯″瀷浼樺寲骞惰鎬э紙濡備互澶潑鍒嗙墖锛夛紝鍙屾ā鍨嬭瀺鍚堟垚涓烘柊鏂瑰悜銆俓n棰勬湡杈撳嚭锛氬舰鎴愭竻鏅扮殑妯″瀷閫夊瀷妗嗘灦锛岃兘鏍规嵁椤圭洰闇€姹傞€夋嫨鍚堥€傜殑璁拌处妯″瀷銆?,'娌℃湁缁濆鏈€浼樼殑妯″瀷锛屽彧鏈夋渶閫傚悎鍦烘櫙鐨勬ā鍨嬶紝闇€鍦ㄩ殣绉佹€с€佹€ц兘銆佸姛鑳芥墿灞曟€т箣闂村仛鏉冭　',NULL),(141,20,1,'鐜鍑嗗涓庡畨鍏ㄥ熀纭€姊崇悊','1. 鐜閰嶇疆锛氱‘淇漃ython 3.7+鐜锛屾棤闇€棰濆渚濊禆搴擄紙鏍稿績閫昏緫鍩轰簬鍘熺敓Python瀹炵幇锛岃仛鐒︽紡娲炲師鐞嗚€岄潪璇█缁嗚妭锛夈€俓n2. 鏍稿績姒傚康鍥為【锛氭櫤鑳藉悎绾﹀畨鍏ㄧ殑鏍稿績鐩爣锛堥槻鐩楃獌銆侀槻绡℃敼銆侀槻鏈巿鏉冭闂級銆佷互澶潑铏氭嫙鏈猴紙EVM锛夋墽琛屾ā鍨嬶紙澶栭儴璋冪敤鏈哄埗銆佹暣鏁板瓨鍌ㄨ鍒欍€佹潈闄愰獙璇侀€昏緫锛夈€佸父瑙侀珮鍗辨紡娲炲垎绫伙紙OWASP Top 10鍖哄潡閾惧畨鍏ㄩ闄╋級銆俓n3. 鍘嗗彶浜嬩欢鑳屾櫙锛氱畝瑕佸洖椤句笁澶ф紡娲炲搴旂殑鏍囧織鎬т簨浠讹紙2016骞碊AO閲嶅叆鏀诲嚮瀵艰嚧浠ュお鍧婂垎鍙夈€?018骞碆atchOverflow鏁存暟婧㈠嚭瀵艰嚧浠ｅ竵鏃犻檺閾搁€犮€?017骞碢arity閽卞寘璁块棶鎺у埗婕忔礊瀵艰嚧璧勯噾鍐荤粨锛夛紝鐞嗚В婕忔礊鐨勫疄闄呭嵄瀹炽€俓n棰勬湡杈撳嚭锛氭槑纭櫤鑳藉悎绾﹀畨鍏ㄧ殑閲嶈鎬э紝姊崇悊涓夊ぇ婕忔礊鐨勬牳蹇冨奖鍝嶏紝涓哄悗缁紡娲炲鐜颁笌闃插尽濂犲畾鍩虹銆?,'鏅鸿兘鍚堢害鐨勨€滀笉鍙鏀光€濈壒鎬ф剰鍛崇潃婕忔礊涓€鏃﹂儴缃叉棤娉曚慨鏀癸紝鍥犳鈥滃畨鍏ㄥ紑鍙戔€濇瘮鈥滀簨鍚庝慨澶嶁€濇洿閲嶈锛岄渶閲嶇偣鍏虫敞鈥滈闃插瀷鈥濋槻寰℃柟妗?,NULL),(142,20,2,'閲嶅叆鏀诲嚮锛圧eentrancy锛夛細鍘熺悊銆佸鐜颁笌闃插尽','1. 婕忔礊鍘熺悊锛歕n   - 鏍稿績閫昏緫锛氭櫤鑳藉悎绾﹀湪鎵ц澶栭儴璋冪敤锛坈all()/send()/transfer()锛夋椂锛屾湭鍏堟洿鏂拌嚜韬姸鎬侊紙濡備綑棰濇墸闄わ級锛屽鑷存敾鍑昏€呭彲閫氳繃鍥炶皟鍑芥暟鍙嶅瑙﹀彂鐩爣鍑芥暟锛屽舰鎴愰€掑綊璋冪敤閾撅紝绐冨彇瓒呴璧勯噾銆俓n   - 鏁板鎶借薄锛氳鏀诲嚮鑰呭垵濮嬩綑棰濅负b锛屾瘡娆℃彁娆鹃噾棰濅负未锛屾甯搁€昏緫涓嬩綑棰濇洿鏂颁负b-未锛涜嫢鐘舵€佹洿鏂版粸鍚庝簬澶栭儴璋冪敤锛屾敾鍑昏€呭彲瑙﹀彂n娆￠€掑綊璋冪敤锛屾渶缁堜綑棰濅负b-n未锛坣>1锛夛紝闈炴硶鑾峰彇(n-1)未璧勯噾銆俓n   - 鍏抽敭鍓嶆彁锛氬閮ㄨ皟鐢ㄥ彲瑙﹀彂鍥炶皟锛堝fallback()/receive()鍑芥暟锛夈€佺姸鎬佹洿鏂伴『搴忛敊璇紙鍏堣皟鐢ㄥ悗鏇存柊锛夈€俓n2. 婕忔礊澶嶇幇锛歕n   - 瀹炵幇鏈夋紡娲炵殑鍚堢害VulnerableContract锛氭彁娆惧嚱鏁皐ithdraw鍏堟墽琛屽閮ㄨ皟鐢紙妯℃嫙杞处锛夛紝鍚庢墸闄や綑棰濄€俓n   - 妯℃嫙鏀诲嚮鑰咃細閫氳繃鍥炶皟鍑芥暟鍦ㄦ帴鏀垛€滆浆璐︹€濇椂鍐嶆璋冪敤withdraw锛屽舰鎴愰噸鍏ラ摼銆俓n   - 瑙傚療鏀诲嚮缁撴灉锛氭敾鍑昏€呭垵濮嬩綑棰?00 wei锛岄€氳繃5娆￠噸鍏ヨ皟鐢紝鏈€缁堟彁鍙栬繙瓒呭垵濮嬩綑棰濈殑璧勯噾銆俓n3. 闃插尽鏂规瀹炵幇锛歕n   - 鏂规1锛氭鏌?鏁堟灉-浜や簰锛圕EI锛夋ā寮忥細鍏堟洿鏂扮姸鎬侊紙鎵ｉ櫎浣欓锛夛紝鍚庢墽琛屽閮ㄨ皟鐢ㄣ€俓n   - 鏂规2锛氶噸鍏ラ攣锛圧eentrancy Guard锛夛細娣诲姞甯冨皵閿佸彉閲忥紝鍑芥暟鎵ц鏃堕攣瀹氾紝鎵ц瀹屾瘯瑙ｉ攣锛岄槻姝㈤€掑綊璋冪敤銆俓n   - 瀹炵幇瀹夊叏鍚堢害SecureContract锛氭暣鍚圕EI妯″紡涓庨噸鍏ラ攣锛屽鐜版敾鍑婚獙璇侀槻寰℃晥鏋溿€俓n棰勬湡杈撳嚭锛氭垚鍔熷鐜伴噸鍏ユ敾鍑绘祦绋嬶紝瑙傚療鏀诲嚮鑰呯獌鍙栬祫閲戠殑杩囩▼锛涢獙璇佸畨鍏ㄥ悎绾﹀彲鏈夋晥闃绘閲嶅叆鏀诲嚮锛岀悊瑙EI妯″紡涓庨噸鍏ラ攣鐨勬牳蹇冧綔鐢ㄣ€?,'閲嶅叆鏀诲嚮鐨勬牳蹇冩槸鈥滅姸鎬佹洿鏂颁笌澶栭儴璋冪敤鐨勯『搴忛敊璇€濓紝闃插尽鐨勫叧閿槸鈥滃垏鏂€掑綊璋冪敤鐨勫墠鎻愨€濃€斺€旇涔堝厛鏇存柊鐘舵€佽鏀诲嚮鑰呮棤娉曢噸澶嶆弧瓒虫潯浠讹紝瑕佷箞鐢ㄩ攣鐩存帴闃绘閫掑綊璋冪敤','from typing import Dict, Optional\nfrom dataclasses import dataclass\n\n\n@dataclass\nclass Account:\n    \"\"\"绠€鍖栬处鎴风被锛岀敤浜庡瓨鍌ㄥ湴鍧€涓庝綑棰漒"\"\"\n    address: str\n    balance: int = 0\n\n\nclass VulnerableContract:\n    \"\"\"瀛樺湪閲嶅叆鏀诲嚮婕忔礊鐨勫悎绾︼紙妯℃嫙DAO婕忔礊锛塡"\"\"\n    \n    def __init__(self):\n        self.balances: Dict[str, int] = {}  # 璐︽埛浣欓鏄犲皠\n        self.call_depth = 0  # 璁板綍璋冪敤娣卞害锛岄槻姝㈡棤闄愰€掑綊锛堜粎鐢ㄤ簬婕旂ず锛塡n        self.max_call_depth = 10  # 鏈€澶ц皟鐢ㄦ繁搴﹂檺鍒禱n    \n    def deposit(self, address: str, amount: int):\n        \"\"\"瀛樻锛氬悜鍚堢害瀛樺叆璧勯噾锛屽鍔犺处鎴蜂綑棰漒"\"\"\n        if amount <= 0:\n            print(f\"[VulnerableContract] 瀛樻澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return\n        self.balances[address] = self.balances.get(address, 0) + amount\n        print(f\"[VulnerableContract] {address[:16]}... 瀛樺叆 {amount} wei锛屽綋鍓嶄綑棰濓細{self.balances[address]} wei\")\n    \n    def get_balance(self, address: str) -> int:\n        \"\"\"鏌ヨ璐︽埛鍦ㄥ悎绾︿腑鐨勪綑棰漒"\"\"\n        return self.balances.get(address, 0)\n    \n    def withdraw(self, address: str, amount: int, attacker_callback: Optional[callable] = None) -> bool:\n        \"\"\"鎻愭锛堝瓨鍦ㄩ噸鍏ユ紡娲烇級锛氬厛璋冪敤澶栭儴鍥炶皟锛堟ā鎷熻浆璐︼級锛屽悗鏇存柊浣欓\"\"\"\n        self.call_depth += 1\n        \n        # 闃叉鏃犻檺閫掑綊锛堜粎鐢ㄤ簬婕旂ず锛岀湡瀹炲満鏅棤姝ら檺鍒讹級\n        if self.call_depth > self.max_call_depth:\n            print(f\"[VulnerableContract] 璋冪敤娣卞害瓒呴檺锛坽self.call_depth}锛夛紝鎷掔粷缁х画鎵ц\")\n            self.call_depth -= 1\n            return False\n        \n        # 妫€鏌ヤ綑棰濓紙鏉′欢婊¤冻锛塡n        current_balance = self.get_balance(address)\n        if current_balance < amount:\n            print(f\"[VulnerableContract] {address[:16]}... 鎻愭澶辫触锛氫綑棰濅笉瓒筹紙闇€{amount} wei锛屾湁{current_balance} wei锛塡")\n            self.call_depth -= 1\n            return False\n        \n        print(f\"\\n[VulnerableContract] {address[:16]}... 鍙戣捣鎻愭 {amount} wei\")\n        print(f\"[VulnerableContract] 姝ラ1锛氭墽琛屽閮ㄨ皟鐢紙妯℃嫙杞处锛塡")\n        # 婕忔礊鏍稿績锛氬厛鎵ц澶栭儴璋冪敤锛堟敾鍑昏€呭彲鍦ㄦ鍥炶皟锛塡n        if attacker_callback:\n            print(f\"[VulnerableContract] 瑙﹀彂澶栭儴鍥炶皟鍑芥暟...\")\n            attacker_callback()  # 鏀诲嚮鑰呯殑鎭舵剰鍥炶皟\n        \n        # 婕忔礊鏍稿績锛氬悗鏇存柊浣欓锛堟鏃跺凡琚噸鍏ヨ皟鐢ㄥ娆★級\n        print(f\"[VulnerableContract] 姝ラ2锛氭洿鏂颁綑棰濓紙鎵ｉ櫎{amount} wei锛塡")\n        self.balances[address] -= amount\n        print(f\"[VulnerableContract] {address[:16]}... 浣欓鏇存柊涓猴細{self.balances[address]} wei\")\n        \n        self.call_depth -= 1\n        return True\n\n\nclass SecureContract:\n    \"\"\"淇閲嶅叆鏀诲嚮鐨勫畨鍏ㄥ悎绾︼紙CEI妯″紡 + 閲嶅叆閿侊級\"\"\"\n    \n    def __init__(self):\n        self.balances: Dict[str, int] = {}  # 璐︽埛浣欓鏄犲皠\n        self.locked = False  # 閲嶅叆閿侊細闃叉閫掑綊璋冪敤\n    \n    def deposit(self, address: str, amount: int):\n        \"\"\"瀛樻锛氫笌婕忔礊鍚堢害涓€鑷碶"\"\"\n        if amount <= 0:\n            print(f\"[SecureContract] 瀛樻澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return\n        self.balances[address] = self.balances.get(address, 0) + amount\n        print(f\"[SecureContract] {address[:16]}... 瀛樺叆 {amount} wei锛屽綋鍓嶄綑棰濓細{self.balances[address]} wei\")\n    \n    def get_balance(self, address: str) -> int:\n        \"\"\"鏌ヨ浣欓锛氫笌婕忔礊鍚堢害涓€鑷碶"\"\"\n        return self.balances.get(address, 0)\n    \n    def withdraw(self, address: str, amount: int, attacker_callback: Optional[callable] = None) -> bool:\n        \"\"\"鎻愭锛堝畨鍏ㄧ増锛夛細閲嶅叆閿?+ CEI妯″紡\"\"\"\n        # 闃插尽1锛氶噸鍏ラ攣鈥斺€斿鏋滃凡閿佸畾锛岀洿鎺ユ嫆缁濓紙闃叉閫掑綊璋冪敤锛塡n        if self.locked:\n            print(f\"[SecureContract] 妫€娴嬪埌閲嶅叆鏀诲嚮灏濊瘯锛氬悎绾﹀凡閿佸畾锛屾嫆缁濇墽琛孿")\n            return False\n        \n        # 閿佸畾鍚堢害\n        self.locked = True\n        \n        try:\n            # 闃插尽2锛氭鏌ワ紙Check锛夆€斺€旈獙璇佷綑棰濇潯浠禱n            current_balance = self.get_balance(address)\n            if current_balance < amount:\n                print(f\"[SecureContract] {address[:16]}... 鎻愭澶辫触锛氫綑棰濅笉瓒筹紙闇€{amount} wei锛屾湁{current_balance} wei锛塡")\n                return False\n            \n            # 闃插尽3锛氭晥鏋滐紙Effects锛夆€斺€斿厛鏇存柊鐘舵€侊紙鎵ｉ櫎浣欓锛塡n            print(f\"\\n[SecureContract] {address[:16]}... 鍙戣捣鎻愭 {amount} wei\")\n            print(f\"[SecureContract] 姝ラ1锛氭洿鏂颁綑棰濓紙鎵ｉ櫎{amount} wei锛塡")\n            self.balances[address] -= amount\n            print(f\"[SecureContract] {address[:16]}... 浣欓鏇存柊涓猴細{self.balances[address]} wei\")\n            \n            # 闃插尽4锛氫氦浜掞紙Interactions锛夆€斺€斿悗鎵ц澶栭儴璋冪敤\n            print(f\"[SecureContract] 姝ラ2锛氭墽琛屽閮ㄨ皟鐢紙妯℃嫙杞处锛塡")\n            if attacker_callback:\n                print(f\"[SecureContract] 瑙﹀彂澶栭儴鍥炶皟鍑芥暟...\")\n                attacker_callback()  # 鍗充娇鍥炶皟锛屼綑棰濆凡鏇存柊锛屾棤娉曢噸鍏ユ垚鍔焅n            \n            return True\n        finally:\n            # 瑙ｉ攣鍚堢害锛堢‘淇濇墽琛屽畬姣曞悗閲婃斁閿侊級\n            self.locked = False\n\n\n# 婕旂ず閲嶅叆鏀诲嚮涓庨槻寰ndef demo_reentrancy_attack():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氶噸鍏ユ敾鍑伙紙Reentrancy Attack锛? 妯℃嫙DAO浜嬩欢\")\n    print(\"=\"*60)\n    \n    # 鍦烘櫙璁惧畾锛氭敾鍑昏€呴€氳繃鍥炶皟鍑芥暟鍙嶅璋冪敤鎻愭鎺ュ彛\n    victim_address = \"0xVictim_1234567890abcdef\"  # 鍙楀鑰呭湴鍧€\n    attacker_address = \"0xAttacker_abcdef1234567890\"  # 鏀诲嚮鑰呭湴鍧€\n    \n    # 姝ラ1锛氶儴缃插瓨鍦ㄦ紡娲炵殑鍚堢害\n    print(\"\\n[姝ラ1] 閮ㄧ讲瀛樺湪閲嶅叆婕忔礊鐨勫悎绾")\n    vulnerable_contract = VulnerableContract()\n    \n    # 姝ラ2锛氬彈瀹宠€呭拰鏀诲嚮鑰呭悜鍚堢害瀛樻\n    print(\"\\n[姝ラ2] 鍚戝悎绾﹀瓨娆綷")\n    vulnerable_contract.deposit(victim_address, 1000)  # 鍙楀鑰呭瓨鍏?000 wei\n    vulnerable_contract.deposit(attacker_address, 100)  # 鏀诲嚮鑰呭瓨鍏?00 wei\n    print(f\"[VulnerableContract] 鍚堢害鎬昏祫閲戯細{sum(vulnerable_contract.balances.values())} wei\")\n    \n    # 姝ラ3锛氭敾鍑昏€呭彂璧烽噸鍏ユ敾鍑籠n    print(\"\\n[姝ラ3] 鏀诲嚮鑰呭彂璧烽噸鍏ユ敾鍑籠")\n    print(\"鏀诲嚮閫昏緫锛氬湪鍥炶皟鍑芥暟涓啀娆¤皟鐢╳ithdraw锛屽舰鎴愰€掑綊閲嶅叆\")\n    \n    attack_count = [0]  # 璁板綍鏀诲嚮娆℃暟锛堢敤鍒楄〃瀹炵幇闂寘鍙慨鏀癸級\n    \n    def attacker_malicious_callback():\n        \"\"\"鏀诲嚮鑰呯殑鎭舵剰鍥炶皟鍑芥暟锛氬啀娆¤皟鐢ㄦ彁娆炬帴鍙"\"\"\n        attack_count[0] += 1\n        print(f\"\\n[鏀诲嚮鑰匽 绗瑊attack_count[0]}娆￠噸鍏ュ洖璋冭Е鍙戯紒\")\n        # 鍐嶆璋冪敤鎻愭鍑芥暟锛堟鏃跺悎绾︿綑棰濆皻鏈洿鏂帮級\n        if attack_count[0] < 5:  # 闄愬埗鏀诲嚮娆℃暟锛屼究浜庤瀵焅n            vulnerable_contract.withdraw(attacker_address, 100, attacker_malicious_callback)\n    \n    # 鏀诲嚮鑰呴娆¤皟鐢ㄦ彁娆撅紙瑙﹀彂绗竴娆″洖璋冿級\n    vulnerable_contract.withdraw(attacker_address, 100, attacker_malicious_callback)\n    \n    # 鏀诲嚮缁撴灉鍒嗘瀽\n    print(\"\\n\" + \"-\"*40)\n    print(\"[鏀诲嚮缁撴灉] 婕忔礊鍚堢害\")\n    print(f\"鏀诲嚮鑰呭垵濮嬩綑棰濓細100 wei锛屾渶缁堜綑棰濓細{vulnerable_contract.get_balance(attacker_address)} wei\")\n    print(f\"鍙楀鑰呬綑棰濓細{vulnerable_contract.get_balance(victim_address)} wei\")\n    print(f\"鏀诲嚮娆℃暟锛歿attack_count[0]}娆★紝鏀诲嚮鑰呴潪娉曡幏鍙栬秴棰濊祫閲戯紒\")\n    \n    # 姝ラ4锛氶儴缃插畨鍏ㄥ悎绾︼紝楠岃瘉闃插尽鏁堟灉\n    print(\"\\n\" + \"-\"*60)\n    print(\"[姝ラ4] 閮ㄧ讲淇鍚庣殑瀹夊叏鍚堢害锛圕EI妯″紡 + 閲嶅叆閿侊級\")\n    secure_contract = SecureContract()\n    \n    # 姝ラ5锛氶噸鏂板瓨娆綷n    print(\"\\n[姝ラ5] 鍚戝畨鍏ㄥ悎绾﹀瓨娆綷")\n    secure_contract.deposit(victim_address, 1000)  # 鍙楀鑰呭瓨鍏?000 wei\n    secure_contract.deposit(attacker_address, 100)  # 鏀诲嚮鑰呭瓨鍏?00 wei\n    print(f\"[SecureContract] 鍚堢害鎬昏祫閲戯細{sum(secure_contract.balances.values())} wei\")\n    \n    # 姝ラ6锛氭敾鍑昏€呭皾璇曢噸鍏ユ敾鍑诲畨鍏ㄥ悎绾n    print(\"\\n[姝ラ6] 鏀诲嚮鑰呭皾璇曟敾鍑诲畨鍏ㄥ悎绾")\n    attack_count_secure = [0]\n    \n    def attacker_malicious_callback_secure():\n        attack_count_secure[0] += 1\n        print(f\"\\n[鏀诲嚮鑰匽 绗瑊attack_count_secure[0]}娆￠噸鍏ュ洖璋冭Е鍙戯紒\")\n        secur