囩▼锛涢獙璇佸畨鍏ㄥ悎绾﹀彲鏈夋晥妫€娴嬪苟闃绘婧㈠嚭锛岀悊瑙afeMath鐨勬牳蹇冧綔鐢ㄣ€?,'鏁存暟婧㈠嚭鐨勬牳蹇冩槸鈥滅畻鏈繍绠楁湭鍋氳竟鐣屾鏌モ€濓紝闃插尽鐨勫叧閿槸鈥滃己鍒堕獙璇佽繍绠楃粨鏋滄槸鍚﹀湪鍚堟硶鑼冨洿鍐呪€濃€斺€旀墜鍔ㄦ鏌ユ垨渚濊禆缂栬瘧鍣ㄨ嚜鍔ㄦ鏌?,'from typing import Dict, List, Optional\n\n\nclass IntegerOverflowVulnerable:\n    \"\"\"瀛樺湪鏁存暟婧㈠嚭/涓嬫孩婕忔礊鐨勫悎绾︼紙妯℃嫙BatchOverflow婕忔礊锛塡"\"\"\n    \n    def __init__(self):\n        self.balances: Dict[str, int] = {}  # 璐︽埛浣欓鏄犲皠\n        self.MAX_UINT256 = 2**256 - 1  # uint256鏈€澶у€糪n        self.MIN_UINT256 = 0  # uint256鏈€灏忓€糪n    \n    def set_balance(self, address: str, amount: int):\n        \"\"\"璁剧疆璐︽埛浣欓锛堜粎鐢ㄤ簬婕旂ず锛屾ā鎷熷垵濮嬭祫閲戯級\"\"\"\n        if amount < self.MIN_UINT256 or amount > self.MAX_UINT256:\n            print(f\"[Vulnerable] 浣欓璁剧疆澶辫触锛氳秴鍑簎int256鑼冨洿\")\n            return\n        self.balances[address] = amount\n        print(f\"[Vulnerable] {address[:16]}... 鍒濆浣欓璁剧疆涓猴細{amount} wei\")\n    \n    def get_balance(self, address: str) -> int:\n        \"\"\"鏌ヨ璐︽埛浣欓\"\"\"\n        return self.balances.get(address, 0)\n    \n    def transfer(self, from_addr: str, to_addr: str, amount: int) -> bool:\n        \"\"\"杞处锛堝瓨鍦ㄦ孩鍑烘紡娲烇級锛氭湭妫€鏌ョ畻鏈繍绠楄竟鐣孿"\"\"\n        if amount <= 0:\n            print(f\"[Vulnerable] 杞处澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return False\n        \n        # 婕忔礊锛氭湭妫€鏌ュ噺娉曚笅婧紙from_addr浣欓鍙兘灏忎簬amount锛塡n        from_balance = self.get_balance(from_addr)\n        if from_balance < amount:\n            print(f\"[Vulnerable] 杞处澶辫触锛歿from_addr[:16]}... 浣欓涓嶈冻锛堥渶{amount} wei锛屾湁{from_balance} wei锛塡")\n            return False\n        \n        # 婕忔礊锛氭湭妫€鏌ュ姞娉曟孩鍑猴紙to_addr浣欓+amount鍙兘瓒呭嚭uint256锛塡n        to_balance = self.get_balance(to_addr)\n        new_from_balance = from_balance - amount\n        new_to_balance = to_balance + amount\n        \n        # 鏇存柊浣欓\n        self.balances[from_addr] = new_from_balance\n        self.balances[to_addr] = new_to_balance\n        \n        print(f\"[Vulnerable] 杞处鎴愬姛锛歿from_addr[:16]}... 鈫?{to_addr[:16]}...锛岄噾棰濓細{amount} wei\")\n        print(f\"[Vulnerable] {from_addr[:16]}... 浣欓锛歿new_from_balance} wei\")\n        print(f\"[Vulnerable] {to_addr[:16]}... 浣欓锛歿new_to_balance} wei\")\n        return True\n    \n    def batch_transfer(self, from_addr: str, recipients: List[str], amounts: List[int]) -> bool:\n        \"\"\"鎵归噺杞处锛堝瓨鍦ㄦ孩鍑烘紡娲烇級锛氭€婚璁＄畻鏈鏌ユ孩鍑篭"\"\"\n        if len(recipients) != len(amounts):\n            print(f\"[Vulnerable] 鎵归噺杞处澶辫触锛氭帴鏀惰€呬笌閲戦鏁伴噺涓嶅尮閰峔")\n            return False\n        \n        # 婕忔礊锛氭€婚璁＄畻鍙兘婧㈠嚭锛坰um(amounts)瓒呭嚭uint256锛塡n        total_amount = sum(amounts)\n        print(f\"[Vulnerable] 鎵归噺杞处锛氭€婚={total_amount} wei\")\n        \n        from_balance = self.get_balance(from_addr)\n        if from_balance < total_amount:\n            print(f\"[Vulnerable] 鎵归噺杞处澶辫触锛氫綑棰濅笉瓒砛")\n            return False\n        \n        # 鎵ц杞处\n        for recipient, amount in zip(recipients, amounts):\n            self.transfer(from_addr, recipient, amount)\n        return True\n\n\nclass IntegerOverflowSecure:\n    \"\"\"淇鏁存暟婧㈠嚭/涓嬫孩鐨勫畨鍏ㄥ悎绾︼紙瀹炵幇SafeMath閫昏緫锛塡"\"\"\n    \n    def __init__(self):\n        self.balances: Dict[str, int] = {}  # 璐︽埛浣欓鏄犲皠\n        self.MAX_UINT256 = 2**256 - 1  # uint256鏈€澶у€糪n        self.MIN_UINT256 = 0  # uint256鏈€灏忓€糪n    \n    def set_balance(self, address: str, amount: int):\n        \"\"\"璁剧疆璐︽埛浣欓锛堜笌婕忔礊鍚堢害涓€鑷达級\"\"\"\n        if amount < self.MIN_UINT256 or amount > self.MAX_UINT256:\n            print(f\"[Secure] 浣欓璁剧疆澶辫触锛氳秴鍑簎int256鑼冨洿\")\n            return\n        self.balances[address] = amount\n        print(f\"[Secure] {address[:16]}... 鍒濆浣欓璁剧疆涓猴細{amount} wei\")\n    \n    def get_balance(self, address: str) -> int:\n        \"\"\"鏌ヨ璐︽埛浣欓锛堜笌婕忔礊鍚堢害涓€鑷达級\"\"\"\n        return self.balances.get(address, 0)\n    \n    def _safe_add(self, a: int, b: int) -> Optional[int]:\n        \"\"\"瀹夊叏鍔犳硶锛氭鏌ユ孩鍑猴紙a + b 鈮?MAX_UINT256锛塡"\"\"\n        result = a + b\n        if result > self.MAX_UINT256 or result < a:  # 婧㈠嚭鍚巖esult浼氬皬浜巃锛圥ython涓璱nt鏃犳孩鍑猴紝妯℃嫙EVM琛屼负锛塡n            print(f\"[Secure] 鍔犳硶婧㈠嚭妫€娴嬶細{a} + {b} 瓒呭嚭uint256鑼冨洿\")\n            return None\n        return result\n    \n    def _safe_sub(self, a: int, b: int) -> Optional[int]:\n        \"\"\"瀹夊叏鍑忔硶锛氭鏌ヤ笅婧紙a - b 鈮?MIN_UINT256锛塡"\"\"\n        if a < b:\n            print(f\"[Secure] 鍑忔硶涓嬫孩妫€娴嬶細{a} - {b} 灏忎簬0\")\n            return None\n        return a - b\n    \n    def transfer(self, from_addr: str, to_addr: str, amount: int) -> bool:\n        \"\"\"杞处锛堝畨鍏ㄧ増锛夛細浣跨敤SafeMath妫€鏌ユ孩鍑?涓嬫孩\"\"\"\n        if amount <= 0:\n            print(f\"[Secure] 杞处澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n            return False\n        \n        from_balance = self.get_balance(from_addr)\n        to_balance = self.get_balance(to_addr)\n        \n        # 闃插尽1锛氬畨鍏ㄥ噺娉曪紙妫€鏌ヤ笅婧級\n        new_from_balance = self._safe_sub(from_balance, amount)\n        if new_from_balance is None:\n            return False\n        \n        # 闃插尽2锛氬畨鍏ㄥ姞娉曪紙妫€鏌ユ孩鍑猴級\n        new_to_balance = self._safe_add(to_balance, amount)\n        if new_to_balance is None:\n            return False\n        \n        # 鏇存柊浣欓\n        self.balances[from_addr] = new_from_balance\n        self.balances[to_addr] = new_to_balance\n        \n        print(f\"[Secure] 杞处鎴愬姛锛歿from_addr[:16]}... 鈫?{to_addr[:16]}...锛岄噾棰濓細{amount} wei\")\n        print(f\"[Secure] {from_addr[:16]}... 浣欓锛歿new_from_balance} wei\")\n        print(f\"[Secure] {to_addr[:16]}... 浣欓锛歿new_to_balance} wei\")\n        return True\n    \n    def batch_transfer(self, from_addr: str, recipients: List[str], amounts: List[int]) -> bool:\n        \"\"\"鎵归噺杞处锛堝畨鍏ㄧ増锛夛細瀹夊叏璁＄畻鎬婚\"\"\"\n        if len(recipients) != len(amounts):\n            print(f\"[Secure] 鎵归噺杞处澶辫触锛氭帴鏀惰€呬笌閲戦鏁伴噺涓嶅尮閰峔")\n            return False\n        \n        # 闃插尽锛氬畨鍏ㄨ绠楁€婚锛堥伩鍏嶆孩鍑猴級\n        total_amount = 0\n        for amount in amounts:\n            if amount <= 0:\n                print(f\"[Secure] 鎵归噺杞处澶辫触锛氶噾棰濆繀椤诲ぇ浜?\")\n                return False\n            total_amount = self._safe_add(total_amount, amount)\n            if total_amount is None:\n                return False\n        \n        print(f\"[Secure] 鎵归噺杞处锛氭€婚={total_amount} wei\")\n        \n        from_balance = self.get_balance(from_addr)\n        if from_balance < total_amount:\n            print(f\"[Secure] 鎵归噺杞处澶辫触锛氫綑棰濅笉瓒砛")\n            return False\n        \n        # 鎵ц杞处\n        for recipient, amount in zip(recipients, amounts):\n            self.transfer(from_addr, recipient, amount)\n        return True\n\n\n# 婕旂ず鏁存暟婧㈠嚭鏀诲嚮涓庨槻寰ndef demo_integer_overflow():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氭暣鏁版孩鍑?涓嬫孩鏀诲嚮锛圛nteger Overflow/Underflow锛? 妯℃嫙BatchOverflow浜嬩欢\")\n    print(\"=\"*60)\n    \n    # 鍦烘櫙璁惧畾锛氭敾鍑昏€呭埄鐢ㄦ孩鍑轰娇浣欓缁曞洖锛屽疄鐜伴潪娉曡浆璐n    user_address = \"0xUser_1234567890abcdef\"  # 鏅€氱敤鎴峰湴鍧€\n    attacker_address = \"0xAttacker_abcdef1234567890\"  # 鏀诲嚮鑰呭湴鍧€\n    \n    # 姝ラ1锛氶儴缃插瓨鍦ㄦ紡娲炵殑鍚堢害\n    print(\"\\n[姝ラ1] 閮ㄧ讲瀛樺湪鏁存暟婧㈠嚭婕忔礊鐨勫悎绾")\n    vulnerable_contract = IntegerOverflowVulnerable()\n    \n    # 姝ラ2锛氳缃垵濮嬩綑棰濓紙鏀诲嚮鑰呬綑棰濇帴杩憉int256鏈€澶у€硷級\n    print(\"\\n[姝ラ2] 璁剧疆鍒濆浣欓\")\n    vulnerable_contract.set_balance(user_address, 100)  # 鏅€氱敤鎴蜂綑棰?00 wei\n    attacker_initial_balance = vulnerable_contract.MAX_UINT256 - 50  # 鏀诲嚮鑰呬綑棰濓細2虏鈦碘伓-50 wei\n    vulnerable_contract.set_balance(attacker_address, attacker_initial_balance)\n    \n    # 姝ラ3锛氭敾鍑昏€呭彂璧锋孩鍑烘敾鍑伙紙杞处100 wei锛岃Е鍙戝姞娉曟孩鍑猴級\n    print(\"\\n[姝ラ3] 鏀诲嚮鑰呭彂璧锋暣鏁版孩鍑烘敾鍑籠")\n    print(f\"鏀诲嚮閫昏緫锛氭敾鍑昏€呬綑棰濓紙{attacker_initial_balance}锛? 100 鈫?瓒呭嚭uint256鑼冨洿锛岃Е鍙戞孩鍑篭")\n    vulnerable_contract.transfer(user_address, attacker_address, 100)\n    \n    # 鏀诲嚮缁撴灉鍒嗘瀽\n    print(\"\\n\" + \"-\"*40)\n    print(\"[鏀诲嚮缁撴灉] 婕忔礊鍚堢害\")\n    print(f\"鏀诲嚮鑰呮渶缁堜綑棰濓細{vulnerable_contract.get_balance(attacker_address)} wei\")\n    print(f\"棰勬湡缁撴灉锛歿attacker_initial_balance + 100} 鈫?瀹為檯缁撴灉锛堟孩鍑哄悗锛夛細{vulnerable_contract.get_balance(attacker_address)} wei\")\n    print(f\"婧㈠嚭婕忔礊瀵艰嚧浣欓缁曞洖锛屾敾鍑昏€呴潪娉曡幏鍙栬祫閲戯紒\")\n    \n    # 姝ラ4锛氶儴缃插畨鍏ㄥ悎绾︼紝楠岃瘉闃插尽鏁堟灉\n    print(\"\\n\" + \"-\"*60)\n    print(\"[姝ラ4] 閮ㄧ讲淇鍚庣殑瀹夊叏鍚堢害锛圫afeMath閫昏緫锛塡")\n    secure_contract = IntegerOverflowSecure()\n    \n    # 姝ラ5锛氶噸鏂拌缃垵濮嬩綑棰漒n    print(\"\\n[姝ラ5] 璁剧疆鍒濆浣欓\")\n    secure_contract.set_balance(user_address, 100)  # 鏅€氱敤鎴蜂綑棰?00 wei\n    secure_contract.set_balance(attacker_address, attacker_initial_balance)  # 鏀诲嚮鑰呬綑棰濓細2虏鈦碘伓-50 wei\n    \n    # 姝ラ6锛氭敾鍑昏€呭皾璇曟敾鍑诲畨鍏ㄥ悎绾n    print(\"\\n[姝ラ6] 鏀诲嚮鑰呭皾璇曟敾鍑诲畨鍏ㄥ悎绾")\n    print(f\"鏀诲嚮閫昏緫锛氭敾鍑昏€呬綑棰濓紙{attacker_initial_balance}锛? 100 鈫?灏濊瘯瑙﹀彂婧㈠嚭\")\n    attack_success = secure_contract.transfer(user_address, attacker_address, 100)\n    \n    # 闃插尽缁撴灉鍒嗘瀽\n    print(\"\\n\" + \"-\"*40)\n    print(\"[闃插尽缁撴灉] 瀹夊叏鍚堢害\")\n    if not attack_success:\n        print(f\"鏁存暟婧㈠嚭琚垚鍔熸娴嬪苟闃绘锛乗")\n    print(f\"鏀诲嚮鑰呮渶缁堜綑棰濓細{secure_contract.get_balance(attacker_address)} wei\")\n    print(f\"鏅€氱敤鎴锋渶缁堜綑棰濓細{secure_contract.get_balance(user_address)} wei\")\n    \n    # 棰濆婕旂ず锛氫笅婧㈡敾鍑婚槻寰n    print(\"\\n\" + \"-\"*40)\n    print(\"[棰濆婕旂ず] 鍑忔硶涓嬫孩鏀诲嚮闃插尽\")\n    # 鏀诲嚮鑰呭皾璇曚粠浣欓涓?鐨勮处鎴疯浆璐? wei锛堣Е鍙戜笅婧級\n    zero_balance_addr = \"0xZeroBalance_0000000000000000\"\n    secure_contract.set_balance(zero_balance_addr, 0)\n    print(f\"\\n灏濊瘯浠庝綑棰濅负0鐨勮处鎴疯浆璐? wei锛堣Е鍙戜笅婧級\")\n    secure_contract.transfer(zero_balance_addr, attacker_address, 1)\n    \n    # 鏍稿績闃插尽鎺柦鎬荤粨\n    print(\"\\n\" + \"=\"*60)\n    print(\"鏁存暟婧㈠嚭/涓嬫孩鏍稿績闃插尽鎺柦\")\n    print(\"=\"*60)\n    print(\"1. 浣跨敤SafeMath搴擄細鎵嬪姩妫€鏌ョ畻鏈繍绠楄竟鐣岋紙add/sub/mul/div锛塡")\n    print(\"2. 鍗囩骇Solidity鐗堟湰锛?.8.0+缂栬瘧鍣ㄩ粯璁ゆ坊鍔犳孩鍑烘鏌ワ紝鑷姩revert\")\n    print(\"3. 杈撳叆楠岃瘉锛氶檺鍒剁敤鎴疯緭鍏ョ殑鏁板€艰寖鍥达紝閬垮厤鏋佺鍊糪")\n    print(\"4. 鎵归噺鎿嶄綔鏃讹細鍒嗘璁＄畻鎬婚锛屾瘡姝ユ鏌ユ孩鍑篭")\n    \n    return True\n\n# 鎵ц婕旂ず\ndemo_integer_overflow()'),(144,20,4,'璁块棶鎺у埗婕忔礊锛圓ccess Control锛夛細鍘熺悊銆佸鐜颁笌闃插尽','1. 婕忔礊鍘熺悊锛歕n   - 鏍稿績閫昏緫锛氭櫤鑳藉悎绾︿腑鍏抽敭鍑芥暟锛堝鎻愭銆佹洿鏀规墍鏈夎€呫€佽浆璐︼級鏈缃弗鏍肩殑鏉冮檺楠岃瘉锛屾垨楠岃瘉閫昏緫閿欒锛堝浣跨敤tx.origin鑰岄潪msg.sender锛夛紝瀵艰嚧鏀诲嚮鑰呭彲鏈巿鏉冭皟鐢ㄦ晱鎰熸搷浣滐紝绐冨彇璧勯噾鎴栨帴绠″悎绾︺€俓n   - 鏁板妯″瀷锛氬畾涔夎皟鐢ㄩ摼涓簅rigin=E鈧€鈫扙鈧佲啋...鈫扙鈧?sender锛圗鈧€鏄師濮嬪彂璧疯€咃紝E鈧栨槸