浣欎綑棰濓細{self.balance} wei\")\n        return True\n    \n    def set_owner(self, caller_address: str, new_owner_address: str) -> bool:\n        \"\"\"鏇存敼鎵€鏈夎€咃紙瀛樺湪婕忔礊锛夛細鏈獙璇佽皟鐢ㄨ€呮槸鍚︿负褰撳墠鎵€鏈夎€匼"\"\"\n        # 婕忔礊锛氭棤鏉冮檺楠岃瘉\n        old_owner = self.owner\n        self.owner = new_owner_address\n        print(f\"[VulnerableAC] 鎵€鏈夎€呮洿鏀规垚鍔燂紒鏃ф墍鏈夎€咃細{old_owner[:16]}...锛屾柊鎵€鏈夎€咃細{new_owner_address[:16]}...\")\n        return True\n    \n    def pause_contract(self, caller_address: str) -> bool:\n        \"\"\"鏆傚仠鍚堢害锛堝瓨鍦ㄦ紡娲烇級锛氭湭楠岃瘉鏉冮檺\"\"\"\n        self.paused = True\n        print(f\"[VulnerableAC] 鍚堢害宸叉殏鍋滐紝璋冪敤鑰咃細{caller_address[:16]}...\")\n        return True\n\n\nclass AccessControlSecure:\n    \"\"\"淇璁块棶鎺у埗婕忔礊鐨勫畨鍏ㄥ悎绾︼紙RBAC瑙掕壊绠＄悊锛塡"\"\"\n    \n    def __init__(self, owner_address: str):\n        self.owner = owner_address  # 瓒呯骇绠＄悊鍛橈紙鎵€鏈夎€咃級\n        self.admins: Set[str] = {owner_address}  # 绠＄悊鍛樿鑹查泦鍚圽n        self.balance = 1000  # 鍚堢害璧勯噾浣欓锛坵ei锛塡n        self.paused = False  # 鍚堢害鏆傚仠鏍囪\n        print(f\"[SecureAC] 瀹夊叏鍚堢害閮ㄧ讲鎴愬姛锛屾墍鏈夎€咃細{owner_address[:16]}...锛屽垵濮嬩綑棰濓細{self.balance} wei\")\n    \n    def _is_owner(self, caller_address: str) -> bool:\n        \"\"\"楠岃瘉鏄惁涓烘墍鏈夎€匼"\"\"\n        return caller_address == self.owner\n    \n    def _is_admin(self, caller_address: str) -> bool:\n        \"\"\"楠岃瘉鏄惁涓虹鐞嗗憳\"\"\"\n        return caller_address in self.admins\n    \n    def withdraw(self, caller_address: str, amount: int) -> bool:\n        \"\"\"鎻愭锛堝畨鍏ㄧ増锛夛細浠呮墍鏈夎€呭彲璋冪敤\"\"\"\n        # 闃插尽1锛氭潈闄愰獙璇侊紙浠呮墍鏈夎€咃級\n        if not self._is_owner(caller_address):\n            print(f\"[SecureAC] 鎻愭澶辫触锛氭潈闄愭嫆缁濓紒浠呮墍鏈夎€呭彲璋冪敤锛屽綋鍓嶈皟鐢ㄨ€咃細{caller_address[:16]}...\")\n            return False\n        if self.paused:\n            print(f\"[SecureAC] 鍚堢害宸叉殏鍋滐紝鏃犳硶鎻愭\")\n            return False\n        if amount <= 0 or amount > self.balance:\n            print(f\"[SecureAC] 鎻愭澶辫触锛氶噾棰濇棤鏁堬紙闇€1-{self.balance} wei锛塡")\n            return False\n        \n        self.balance -= amount\n        print(f\"[SecureAC] 鎻愭鎴愬姛锛佹墍鏈夎€咃細{caller_address[:16]}...锛屾彁鍙栭噾棰濓細{amount} wei锛屽墿浣欎綑棰濓細{self.balance} wei\")\n        return True\n    \n    def set_owner(self, caller_address: str, new_owner_address: str) -> bool:\n        \"\"\"鏇存敼鎵€鏈夎€咃紙瀹夊叏鐗堬級锛氫粎褰撳墠鎵€鏈夎€呭彲璋冪敤\"\"\"\n        # 闃插尽1锛氭潈闄愰獙璇侊紙浠呭綋鍓嶆墍鏈夎€咃級\n        if not self._is_owner(caller_address):\n            print(f\"[SecureAC] 鏇存敼鎵€鏈夎€呭け璐ワ細鏉冮檺鎷掔粷锛佷粎褰撳墠鎵€鏈夎€呭彲璋冪敤锛屽綋鍓嶈皟鐢ㄨ€咃細{caller_address[:16]}...\")\n            return False\n        \n        old_owner = self.owner\n        self.owner = new_owner_address\n        self.admins.add(new_owner_address)  # 鏂版墍鏈夎€呰嚜鍔ㄦ垚涓虹鐞嗗憳\n        self.admins.discard(old_owner)  # 鏃ф墍鏈夎€呬笉鍐嶆槸绠＄悊鍛橈紙鍙€夛級\n        print(f\"[SecureAC] 鎵€鏈夎€呮洿鏀规垚鍔燂紒鏃ф墍鏈夎€咃細{old_owner[:16]}...锛屾柊鎵€鏈夎€咃細{new_owner_address[:16]}...\")\n        return True\n    \n    def add_admin(self, caller_address: str, new_admin_address: str) -> bool:\n        \"\"\"娣诲姞绠＄悊鍛橈紙瀹夊叏鐗堬級锛氫粎鎵€鏈夎€呭彲璋冪敤\"\"\"\n        if not self._is_owner(caller_address):\n            print(f\"[SecureAC] 娣诲姞绠＄悊鍛樺け璐ワ細鏉冮檺鎷掔粷锛佷粎鎵€鏈夎€呭彲璋冪敤\")\n            return False\n        if new_admin_address in self.admins:\n            print(f\"[SecureAC] 娣诲姞绠＄悊鍛樺け璐ワ細{new_admin_address[:16]}... 宸叉槸绠＄悊鍛榎")\n            return False\n        \n        self.admins.add(new_admin_address)\n        print(f\"[SecureAC] 娣诲姞绠＄悊鍛樻垚鍔燂細{new_admin_address[:16]}...\")\n        return True\n    \n    def pause_contract(self, caller_address: str) -> bool:\n        \"\"\"鏆傚仠鍚堢害锛堝畨鍏ㄧ増锛夛細浠呯鐞嗗憳鍙皟鐢╘"\"\"\n        if not self._is_admin(caller_address):\n            print(f\"[SecureAC] 鏆傚仠鍚堢害澶辫触锛氭潈闄愭嫆缁濓紒浠呯鐞嗗憳鍙皟鐢╘")\n            return False\n        \n        self.paused = True\n        print(f\"[SecureAC] 鍚堢害宸叉殏鍋滐紝绠＄悊鍛橈細{caller_address[:16]}...\")\n        return True\n\n\n# 婕旂ず璁块棶鎺у埗婕忔礊涓庨槻寰ndef demo_access_control():\n    print(\"\\n\" + \"=\"*60)\n    print(\"婕旂ず锛氳闂帶鍒舵紡娲烇紙Access Control锛? 妯℃嫙Parity閽卞寘浜嬩欢\")\n    print(\"=\"*60)\n    \n    # 鍦烘櫙璁惧畾锛氭敾鍑昏€呭埄鐢ㄧ己澶辩殑鏉冮檺楠岃瘉锛屾湭鎺堟潈璁块棶鏁忔劅鎿嶄綔\n    owner_address = \"0xOwner_1234567890abcdef\"  # 鍚堢害鎵€鏈夎€呭湴鍧€\n    attacker_address = \"0xAttacker_abcdef1234567890\"  # 鏀诲嚮鑰呭湴鍧€\n    user_address = \"0xUser_0000000000000000\"  # 鏅€氱敤鎴峰湴鍧€\n    \n    # 姝ラ1锛氶儴缃插瓨鍦ㄦ紡娲炵殑鍚堢害\n    print(\"\\n[姝ラ1] 閮ㄧ讲瀛樺湪璁块棶鎺у埗婕忔礊鐨勫悎绾")\n    vulnerable_contract = AccessControlVulnerable(owner_address)\n    \n    # 姝ラ2锛氭敾鍑昏€呮湭鎺堟潈鎻愭\n    print(\"\\n[姝ラ2] 鏀诲嚮鑰呭皾璇曟湭鎺堟潈鎻愭\")\n    vulnerable_contract.withdraw(attacker_address, 500)  # 鏀诲嚮鑰呴潪鎵€鏈夎€咃紝鎴愬姛鎻愭\n    \n    # 姝ラ3锛氭敾鍑昏€呮湭鎺堟潈鏇存敼鎵€鏈夎€匼n    print(\"\\n[姝ラ3] 鏀诲嚮鑰呭皾璇曟洿鏀瑰悎绾︽墍鏈夎€匼")\n    vulnerable_contract.set_owner(attacker_address, attacker_address)  # 鏀诲嚮鑰呮垚涓烘柊鎵€鏈夎€匼n    \n    # 鏀诲嚮缁撴灉鍒嗘瀽\n    print(\"\\n\" + \"-\"*40)\n    print(\"[鏀诲嚮缁撴灉] 婕忔礊鍚堢害\")\n    print(f\"鍚堢害褰撳墠鎵€鏈夎€咃細{vulnerable_contract.owner[:16]}...\")\n    print(f\"鍚堢害鍓╀綑浣欓锛歿vulnerable_contract.balance} wei\")\n    print(f\"鏀诲嚮鑰呮垚鍔熸湭鎺堟潈鎻愭骞舵帴绠″悎绾︼紒\")\n    \n    # 姝ラ4锛氶儴缃插畨鍏ㄥ悎绾︼紙RBAC瑙掕壊绠＄悊锛塡n    print(\"\\n\" + \"-\"*60)\n    print(\"[姝ラ4] 閮ㄧ讲淇鍚庣殑瀹夊叏鍚堢害锛圧BAC瑙掕壊绠＄悊锛塡")\n    secure_contract = AccessControlSecure(owner_address)\n    \n    # 姝ラ5锛氭敾鍑昏€呭皾璇曟湭鎺堟潈鎻愭\n    print(\"\\n[姝ラ5] 鏀诲嚮鑰呭皾璇曟湭鎺堟潈鎻愭\")\n    secure_contract.withdraw(attacker_address, 500)  # 鏉冮檺鎷掔粷\n    \n    # 姝ラ6锛氭敾鍑昏€呭皾璇曟洿鏀规墍鏈夎€匼n    print(\"\\n[姝ラ6] 鏀诲嚮鑰呭皾璇曟洿鏀瑰悎绾︽墍鏈夎€匼")\n    secure_contract.set_owner(attacker_address, attacker_address)  # 鏉冮檺鎷掔粷\n    \n    # 姝ラ7锛氬悎娉曟搷浣滄紨绀猴紙鎵€鏈夎€呮彁娆撅級\n    print(\"\\n[姝ラ7] 鎵€鏈夎€呮墽琛屽悎娉曟彁娆綷")\n    secure_contract.withdraw(owner_address, 300)  # 鏉冮檺閫氳繃\n    \n    # 姝ラ8锛氭墍鏈夎€呮坊鍔犵鐞嗗憳锛岀鐞嗗憳鏆傚仠鍚堢害\n    print(\"\\n[姝ラ8] 鎵€鏈夎€呮坊鍔犵鐞嗗憳锛岀鐞嗗憳鏆傚仠鍚堢害\")\n    secure_contract.add_admin(owner_address, user_address)  # 鎵€鏈夎€呮坊鍔犳櫘閫氱敤鎴蜂负绠＄悊鍛榎n    secure_contract.pause_contract(user_address)  # 鏂扮鐞嗗憳鏆傚仠鍚堢害\n    \n    # 闃插尽缁撴灉鍒嗘瀽\n    print(\"\\n\" + \"-\"*40)\n    print(\"[闃插尽缁撴灉] 瀹夊叏鍚堢害\")\n    print(f\"鍚堢害褰撳墠鎵€鏈夎€咃細{secure_contract.owner[:16]}...\")\n    print(f\"鍚堢害绠＄悊鍛橀泦鍚堬細{[add