 else {\n      hash = sha256(hash + step.hash);\n    }\n  }\n  return hash === root;\n}'),(151,21,5,'瀛︿範閿氬畾涓庢ˉ鎺ユā鍨嬪伐浣滄祦绋?,'1. 鏍稿績鎬濇兂锛氶€氳繃鈥滈攣瀹?閾搁€犫€濆疄鐜拌祫浜ц法閾炬槧灏勶紝濡傞摼A閿佸畾1BTC锛岄摼B閾搁€?WBTC锛沑n2. 鎺屾彙瀹屾暣娴佺▼锛歕n   - 姝ｅ悜杞Щ锛氱敤鎴疯皟鐢ㄩ摼A妗ユ帴鍚堢害閿佸畾璧勪骇 鈫?楠岃瘉鑰呯‘璁や簨浠?鈫?閾綛閾搁€犲搴斾唬甯侊紱\n   - 鍙嶅悜璧庡洖锛氶摼B閿€姣佹槧灏勪唬甯?鈫?閾続閲婃斁鍘熻祫浜э紱\n3. 鐞嗚В瀹夊叏鏈哄埗锛歕n   - 澶氱鏈哄埗锛氳祫浜ч噴鏀鹃渶婊¤冻绛惧悕鏁伴噺鈮ラ槇鍊紅锛圴alid鉄簗signatures|鈮锛夛紱\n   - 闂ㄩ檺绛惧悕锛歵-of-n绉樺瘑鍏变韩鐢熸垚鍗曚竴绛惧悕蟽=Combine(蟽鈧?鈥?蟽鈧?锛沑n   - 杞诲鎴风楠岃瘉妗ワ細鏃犻渶淇′换涓棿鑺傜偣锛岀洿鎺ラ獙璇佸鏂归摼鍖哄潡澶翠笌Merkle璇佹槑銆?,'闂ㄩ檺绛惧悕鐩告瘮澶氱鏇寸畝娲侊紝涓旂鍚嶇敓鎴愯繃绋嬫洿鍏烽殣绉佹€?,NULL),(152,21,6,'璁よ瘑璺ㄩ摼瀹夊叏濞佽儊涓庨槻寰℃満鍒?,'1. 閫愪竴瀛︿範涓昏鏀诲嚮绫诲瀷锛氫腑缁т吉閫犮€侀噸鏀炬敾鍑汇€佹ˉ鍚堢害婕忔礊銆佽祫浜у弻鑺便€侀獙璇佽妭鐐逛覆璋嬶紱\n2. 鎺屾彙瀵瑰簲闃插尽鎺柦锛歕n   - 涓户浼€狅細澶氱+杞诲鎴风楠岃瘉锛沑n   - 閲嶆斁鏀诲嚮锛氶獙璇佸尯鍧楅珮搴︿笌Nonce锛沑n   - 妗ュ悎绾︽紡娲烇細瀹¤+闄愬埗鏉冮檺锛沑n   - 璧勪骇鍙岃姳锛氬弻鍚戠姸鎬侀攣+瓒呮椂閿侊紱\n   - 楠岃瘉鑺傜偣涓茶皨锛氬幓淇′换闂ㄩ檺绛惧悕+闅忔満楠岃瘉鑰呴泦锛沑n3. 鐞嗚В璺ㄩ摼瀹夊叏涓夊厓缁?C,V,A)锛欳涓鸿法閾惧悎绾?璇佹槑绯荤粺锛孷涓洪獙璇佸嚱鏁帮紙Merkle/绛惧悕锛夛紝A涓哄師瀛愭€х害鏉燂紙鏃堕棿/鍝堝笇閿侊級锛屽畨鍏ㄦ€ф潯浠朵负鈭€m鈭圡,V(C(m))=1鈬扐(m)=Atomic銆?,'璺ㄩ摼瀹夊叏鐨勬牳蹇冩槸鈥滃彲楠岃瘉鎬р€濅笌鈥滃師瀛愭€р€濓紝涓よ€呯己涓€涓嶅彲',NULL),(153,21,7,'瀹炶返鍘熷瓙浜ゆ崲鍗忚浠ｇ爜瀹炵幇','1. 鐜鍑嗗锛氱‘淇漃ython鐜姝ｅ父锛屽鍏ashlib銆乻ecrets銆乼ime绛変緷璧栧簱锛沑n2. 鐞嗚В鏍稿績绫昏璁★細Blockchain绫绘ā鎷熷尯鍧楅摼鍩虹鍔熻兘锛堝垱寤鸿处鎴枫€佹坊鍔犱氦鏄撱€佹寲鐭匡級锛孉tomicSwap绫诲疄鐜板師瀛愪氦鎹㈤€昏緫锛沑n3. 鍒嗘杩愯婕旂ず浠ｇ爜锛歕n   - 鍒涘缓Bitcoin鍜孍thereum涓ゆ潯妯℃嫙閾撅紝鍒濆鍖朅lice鍜孊ob鐨勮处鎴蜂綑棰濓紱\n   - 璋冪敤initiate_swap鏂规硶鍙戣捣浜ゆ崲锛岀敓鎴愮瀵唖鍜屽搱甯宧锛屽垱寤轰袱鏉￠摼涓婄殑HTLC鍚堢害锛沑n   - 鎸栫熆纭浜ゆ槗锛屾洿鏂板尯鍧楅珮搴︼紱\n   - 璋冪敤complete_swap鏂规硶锛屼娇鐢ㄧ瀵唖瑙ｉ攣鍙屾柟鍚堢害锛屾寲鐭跨‘璁ゅ悗鏌ョ湅璐︽埛浣欓鍙樺寲锛沑n   - 棰勬湡杈撳嚭锛欰lice鐨凚TC浣欓鍑忓皯锛孍TH浣欓澧炲姞锛汢ob鐨凚TC浣欓澧炲姞锛孍TH浣欓鍑忓皯锛屼氦鎹㈡垚鍔熴€?,'杩愯浠ｇ爜鏃跺彲淇敼time_lock鍙傛暟锛岃瀵熻秴鏃堕€€娆炬満鍒剁殑瑙﹀彂鏉′欢','// 鏍稿績婕旂ず浠ｇ爜鐗囨锛堝畬鏁翠唬鐮佽璧勬枡锛塡ndef demo_atomic_swap():\n    # 鍒涘缓鍖哄潡閾綷n    bitcoin_chain = Blockchain(ChainType.BITCOIN, \"Bitcoin涓荤綉\")\n    ethereum_chain = Blockchain(ChainType.ETHEREUM, \"Ethereum涓荤綉\")\n    \n    # 鍒涘缓璐︽埛骞跺垵濮嬪寲浣欓\n    alice_btc = \"alice_btc_address\"\n    bob_eth = \"bob_eth_address\"\n    bitcoin_chain.create_account(alice_btc, 2.0)\n    ethereum_chain.create_account(bob_eth, 20.0)\n    \n    # 鍒濆鍖栧師瀛愪氦鎹n    atomic_swap = AtomicSwap(bitcoin_chain, ethereum_chain)\n    swap_id, secret_hash = atomic_swap.initiate_swap(\n        initiator=alice_btc, responder=bob_eth, amount_a=1.0, amount_b=15.0\n    )\n    \n    # 鎸栫熆纭\n    bitcoin_chain.mine_block()\n    ethereum_chain.mine_block()\n    \n    # 瀹屾垚浜ゆ崲\n    secret = atomic_swap.swaps[swap_id][\'secret\']\n    atomic_swap.complete_swap(swap_id, secret)\n    \n    # 鏌ョ湅缁撴灉\n    print(\"Alice BTC浣欓:\", bitcoin_chain.get_balance(alice_btc))\n    print(\"Bob ETH浣欓:\", ethereum_chain.get_balance(bob_eth))'),(154,21,8,'瀹炶返璺ㄩ摼妗ユ帴涓庝晶閾惧崗璁?,'1. 璺ㄩ摼妗ユ帴婕旂ず锛歕n   - 鍒涘缓Ethereum鍜孭olygon妯℃嫙閾撅紝鍒濆鍖栫敤鎴疯处鎴凤紱\n   - 璋冪敤lock_assets鏂规硶鍦‥thereum閿佸畾璧勪骇锛屾寲鐭跨‘璁わ紱\n   - 璋冪敤mint_assets鏂规硶鍦≒olygon閾搁€犲搴旇祫浜э紝鏌ョ湅鐢ㄦ埛鍦≒olygon鐨勪綑棰濓紱\n   - 璋冪敤burn_assets鏂规硶鍦≒olygon閿€姣佽祫浜э紝璋冪敤unlock_assets鏂规硶鍦‥thereum瑙ｉ攣璧勪骇锛岄獙璇佸弽鍚戣浆绉绘祦绋嬶紱\n   - 棰勬湡杈撳嚭锛氭鍚戣浆绉诲悗鐢ㄦ埛ETH浣欓鍑忓皯锛孭olygon浣欓澧炲姞锛涘弽鍚戣浆绉诲悗ETH浣欓澧炲姞锛孭olygon浣欓鍑忓皯銆俓n2. 渚ч摼鍗忚婕旂ず锛歕n   - 鍒涘缓Bitcoin涓婚摼鍜孡iquid渚ч摼锛屽垵濮嬪寲鐢ㄦ埛璐︽埛锛沑n   - 璋冪敤peg_in鏂规硶灏嗕富閾捐祫浜ц浆绉诲埌渚ч摼锛屾寲鐭跨‘璁ゅ悗鏌ョ湅浣欓锛沑n   - 鍦ㄤ晶閾惧垱寤哄揩閫熶氦鏄擄紝鎸栫熆纭锛沑n   - 璋冪敤peg_out鏂规硶灏嗕晶閾捐祫浜ц浆绉诲洖涓婚摼锛岄獙璇佸畬鏁存祦绋嬶紱\n   - 棰勬湡杈撳嚭锛歅eg-in鍚庝富閾句綑棰濆噺灏戯紝渚ч摼浣欓澧炲姞锛涗晶閾句氦鏄撴甯告墽琛岋紱Peg-out鍚庝晶閾句綑棰濆噺灏戯紝涓婚摼浣欓澧炲姞銆?,'瀵规瘮璺ㄩ摼妗ユ帴涓庝晶閾剧殑宸紓锛氫晶閾鹃€氬父涓庝富閾炬湁鏇村己鐨勮€﹀悎鎬э紝鑰岃法閾炬ˉ鎺ユ洿鐏垫椿鏀寔寮傛瀯閾?,'// 璺ㄩ摼妗ユ帴鏍稿績浠ｇ爜鐗囨\ndef demo_cross_chain_bridge():\n    ethereum_chain = Blockchain(ChainType.ETHEREUM, \"Ethereum涓荤綉\")\n    polygon_chain = Blockchain(ChainType.POLKADOT, \"Polygon缃戠粶\")\n    \n    user_eth = \"user_eth_address\"\n    ethereum_chain.create_account(user_eth, 10.0)\n    \n    # 鍒濆鍖栬法閾炬ˉ\n    bridge = CrossChainBridge(ethereum_chain, polygon_chain)\n    bridge_id = bridge.lock_assets(user_eth, 5.0, \"user_polygon_address\")\n    \n    # 閾搁€犺祫浜n    bridge.mint_assets(bridge_id)\n    print(\"鐢ㄦ埛ETH浣欓:\", ethereum_chain.get_balance(user_eth))\n    print(\"鐢ㄦ埛Polygon浣欓:\", polygon_chain.get_balance(\"user_polygon_address\"))'),(155,21,9,'鎬荤粨璺ㄩ摼鍗忚鐨勬暟瀛﹀熀纭€涓庡簲鐢ㄤ环鍊?,'1. 姊崇悊鏍稿績鏁板鎶€鏈細鍝堝笇鎵胯锛圚(x)涓嶅彲閫嗘€э級銆佹椂闂撮攣涓庡師瀛愭€ф潯浠躲€丮erkle鏍戣瘉鏄庛€侀棬闄愮鍚嶃€侀浂鐭ヨ瘑璇佹槑锛沑n2. 鐞嗚