垎鍧楁搷浣滐紱\n3. 娑堟伅璋冨害鎵╁睍锛氬皢512姣旂壒鍧楁墿灞曚负64涓?2浣嶅瓧锛圫HA-256锛?80涓?2浣嶅瓧锛圫HA-1锛夛紱\n4. 杩唬鍘嬬缉璁＄畻锛氭寜杞鎵ц鍘嬬缉鍑芥暟锛屾洿鏂板搱甯岀姸鎬侊紱\n5. 缁撴灉杈撳嚭锛氬皢鏈€缁堝搱甯岀姸鎬佽浆鎹负鍗佸叚杩涘埗瀛楃涓层€俓n6. 楠岃瘉锛氫娇鐢ㄦ爣鍑嗘祴璇曞悜閲忥紙绌哄瓧绗︿覆銆乗"abc\"绛夛級楠岃瘉瀹炵幇姝ｇ‘鎬э紝纭繚杈撳嚭涓庨鏈熷搱甯屽€间竴鑷淬€?,'娉ㄦ剰鍖哄垎SHA-1涓嶴HA-256鐨勫弬鏁板樊寮傦紙濡傚垵濮嬪悜閲忋€佽疆甯告暟銆佽疆娆°€佽緭鍑洪暱搴︾瓑锛?,'def right_rotate(value, amount):\n    \"\"\"32浣嶆暣鏁扮殑寰幆鍙崇Щ\"\"\"\n    return ((value >> amount) | (value << (32 - amount))) & 0xFFFFFFFF\n\n\ndef sha256(message):\n    \"\"\"\n    璁＄畻杈撳叆娑堟伅鐨凷HA-256鏁ｅ垪鍊糪n    \n    鍙傛暟:\n        message (str 鎴?bytes): 瑕佽绠楁暎鍒楀€肩殑娑堟伅\n    \n    杩斿洖:\n        str: SHA-256鏁ｅ垪鍊肩殑鍗佸叚杩涘埗瀛楃涓茶〃绀篭n    \"\"\"\n    # 灏嗚緭鍏ユ秷鎭浆鎹负瀛楄妭\n    if isinstance(message, str):\n        message = message.encode(\'utf-8\')\n    \n    # SHA-256绠楁硶浣跨敤鐨勫垵濮嬪搱甯屽€?(鍓?涓川鏁扮殑骞虫柟鏍瑰皬鏁伴儴鍒嗙殑鍓?2浣?\n    h = [\n        0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a,\n        0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19\n    ]\n    \n    # SHA-256绠楁硶浣跨敤鐨勫父閲?(鍓?4涓川鏁扮殑绔嬫柟鏍瑰皬鏁伴儴鍒嗙殑鍓?2浣?\n    k = [\n        0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5,\n        0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,\n        0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3,\n        0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,\n        0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc,\n        0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,\n        0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7,\n        0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,\n        0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13,\n        0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,\n        0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3,\n        0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,\n        0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5,\n        0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,\n        0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208,\n        0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2\n    ]\n    \n    # 棰勫鐞? 濉厖娑堟伅\n    # 1. 闄勫姞姣旂壒\'1\'\n    # 2. 闄勫姞k涓瘮鐗筡'0\', k鏄弧瓒?(娑堟伅闀垮害 + 1 + k + 8) % 512 = 0 鐨勬渶灏忛潪璐熸暣鏁癨n    # 3. 闄勫姞娑堟伅闀垮害鐨?4浣嶈〃绀篭n    \n    # 璁＄畻鍘熷姣旂壒闀垮害\n    original_bit_len = len(message) * 8\n    \n    # 闄勫姞姣旂壒\'1\'\n    message += b\'\\x80\'\n    \n    # 闄勫姞姣旂壒\'0\'鐩村埌娑堟伅闀垮害婊¤冻鏉′欢 (娑堟伅闀垮害 + 1 + k + 8) % 64 = 0 (浠ュ瓧鑺備负鍗曚綅)\n    while (len(message) % 64) != 56:\n        message += b\'\\x00\'\n    \n    # 闄勫姞娑堟伅闀垮害(鍘熷娑堟伅鐨勬瘮鐗归暱搴?鐨?4浣?8瀛楄妭)琛ㄧず\n    message += original_bit_len.to_bytes(8, byteorder=\'big\')\n    \n    # 澶勭悊娑堟伅鍧梊n    for i in range(0, len(message), 64):\n        chunk = message[i:i+64]\n        \n        # 鍒涘缓娑堟伅璋冨害琛?(message schedule)\n        w = [0] * 64\n        \n        # 灏嗗潡鎷嗗垎涓?6涓?2浣?4瀛楄妭)瀛梊n        for j in range(16):\n            w[j] = int.from_bytes(chunk[j*4:j*4+4], byteorder=\'big\')\n        \n        # 鎵╁睍鍓╀綑鐨?8涓瓧\n        for j in range(16, 64):\n            s0 = right_rotate(w[j-15], 7) ^ right_rotate(w[j-15], 18) ^ (w[j-15] >> 3)\n            s1 = right_rotate(w[j-2], 17) ^ right_rotate(w[j-2], 19) ^ (w[j-2] >> 10)\n            w[j] = (w[j-16] + s0 + w[j-7] + s1) & 0xFFFFFFFF\n        \n        # 鍒濆鍖栧伐浣滃彉閲忎负褰撳墠鐨勫搱甯屽€糪n        a, b, c, d, e, f, g, h_val = h\n        \n        # 鍘嬬缉鍑芥暟涓诲惊鐜痋n        for j in range(64):\n            S1 = right_rotate(e, 6) ^ right_rotate(e, 11) ^ right_rotate(e, 25)\n            ch = (e & f) ^ ((~e) & g)\n            temp1 = (h_val + S1 + ch + k[j] + w[j]) & 0xFFFFFFFF\n            S0 = right_rotate(a, 2) ^ right_rotate(a, 13) ^ right_rotate(a, 22)\n            maj = (a & b) ^ (a & c) ^ (b & c)\n            temp2 = (S0 + maj) & 0xFFFFFFFF\n            \n            h_val = g\n            g = f\n            f = e\n            e = (d + temp1) & 0xFFFFFFFF\n            d = c\n            c = b\n            b = a\n            a = (temp1 + temp2) & 0xFFFFFFFF\n        \n        # 灏嗗帇缂╁悗鐨勫潡娣诲姞鍒板綋鍓嶅搱甯屽€糪n        h[0] = (h[0] + a) & 0xFFFFFFFF\n        h[1] = (h[1] + b) & 0xFFFFFFFF\n        h[2] = (h[2] + c) & 0xFFFFFFFF\n        h[3] = (h[3] + d) & 0xFFFFFFFF\n        h[4] = (h[4] + e) & 0xFFFFFFFF\n        h[5] = (h[5] + f) & 0xFFFFFFFF\n        h[6] = (h[6] + g) & 0xFFFFFFFF\n        h[7] = (h[7] + h_val) & 0xFFFFFFFF\n    \n    # 灏嗘渶缁堝搱甯屽€艰浆鎹负鍗佸叚杩涘埗瀛楃涓瞈n    return \'\'.join(format(h_val, \'08x\') for h_val in h)\n\n# 婕旂ず楠岃瘉\ntest_vectors = [\n    (\"\", \"e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855\"),\n    (\"abc\", \"ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad\"),\n    (\"abcdbcdecdefdefgefghfghighijhijkijkljklmklmnlmnomnopnopq\",\n     \"248d6a61d20638b8e5c026930c3e6039a33ce45964ff2167f6ecedd419db06c1\"),\n]\n\nfor message, expected in test_vectors:\n    result = sha256(message)\n    print(f\"娑堟伅: {message!r}\")\n    print(f\"SHA-256: {result}\")\n    print(f\"棰勬湡缁撴灉: {expected}\")\n    print(f\"楠岃瘉: {\'閫氳繃\' if result == expected else \'澶辫触\'}\")\n    print()'),(228,39,1,'浜嗚ВMD5鐨勮捣婧愪笌鑳屾櫙','1. MD5鍏ㄧО涓篗essage Digest Algorithm 5锛堟秷鎭憳瑕佺畻娉曠浜旂増锛夛紝鐢盧SA涓変綅鍙戞槑浜轰箣涓€鐨凴on Rivest鍦?991骞磋璁″苟鍙戝竷銆俓n2. 瀹冩槸MD绯诲垪鍝堝笇鍑芥暟鐨勬渶鍚庝竴浠ｏ紝婕旇繘璺緞涓篗D2锛?989锛岄拡瀵?浣嶆満浼樺寲锛夆啋 MD4锛?990锛岄€熷害蹇絾瀹夊叏鎬т笉瓒筹級鈫?MD5锛?991锛屾敼杩汳D4瀹夊叏寮辩偣锛夈€俓n3. 璁捐鑳屾櫙婧愪簬90骞翠唬鍒濅簰鑱旂綉鍙戝睍瀵规暟瀛楃鍚嶃€佹枃浠跺畬鏁存€ф牎楠屻€佹秷鎭槻绡℃敼鐨勯渶姹傦紝鏍稿績鏄湪MD4鍩虹涓婂姞寮鸿繍绠楁楠や互鎻愬崌瀹夊叏鎬с€?,NULL,NULL),(229,39,2,'姊崇悊MD5鐨勫簲鐢ㄤ笌寮冪敤鍘嗙▼','1. 鏍囧噯鍖栦笌搴旂敤闃舵锛歁D5蹇€熸垚涓轰簨瀹炰笂鐨勮涓氭爣鍑嗭紝骞挎硾搴旂敤浜庢棭鏈烻SL/TLS锛圚TTPS鍗忚锛夈€丳GP/SSH鍔犲瘑宸ュ叿銆丷SA/DSA鏁板瓧绛惧悕鍝堝笇棰勫鐞嗐€乵d5sum鏂囦欢鏍￠獙宸ュ叿绛夊満鏅€俓n2. 寮辩偣鏆撮湶闃舵锛?996骞碒ans Dobbertin鎸囧嚭鍏跺帇缂╁嚱鏁板瓨鍦ㄥ急鐐癸紱2004骞寸帇灏忎簯鍥㈤槦鍏竷瀹炵敤纰版挒鏀诲嚮鏂规硶锛?008骞寸爺绌朵汉鍛樺埄鐢∕D5纰版挒浼€燙A璇佷功锛岀洿鎺ュ▉鑳佷簰鑱旂綉瀹夊叏銆俓n3. 寮冪敤闃舵锛?008骞磋捣IETF銆丯IST绛夋満鏋勬槑纭鐢∕D5锛岀幇浠ｅ簲鐢ㄥ叏闈㈣縼绉昏嚦SHA-2鎴朣HA-3锛岀洰鍓嶄粎鐢ㄤ簬闈炲畨鍏ㄥ満鏅紙濡傚揩閫熸枃浠舵牎楠岋級銆?,NULL,NULL),(230,39,3,'鎺屾彙MD5鐨勬€讳綋绠楁硶缁撴瀯','MD5閲囩敤涓嶴HA-1鍚屾簮鐨凪erkle鈥揇amg氓rd缁忓吀鍝堝笇缁撴瀯锛屾暣浣撴墽琛屾祦绋嬪垎涓哄洓涓牳蹇冪幆鑺傦細\n1. 娑堟伅濉厖锛圥adding锛夛細瀵硅緭鍏ユ秷鎭繘琛屾爣鍑嗗寲濉厖锛屼繚璇侀暱搴︾鍚堢畻娉曡姹傦紱\n2. 娑堟伅鍒嗗潡锛氬皢濉厖鍚庣殑娑堟伅鎷嗗垎涓哄浐瀹氬ぇ灏忕殑512姣旂壒鍒嗙粍锛沑n3. 杩唬鍘嬬缉鍑芥暟锛氬姣忎釜鍒嗙粍鎵ц64杞潪绾挎€ц凯浠ｈ繍绠楋紝鏇存柊鍝堝笇鐘舵€侊紱\n4. 杈撳嚭鎽樿锛氭墍鏈夊垎缁勫鐞嗗畬鎴愬悗锛屾嫾鎺ユ渶缁堝搱甯岀姸鎬佸緱鍒?28浣嶆秷鎭憳瑕併€?,NULL,NULL),(231,39,4,'鎵ц娑堟伅棰勫鐞嗘搷浣?,'棰勫鐞嗘槸MD5淇濊瘉杈撳叆鍞竴鎬у拰绠楁硶瑙勮寖鎬х殑鍏抽敭姝ラ锛屽垎涓哄～鍏呭拰鍒嗗潡涓ゆ锛歕n1. 濉厖瑙勫垯锛歕n   - 