       message (str 鎴?bytes): 瑕佽绠楁潅鍑戝€肩殑娑堟伅\n    \n    杩斿洖:\n        str: SM3鏉傚噾鍊肩殑鍗佸叚杩涘埗瀛楃涓茶〃绀篭n    \"\"\"\n    # 灏嗚緭鍏ユ秷鎭浆鎹负瀛楄妭\n    if isinstance(message, str):\n        message = message.encode(\'utf-8\')\n    \n    # SM3绠楁硶浣跨敤鐨勫垵濮嬪€糪n    h = [\n        0x7380166F, 0x4914B2B9, 0x172442D7, 0xDA8A0600,\n        0xA96F30BC, 0x163138AA, 0xE38DEE4D, 0xB0FB0E4E\n    ]\n    \n    # 棰勫鐞嗭細娣诲姞濉厖\n    message_len = len(message)\n    message += b\'\\x80\'  # 娣诲姞涓€涓?浣嶏紝鍏朵綑涓?\n    \n    # 濉厖鍒伴暱搴︿负448 mod 512\n    while len(message) % 64 != 56:\n        message += b\'\\x00\'\n    \n    # 娣诲姞鍘熷娑堟伅闀垮害锛堜互浣嶄负鍗曚綅锛?4浣嶅ぇ绔簭锛塡n    message += struct.pack(\'>Q\', message_len * 8)\n    \n    # 澶勭悊姣忎釜512浣嶇殑鍧梊n    for chunk_start in range(0, len(message), 64):\n        chunk = message[chunk_start:chunk_start + 64]\n        \n        # 灏嗗潡鍒嗚В涓?6涓?2浣嶇殑澶х搴忓瓧\n        w = list(struct.unpack(\'>16I\', chunk))\n        \n        # 鎵╁睍涓?8涓瓧\n        for j in range(16, 68):\n            w_j_16 = w[j-16]\n            w_j_9 = w[j-9]\n            w_j_3 = w[j-3]\n            w_j_13 = w[j-13]\n            w_j_6 = w[j-6]\n            \n            temp = w_j_16 ^ w_j_9 ^ left_rotate(w_j_3, 15)\n            temp = p1(temp) ^ left_rotate(w_j_13, 7) ^ w_j_6\n            w.append(temp)\n        \n        # 璁＄畻W\'\n        w_prime = []\n        for j in range(64):\n            w_prime.append(w[j] ^ w[j+4])\n        \n        # 鍒濆鍖栬繖涓€杞殑鏉傚噾鍊糪n        a, b, c, d, e, f, g, h_val = h\n        \n        # 涓诲惊鐜痋n        for j in range(64):\n            if j < 16:\n                t_j = 0x79CC4519\n            else:\n                t_j = 0x7A879D8A\n            \n            ss1 = left_rotate((left_rotate(a, 12) + e + left_rotate(t_j, j % 32)) & 0xFFFFFFFF, 7)\n            ss2 = ss1 ^ left_rotate(a, 12)\n            \n            if j < 16:\n                ff_result = ff_0_15(a, b, c)\n                gg_result = gg_0_15(e, f, g)\n            else:\n                ff_result = ff_16_63(a, b, c)\n                gg_result = gg_16_63(e, f, g)\n            \n            tt1 = (ff_result + d + ss2 + w_prime[j]) & 0xFFFFFFFF\n            tt2 = (gg_result + h_val + ss1 + w[j]) & 0xFFFFFFFF\n            \n            d = c\n            c = left_rotate(b, 9)\n            b = a\n            a = tt1\n            h_val = g\n            g = left_rotate(f, 19)\n            f = e\n            e = p0(tt2)\n            \n            # 纭繚鎵€鏈夊€奸兘鏄?2浣峔n            a, b, c, d, e, f, g, h_val = [x & 0xFFFFFFFF for x in [a, b, c, d, e, f, g, h_val]]\n        \n        # 娣诲姞杩欎竴杞殑鏉傚噾鍊煎埌缁撴灉涓璡n        h[0] = (h[0] ^ a) & 0xFFFFFFFF\n        h[1] = (h[1] ^ b) & 0xFFFFFFFF\n        h[2] = (h[2] ^ c) & 0xFFFFFFFF\n        h[3] = (h[3] ^ d) & 0xFFFFFFFF\n        h[4] = (h[4] ^ e) & 0xFFFFFFFF\n        h[5] = (h[5] ^ f) & 0xFFFFFFFF\n        h[6] = (h[6] ^ g) & 0xFFFFFFFF\n        h[7] = (h[7] ^ h_val) & 0xFFFFFFFF\n    \n    # 浜х敓鏈€缁堢殑鏉傚噾鍊糪n    return \'\'.join(f\'{x:08x}\' for x in h)\n\n\ndef ff_0_15(x, y, z):\n    \"\"\"甯冨皵鍑芥暟FF锛岀敤浜巎=0,1,...,15\"\"\"\n    return x ^ y ^ z\n\n\ndef ff_16_63(x, y, z):\n    \"\"\"甯冨皵鍑芥暟FF锛岀敤浜巎=16,17,...,63\"\"\"\n    return (x & y) | (x & z) | (y & z)\n\n\ndef gg_0_15(x, y, z):\n    \"\"\"甯冨皵鍑芥暟GG锛岀敤浜巎=0,1,...,15\"\"\"\n    return x ^ y ^ z\n\n\ndef gg_16_63(x, y, z):\n    \"\"\"甯冨皵鍑芥暟GG锛岀敤浜巎=16,17,...,63\"\"\"\n    return (x & y) | (~x & z)\n\n\ndef p0(x):\n    \"\"\"缃崲鍑芥暟P0\"\"\"\n    return x ^ left_rotate(x, 9) ^ left_rotate(x, 17)\n\n\ndef p1(x):\n    \"\"\"缃崲鍑芥暟P1\"\"\"\n    return x ^ left_rotate(x, 15) ^ left_rotate(x, 23)\n\n# 婕旂ず楠岃瘉\ntest_cases = [\n    \"\",\n    \"a\",\n    \"abc\",\n    \"message digest\",\n    \"abcdefghijklmnopqrstuvwxyz\",\n    \"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789\",\n    \"1234567890\" * 8,\n    \"涓浗鍥藉瀵嗙爜绠楁硶SM3\",\n    \"娌冲崡澶у瀵嗙爜瀛︾郴鐗涢€糪"\n]\n\nprint(\"杩涜娴嬭瘯:\")\nfor message in test_cases:\n    hash_value = sm3(message)\n    print(f\"SM3(\'{message[:30]}{\'...\' if len(message) > 30 else \'\'}\') = {hash_value}\")'),(247,41,1,'鐞嗚ВMD5纰版挒鏀诲嚮鐨勬牳蹇冩蹇?,'1. MD5纰版挒鏀诲嚮瀹氫箟锛氭壘鍒颁袱涓笉鍚岃緭鍏ヤ骇鐢熺浉鍚?28浣峂D5鎽樿鐨勬敾鍑绘柟娉曪紝鐜嬪皬浜戞暀鎺?004骞寸殑鍙戠幇浠庢牴鏈笂鐮村潖浜哅D5鐨勫畨鍏ㄥ亣璁俱€俓n2. 鎶€鏈獊鐮寸偣锛氬皢鐞嗚纰版挒澶嶆潅搴︿粠2^64锛堢敓鏃ユ敾鍑伙級闄嶈嚦瀹為檯鍙疄鐜扮殑2^39锛屾櫘閫氳绠楁満鍑犲皬鏃跺唴鍗冲彲瀹屾垚纰版挒鐢熸垚銆俓n3. 瀹為檯鍗卞锛氬彲鐢ㄤ簬鏁板瓧璇佷功浼€犮€佹伓鎰忚蒋浠朵吉瑁呫€佸瘑鐮侀獙璇佺粫杩囩瓑鍦烘櫙锛岀洿鎺ュ▉鑳佸熀浜嶮D5鐨勫畨鍏ㄤ綋绯汇€?,NULL,NULL),(248,41,2,'浜嗚ВMD5纰版挒鏀诲嚮鐨勫巻鍙茶儗鏅?,'1. 鐜嬪皬浜戞暀鎺堢殑瀛︽湳璐＄尞锛氭竻鍗庡ぇ瀛︽暀鎺堛€佷腑绉戦櫌闄㈠＋锛?004骞村湪CRYPTO浼氳瀹ｅ竷MD5/SHA-1纰版挒鏀诲嚮锛屽紑鍒涗簡宸垎瀵嗙爜鍒嗘瀽鍦ㄥ搱甯屽嚱鏁版敾鍑讳腑鐨勭郴缁熸€у簲鐢ㄣ€俓n2. MD5鐨勫畨鍏ㄦ紨杩涳細1991骞村彂甯冣啋1996骞村彂鐜板帇缂╁嚱鏁板急鐐光啋2004骞磋瀹屾暣鐮磋В鈫?006骞碞IST寤鸿鍋滅敤鈫掔洰鍓嶄粎鐢ㄤ簬闈炲畨鍏ㄥ満鏅€俓n3. 瀵嗙爜瀛﹀彂灞曞奖鍝嶏細鎺ㄥ姩浜嗘姉纰版挒鍝堝笇鍑芥暟鐮旂┒锛屽姞閫熶簡鍏ㄧ悆浠嶮D5鍚慡HA-2/SHA-3/SM3鐨勮縼绉汇€?,NULL,NULL),(249,41,3,'鎺屾彙MD5纰版挒鏀诲嚮鐨勬妧鏈師鐞?,'1. 宸垎瀵嗙爜鍒嗘瀽鏍稿績锛氬垎鏋愯緭鍏ュ樊鍒嗭紙螖x=x1鈯晉2锛夊浣曢€氳繃绠楁硶澶勭悊浜х敓杈撳嚭宸垎锛埼攜=f(x1)鈯昮(x2)锛夛紝鏋勯€犻珮姒傜巼鐨勫樊鍒嗕紶鎾矾寰勩€俓n2. MD5鐨勭粨鏋勬€у急鐐癸細\n   - Merkle-Damg氓rd缁撴瀯鏄撳彈闀垮害鎵╁睍鏀诲嚮锛沑n   - 鍘嬬缉鍑芥暟杞嚱鏁伴潪绾挎€у害涓嶈冻锛屽樊鍒嗘槗浼犳挱锛沑n   - 娑堟伅璋冨害璁捐绠€鍗曪紝宸垎鍙帶鎬у己銆俓n3. 鏀诲嚮鍏抽敭姝ラ锛歕n   - 鏋勯€犵壒瀹氬樊鍒嗚矾寰勶紙杈撳叆宸垎妯″紡锛夛紱\n   - 鍒╃敤灞€閮ㄧ鎾炲垱閫犱腑闂寸姸鎬佺鎾烇紱\n   - 閫氳繃娑堟伅淇敼鎶€鏈帶鍒跺樊鍒嗕紶鎾紱\n   - 鏈€缁堝疄鐜板畬鏁碝D5鎽樿纰版挒銆?,NULL,NULL),(250,41,4,'鏋勯€燤D5纰版挒鏀诲嚮鐨勫樊鍒嗚矾寰?,'1. 宸垎璺緞璁捐锛氱帇灏忎簯鏀诲嚮閲囩敤鐨勬牳蹇冨樊鍒嗘ā寮忔槸鍦ㄧ壒瀹氫綅缃殑31浣嶏紙0x80000000锛夊紩鍏ュ樊寮傦紝鍏稿瀷妯″紡涓猴細\n   - 绗竴鍧楋細浣嶇疆0銆?銆?0銆?5鍚勮缃?x80000000宸垎锛沑n   - 绗簩鍧楋細涓庣涓€鍧楃浉鍚岀殑宸垎妯″紡锛岀敤浜庢姷娑堢涓€鍧楃殑宸垎褰卞搷銆俓n2. 宸垎鐗规€у垎鏋愶細\n   - 姹夋槑閲嶉噺锛氫粎4涓樊鍒嗕綅锛岄檷浣庢敾鍑诲鏉傚害锛沑n   - 宸垎姒傜巼锛氱害2^(-39)锛岃繙楂樹簬闅忔満纰版挒姒傜巼锛沑n   - 浣嶄綅缃€夋嫨锛氱簿蹇冮€夋嫨鐨勪綅缃娇宸垎浼犳挱姒傜巼鏈€澶у寲銆俓n3. 鏁板鍩虹锛氶€氳繃璁＄畻宸垎璺緞鐨勬鐜囷紝浼樺寲灞€閮ㄧ鎾炲拰宸垎浼犳挱锛屽疄鐜板鏉傚害浠?^64鍒?^39鐨勭獊鐮淬€?,NULL,NULL),(251,41,5,'瀹炵幇MD5纰版挒鏀诲嚮鐨勬牳蹇冮€昏緫','1. 宸垎璺緞搴旂敤锛氬皢璁捐濂界殑宸垎妯″紡搴旂敤鍒板熀纭€娑堟伅鐨勭壒瀹氫綅缃紝淇敼瀵瑰簲32浣嶅瓧鐨?1浣嶅€笺€俓n2. 纰版挒娑堟伅鐢熸垚锛歕n   - 鐢熸垚128瀛楄妭锛?涓?12浣嶅潡锛夌殑闅忔満鍩虹娑堟伅锛沑n   - 瀵逛袱涓潡鍒嗗埆搴旂敤宸垎璺緞锛沑n   - 鏋勯€犲師濮嬫秷鎭拰淇敼娑堟伅涓ゅ鍊欓€夌鎾炴秷鎭€俓n3. 纰版挒楠岃瘉锛氳绠椾袱瀵规秷鎭殑MD5鍊硷紝楠岃瘉鏄惁纰版挒锛屽垎鏋愭秷鎭樊寮傛槸鍚︾鍚堥鏈熺殑宸垎妯″紡锛?x80锛夈€?,NULL,NULL),(252,41,6,'楠岃瘉鐜嬪皬浜戠殑鐪熷疄MD5纰版挒瀵?,'1. 鐪熷疄纰版挒瀵圭壒寰侊細鐜嬪皬浜戝彂鐜扮殑缁忓吀纰版挒瀵逛粎鏈?澶勫瓧鑺傚樊寮傦紙鍧囦负0x80锛夛紝浣哅D5鍊煎畬鍏ㄧ浉鍚岋紙79054025255fb1a26e4bc422aef54eb4锛夈€俓n2. 宸紓鍒嗘瀽锛氱鎾炲鐨勫樊寮備綅鍧囧嚭鐜板湪绮惧績閫夋嫨鐨勪綅缃紝纭繚宸垎閫氳繃64杞凯浠ｅ悗鐩镐簰鎶垫秷锛屾渶缁堜骇鐢熺浉鍚岀殑鍝堝笇鐘舵€併€俓n3. 楠岃瘉