ex(d) for d in block1_diff]}\")\n        print(f\"绗簩鍧楀樊鍒嗘ā寮? {[hex(d) for d in block2_diff]}\")\n        \n        # 鍒嗘瀽宸垎璺緞鐨勭壒鎬n        self._analyze_differential_properties(block1_diff, block2_diff)\n        \n        return block1_diff, block2_diff\n    \n    def _analyze_differential_properties(self, diff1: List[int], diff2: List[int]):\n        \"\"\"鍒嗘瀽宸垎璺緞鐨勬暟瀛︾壒鎬"\"\"\n        print(\"\\n=== 宸垎璺緞鍒嗘瀽 ===\")\n        \n        # 璁＄畻姹夋槑閲嶉噺\n        hamming_weight1 = sum(bin(d).count(\'1\') for d in diff1)\n        hamming_weight2 = sum(bin(d).count(\'1\') for d in diff2)\n        \n        print(f\"绗竴鍧楁眽鏄庨噸閲? {hamming_weight1}\")\n        print(f\"绗簩鍧楁眽鏄庨噸閲? {hamming_weight2}\")\n        \n        # 鍒嗘瀽浣嶄綅缃甛n        bit_positions1 = []\n        bit_positions2 = []\n        \n        for i, diff in enumerate(diff1):\n            if diff != 0:\n                bit_pos = 31  # 0x80000000鐨勬渶楂樹綅\n                bit_positions1.append((i, bit_pos))\n        \n        for i, diff in enumerate(diff2):\n            if diff != 0:\n                bit_pos = 31  # 0x80000000鐨勬渶楂樹綅\n                bit_positions2.append((i, bit_pos))\n        \n        print(f\"绗竴鍧楀樊寮備綅缃? {bit_positions1}\")\n        print(f\"绗簩鍧楀樊寮備綅缃? {bit_positions2}\")\n        \n        # 璁＄畻宸垎璺緞姒傜巼锛堢帇灏忎簯鏀诲嚮鐨勫疄闄呮鐜囩害涓?^(-39)锛塡n        probability = self._calculate_differential_probability(diff1, diff2)\n        print(f\"宸垎璺緞姒傜巼: {probability:.2e}\")\n        print(f\"棰勬湡灏濊瘯娆℃暟: {1/probability:.0f}\")\n    \n    def _calculate_differential_probability(self, diff1: List[int], diff2: List[int]) -> float:\n        \"\"\"璁＄畻宸垎璺緞鐨勬鐜囷紙绠€鍖栫増锛塡"\"\"\n        # 鐜嬪皬浜戞敾鍑荤殑鎴愬姛姒傜巼绾︿负2^(-39)\n        base_prob = 2**(-39)\n        \n        # 宸垎浣嶆暟閲忚皟鏁碶n        diff_count1 = sum(1 for d in diff1 if d != 0)\n        diff_count2 = sum(1 for d in diff2 if d != 0)\n        adjustment = 2**(diff_count1 + diff_count2 - 8)\n        \n        return base_prob * adjustment\n    \n    def apply_differential_path(self, base_message: bytes, differential_path: List[int]) -> bytes:\n        \"\"\"\n        灏嗗樊鍒嗚矾寰勫簲鐢ㄥ埌鍩虹娑堟伅涓奬n        \n        Args:\n            base_message: 鍩虹娑堟伅锛堝繀椤绘槸512浣嶇殑鍊嶆暟锛塡n            differential_path: 宸垎璺緞\n            \n        Returns:\n            bytes: 搴旂敤宸垎鍚庣殑娑堟伅\n        \"\"\"\n        print(f\"\\n=== 搴旂敤宸垎璺緞 ===\")\n        print(f\"鍘熷娑堟伅闀垮害: {len(base_message)} 瀛楄妭\")\n        \n        # 纭繚娑堟伅闀垮害鏄?12浣嶇殑鍊嶆暟\n        if len(base_message) % 64 != 0:\n            raise ValueError(\"娑堟伅闀垮害蹇呴』鏄?12浣嶇殑鍊嶆暟\")\n        \n        # 灏嗘秷鎭浆鎹负32浣嶅皬绔簭瀛楁暟缁刓n        words = []\n        for i in range(0, len(base_message), 4):\n            word = struct.unpack(\'<I\', base_message[i:i+4])[0]\n            words.append(word)\n        \n        print(f\"娑堟伅瀛楁暟閲? {len(words)}\")\n        \n        # 搴旂敤宸垎璺緞\n        modified_words = words.copy()\n        for i, diff in enumerate(differential_path):\n            if i < len(modified_words) and diff != 0:\n                original_word = modified_words[i]\n                modified_words[i] = original_word ^ diff\n                print(f\"浣嶇疆 {i}: 0x{original_word:08x} -> 0x{modified_words[i]:08x}\")\n        \n        # 杞崲鍥炲瓧鑺傦紙灏忕搴忥級\n        modified_message = b\'\'\n        for word in modified_words:\n            modified_message += struct.pack(\'<I\', word)\n        \n        print(f\"淇敼鍚庢秷鎭暱搴? {len(modified_message)} 瀛楄妭\")\n        \n        return modified_message\n    \n    def generate_collision_from_differential(self, differential_path: Tuple[List[int], List[int]]) -> Tuple[bytes, bytes]:\n        \"\"\"\n        浣跨敤宸垎璺緞鐢熸垚纰版挒娑堟伅瀵筡n        \"\"\"\n        print(\"\\n=== 浣跨敤宸垎璺緞鐢熸垚纰版挒 ===\")\n        \n        block1_diff, block2_diff = differential_path\n        \n        # 鐢熸垚闅忔満鐨勫熀纭€娑堟伅锛?28瀛楄妭 = 1024浣?= 2涓?12浣嶅潡锛塡n        random.seed(42)  # 鍥哄畾绉嶅瓙淇濊瘉鍙鐜癨n        base_message = bytes([random.randint(0, 255) for _ in range(128)])\n        \n        print(f\"鐢熸垚鐨勫熀纭€娑堟伅闀垮害: {len(base_message)} 瀛楄妭\")\n        \n        # 灏嗘秷鎭垎鎴愪袱涓?12浣嶅潡\n        block1 = base_message[:64]   # 绗竴涓?12浣嶅潡\n        block2 = base_message[64:]    # 绗簩涓?12浣嶅潡\n        \n        print(f\"绗竴鍧楅暱搴? {len(block1)} 瀛楄妭\")\n        print(f\"绗簩鍧楅暱搴? {len(block2)} 瀛楄妭\")\n        \n        # 搴旂敤宸垎璺緞鍒扮涓€鍧梊n        modified_block1 = self.apply_differential_path(block1, block1_diff)\n        \n        # 搴旂敤宸垎璺緞鍒扮浜屽潡\n        modified_block2 = self.apply_differential_path(block2, block2_diff)\n        \n        # 鏋勯€犲畬鏁寸殑娑堟伅\n        message1 = block1 + block2\n        message2 = modified_block1 + modified_block2\n        \n        print(f\"\\n鐢熸垚鐨勬秷鎭:\")\n        print(f\"娑堟伅1闀垮害: {len(message1)} 瀛楄妭\")\n        print(f\"娑堟伅2闀垮害: {len(message2)} 瀛楄妭\")\n        \n        return message1, message2\n    \n    def verify_collision_with_differential(self, msg1: bytes, msg2: bytes, differential_path: Tuple[List[int], List[int]]) -> bool:\n        \"\"\"\n        楠岃瘉纰版挒骞跺垎鏋愬樊鍒嗚矾寰勭殑鏁堟灉\n        \"\"\"\n        print(\"\\n=== 楠岃瘉纰版挒鍜屽樊鍒嗗垎鏋?===\")\n        \n        # 璁＄畻MD5鍊糪n        hash1 = hashlib.md5(msg1).hexdigest()\n        hash2 = hashlib.md5(msg2).hexdigest()\n        \n        print(f\"娑堟伅1 MD5: {hash1}\")\n        print(f\"娑堟伅2 MD5: {hash2}\")\n        print(f\"鏄惁纰版挒: {hash1 == hash2}\")\n        \n        # 鍒嗘瀽娑堟伅宸紓\n        self._analyze_message_differences(msg1, msg2)\n        \n        # 楠岃瘉宸垎璺緞鏄惁姝ｇ‘搴旂敤\n        self._verify_differential_application(msg1, msg2, differential_path)\n        \n        return hash1 == hash2\n    \n    def _analyze_message_differences(self, msg1: bytes, msg2: bytes):\n        \"\"\"鍒嗘瀽涓や釜娑堟伅鐨勫樊寮俓"\"\"\n        print(\"\\n=== 娑堟伅宸紓鍒嗘瀽 ===\")\n        \n        differences = []\n        for i, (b1, b2) in enumerate(zip(msg1, msg2)):\n            if b1 != b2:\n                diff = b1 ^ b2\n                differences.append((i, b1, b2, diff))\n                print(f\"浣嶇疆 {i:3d}: 0x{b1:02x} -> 0x{b2:02x} (宸€? 0x{diff:02x})\")\n        \n        print(f\"鎬诲樊寮傛暟: {len(differences)}\")\n        \n        if differences:\n            diff_values = [d[3] for d in differences]\n            unique_diffs = set(diff_values)\n            print(f\"鍞竴宸紓鍊? {[hex(d) for d in unique_diffs]}\")\n            \n            # 妫€鏌ユ槸鍚︾鍚堥鏈熺殑宸垎妯″紡\n            expected_diff = 0x80  # 0x80000000鐨勬渶浣庡瓧鑺俓n            if all(d == expected_diff for d in diff_values):\n                print(\"宸紓妯″紡绗﹀悎棰勬湡 (0x80) 鉁揬")\n            else:\n                print(\"宸紓妯″紡涓嶇鍚堥鏈?鉁梊")\n    \n    def _verify_differential_application(self, msg1: bytes, msg2: bytes, differential_path: Tuple[List[int], List[int]]):\n        \"\"\"楠岃瘉宸垎璺緞鏄惁姝ｇ‘搴旂敤\"\"\"\n        print(\"\\n=== 宸垎璺緞楠岃瘉 ===\")\n        \n        block1_diff, block2_diff = differential_path\n        \n        # 妫€鏌ョ涓€鍧楃殑宸垎搴旂敤\n        block1_1 = msg1[:64]\n        block1_2 = msg2[:64]\n        \n        print(\"绗竴鍧楀樊鍒嗛獙璇?\")\n        for i in range(0, len(block1_1), 4):\n            word1 = struct.unpack(\'<I\', block1_1[i:i+4])[0]\n            word2 = struct.unpack(\'<I\', block1_2[i:i+4])[0]\n            word_diff = word1 ^ word2\n            expected_diff = block1_diff[i//4]\n            \n            if word_diff == expected_diff:\n                print(f\"  浣嶇疆 {i//4}: 宸垎姝ｇ‘ (0x{word_diff:08x}) 鉁揬")\n            else:\n                print(f\"  浣嶇疆 {i//4}: 宸垎閿欒 (鏈熸湜: 0x{expected_diff:08x}, 瀹為檯: 0x{word_diff:08x}) 鉁梊")\n        \n        # 妫€鏌ョ浜屽潡鐨勫樊鍒嗗簲鐢╘n        block2_1 = msg1[64:]\n        block2_2 = msg2[64:]\n        \n        print(\"绗簩鍧楀樊鍒嗛獙璇?\")\n        for i in range(0, len(block2_1), 4):\n            word1 = struct.unpack(\'<I\', block2_1[i:i+4])[0]\n            word2 = struct.unpack(\'<I\', block2_2[i:i+4])[0]\n            word_diff = word1 ^ word2\n            expected_diff = block2_diff[i//4]\n            \n            if word_diff == expected_diff:\n                print(f\"  浣嶇疆 {i//4}: 宸垎姝ｇ‘ (0x{word_diff:08x}) 鉁揬")\n            else:\n                print(f\"  浣嶇疆 {i//4}: 宸垎閿欒 (鏈熸湜: 0x{expected_diff:08x}, 瀹為檯: 0x{word_diff:08x}) 鉁梊")\n    \n    def demonstrate_wang_xiaoyun_collision(self):\n        \"\"\"\n        婕旂ず鐜嬪皬浜戝彂鐜扮殑鐪熷疄MD5纰版挒瀵筡n        杩欐槸瀵嗙爜瀛﹀彶涓婄涓€涓疄闄呯殑MD5纰版挒瀵筡n        \"\"\"\n        print(\"\\n=== 鐜嬪皬浜戠湡瀹炵鎾炲婕旂ず ===\")\n        \n        # 鐜嬪皬浜戠瓑浜哄彂鐜扮殑绗竴涓狹D5纰版挒瀵筡n        message1_hex = (\n            \"d131dd02c5e6eec4693d9a0698aff95c2fcab58712467eab4004583eb8fb7f89\"\n            \"55ad340609f4b30283e488832571415a085125e8f7cdc99fd91dbdf280373c5b\"\n            \"d8823e3156348f5bae6dacd436c919c6dd53e2b487da03fd02396306d248cda0\"\n            \"e99f33420f577ee8ce54b67080a80d1ec69821bcb6a8839396f9652b6ff72a70\"\n        )\n        \n        message2_hex = (\n            \"d131dd02c5e6eec4693d9a0698aff95c2fcab50712467eab4004583eb8fb7f89\"\n            \"55ad340609f4b30283e4888325f1415a085125e8f7cdc99fd91dbd7280373c5b\"\n            \"d8823e3156348f5bae6dacd436c919c6dd53e23487da03fd02396306d248cda0\"\n            \"e99f33420f577ee8ce54b67080280d1ec69821bcb6a8839396f965ab6ff72a70\"\n        )\n        \n        message1 = bytes.fromhex(message1_hex)\n        message2 = bytes.fromhex(message2_hex)\n        \n        hash1 = hashlib.md5(message1).hexdigest()\n        hash2 = hashlib.md5(message2).hexdigest()\n        \n        print(f\"鐜嬪皬浜戠鎾炲楠岃瘉:\")\n        print(f\"娑堟伅1 MD5: {hash1}\")\n        print(f\"娑堟伅2 MD5: {hash2}\")\n        print(f\"纰版挒楠岃瘉: {\'鎴愬姛 鉁揬' if hash1 == hash2 else \'澶辫触 鉁梊'}\")\n        \n        if hash1 == hash2:\n            print(\"杩欐槸涓€涓湁鏁堢殑MD5纰版挒瀵癸紒\")\n            self._analyze_message_differences(message1, message2)\n        \n        return hash1 == hash2\n\n# ==================== 婕旂ず浠ｇ爜 ====================\nif __name__ == \"__main__\":\n    # 鍒涘缓鏀诲嚮瀹炰緥\n    attack = MD5DifferentialAttack()\n    \n    # 姝ラ1: 鏋勯€犲樊鍒嗚矾寰刓n    print(\"\\n\" + \"=\" * 40)\n    print(\"姝ラ1: 鏋勯€犲樊鍒嗚矾寰刓")\n    print(\"=\" * 40)\n    differential_path = attack.construct_differential_path()\n    \n    # 姝ラ2: 浣跨敤宸垎璺緞鐢熸垚纰版挒娑堟伅瀵筡n    print(\"\\n\" + \"=\" * 40)\n    print(\"姝ラ2: 浣跨敤宸垎璺緞鐢熸垚纰版挒娑堟伅瀵筡")\n    print(\"=\" * 40)\n    msg1, msg2 = attack.generate_collision_from_differential(differential_path)\n    \n    # 姝ラ3: 楠岃瘉纰版挒鍜屽樊鍒嗚矾寰勬晥鏋淺n    print(\"\\n\" + \"=\" * 40)\n    print(\"姝ラ3: 楠岃瘉纰版挒鍜屽樊鍒嗚矾寰勬晥鏋淺")\n    print(\"=\" * 40)\n    is_collision = attack.verify_collision_with_differential(msg1, msg2, differential_path)\n    \n    # 姝ラ4: 婕旂ず鐜嬪皬浜戠湡瀹炵鎾炲\n    print(\"\\n\" + \"=\" * 40)\n    print(\"姝ラ4: 鐜嬪皬浜戠湡瀹炵鎾炲婕旂ず\")\n    print(\"=\" * 40)\n    wang_collision = attack.demonstrate_wang_xiaoyun_collision()\n    \n    # 姝ラ5: 杈撳嚭闃叉姢寤鸿\n    print(\"\\n\" + \"=\" * 40)\n    print(\"姝ラ5: MD5纰版挒鏀诲嚮闃叉姢寤鸿\")\n    print(\"=\" * 40)\n    print(\"1. 绔嬪嵆鍋滅敤MD5鐢ㄤ簬鎵€鏈夊畨鍏ㄧ浉鍏冲満鏅痋")\n    print(\"2. 鎺ㄨ崘浣跨敤SHA-256/SHA-3/SM3鏇夸唬MD5\")\n    print(\"3. 瀵瑰叧閿簲鐢ㄩ噰鐢ㄧ畻娉曞崌绾у拰鍙岄噸鍝堝笇绛栫暐\")\n    print(\"4. 瀹氭湡璇勪及瀵嗙爜瀛︾畻娉曠殑瀹夊叏鎬")'),(254,41,8,'MD5纰版挒鏀诲嚮鐨勯槻鎶ゆ帾鏂?,'1. 绠楁硶鏇夸唬鏂规锛堟寜鎺ㄨ崘浼樺厛绾э級锛歕n   - SHA-256锛?56浣嶈緭鍑猴紝瀹夊叏涓斿簲鐢ㄥ箍娉涳紝浣滀负鏈€浣庡畨鍏ㄦ爣鍑嗭紱\n   - SM3锛氫腑鍥借嚜涓昏璁＄殑256浣嶅搱甯岀畻娉曪紝鍥藉瘑浣撶郴鏍稿績锛沑n   - SHA-3锛氭渶鏂板浗闄呮爣鍑嗭紝鎶楅噺瀛愯绠楁敾鍑昏兘鍔涘己锛沑n   - BLAKE2锛氶珮鎬ц兘瀹夊叏鍝堝笇绠楁硶銆俓n2. 鏈€浣冲疄璺碉細\n   - 绔嬪嵆鍋滅敤MD5锛氬湪鏁板瓧绛惧悕銆佽瘉涔﹂獙璇併€佸瘑鐮佸瓨鍌ㄧ瓑瀹夊叏鍦烘櫙锛沑n   - 绠楁硶鍗囩骇锛氶€愭灏嗙幇鏈塎D5搴旂敤杩佺Щ鍒板畨鍏ㄧ畻娉曪紱\n   - 鍙岄噸鍝堝笇锛氳繃娓℃湡鍙噰鐢∕D5(SHA256(data))鐨勫吋瀹规柟妗堬紱\n   - 瀹氭湡瀹¤锛氳瘎浼扮郴缁熶腑浣跨敤鐨勫搱甯岀畻娉曞畨鍏ㄦ€с€俓n3. 琛屼笟鏍囧噯锛氶伒寰狽IST銆両ETF绛夋満鏋勭殑鏈€鏂板瘑鐮佸鏍囧噯锛岄伩鍏嶄娇鐢ㄥ凡琚牬瑙ｇ殑绠楁硶銆?,NULL,NULL),(255,42,1,'浜嗚ВAES鑳屾櫙涓庢牳蹇冪壒鎬?,'棣栧厛鏄庣‘AES鐨勮癁鐢熻儗鏅細DES鍥?6浣嶅瘑閽ヨ繃鐭紝鍦ㄨ绠楄兘鍔涙彁鍗囧悗鏄撹鏆村姏鐮磋В锛孨IST閫氳繃鍏ㄧ悆绔炶禌閫夊畾Rijndael绠楁硶浣滀负AES鏍囧噯銆俓n鏍稿績鐗规€ч渶鎺屾彙锛氬垎缁勯暱搴﹀浐瀹?28浣嶏紝鏀寔128/192/256浣嶅瘑閽ワ紝鍩轰簬浠ｆ崲-缃崲缃戠粶锛圫PN锛夌粨鏋勶紝鏇夸唬DES鎴愪负鍏ㄧ悆涓绘祦瀵圭О鍔犲瘑鏍囧噯銆?,'閲嶇偣鍖哄垎AES涓嶥ES鐨勬牳蹇冨樊寮傦細瀵嗛挜闀垮害銆佸簳灞傜粨鏋?,NULL),(256,42,2,'鎺屾彙AES鏁板鍩虹','AES鏍稿績杩愮畻鍩轰簬鏈夐檺鍩?GF(2^8)$锛岄渶鐞嗚В涓や釜鍏抽敭鎿嶄綔锛歕n1. 鏈夐檺鍩熶箻娉曪細閬靛惊涓嶅彲绾﹀椤瑰紡$x^8 + x^4 + x^3 + x + 1$锛岃繍绠楃粨鏋滈渶妯?0x1b$纭繚鍦?浣嶈寖鍥村唴銆俓n2. 闈炵嚎鎬у彉鎹細渚濊禆S鐩掞紝閫氳繃姹傚瓧鑺備箻娉曢€嗗厓+浠垮皠鍙樻崲$S(x)=A路x^{-1}鈯昩$寮曞叆闈炵嚎鎬э紝鎶垫姉绾挎€ф敾鍑汇€?,'鏃犻渶娣卞叆鎺ㄥ鏁板鍏紡锛岀悊瑙ｈ繍绠楃洰鐨勫嵆鍙?,NULL),(257,42,3,'鎷嗚В