e ValueError(\"鏄庢枃鍧楀繀椤绘槸16瀛楄妭\")\n    # 灏嗘槑鏂囧潡鍒嗕负4涓?2浣嶅瓧\n    x = list(struct.unpack(\'>4I\', plaintext_block))\n    # 32杞姞瀵哱n    for i in range(32):\n        x[0] = self._f_function(x[0], x[1], x[2], x[3], self.round_keys[i])\n        # 寰幆绉讳綅\n        x = x[1:] + [x[0]]\n    # 鍙嶅簭鍙樻崲\n    x = x[::-1]\n    return struct.pack(\'>4I\', *x)'),(268,43,6,'瀹炵幇PKCS#7濉厖涓庡妯″紡鏀寔','SM4瑕佹眰鏄庢枃鍧楅暱搴︿负16瀛楄妭锛岄渶瀹炵幇PKCS#7濉厖锛屽苟鎵╁睍澶氬姞瀵嗘ā寮忥細\n1. PKCS#7濉厖/鍘诲～鍏咃細涓嶢ES涓€鑷达紝璁＄畻濉厖闀垮害$padding_length=16-(len(data)\\%16)$锛屽～鍏呭搴斿瓧鑺傦紱\n2. ECB妯″紡灏佽锛氬疄鐜皊m4_encrypt/sm4_decrypt鍑芥暟锛屽鐞嗗瓧绗︿覆缂栫爜銆佸垎鍧楀姞瑙ｅ瘑锛沑n3. CBC妯″紡鎵╁睍锛歕n   a. 鍔犲瘑锛氭槑鏂囧潡鍏堜笌鍓嶄竴涓瘑鏂囧潡锛堟垨IV锛夊紓鎴栵紝鍐嶅姞瀵嗭紱\n   b. 瑙ｅ瘑锛氬瘑鏂囧潡鍏堣В瀵嗭紝鍐嶄笌鍓嶄竴涓瘑鏂囧潡锛堟垨IV锛夊紓鎴栧緱鍒版槑鏂囷紱\n   c. 鍏抽敭锛欼V闇€涓?6瀛楄妭闅忔満鍊硷紝涓斿姞瀵嗗拰瑙ｅ瘑浣跨敤鐩稿悓IV銆?,NULL,'def sm4_cbc_encrypt(plaintext, key, iv):\n    if isinstance(plaintext, str):\n        plaintext = plaintext.encode(\'utf-8\')\n    if len(iv) != 16:\n        raise ValueError(\"IV蹇呴』鏄?6瀛楄妭\")\n    padded_plaintext = pkcs7_pad(plaintext)\n    sm4 = SM4(key)\n    ciphertext = b\'\'\n    prev_block = iv\n    for i in range(0, len(padded_plaintext), 16):\n        block = padded_plaintext[i:i+16]\n        xor_block = bytes(a ^ b for a, b in zip(block, prev_block))\n        encrypted_block = sm4.encrypt_block(xor_block)\n        ciphertext += encrypted_block\n        prev_block = encrypted_block\n    return ciphertext'),(269,43,7,'娴嬭瘯SM4鍔犺В瀵嗘纭€?,'璁捐澶氱被鍨嬫祴璇曠敤渚嬮獙璇丼M4瀹炵幇姝ｇ‘鎬э細\n1. 娴嬭瘯鍑嗗锛氱敓鎴?6瀛楄妭娴嬭瘯瀵嗛挜锛堝b\'0123456789abcdef\'锛夛紝鍑嗗澶氱被鍨嬫槑鏂囷紙鑻辨枃鐭彞銆佷腑鏂囨枃鏈€侀暱鏂囨湰锛夛紱\n2. ECB妯″紡娴嬭瘯锛歕n   a. 瀵规瘡涓祴璇曠敤渚嬫墽琛宻m4_encrypt鍔犲瘑锛岃緭鍑哄崄鍏繘鍒跺瘑鏂囷紱\n   b. 瀵瑰瘑鏂囨墽琛宻m4_decrypt瑙ｅ瘑锛岄獙璇佽В瀵嗙粨鏋滀笌鍘熷鏄庢枃涓€鑷达紱\n3. CBC妯″紡娴嬭瘯锛歕n   a. 鐢熸垚16瀛楄妭闅忔満IV锛坥s.urandom(16)锛夛紱\n   b. 鎵цsm4_cbc_encrypt鍔犲瘑鍜宻m4_cbc_decrypt瑙ｅ瘑锛岄獙璇佺粨鏋滄纭€э紱\n4. 楠岃瘉鏍囧噯锛氭墍鏈夋祴璇曠敤渚嬭В瀵嗗悗闇€涓庡師鏄庢枃瀹屽叏涓€鑷达紝楠岃瘉鏍囪涓衡湏銆?,NULL,'# 娴嬭瘯瀵嗛挜锛?28浣嶏級\nkey = b\'0123456789abcdef\'\n# 娴嬭瘯鐢ㄤ緥\ntest_cases = [\"Hello, World!\", \"SM4鏄腑鍥藉浗瀹跺瘑鐮佺畻娉昞"]\n# ECB妯″紡娴嬭瘯\nfor i, plaintext in enumerate(test_cases, 1):\n    print(f\"娴嬭瘯鐢ㄤ緥 {i}:\")\n    print(f\"鏄庢枃: {plaintext}\")\n    # 鍔犲瘑\n    ciphertext = sm4_encrypt(plaintext, key)\n    print(f\"瀵嗘枃: {ciphertext.hex()}\")\n    # 瑙ｅ瘑\n    decrypted = sm4_decrypt(ciphertext, key).decode(\'utf-8\')\n    print(f\"瑙ｅ瘑: {decrypted}\")\n    # 楠岃瘉\n    success = \"鉁揬" if plaintext == decrypted else \"鉁梊"\n    print(f\"楠岃瘉: {success}\")'),(270,43,8,'鐞嗚ВSM4瀹夊叏鎬т笌瀹為檯搴旂敤','SM4鐨勫畨鍏ㄦ€т笌搴旂敤鍦烘櫙闇€閲嶇偣鎺屾彙锛歕n1. 瀹夊叏鎬х壒鎬э細\n   a. S鐩掕璁★細鍩轰簬$GF(2^8)$鏈夐檺鍩燂紝鍏锋湁楂橀潪绾挎€с€佷綆宸垎鍧囧寑鎬э紝鎶垫姉宸垎/绾挎€ф敾鍑伙紱\n   b. 杞暟璁捐锛?2杞凯浠ｈ繙瓒呭畨鍏ㄦ墍闇€锛堜竴鑸?6杞嵆鍙級锛屾棤瀹炵敤绾ф敾鍑绘柟娉曪紱\n   c. 瀵嗛挜鎵╁睍锛氱粨鍚圫鐩掑拰绾挎€у彉鎹紝閬垮厤寮卞瘑閽ュ拰鐩稿叧瀵嗛挜鏀诲嚮銆俓n2. 瀹為檯搴旂敤寤鸿锛歕n   a. 閬垮厤浣跨敤ECB妯″紡锛堢浉鍚屾槑鏂囧潡鍔犲瘑缁撴灉鐩稿悓锛夛紝浼樺厛閫夋嫨CBC/GCM妯″紡锛沑n   b. IV闇€闅忔満鐢熸垚锛屼笖姣忎釜鍔犲瘑浼氳瘽浣跨敤涓嶅悓IV锛沑n   c. 瀵嗛挜闇€閫氳繃鍔犲瘑瀹夊叏闅忔満鏁扮敓鎴愬櫒鐢熸垚锛岄伩鍏嶇‖缂栫爜锛沑n   d. 鏍稿績鍦烘櫙锛氱數瀛愭斂鍔°€侀噾铻嶆敮浠樸€佺數淇￠€氫俊銆佷簯璁＄畻/鍖哄潡閾剧瓑鍥戒骇瀵嗙爜鍚堣鍦烘櫙銆?,'鍦ㄩ渶瑕佹弧瓒崇瓑淇濆悎瑙勩€佸晢鐢ㄥ瘑鐮佸簲鐢ㄥ畨鍏ㄦ€ц瘎浼扮殑鍦烘櫙涓紝SM4鏄閫夊绉板姞瀵嗙畻娉?,NULL),(271,44,1,'鐞嗚ВECB妯″紡鏍稿績宸ヤ綔鍘熺悊','ECB锛圗lectronic Codebook锛岀數瀛愬瘑鐮佹湰锛夋槸鏈€鍩虹鐨勫垎缁勫瘑鐮佸伐浣滄ā寮忥紝鏍稿績閫昏緫鏄?*姣忎釜鏄庢枃鍒嗙粍鐙珛鍔犲瘑**锛歕n1. 棣栧厛灏嗘槑鏂囨寜鍒嗙粍闀垮害锛堝16瀛楄妭锛夋媶鍒嗕负鑻ュ共涓槑鏂囧潡$P_1, P_2, P_3, ...$锛沑n2. 瀵规瘡涓槑鏂囧潡浣跨敤鐩稿悓鐨勫瘑閽鐙珛鎵ц鍒嗙粍鍔犲瘑绠楁硶锛堝AES/SM4锛夛細$C_i = E_K(P_i)$锛沑n3. 灏嗘墍鏈夊姞瀵嗗悗鐨勫瘑鏂囧潡鎸夐『搴忔嫾鎺ワ紝寰楀埌鏈€缁堝瘑鏂?C = C_1 || C_2 || C_3 || ...$锛沑n4. 瑙ｅ瘑杩囩▼鍚岀悊锛氬姣忎釜瀵嗘枃鍧楃嫭绔嬭В瀵?P_i = D_K(C_i)$锛屾嫾鎺ュ悗鍘诲～鍏呭緱鍒版槑鏂囥€俓n璇ユā寮忕殑鏍稿績鐗瑰緛鏄棤涓婁笅鏂囧叧鑱旓紝姣忎釜鍒嗙粍鐨勫姞瑙ｅ瘑缁撴灉浠呯敱鑷韩鍜屽瘑閽ュ喅瀹氥€?,'鍙互绫绘瘮涓烘煡瀵嗙爜鏈細姣忎釜鏄庢枃鍧楀搴斿敮涓€鐨勫瘑鏂囧潡锛屽鍚屽瓧鍏镐腑鐨勪竴涓€鏄犲皠',NULL),(272,44,2,'鍒嗘瀽ECB妯″紡鐨勫疄鐜扮壒鎬?,'鍩轰簬ECB鐨勫伐浣滃師鐞嗭紝鍏跺疄鐜板眰闈㈡湁涓変釜鏍稿績鐗规€э細\n1. 鏃犻渶鍒濆鍖栧悜閲忥紙IV锛夛細涓嶅悓浜嶤BC/CFB绛夋ā寮忥紝ECB涓嶉渶瑕侀澶栫殑鍒濆鍖栧悜閲忥紝鍔犺В瀵嗕粎渚濊禆瀵嗛挜锛沑n2. 鏀寔骞惰澶勭悊锛氱敱浜庡悇鍒嗙粍鐙珛锛屾墍鏈夋槑鏂囧潡鍙悓鏃跺姞瀵嗭紝鎵€鏈夊瘑鏂囧潡鍙悓鏃惰В瀵嗭紝澶勭悊鏁堢巼楂橈紱\n3. 瀹屽叏纭畾鎬э細鐩稿悓瀵嗛挜涓嬶紝鐩稿悓鐨勬槑鏂囧潡姘歌繙鐢熸垚鐩稿悓鐨勫瘑鏂囧潡锛岃繖鏄疎CB鏈€鏄捐憲鐨勭壒寰侊紝涔熸槸鏍稿績瀹夊叏闅愭偅銆俓n鏁板琛ㄨ揪寮忎笂锛孍CB鐨勫姞瑙ｅ瘑鍙畝鍖栦负锛歕n鍔犲瘑锛?C_i = E_K(P_i)$\n瑙ｅ瘑锛?P_i = D_K(C_i)$\n鍏朵腑$P_i$涓虹i涓槑鏂囧潡锛?C_i$涓虹i涓瘑鏂囧潡锛?E_K$涓哄姞瀵嗗嚱鏁帮紝$D_K$涓鸿В瀵嗗嚱鏁般€?,'骞惰澶勭悊鏄疎CB浠呮湁鐨勪紭鍔匡紝浣嗗畨鍏ㄦ€х己闄蜂娇鍏舵棤娉曞湪澶ч儴鍒嗗満鏅娇鐢?,NULL),(273,44,3,'璇嗗埆ECB妯″紡鐨勫畨鍏ㄩ棶棰?,'ECB妯″紡鐨勭‘瀹氭€у鑷村叾瀛樺湪涓ラ噸瀹夊叏缂洪櫡锛屼富瑕佸寘鎷細\n1. 妯″紡娉勯湶锛氳嫢鏄庢枃涓瓨鍦ㄩ噸澶嶇殑鍒嗙粍锛屽瘑鏂囦腑浼氬嚭鐜扮浉鍚岀殑瀵嗘枃鍒嗙粍锛屾敾鍑昏€呭彲閫氳繃瀵嗘