 decrypt(self, ciphertext: bytes, key: bytes, iv: Optional[bytes] = None) -> bytes:\n        \"\"\"ECB妯″紡瑙ｅ瘑\"\"\"\n        cipher = SimpleAES(key)\n        if len(ciphertext) % self.block_size != 0:\n            raise ValueError(\"瀵嗘枃闀垮害蹇呴』鏄垎缁勫ぇ灏忕殑鍊嶆暟\")\n        # 鍒嗙粍瑙ｅ瘑\n        plaintext = b\'\'\n        blocks = self._split_blocks(ciphertext)\n        for block in blocks:\n            decrypted_block = cipher.decrypt_block(block)\n            plaintext += decrypted_block\n        # 绉婚櫎濉厖\n        return self._unpad_pkcs7(plaintext)'),(276,44,6,'娴嬭瘯ECB妯″紡鐨勫姞瑙ｅ瘑姝ｇ‘鎬?,'缂栧啓娴嬭瘯浠ｇ爜楠岃瘉ECB妯″紡鐨勫姞瑙ｅ瘑鍔熻兘锛歕n1. 鍑嗗娴嬭瘯鏁版嵁锛?6瀛楄妭瀵嗛挜锛堢鍚圓ES-128瑕佹眰锛夈€侀暱搴﹂潪鍒嗙粍鏁存暟鍊嶇殑鏄庢枃锛堝53瀛楄妭锛夛紱\n2. 鍒濆鍖朎CB妯″紡瀵硅薄锛屾寚瀹氬垎缁勯暱搴︿负16瀛楄妭锛沑n3. 鎵ц鍔犲瘑鎿嶄綔锛氳緭鍑哄師鏂囥€佸師鏂囬暱搴︺€佸瘑鏂囬暱搴︺€佸瘑鏂囷紙鎴彇鍓?4浣嶅崄鍏繘鍒讹級锛沑n4. 鎵ц瑙ｅ瘑鎿嶄綔锛氳緭鍑鸿В瀵嗙粨鏋滐紝楠岃瘉鏄惁涓庡師鏂囦竴鑷达紱\n5. 鍏抽敭楠岃瘉鐐癸細\n   a. 瀵嗘枃闀垮害搴斾负澶т簬绛変簬鍘熸枃闀垮害鐨勬渶灏忓垎缁勬暣鏁板€嶏紙53瀛楄妭鈫?4瀛楄妭锛夛紱\n   b. 瑙ｅ瘑缁撴灉闇€涓庡師濮嬫槑鏂囧畬鍏ㄤ竴鑷达紱\n   c. 閲嶅鍔犲瘑鐩稿悓鏄庢枃锛屽緱鍒扮殑瀵嗘枃蹇呴』瀹屽叏鐩稿悓锛堥獙璇佺‘瀹氭€э級銆?,NULL,'# 娴嬭瘯鏁版嵁\nkey = b\'0123456789abcdef\'  # 16瀛楄妭瀵嗛挜\nplaintext = b\'Hello, this is a test message for block cipher modes!\' \nprint(f\"鍘熸枃: {plaintext}\")\nprint(f\"鍘熸枃闀垮害: {len(plaintext)} 瀛楄妭\")\nprint()\n# 鍒涘缓妯″紡\nmode = ECBMode()\n# 鍔犲瘑\nciphertext = mode.encrypt(plaintext, key)\nprint(f\"瀵嗘枃闀垮害: {len(ciphertext)} 瀛楄妭\")\nprint(f\"瀵嗘枃: {ciphertext.hex()[:64]}...\")\n# 瑙ｅ瘑\ndecrypted = mode.decrypt(ciphertext, key)\nprint(f\"瑙ｅ瘑: {decrypted}\")\n# 楠岃瘉\nis_correct = plaintext == decrypted\nprint(f\"姝ｇ‘鎬? {\'鉁匼' if is_correct else \'鉂孿'}\")'),(277,44,7,'鎬荤粨ECB妯″紡鐨勪娇鐢ㄨ鑼?,'鍩轰簬ECB妯″紡鐨勭壒鎬у拰瀹夊叏闂锛岄渶閬靛畧浠ヤ笅浣跨敤瑙勮寖锛歕n1. 绂佹鍦烘櫙锛氬姞瀵嗘湁閲嶅妯″紡鐨勪笟鍔℃暟鎹紙濡傛枃鏈€佸浘鐗囥€侀煶棰戯級銆侀暱鏁版嵁銆佺敤鎴锋晱鎰熶俊鎭紱\n2. 闄愬埗鍦烘櫙锛氫粎鍦ㄦ暟鎹畬鍏ㄩ殢鏈?鏃犻噸澶嶆ā寮忋€侀暱搴︽瀬鐭殑鐗规畩鍦烘櫙涓嬭皑鎱庝娇鐢紱\n3. 鏇夸唬鏂规锛氫紭鍏堜娇鐢–BC锛堥渶闅忔満IV锛夈€丟CM锛堝甫璁よ瘉锛夌瓑瀹夊叏妯″紡锛沑n4. 瀹炵幇娉ㄦ剰锛氬嵆浣垮疄鐜癊CB妯″紡锛屼篃闇€瀹屽杽濉厖/鍘诲～鍏呫€侀暱搴︽牎楠岀瓑杈圭晫澶勭悊锛沑n5. 瀹夊叏瀹¤锛氳嫢绯荤粺涓娇鐢ㄤ簡ECB妯″紡锛岄渶璇勪及鏄惁瀛樺湪鏁版嵁娉勯湶椋庨櫓锛屽強鏃舵浛鎹负瀹夊叏妯″紡銆?,'璁颁綇鏍稿績缁撹锛欵CB妯″紡浠呴€傚悎鐞嗚瀛︿範鍜屾瀬鐗规畩鍦烘櫙锛屽疄闄呴」鐩腑搴旈伩鍏嶄娇鐢?,NULL),(278,45,1,'鐞嗚ВCBC妯″紡鏍稿績宸ヤ綔鍘熺悊','CBC锛圕ipher Block Cha