€俓n### 涓嶉€傜敤鍦烘櫙\n- 璧勬簮鏋佸害鍙楅檺鐨勫井鍨嬭澶囷紙濡?浣峂CU锛夛細GF(2^128)涔樻硶璁＄畻寮€閿€杈冨ぇ锛沑n- 鏃犳硶淇濊瘉Nonce鍞竴鎬х殑鍦烘櫙锛堥渶鏀圭敤GMAC+CTR缁勫悎锛夛紱\n- 闇€鍏煎鑰佹棫绯荤粺鐨勫満鏅紙浼樺厛閫夋嫨CBC+HMAC锛夈€?,'瀹為檯宸ョ▼涓紭鍏堜娇鐢∣penSSL/瀵嗙爜瀛﹀簱鐨勫師鐢烥CM瀹炵幇锛岄伩鍏嶈嚜琛屽疄鐜颁冀缃楀崕涔樻硶锛堟槗寮曞叆瀹夊叏婕忔礊锛?,NULL),(317,50,5,'瀹炵幇GCM妯″紡鐨勬牳蹇冨姞瑙ｅ瘑绫?,'鍩轰簬Python瀹炵幇GCM妯″紡鐨勮璇佸姞瀵嗛€昏緫锛岀户鎵垮垎缁勫瘑鐮佹ā寮忓熀绫伙紝鏍稿績妯″潡鎷嗚В锛歕n1. 鍒濆鍖栨柟娉曪細\n   - 寮哄埗128浣嶏紙16瀛楄妭锛夊垎缁勯暱搴︼紝GCM浠呮敮鎸佽瑙勬牸锛沑n   - 璁剧疆妯″紡鍚嶇О涓篭"GCM\"锛沑n2. 鏍稿績杈呭姪鏂规硶锛歕n   a. `_ghash`锛欸alois鍩熷搱甯屽嚱鏁帮紝澶勭悊AAD+瀵嗘枃鐢熸垚璁よ瘉鎽樿锛沑n      - 鏁版嵁濉厖鑷冲垎缁勮竟鐣岋紝鍒濆鍖栭浂鍧楃粨鏋滐紱\n      - 閫愬垎缁勫紓鎴栧悗鎵цGalois涔樻硶锛沑n   b. `_galois_multiply`锛欸F(2^128)澶氶」寮忎箻娉曪紙绠€鍖栧疄鐜帮紝鐢熶骇鐜闇€鐢ㄦ爣鍑嗗疄鐜帮級锛沑n   c. `_increment_counter`锛?28浣嶈鏁板櫒閫掑锛堝ぇ绔簭锛屾ā2^128锛夛紱\n   d. `_constant_time_compare`锛氬父鏁版椂闂存瘮杈冩爣绛撅紝闃叉璁℃椂鏀诲嚮锛沑n3. 鍔犲瘑鏂规硶`encrypt`锛歕n   - 鐢熸垚/楠岃瘉96浣峃once锛岃绠楀搱甯屽瘑閽=E_K(闆跺潡)锛沑n   - 鍒濆鍖栬鏁板櫒J0锛?6浣峃once+00000001锛夛紱\n   - 鎵цCTR鍔犲瘑鐢熸垚瀵嗘枃锛沑n   - 鏋勫缓璁よ瘉鏁版嵁锛圓AD闀垮害+瀵嗘枃闀垮害+AAD+瀵嗘枃锛夛紱\n   - 璁＄畻GHASH鍊糞锛屽紓鎴朎_K(J0)鐢熸垚128浣嶆爣绛撅紱\n   - 杩斿洖锛堝瘑鏂囷紝鏍囩锛夛紱\n4. 瑙ｅ瘑鏂规硶`decrypt`锛歕n   - 楠岃瘉Nonce/鏍囩闀垮害锛岃绠楀搱甯屽瘑閽锛沑n   - 閲嶆柊璁＄畻璁よ瘉鏍囩骞朵笌浼犲叆鏍囩甯告暟鏃堕棿姣旇緝锛堜笉鍖归厤鍒欐姏寮傚父锛夛紱\n   - 鏍囩楠岃瘉閫氳繃鍚庢墽琛孋TR瑙ｅ瘑锛岃繑鍥炴槑鏂囥€?,NULL,'import os\nimport struct\nfrom typing import List, Tuple, Callable, Optional\nfrom modes_base import BlockCipherMode, SimpleAES\n\nclass GCMMode(BlockCipherMode):\n    \"\"\"Galois/Counter Mode (GCM) - 璁よ瘉鍔犲瘑妯″紡\"\"\"\n    \n    def __init__(self, block_size: int = 16):\n        super().__init__(block_size)\n        self.name = \"GCM\"\n        # GCM浠呮敮鎸?28浣嶏紙16瀛楄妭锛夊垎缁勫ぇ灏廫n        if block_size != 16:\n            raise ValueError(\"GCM妯″紡鍙敮鎸?28浣嶅垎缁勫ぇ灏廫")\n    \n    def _ghash(self, data: bytes, h: bytes) -> bytes:\n        \"\"\"GHASH鍑芥暟 - Galois鍩烥F(2^128)涓婄殑涔樻硶鍝堝笇\"\"\"\n        # 濉厖鍒板垎缁勮竟鐣孿n        if len(data) % self.block_size != 0:\n            padding_length = self.block_size - (len(data) % self.block_size)\n            data += b\'\\x00\' * padding_length\n        \n        result = b\'\\x00\' * self.block_size\n        # 閫愬垎缁勫鐞哱n        for i in range(0, len(data), self.block_size):\n            block = data[i:i + self.block_size]\n            result = self._xor_blocks(result, block)\n            result = self._galois_multiply(result, h)\n        return result\n    \n    def _galois_multiply(self, x: bytes, y: bytes) -> bytes:\n        \"\"\"GF(2^128)鍩熶笂鐨勫椤瑰紡涔樻硶锛堢畝鍖栧疄鐜帮級\"\"\"\n        x_int = int.from_bytes(x, \'big\')\n        y_int = int.from_bytes(y, \'big\')\n        \n        result = 0\n        for i in range(128):\n            if (y_int >> i) & 1:\n                result ^= (x_int << i)\n        \n        # 妯ES涓嶅彲绾﹀椤瑰紡 x^128 + x^7 + x^2 + x + 1\n        result = result & ((1 << 128) - 1)\n        return result.to_bytes(16, \'big\')\n    \n    def _generate_nonce(self) -> bytes:\n        \"\"\"鐢熸垚鎺ㄨ崘鐨?6浣嶏紙12瀛楄妭锛夐殢鏈簄once\"\"\"\n        return os.urandom(12)\n    \n    def encrypt(self, plaintext: bytes, key: bytes, iv: Optional[bytes] = None, \n                aad: bytes = b\'\') -> Tuple[bytes, bytes]:\n        \"\"\"GCM鍔犲瘑锛氳繑鍥?瀵嗘枃, 璁よ瘉鏍囩)\"\"\"\n        cipher = SimpleAES(key)\n        \n        # 澶勭悊Nonce锛堟帹鑽?2瀛楄妭锛塡n        if iv is None:\n            nonce = self._generate_nonce()\n        else:\n            nonce = iv\n            if len(nonce) != 12:\n                raise ValueError(\"GCM nonce闀垮害蹇呴』涓?2瀛楄妭\")\n        \n        # 璁＄畻鍝堝笇瀵嗛挜H = E_K(0^128)\n        zero_block = b\'\\x00\' * self.block_size\n        h = cipher.encrypt_block(zero_block)\n        \n        # 鍒濆鍖栬鏁板櫒J0\n        j0 = nonce + b\'\\x00\\x00\\x00\\x01\'\n        \n        # CTR妯″紡鍔犲瘑\n        ciphertext = b\'\'\n        counter = j0\n        for i in range(0, len(plaintext), self.block_size):\n            keystream_block = cipher.encrypt_block(counter)\n            plaintext_block = plaintext[i:i + self.block_size]\n            ciphertext_block = self._xor_blocks(plaintext_block, keystream_block[:len(plaintext_block)])\n            ciphertext += ciphertext_block\n            counter = self._increment_counter(counter)\n        \n        # 璁＄畻璁よ瘉鏍囩\n        aad_len = len(aad) * 8  # 杞崲涓轰綅\n        ciphertext_len = len(ciphertext) * 8\n        auth_data = struct.pack(\'>QQ\', aad_len, ciphertext_len) + aad + ciphertext\n        s = self._ghash(auth_data, h)\n        tag = self._xor_blocks(s, cipher.encrypt_block(j0))\n        \n        return ciphertext, tag\n    \n    def decrypt(self, ciphertext: bytes, key: bytes, tag: bytes, \n                iv: Optional[bytes] = None, aad: bytes = b\'\') -> bytes:\n        \"\"\"GCM瑙ｅ瘑锛氬厛楠岃瘉鏍囩锛屽啀瑙ｅ瘑\"\"\"\n        cipher = SimpleAES(key)\n        \n        # 楠岃瘉杈撳叆鍙傛暟\n        if iv is None:\n            raise ValueError(\"GCM瑙ｅ瘑闇€瑕佹彁渚沶once\")\n        if len(iv) != 12 or len(tag) != 16:\n            raise ValueError(\"Nonce蹇呴』12瀛楄妭锛屾爣绛惧繀椤?6瀛楄妭\")\n        \n        # 璁＄畻鍝堝笇瀵嗛挜H\n        zero_block = b\'\\x00\' * self.block_size\n        h = cipher.encrypt_block(zero_block)\n        \n        # 楠岃瘉璁よ瘉鏍囩\n        j0 = iv + b\'\\x00\\x00\\x00\\x01\'\n        aad_len = len(aad) * 8\n        ciphertext_len = len(ciphertext) * 8\n        auth_data = struct.pack(\'>QQ\', aad_len, ciphertext_len) + aad + ciphertext\n        s = self._ghash(auth_data, h)\n        expected_tag = self._xor_blocks(s, cipher.encrypt_block(j0))\n        \n        # 甯告暟鏃堕棿姣旇緝锛岄槻姝㈣鏃舵敾鍑籠n        if not self._constant_time_compare(tag, expected_tag):\n            raise ValueError(\"璁よ瘉澶辫触锛氭爣绛句笉鍖归厤\")\n        \n        # CTR妯″紡瑙ｅ瘑\n        plaintext = b\'\'\n        counter = j0\n        for i in range(0, len(ciphertext), self.block_size):\n            keystream_block = cipher.encrypt_block(counter)\n            ciphertext_block = ciphertext[i:i + self.block_size]\n            plaintext_block = self._xor_blocks(ciphertext_block, keystream_block[:len(ciphertext_block)])\n            plaintext += plaintext_block\n            counter = self._increment_counter(counter)\n        \n        return plaintext\n    \n    def _increment_counter(self, counter: bytes) -> bytes:\n        \"\"\"128浣嶈鏁板櫒閫掑锛堝ぇ绔簭锛塡"\"\"\n        counter_int = int.from_bytes(counter, byteorder=\'big\')\n        counter_int = (counter_int + 1) % (2 ** 128)\n        return counter_int.to_bytes(16, byteorder=\'big\')\n    \n    def _constant_time_compare(self, a: bytes, b: bytes) -> bool:\n        \"\"\"甯告暟鏃堕棿姣旇緝锛岄伩鍏嶈鏃舵敾鍑籠"\"\"\n        if len(a) != len(b):\n            return False\n        result = 0\n        for x, y in zip(a, b):\n            result |= x ^ y\n        return result == 0'),(318,50,6,'娴嬭瘯GCM妯″紡鐨勮璇佸姞瀵嗘纭€?,'缂栧啓瀹屾暣娴嬭瘯浠ｇ爜锛岄獙璇丟CM妯″紡鐨勬牳蹇冨姛鑳斤細\n1. 鍩虹鍔犺В瀵嗛獙璇侊細\n   - 浣跨敤12瀛楄妭鍥哄畾Nonce锛堜究浜庢紨绀猴級銆?6瀛楄妭AES瀵嗛挜锛沑n   - 鍔犲瘑娴嬭瘯鏄庢枃锛岃緭鍑哄瘑鏂囬暱搴︺€佹爣绛鹃暱搴︺€佸瘑鏂囩墖娈点€佹爣绛撅紱\n   - 瑙ｅ瘑骞堕獙璇佹槑鏂囦竴鑷存€э紱\n2. AAD闄勫姞璁よ瘉鏁版嵁娴嬭瘯锛歕n   - 浼犲叆鑷畾涔堿AD鏁版嵁锛堝\"Additional authenticated data\"锛夛紱\n   - 鍔犲瘑鐢熸垚甯AD鐨勫瘑鏂囧拰鏍囩锛沑n   - 瑙ｅ瘑鏃朵紶鍏ョ浉鍚孉AD锛岄獙璇佹槑鏂囦竴鑷存€э紱\n3. 寮傚父鍦烘櫙娴嬭瘯锛堝彲閫夛級锛歕n   - 绡℃敼鏍囩鍚庤В瀵嗭紝楠岃瘉璁よ瘉澶辫触锛沑n   - 鏇存敼AAD鍚庤В瀵嗭紝楠岃瘉璁よ瘉澶辫触锛沑n   - 浣跨敤闈?2瀛楄妭Nonce锛岄獙璇佸弬鏁版牎楠岋紱\n4. 鏍稿績楠岃瘉鐐癸細\n   - 鏍囩闀垮害鍥哄畾涓?6瀛楄妭锛沑n   - 瀵嗘枃闀垮害涓庢槑鏂囦竴鑷达紙鏃犲～鍏咃級锛沑n   - 鏍囩楠岃瘉澶辫触鏃舵棤娉曡В瀵嗐€?,NULL,'# GCM妯″紡娴嬭瘯浠ｇ爜\nkey = b\'0123456789abcdef\'  # 16瀛楄妭AES瀵嗛挜\nplaintext = b\'Hello, this is a test message for block cipher modes!\'  # 53瀛楄妭鏄庢枃\n\ntry:\n    # 鍒濆鍖朑CM妯″紡\n    gcm_mode = GCMMode()\n    \n    # 1. 鍩虹鍔犺В瀵嗘祴璇曪紙鍥哄畾Nonce渚夸簬婕旂ず锛塡n    nonce = b\'012345678901\'  # 12瀛楄妭Nonce\n    ciphertext, tag = gcm_mode.encrypt(plaintext, key, iv=nonce)\n    print(f\"瀵嗘枃闀垮害: {len(ciphertext)} 瀛楄妭\")\n    print(f\"璁よ瘉鏍囩闀垮害: {len(tag)} 瀛楄妭\")\n    print(f\"瀵嗘枃: {ciphertext.hex()[:64]}...\")\n    print(f\"鏍囩: {tag.hex()}\")\n    \n    # 瑙ｅ瘑楠岃瘉\n    decrypted = gcm_mode.decrypt(ciphertext, key, tag, iv=nonce)\n    print(f\"瑙ｅ瘑缁撴灉: {decrypted}\")\n    print(f\"鍩虹娴嬭瘯姝ｇ‘鎬? {\'鉁匼' if plaintext == decrypted else \'鉂孿'}\")\n    \n    # 2. AAD闄勫姞璁よ瘉鏁版嵁娴嬭瘯\n    aad = b\"Additional authenticated data\"  # 闄勫姞璁よ瘉鏁版嵁锛堝鍗忚澶达級\n    ciphertext_aad, tag_aad = gcm_mode.encrypt(plaintext, key, iv=nonce, aad=aad)\n    decrypted_aad = gcm_mode.decrypt(ciphertext_aad, key, tag_aad, iv=nonce, aad=aad)\n    print(f\"AAD璁よ瘉娴嬭瘯: {\'鉁匼' if plaintext == decrypted_aad else \'鉂孿'}\")\n    \n    # 3. 鏍囩绡℃敼娴嬭瘯锛堥獙璇佽璇佸け璐ワ級\n    fake_tag = tag[:7] + b\'\\xff\' + tag[8:]\n    try:\n        gcm_mode.decrypt(ciphertext, key, fake_tag, iv=nonce)\n        print(f\"鏍囩绡℃敼娴嬭瘯: 鉂?璁よ瘉鏈け璐")\n    except ValueError as e:\n        print(f\"鏍囩绡℃敼娴嬭瘯: 鉁?{e}\")\n        \nexcept Exception as e:\n    print(f\"鉂?娴嬭瘯閿欒: {e}\")'),(319,50,7,'鎬荤粨GCM妯″紡鐨勪娇鐢ㄨ鑼冧笌宸ョ▼瀹炶返','### 鏍稿績浣跨敤瑙勮寖\n1. Nonce绠＄悊锛堟渶楂樹紭鍏堢骇锛夛細\n   - 蹇呴』浣跨敤鍔犲瘑瀹夊叏鐨勯殢鏈烘暟鐢熸垚鍣ㄧ敓鎴?6浣峃once锛沑n   - 鍚屼竴瀵嗛挜涓婲once缁濆涓嶈兘閲嶅锛堝缓璁瘑閽ヨ疆鎹㈡満鍒讹級锛沑n   - 绂佹浣跨敤鍙娴嬬殑Nonce锛堝鏃堕棿鎴炽€佽嚜澧炲簭鍒楋級锛沑n2. 鏍囩澶勭悊锛歕n   - 鏍囩闀垮害鍥哄畾涓?28浣嶏紙16瀛楄妭锛夛紝绂佹缂╃煭锛沑n   - 瑙ｅ瘑鏃跺繀椤诲厛楠岃瘉鏍囩锛岄獙璇佸け璐ョ珛鍗崇粓姝㈡祦绋嬶紱\n   - 鏍囩闇€涓庡瘑鏂囦竴璧峰瓨鍌?浼犺緭锛屼笉鍙崟鐙涪寮冿紱\n3. AAD浣跨敤锛歕n   - AAD鍖呭惈闇€瑕佽璇佷絾鏃犻渶鍔犲瘑鐨勬暟鎹紙濡傚崗璁増鏈€佽姹傚ご锛夛紱\n   - 鍔犲瘑鍜岃В瀵嗙殑AAD蹇呴』瀹屽叏涓€鑷达紙瀛楄妭绾у尮閰嶏級锛沑n4. 瀹炵幇瑙勮寖锛歕n   - 鐢熶骇鐜浼樺厛浣跨敤鎴愮啛瀵嗙爜搴擄紙濡侽penSSL銆乧ryptography锛夌殑GCM瀹炵幇锛沑n   - 鑷畾涔夊疄鐜伴渶涓ユ牸閬靛惊GF(2^128)涔樻硶鏍囧噯锛岀姝㈢畝鍖栵紱\n   - 鏍囩姣旇緝蹇呴』浣跨敤甯告暟鏃堕棿绠楁硶锛岄槻姝㈣鏃舵敾鍑汇€俓n### 宸ョ▼瀹炶返寤鸿\n- 瀵嗛挜绠＄悊锛氫娇鐢ㄥ瘑閽ユ淳鐢熷嚱鏁帮紙KDF锛夌敓鎴怗CM瀵嗛挜锛屽畾鏈熻疆鎹紱\n- 鎬ц兘浼樺寲锛氬埄鐢ㄥ苟琛岃绠楀姞閫烠TR鍔犲瘑鍜孏HASH璁よ瘉锛沑n- 鍏煎鎬э細TLS 1.3涓璆CM鏄粯璁ゆā寮忥紝闇€鍏煎96浣峃once瑙勮寖锛沑n- 鐩戞帶锛氳褰昇once浣跨敤鎯呭喌锛岄槻姝㈤噸澶嶄娇鐢ㄣ€?,'璁颁綇GCM鐨勬牳蹇冨彛璇€锛歕"CTR鍔犲瘑淇濇満瀵嗭紝Galois璁よ瘉淇濆畬鏁达紝Nonce鍞竴淇濆畨鍏紝鏍囩楠岃瘉鍏堜簬瑙ｅ瘑\"',NULL),(320,51,1,'浜嗚ВRSA绠楁硶璧锋簮涓庢剰涔?,'RSA鐢盡IT瀛﹁€匯ivest銆丼hamir鍜孉dleman浜?977骞存彁鍑猴紝鍙栦笁浜哄姘忛瀛楁瘝鍛藉悕锛屾槸绗竴涓疄鐢ㄧ殑鍏挜瀵嗙爜浣撳埗銆俓n鍦≧SA鍑虹幇鍓嶏紝瀵嗙爜瀛︿互瀵圭О鍔犲瘑涓轰富锛屾牳蹇冪棝鐐规槸瀵嗛挜鍒嗗彂闅鹃鈥斺€旈€氫俊鍙屾柟闇€鎻愬墠瀹夊叏鍏变韩瀵嗛挜锛屾棤娉曢€傚簲寮€鏀剧綉缁滅幆澧冦€俓n1976骞碊iffie鍜孒ellman鎻愬嚭鍏挜瀵嗙爜瀛︽蹇碉紝浣嗘湭瀹炵幇瀹屾暣鍔犲瘑涓庣鍚嶏紱RSA鐨勭獊鐮村湪浜庡熀浜庡ぇ鏁存暟鍥犳暟鍒嗚В鐨勫崟鍚戝嚱鏁扮壒鎬э紝棣栨瀹炵幇浜嗗姞瀵嗐€佽В瀵嗐€佺鍚嶃€侀獙璇佸叏鍔熻兘锛屼负浜掕仈缃戝畨鍏ㄥ瀹氬熀纭€銆俓nRSA浜?977骞村叕寮€鍙戣〃锛?978骞寸敵璇蜂笓鍒╋紝2000骞翠笓鍒╄繃鏈熷悗杩涘叆鍏叡棰嗗煙锛岃嚦浠婁粛鏄疕TTPS銆丼SH銆丳GP绛夊崗璁殑鏍稿績缁勪欢锛屽瘑閽ラ暱搴︿粠鏃╂湡512浣嶆紨杩涜嚦褰撳墠涓绘祦鐨?048浣嶃€?096浣嶃€?,'RSA鏄瘑鐮佸鍙蹭笂鐨勯噷绋嬬锛岃В鍐充簡瀵圭О鍔犲瘑鐨勫瘑閽ュ垎鍙戦毦棰?,NULL),(321,51,2,'鎺屾彙RSA鏍稿績鏁拌鍩虹','RSA鐨勬暟瀛﹀熀鐭虫槸鏁拌涓殑妯¤繍绠椼€佹鎷夊嚱鏁般€佹鎷夊畾鐞嗐€佹ā閫嗗厓鍜屼腑鍥藉墿浣欏畾鐞嗭紝鏍稿績鐭ヨ瘑鐐瑰涓嬶細\n1. 妯¤繍绠楋細鑻?n \\mid (a - b)$锛屽垯$a \\equiv b \\pmod{n}$锛屾槸RSA鍔犺В瀵嗙殑鍩虹杩愮畻锛沑n2. 娆ф媺鍑芥暟锛氳嫢$n = pq$锛?p銆乹$涓鸿川鏁帮級锛屽垯$\\phi(n) = (p-1)(q-1)$锛岃〃绀?~n涓笌n浜掕川鐨勬暣鏁颁釜鏁帮紱\n3. 娆ф媺瀹氱悊锛氳嫢$\\gcd(a, n) = 1$锛屽垯$a^{\\phi(n)} \\equiv 1 \\pmod{n}$锛屾槸RSA鍙€嗘€х殑鏍稿績淇濋殰锛沑n4. 璐归┈灏忓畾鐞嗭細娆ф媺瀹氱悊鐨勭壒渚嬶紝鑻?p$涓虹礌鏁颁笖$\\gcd(a, p) = 1$锛屽垯$a^{p-1} \\equiv 1 \\pmod{p}$锛沑n5. 妯￠€嗗厓锛氳嫢$ed \\equiv 1 \\pmod{\\phi(n)}$锛屽垯$d$鏄?e$鍦ㄦā$\\phi(n)$涓嬬殑閫嗗厓锛屾槸绉侀挜鐢熸垚鐨勫叧閿紱\n6. 涓浗鍓╀綑瀹氱悊锛氱敤浜庝紭鍖朢SA瑙ｅ瘑杩囩▼锛屽皢澶ф暣鏁拌繍绠楁媶瑙ｄ负灏忔暣鏁拌繍绠楋紝鎻愬崌瑙ｅ瘑鏁堢巼銆?,'鏃犻渶娣卞叆鎺ㄥ鏁拌瀹氱悊锛岄噸鐐规帉鎻″簲鐢ㄥ満鏅拰鍏紡鍚箟',NULL),(322,51,3,'鐞嗚ВRSA瀵嗛挜鐢熸垚娴佺▼','RSA瀵嗛挜鐢熸垚鏄畻娉曠殑鏍稿績姝ラ锛屽熀浜庡ぇ绱犳暟鍜屾暟璁虹壒鎬х敓鎴愬叕閽ュ拰绉侀挜锛屽叿浣撴祦绋嬪涓嬶細\n1. 閫夊彇涓や釜澶ц川鏁?p$鍜?q$锛氶渶淇濊瘉$p \\neq q$锛屼笖浣嶆暟瓒冲锛堝1024浣嶅瘑閽ュ搴斾袱涓?12浣嶈川鏁帮級锛岃川鏁拌川閲忕洿鎺ュ喅瀹歊SA瀹夊叏鎬э紱\n2. 璁＄畻妯℃暟$n$锛?n = p \\times q$锛?n$鏄叕閽ュ拰绉侀挜鐨勫叡鍚岀粍鎴愰儴鍒嗭紝涔熸槸鍔犺В瀵嗙殑鏍稿績鍙傛暟锛屽叾浣嶆暟鍗冲瘑閽ラ暱搴︼紱\n3. 璁＄畻娆ф媺鍑芥暟$\\phi(n)$锛氭牴鎹鎷夊嚱鏁版€ц川锛?\\phi(n) = (p-1)(q-1)$锛岀敤浜庡悗缁閽ユ寚鏁拌绠楋紱\n4. 閫夋嫨鍏挜鎸囨暟$e$锛氭弧瓒?1 < e < \\phi(n)$涓?\\gcd(e, \\phi(n)) = 1$锛堝嵆$e$涓?\\phi(n)$浜掕川锛夛紝甯哥敤鍊间负65537锛堟棦瀹夊叏鍙堥珮鏁堬紝鍏奸【璁＄畻閫熷害鍜屾姉鏀诲嚮鑳藉姏锛夛紱\n5. 璁＄畻绉侀挜鎸囨暟$d$锛?d$鏄?e$鍦ㄦā$\\phi(n)$涓嬬殑閫嗗厓锛屽嵆婊¤冻$ed \\equiv 1 \\pmod{\\phi(n)}$锛岄€氳繃鎵╁睍娆у嚑閲屽緱绠楁硶姹傝В锛沑n6. 纭畾瀵嗛挜瀵癸細鍏挜涓?(e, n)$锛堝彲鍏紑锛夛紝绉侀挜涓?(d, n)$锛堥渶涓ユ牸淇濆瘑锛夛紝鍚屾椂閿€姣佷腑闂村弬鏁?p銆乹銆乗\phi(n)$銆俓n绀轰緥锛氬彇$p=61$銆?q=53$锛屽垯$n=61脳53=3233$锛?\\phi(n)=60脳52=3120$锛岄€?e=17$锛堜笌3120浜掕川锛夛紝閫氳繃鎵╁睍娆у嚑閲屽緱绠楁硶姹傚緱$d=2753$锛屾渶缁堝叕閽?(17, 3233)$锛岀閽?(2753, 3233)$銆?,'鍏挜鎸囨暟$e=65537$鏄伐涓氭爣鍑嗭紝閬垮厤浣跨敤杩囧皬鐨?e$锛堝3銆?7锛変互闄嶄綆瀹夊叏椋庨櫓',NULL),(323,51,4,'鎺屾彙RSA鍔犺В瀵嗗師鐞嗕笌鍏紡','RSA鍔犺В瀵嗗熀浜庢ā骞傝繍绠楋紝鍒╃敤鍏挜鍔犲瘑銆佺閽ヨВ瀵嗭紝涓旇繃绋嬪彲閫嗭紝鏍稿績鍏紡鍜屾祦绋嬪涓嬶細\n### 鍔犲瘑杩囩▼\n1. 鏄庢枃棰勫鐞嗭細灏嗘槑鏂囪浆鎹负鏁存暟$M$锛岄渶婊¤冻$0 < M < n$锛堣嫢鏄庢枃闀垮害瓒呰繃$n$鐨勬瘮鐗规暟锛岄渶鍒嗘鍔犲瘑锛夛紱\n2. 妯″箓杩愮畻锛氫娇鐢ㄥ叕閽?(e, n)$璁＄畻瀵嗘枃$C$锛屽叕寮忎负$C \\equiv M^e \\pmod{n}$锛沑n绀轰緥锛氭槑鏂?M=65$锛屽叕閽?(17, 3233)$锛屽垯$C=65^{17} \\pmod{3233}=2790$銆俓n\n### 瑙ｅ瘑杩囩▼\n1. 瀵嗘枃杈撳叆锛氳幏鍙栧瘑鏂?C$锛岀‘淇?0 < C < n$锛沑n2. 妯″箓杩愮畻锛氫娇鐢ㄧ閽?(d, n)$璁＄畻鏄庢枃$M$锛屽叕寮忎负$M \\equiv C^d \\pmod{n}$锛沑n绀轰緥锛氬瘑鏂?C=2790$锛岀閽?(2753, 3233)$锛屽垯$M=2790^{2753} \\pmod{3233}=65$銆俓n\n### 姝ｇ‘鎬ц瘉鏄嶾n鐢辩閽ョ敓鎴愯繃绋嬪彲鐭?ed \\equiv 1 \\pmod{\\phi(n)}$锛屽嵆瀛樺湪鏁存暟$k$浣垮緱$ed=1+k\\phi(n)$銆俓n鏍规嵁娆ф媺瀹氱悊锛岃嫢$\\gcd(M, n)=1$锛屽垯$M^{\\phi(n)} \\equiv 1 \\pmod{n}$锛屽洜姝わ細\n$M^{ed}=M^{1+k\\phi(n)}=M脳(M^{\\phi(n)})^k \\equiv M脳1^k=M \\pmod{n}$锛屽嵆瑙ｅ瘑鍙繕鍘熸槑鏂囥€俓n鑻?\\gcd(M, n)鈮?$锛屽彲閫氳繃涓浗鍓╀綑瀹氱悊璇佹槑浠嶆弧瓒冲彲閫嗘€с€?,'鍔犺В瀵嗗潎浣跨敤妯″箓杩愮畻锛屽疄闄呭疄鐜伴渶鐢ㄢ€滃钩鏂?涔樷€濈畻娉曚紭鍖栬绠楁晥鐜?,NULL),(324,51,5,'鐞嗚ВRSA鏁板瓧绛惧悕鍘熺悊','RSA涓嶄粎鍙敤浜庡姞瀵嗭紝杩樺彲瀹炵幇鏁板瓧绛惧悕锛屾牳蹇冩€濇兂鏄€滅閽ョ鍚嶃€佸叕閽ラ獙璇佲€濓紝纭繚娑堟伅瀹屾暣鎬у拰涓嶅彲鍚﹁鎬э紝娴佺▼濡備笅锛歕n### 绛惧悕杩囩▼\n1. 娑堟伅鍝堝笇锛氬鍘熷娑堟伅$M$璁＄畻鍝堝笇鍊?H(M)$锛堝SHA-256锛夛紝灏嗗搱甯屽€艰浆鎹负鏁存暟$h$锛屾弧瓒?h < n$锛沑n2. 绛惧悕鐢熸垚锛氫娇鐢ㄧ閽?(d, n)$瀵瑰搱甯屽€艰繘琛岀鍚嶏紝鍏紡涓?S \\equiv h^d \\pmod{n}$锛?S$鍗充负绛惧悕缁撴灉锛沑n### 楠岃瘉杩囩▼\n1. 娑堟伅鍝堝笇锛氭帴鏀舵柟瀵瑰師濮嬫秷鎭?M$閲嶆柊璁＄畻鍝堝笇鍊?H\'(M)$锛岃浆鎹负鏁存暟$h\'$锛沑n2. 绛惧悕楠岃瘉锛氫娇鐢ㄥ叕閽?(e, n)$瀵圭鍚?S$瑙ｅ瘑锛屽叕寮忎负$h\'\' \\equiv S^e \\pmod{n}$锛沑n3. 缁撴灉姣斿锛氳嫢$h\'\' = h\'$锛屽垯绛惧悕鏈夋晥锛堟秷鎭湭绡℃敼涓旀潵鑷閽ユ寔鏈夎€咃級锛屽惁鍒欑鍚嶆棤鏁堛€俓n绀轰緥锛氭秷鎭?M=$鈥淭his is a signed message鈥濓紝鍝堝笇鍚?h$锛岀閽ョ鍚嶅緱$S$锛屾帴鏀舵柟楠岃瘉鏃堕噸鏂拌绠楀搱甯?h\'$锛岃В瀵?S$寰?h\'\'$锛岃嫢$h\'\'=h\'$鍒欓獙璇侀€氳繃銆俓n鏁板瓧绛惧悕鐨勬牳蹇冧环鍊硷細闃叉娑堟伅琚鏀癸紙绡℃敼鍚庡搱甯屽€煎彉鍖栵級銆侀槻姝㈠彂閫佹柟鍚﹁锛堜粎绉侀挜鎸佹湁鑰呰兘鐢熸垚鏈夋晥绛惧悕锛夈€?,'绛惧悕鍓嶅繀椤诲娑堟伅鍝堝笇锛岄伩鍏嶇洿鎺ュ闀挎秷鎭鍚嶅鑷存晥鐜囦綆涓?,NULL),(325,51,6,'鎺屾彙RSA宸ョ▼瀹炵幇鏍稿績妯″潡','RSA宸ョ▼瀹炵幇闇€瑙ｅ喅绱犳暟鐢熸垚銆佹ā閫嗗厓璁＄畻銆佹ā骞傝繍绠椼€佸～鍏呮満鍒剁瓑鍏抽敭闂锛屾牳蹇冩ā鍧楀涓嬶細\n### 1. 鍩虹宸ュ叿鍑芥暟\n- 娆у嚑閲屽緱绠楁硶锛坓cd锛夛細璁＄畻涓や釜鏁扮殑鏈€澶у叕绾︽暟锛岀敤浜庡垽鏂?e$涓?\\phi(n)$鏄惁浜掕川锛沑n- 鎵╁睍娆у嚑閲屽緱绠楁硶锛坋xtended_gcd锛夛細姹傝В妯￠€嗗厓锛屾牳蹇冪敤浜庤绠楃閽ユ寚鏁?d$锛沑n- Miller-Rabin绱犳€ф祴璇曪紙is_prime锛夛細楂樻晥鍒ゆ柇澶ф暣鏁版槸鍚︿负璐ㄦ暟锛岀敤浜庣敓鎴?p$鍜?q$锛沑n- 妯″箓杩愮畻锛坧ow锛夛細浼樺寲澶ф暣鏁版ā骞傝绠楋紝閬垮厤鐩存帴璁＄畻瀵艰嚧鐨勬孩鍑哄拰浣庢晥锛沑n### 2. 濉厖鏈哄埗\n瑁窻SA瀛樺湪瀹夊叏婕忔礊锛堝閫夋嫨鏄庢枃鏀诲嚮銆佽涔夊畨鍏ㄧ己澶憋級锛岄渶閫氳繃濉厖鏈哄埗淇锛屽父鐢≒KCS#1 v1.5濉厖瑙勫垯锛歕n濉厖鏍煎紡锛?0x00 || 0x02 || PS || 0x00 || M$锛屽叾涓璓S鏄嚦灏?瀛楄妭鐨勯殢鏈洪潪闆跺瓧鑺傦紝$M$涓哄師濮嬫槑鏂囷紱\n浣滅敤锛氫繚璇佺浉鍚屾槑鏂囩敓鎴愪笉鍚屽瘑鏂囷紝闄愬埗鏄庢枃闀垮害锛岄槻姝㈡暟瀛︽敾鍑伙紱\n### 3. 瀛楄妭涓庢暣鏁拌浆鎹nRSA鍔犺В瀵嗘搷浣滃璞℃槸鏁存暟锛岄渶瀹炵幇瀛楄妭鏁版嵁涓庢暣鏁扮殑鐩镐簰杞崲锛歕n- bytes_to_int锛氬皢瀛楄妭鏁版嵁杞崲涓哄ぇ鏁存暟锛堝ぇ绔簭锛夛紱\n- int_to_bytes锛氬皢澶ф暣鏁拌浆鎹负鎸囧畾闀垮害鐨勫瓧鑺傛暟鎹紙澶х搴忥級銆?,NULL,'def gcd(a, b):\n    \"\"\"璁＄畻鏈€澶у叕绾︽暟锛堟鍑犻噷寰楃畻娉曪級\"\"\"\n    while b:\n        a, b = b, a % b\n    return a\n\ndef extended_gcd(a, b):\n    \"\"\"鎵╁睍娆у嚑閲屽緱绠楁硶锛岀敤浜庢眰妯￠€嗗厓\"\"\"\n    if a == 0:\n        return b, 0, 1\n    gcd_val, x1, y1 = extended_gcd(b % a, a)\n    x = y1 - (b // a) * x1\n    y = x1\n    return gcd_val, x, y\n\ndef mod_inverse(a, m):\n    \"\"\"璁＄畻妯￠€嗗厓\"\"\"\n    gcd_val, x, y = extended_gcd(a, m)\n    if gcd_val != 1:\n        raise ValueError(\"妯￠€嗗厓涓嶅瓨鍦╘")\n    return (x % m + m) % m'),(326,51,7,'瀹炵幇瀹屾暣RSA鍔犺В瀵嗕笌绛惧悕鍔熻兘','鍩轰簬鏍稿績妯″潡瀹炵幇瀹屾暣鐨凴SA绫伙紝鏀寔瀵嗛挜鐢熸垚銆佸瓧鑺傛暟鎹姞瑙ｅ瘑銆佹暟瀛楃鍚嶄笌楠岃瘉锛屽叿浣撳疄鐜板涓嬶細\n1. 绫诲垵濮嬪寲锛氱敓鎴愭寚瀹氶暱搴︾殑瀵嗛挜瀵癸紝瀛樺偍鍏挜$(n, e)$鍜岀閽?(n, d)$锛岃绠楀瘑閽ュ瓧鑺傞暱搴︼紱\n2. 鍔犲瘑鏂规硶锛坋ncrypt锛夛細鎺ユ敹瀛楃涓叉垨瀛楄妭鏄庢枃锛岃嚜鍔ㄧ紪鐮併€丳KCS#1濉厖銆佽浆鎹负鏁存暟銆佹ā骞傝繍绠楋紝杩斿洖瀛楄妭瀵嗘枃锛沑n3. 瑙ｅ瘑鏂规硶锛坉ecrypt锛夛細鎺ユ敹瀛楄妭瀵嗘枃锛岃浆鎹负鏁存暟銆佹ā骞傝繍绠椼€佽浆鎹负瀛楄妭銆丳KCS#1鍘诲～鍏呫€佽В鐮侊紝杩斿洖鏄庢枃锛沑n4. 绛惧悕鏂规硶锛坰ign锛夛細鎺ユ敹瀛楃涓叉垨瀛楄妭娑堟伅锛岃绠楀搱甯屽€笺€佹ā骞傝繍绠楋紙绉侀挜锛夛紝杩斿洖绛惧悕鏁存暟锛沑n5. 楠岃瘉鏂规硶锛坴erify锛夛細鎺ユ敹娑堟伅鍜岀鍚嶏紝璁＄畻鍝堝笇鍊笺€佹ā骞傝繍绠楋紙鍏挜锛夛紝姣斿缁撴灉杩斿洖楠岃瘉鐘舵€侊紱\n鏍稿績閫昏緫锛氬皝瑁呭簳灞傛暟瀛﹁繍绠楀拰鏁版嵁杞崲锛屾彁渚涚畝娲佺殑API鎺ュ彛锛屽睆钄藉鏉傜殑瀹炵幇缁嗚妭銆?,NULL,'class RSA:\n    \"\"\"RSA鍔犲瘑绫籠"\"\"\n    \n    def __init__(self, bits=1024):\n        \"\"\"鍒濆鍖朢SA瀵硅薄锛岀敓鎴愬瘑閽ュ\"\"\"\n        self.public_key, self.private_key = generate_keypair(bits)\n        self.n, self.e = self.public_key\n        self.d = self.private_key[1]\n        self.key_size = (self.n.bit_length() + 7) // 8\n    \n    def encrypt(self, message):\n        \"\"\"鍔犲瘑娑堟伅锛氭敮鎸佸瓧绗︿覆鎴栧瓧鑺俓"\"\"\n        if isinstance(message, str):\n            message = message.encode(\'utf-8\')\n        return rsa_encrypt_bytes(message, self.public_key)\n    \n    def decrypt(self, ciphertext):\n        \"\"\"瑙ｅ瘑娑堟伅锛氳繑鍥炲瓧鑺傛暟鎹甛"\"\"\n        return rsa_decrypt_bytes(ciphertext, self.private_key)\n    \n    def sign(self, message):\n        \"\"\"鏁板瓧绛惧悕锛氳繑鍥炵鍚嶆暣鏁癨"\"\"\n        if isinstance(message, str):\n            message = message.encode(\'utf-8\')\n        message_hash = hash(message) % self.n\n        return rsa_sign(message_hash, self.private_key)\n    \n    def verify(self, message, signature):\n        \"\"\"楠岃瘉绛惧悕锛氳繑鍥炲竷灏斿€糪"\"\"\n        if isinstance(message, str):\n            message = message.encode(\'utf-8\')\n        message_hash = hash(message) % self.n\n        return rsa_verify(message_hash, signature, self.public_key)'),(327,51,8,'娴嬭瘯RSA鍔熻兘姝ｇ‘鎬т笌瀹夊叏